import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useUIStore } from '@/store/uiStore';
import { useTreeStore } from '@/store/treeStore';
import { Button } from '@/components/ui/Button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { Input } from '@/components/ui/Input';
import { Tree } from '@/types';
import {
  Plus,
  Search,
  Users,
  Calendar,
  MoreVertical,
  Eye,
  Edit,
  Share,
  Archive,
  Trash2,
  Loader2,
  Globe
} from 'lucide-react';
import TreeFormModal from '@/components/trees/TreeFormModal'; // Add this import
import { useMobile } from '@/hooks/useMobile'; // Add mobile hook import

const TreesPage: React.FC = () => {
  const { language } = useUIStore();
  const { trees, publicTrees, fetchTrees, fetchPublicTrees, deleteTree, isLoading, error: storeError } = useTreeStore();
  const { isMobile } = useMobile(); // Add mobile detection
  const [searchQuery, setSearchQuery] = useState('');
  const [localError, setLocalError] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'myTrees' | 'publicTrees'>('myTrees');
  // Add state for modal
  const [isTreeFormModalOpen, setIsTreeFormModalOpen] = useState(false);

  useEffect(() => {
    fetchTrees();
    fetchPublicTrees();
  }, [fetchTrees, fetchPublicTrees]);

  const handleDeleteTree = async (treeId: string) => {
    if (!confirm(language === 'ar' ? 'هل أنت متأكد من حذف هذه الشجرة؟' : 'Are you sure you want to delete this tree?')) {
      return;
    }

    try {
      setDeletingId(treeId);
      await deleteTree(treeId);
    } catch (err) {
      // Removed console.error for error deleting tree
      setLocalError(language === 'ar' ? 'فشل في حذف الشجرة' : 'Failed to delete tree');
      // Clear the error after 3 seconds
      setTimeout(() => setLocalError(null), 3000);
    } finally {
      setDeletingId(null);
    }
  };

  const filteredTrees = trees.filter(tree =>
    tree.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
    tree.description?.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const filteredPublicTrees = publicTrees.filter(tree =>
    tree.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
    tree.description?.toLowerCase().includes(searchQuery.toLowerCase())
  );

  // Update the getCategoryLabel function to handle missing category
  const getCategoryLabel = (category: string) => {
    // Handle case where category might be undefined
    if (!category) return language === 'ar' ? 'غير محدد' : 'Not specified';
    
    const labels = {
      family: language === 'ar' ? 'عائلة' : 'Family',
      research: language === 'ar' ? 'بحث' : 'Research',
      historical: language === 'ar' ? 'تاريخي' : 'Historical',
      other: language === 'ar' ? 'أخرى' : 'Other',
    };
    return labels[category as keyof typeof labels] || category;
  };

  // Update the getCategoryColor function to handle missing category
  const getCategoryColor = (category: string) => {
    // Handle case where category might be undefined
    const colors = {
      family: 'bg-blue-100 text-blue-800',
      research: 'bg-purple-100 text-purple-800',
      historical: 'bg-green-100 text-green-800',
      other: 'bg-gray-100 text-gray-800',
    };
    return colors[category as keyof typeof colors] || colors.other;
  };

  // Use store error or local error
  const errorMessage = storeError || localError;

  // Determine which trees to display based on active tab
  const displayTrees = activeTab === 'myTrees' ? filteredTrees : filteredPublicTrees;
  const isLoadingTrees = isLoading && activeTab === 'myTrees';
  const isLoadingPublicTrees = isLoading && activeTab === 'publicTrees';

  // Add handler for tree creation
  const handleCreateTree = (tree: any) => {
    // Refresh trees list to include the new tree
    fetchTrees();
  };

  // Remove the debug component after fixing the issue
  return (
    <div className="space-y-6">
      {/* Header */}
      <div className={`flex ${isMobile ? 'flex-col gap-4' : 'flex-col sm:flex-row sm:items-center sm:justify-between'}`}>
        <div>
          <h1 className={`font-bold text-foreground ${isMobile ? 'text-2xl' : 'text-3xl'}`}>
            {language === 'ar' ? 'أشجار العائلة' : 'Family Trees'}
          </h1>
          <p className={`mt-2 text-muted-foreground ${isMobile ? 'text-sm' : ''}`}>
            {language === 'ar' 
              ? 'إدارة وعرض جميع أشجار العائلة الخاصة بك والأشجار العامة'
              : 'Manage and view all your family trees and public trees'
            }
          </p>
        </div>
        <div className={isMobile ? 'w-full' : 'mt-4 sm:mt-0'}>
          {/* Replace the Link button with a regular button that opens the modal */}
          <Button onClick={() => setIsTreeFormModalOpen(true)} className="w-full" size={isMobile ? "sm" : "default"}>
            <Plus className={`mr-2 h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
            {isMobile ? (language === 'ar' ? 'إنشاء' : 'Create') : (language === 'ar' ? 'إنشاء شجرة جديدة' : 'Create New Tree')}
          </Button>
        </div>
      </div>

      {/* Tabs */}
      <div className={`border-b border-border ${isMobile ? 'overflow-x-auto' : ''}`}>
        <nav className={`flex ${isMobile ? 'space-x-4 min-w-max' : 'space-x-8'}`}>
          <button
            onClick={() => setActiveTab('myTrees')}
            className={`py-3 px-1 border-b-2 font-medium text-sm ${
              activeTab === 'myTrees'
                ? 'border-primary text-primary'
                : 'border-transparent text-muted-foreground hover:text-foreground hover:border-muted'
            } ${isMobile ? 'text-xs py-2' : ''}`}
          >
            {language === 'ar' ? 'أشجاري' : 'My Trees'}
            <span className={`ml-2 text-xs rounded-full px-2 py-0.5 ${isMobile ? 'text-xs px-1.5 py-0.5' : ''} bg-muted text-muted-foreground`}>
              {trees.length}
            </span>
          </button>
          <button
            onClick={() => setActiveTab('publicTrees')}
            className={`py-3 px-1 border-b-2 font-medium text-sm ${
              activeTab === 'publicTrees'
                ? 'border-primary text-primary'
                : 'border-transparent text-muted-foreground hover:text-foreground hover:border-muted'
            } ${isMobile ? 'text-xs py-2' : ''}`}
          >
            {language === 'ar' ? 'أشجار عامة' : 'Public Trees'}
            <span className={`ml-2 text-xs rounded-full px-2 py-0.5 ${isMobile ? 'text-xs px-1.5 py-0.5' : ''} bg-muted text-muted-foreground`}>
              {publicTrees.length}
            </span>
          </button>
        </nav>
      </div>

      {/* Search and Filters */}
      <div className={`flex ${isMobile ? 'flex-col gap-2' : 'flex-col sm:flex-row gap-4'}`}>
        <div className="flex-1">
          <Input
            placeholder={language === 'ar' ? 'البحث في الأشجار...' : 'Search trees...'}
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            leftIcon={<Search className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />}
            className={isMobile ? 'text-sm py-2' : ''}
          />
        </div>
      </div>

      {/* Loading state */}
      {(isLoadingTrees || isLoadingPublicTrees) && (
        <div className="flex justify-center py-12">
          <Loader2 className={`animate-spin text-primary ${isMobile ? 'h-6 w-6' : 'h-8 w-8'}`} />
        </div>
      )}

      {/* Error state */}
      {errorMessage && (
        <div className="bg-destructive/10 border border-destructive/20 rounded-lg p-4">
          <p className="text-destructive text-center">{errorMessage}</p>
          <div className="text-center mt-4">
            <Button onClick={() => {
              if (activeTab === 'myTrees') {
                fetchTrees();
              } else {
                fetchPublicTrees();
              }
            }} variant="outline" size={isMobile ? "sm" : "default"}>
              {language === 'ar' ? 'إعادة المحاولة' : 'Try Again'}
            </Button>
          </div>
        </div>
      )}

      {/* Trees Grid */}
      {!(isLoadingTrees || isLoadingPublicTrees) && !errorMessage && (
        <div className={`grid ${isMobile ? 'grid-cols-1 gap-4' : 'grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6'}`}>
          {displayTrees.map((tree) => (
            <Card key={tree.id} className="hover:shadow-lg transition-shadow">
              <CardHeader className={isMobile ? 'p-4' : ''}>
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className={`flex items-center space-x-2 mb-2 ${isMobile ? 'flex-wrap gap-1' : ''}`}>
                      <CardTitle className={`font-semibold ${isMobile ? 'text-base' : 'text-lg'}`}>{tree.name}</CardTitle>
                      {/* Display a default category if not available */}
                      <span className={`px-2 py-1 text-xs rounded-full ${getCategoryColor(tree.category || 'other')} ${isMobile ? 'px-1.5 py-0.5' : ''}`}>
                        {getCategoryLabel(tree.category || 'other')}
                      </span>
                      {activeTab === 'publicTrees' && (
                        <span className={`px-2 py-1 text-xs rounded-full bg-blue-100 text-blue-800 ${isMobile ? 'px-1.5 py-0.5' : ''}`}>
                          <Globe className={`h-3 w-3 inline mr-1 ${isMobile ? 'h-2.5 w-2.5' : ''}`} />
                          {language === 'ar' ? 'عامة' : 'Public'}
                        </span>
                      )}
                    </div>
                    <CardDescription className={isMobile ? 'text-xs' : ''}>{tree.description || (language === 'ar' ? 'لا يوجد وصف' : 'No description')}</CardDescription>
                  </div>
                  {/* {activeTab === 'myTrees' && (
                    <Button variant="ghost" size="icon" className="h-8 w-8">
                      <MoreVertical className="h-4 w-4" />
                    </Button>
                  )} */}
                </div>
              </CardHeader>
              
              <CardContent className={isMobile ? 'p-4' : ''}>
                {/* Stats - removed photo counter and generation info */}
                <div className={`grid grid-cols-1 gap-3 mb-3 ${isMobile ? 'gap-2 mb-2' : 'gap-4 mb-4'}`}>
                  <div className="text-center">
                    <div className={`font-bold text-foreground ${isMobile ? 'text-xl' : 'text-2xl'}`}>
                      {tree.stats?.totalPeople !== undefined ? tree.stats.totalPeople : 'N/A'}
                    </div>
                    <div className={`text-muted-foreground ${isMobile ? 'text-xs' : 'text-xs'}`}>
                      {language === 'ar' ? 'أشخاص' : 'People'}
                    </div>
                  </div>
                </div>

                {/* Progress - using placeholder values since API doesn't return stats */}
                <div className={`mb-3 ${isMobile ? 'mb-2' : 'mb-4'}`}>
                  <div className="flex items-center justify-between text-sm mb-1">
                    <span className={`text-muted-foreground ${isMobile ? 'text-xs' : ''}`}>
                      {language === 'ar' ? 'مكتمل' : 'Complete'}
                    </span>
                    <span className={`text-foreground ${isMobile ? 'text-xs' : ''}`}>
                      {tree.stats?.completionPercentage !== undefined ? `${tree.stats.completionPercentage}%` : 'N/A'}
                    </span>
                  </div>
                  <div className="w-full bg-muted rounded-full h-2">
                    <div
                      className="bg-primary h-2 rounded-full transition-all duration-300"
                      style={{ 
                        width: `${tree.stats?.completionPercentage !== undefined ? tree.stats.completionPercentage : 0}%` 
                      }}
                    />
                  </div>
                </div>

                {/* Meta info - using placeholder values since API doesn't return these fields */}
                <div className={`flex items-center justify-between text-muted-foreground mb-3 ${isMobile ? 'text-xs mb-2' : 'text-sm mb-4'}`}>
                  <div className="flex items-center">
                    <Calendar className={`h-4 w-4 mr-1 ${isMobile ? 'h-3 w-3' : ''}`} />
                    {tree.updatedAt ? new Date(tree.updatedAt).toLocaleDateString() : 'N/A'}
                  </div>
                  {/* Using members array length as a proxy for shared users if available */}
                  {tree.members && tree.members.length > 0 && (
                    <div className="flex items-center">
                      <Users className={`h-4 w-4 mr-1 ${isMobile ? 'h-3 w-3' : ''}`} />
                      {tree.members.length}
                    </div>
                  )}

                </div>

                {/* Actions */}
                <div className={`flex ${isMobile ? 'gap-1' : 'gap-2'}`}>
                  <Button asChild size={isMobile ? "sm" : "sm"} className="flex-1">
                    <Link to={`/trees/${tree.id}`}>
                      <Eye className={`h-4 w-4 mr-1 ${isMobile ? 'h-3 w-3' : ''}`} />
                      <span className={isMobile ? 'hidden' : ''}>{language === 'ar' ? 'عرض' : 'View'}</span>
                    </Link>
                  </Button>
                  {activeTab === 'myTrees' ? (
                    <>
                      <Button asChild variant="outline" size={isMobile ? "icon" : "sm"}>
                        <Link to={`/trees/${tree.id}/edit`}>
                          <Edit className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
                        </Link>
                      </Button>
                      <Button 
                        variant="outline" 
                        size={isMobile ? "icon" : "sm"}
                        onClick={() => handleDeleteTree(tree.id)}
                        disabled={deletingId === tree.id}
                      >
                        {deletingId === tree.id ? (
                          <Loader2 className={`h-4 w-4 animate-spin ${isMobile ? 'h-3 w-3' : ''}`} />
                        ) : (
                          <Trash2 className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
                        )}
                      </Button>
                    </>
                  ) : (
                    <Button variant="outline" size={isMobile ? "icon" : "sm"} onClick={() => {
                      // Copy share link to clipboard
                      const shareUrl = `${window.location.origin}/shared/${tree.id}`;
                      copyToClipboard(shareUrl);
                    }}>
                      <Share className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
                    </Button>
                  )}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Empty state */}
      {!(isLoadingTrees || isLoadingPublicTrees) && !errorMessage && displayTrees.length === 0 && (
        <div className="text-center py-12">
          <div className={`mx-auto bg-muted rounded-full flex items-center justify-center mb-4 ${isMobile ? 'w-20 h-20' : 'w-24 h-24'}`}>
            <Users className={`text-muted-foreground ${isMobile ? 'h-10 w-10' : 'h-12 w-12'}`} />
          </div>
          <h3 className={`font-medium text-foreground mb-2 ${isMobile ? 'text-base' : 'text-lg'}`}>
            {searchQuery 
              ? (language === 'ar' ? 'لا توجد نتائج' : 'No results found')
              : activeTab === 'myTrees'
                ? (language === 'ar' ? 'لا توجد أشجار عائلة' : 'No family trees yet')
                : (language === 'ar' ? 'لا توجد أشجار عامة' : 'No public trees available')
            }
          </h3>
          <p className={`text-muted-foreground mb-6 ${isMobile ? 'text-sm' : ''}`}>
            {searchQuery
              ? (language === 'ar' ? 'جرب البحث بكلمات مختلفة' : 'Try searching with different keywords')
              : activeTab === 'myTrees'
                ? (language === 'ar' ? 'ابدأ بإنشاء شجرة عائلتك الأولى' : 'Start by creating your first family tree')
                : (language === 'ar' ? 'تحقق لاحقاً لل_trees العامة الجديدة' : 'Check back later for new public trees')
            }
          </p>
          {activeTab === 'myTrees' && !searchQuery && (
            <Button asChild size={isMobile ? "sm" : "default"}>
              <Link to="/trees/create">
                <Plus className={`mr-2 h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
                {isMobile ? (language === 'ar' ? 'إنشاء' : 'Create') : (language === 'ar' ? 'إنشاء شجرة جديدة' : 'Create New Tree')}
              </Link>
            </Button>
          )}
        </div>
      )}

      {/* Quick stats - removed generation stats card */}
      {!(isLoadingTrees || isLoadingPublicTrees) && !errorMessage && activeTab === 'myTrees' && (
        <div className={`grid ${isMobile ? 'grid-cols-1 gap-3' : 'grid-cols-1 sm:grid-cols-3 gap-4'}`}>
          <Card>
            <CardContent className={`p-3 ${isMobile ? 'p-3' : 'p-4'}`}>
              <div className="flex items-center space-x-2">
                <div className={`rounded-full flex items-center justify-center ${isMobile ? 'w-7 h-7' : 'w-8 h-8'} bg-blue-100`}>
                  <Users className={`text-blue-600 ${isMobile ? 'h-3.5 w-3.5' : 'h-4 w-4'}`} />
                </div>
                <div>
                  <div className={`font-semibold ${isMobile ? 'text-lg' : 'text-lg'}`}>{trees.length}</div>
                  <div className={`text-muted-foreground ${isMobile ? 'text-xs' : 'text-sm'}`}>
                    {language === 'ar' ? 'إجمالي الأشجار' : 'Total Trees'}
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardContent className={`p-3 ${isMobile ? 'p-3' : 'p-4'}`}>
              <div className="flex items-center space-x-2">
                <div className={`rounded-full flex items-center justify-center ${isMobile ? 'w-7 h-7' : 'w-8 h-8'} bg-green-100`}>
                  <Users className={`text-green-600 ${isMobile ? 'h-3.5 w-3.5' : 'h-4 w-4'}`} />
                </div>
                <div>
                  <div className={`font-semibold ${isMobile ? 'text-lg' : 'text-lg'}`}>
                    {/* Calculate total people from available data or show N/A */}
                    {trees.length > 0 && trees.some(tree => tree.stats?.totalPeople !== undefined) 
                      ? trees.reduce((sum, tree) => sum + (tree.stats?.totalPeople || 0), 0)
                      : 'N/A'}
                  </div>
                  <div className={`text-muted-foreground ${isMobile ? 'text-xs' : 'text-sm'}`}>
                    {language === 'ar' ? 'إجمالي الأشخاص' : 'Total People'}
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardContent className={`p-3 ${isMobile ? 'p-3' : 'p-4'}`}>
              <div className="flex items-center space-x-2">
                <div className={`rounded-full flex items-center justify-center ${isMobile ? 'w-7 h-7' : 'w-8 h-8'} bg-purple-100`}>
                  <Share className={`text-purple-600 ${isMobile ? 'h-3.5 w-3.5' : 'h-4 w-4'}`} />
                </div>
                <div>
                  <div className={`font-semibold ${isMobile ? 'text-lg' : 'text-lg'}`}>
                    {/* Calculate shared trees from available data or show N/A */}
                    {trees.length > 0 
                      ? trees.filter(tree => tree.sharing?.isShared || (tree.members && tree.members.length > 0)).length
                      : 'N/A'}
                  </div>
                  <div className={`text-muted-foreground ${isMobile ? 'text-xs' : 'text-sm'}`}>
                    {language === 'ar' ? 'أشجار مشتركة' : 'Shared Trees'}
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>

        </div>
      )}

      {/* Add TreeFormModal */}
      <TreeFormModal
        isOpen={isTreeFormModalOpen}
        onClose={() => setIsTreeFormModalOpen(false)}
        onSubmit={handleCreateTree}
        mode="create"
      />
    </div>
  );

  // Copy text to clipboard
  const copyToClipboard = (text: string) => {
    if (navigator.clipboard) {
      navigator.clipboard.writeText(text).then(() => {
        setLocalError(language === 'ar' ? 'تم نسخ الرابط إلى الحافظة' : 'Link copied to clipboard');
        // Clear the message after 3 seconds
        setTimeout(() => setLocalError(null), 3000);
      }).catch(err => {
        // Removed console.error for failed to copy
        fallbackCopyTextToClipboard(text);
      });
    } else {
      fallbackCopyTextToClipboard(text);
    }
  };

  // Fallback method for older browsers
  const fallbackCopyTextToClipboard = (text: string) => {
    const textArea = document.createElement('textarea');
    textArea.value = text;
    
    // Avoid scrolling to bottom
    textArea.style.top = '0';
    textArea.style.left = '0';
    textArea.style.position = 'fixed';
    textArea.style.opacity = '0';
    
    document.body.appendChild(textArea);
    textArea.focus();
    textArea.select();
    
    try {
      const successful = document.execCommand('copy');
      if (successful) {
        setLocalError(language === 'ar' ? 'تم نسخ الرابط إلى الحافظة' : 'Link copied to clipboard');
      } else {
        setLocalError(language === 'ar' ? 'فشل نسخ الرابط' : 'Failed to copy link');
      }
    } catch (err) {
      // Removed console.error for fallback copy text to clipboard
      setLocalError(language === 'ar' ? 'فشل نسخ الرابط' : 'Failed to copy link');
    }
    
    // Clear the message after 3 seconds
    setTimeout(() => setLocalError(null), 3000);
    
    document.body.removeChild(textArea);
  };
}

export default TreesPage;