import { Person, LifeEvent, PhysicalAttributes, Occupation, Education, ContactInfo, Relationships, Spouse } from '@/types';
import { useMobile } from '@/hooks/useMobile'; // Add mobile hook import

const PersonEditPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  // Removed logging: PersonEditPage rendered with ID param
  const navigate = useNavigate();
  const { language } = useUIStore();
  const { user } = useAuthStore();
  const { trees, currentTree, fetchTrees } = useTreeStore();
  const { isMobile } = useMobile(); // Add mobile detection
  const [activeTab, setActiveTab] = useState<'basic'>('basic');
  const [isEditing, setIsEditing] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const photoInputRef = useRef<HTMLInputElement>(null);
  const documentInputRef = useRef<HTMLInputElement>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const isRTL = language === 'ar';

  // Ensure trees are loaded
  useEffect(() => {
    const loadTrees = async () => {
      try {
        // Removed logging: Loading trees
        await fetchTrees();
        // Removed logging: Trees loaded successfully
      } catch (err) {
        // Removed console.error for failed to load trees
      }
    };
    
    // Only load trees if they haven't been loaded yet
    if (trees.length === 0) {
      loadTrees();
    }
  }, [fetchTrees, trees.length]);

  // Person data state
  const [personData, setPersonData] = useState<Person>({
    id: '',
    firstName: '',
    middleName: '',
    lastName: '',
    nickname: '',
    fullName: '',
    displayName: '',
    gender: 'unknown',
    birth: {
      date: '',
      place: {
        city: '',
        state: '',
        country: ''
      }
    },
    death: {
      date: '',
      place: {
        city: '',
        state: '',
        country: ''
      }
    },
    isDeceased: false,
    physical: {
      height: '',
      weight: '',
      eyeColor: '',
      hairColor: '',
      complexion: '',
      distinguishingMarks: ''
    },
    occupation: [],
    education: [],
    contact: {
      email: '',
      phone: '',
      address: {
        street: '',
        city: '',
        state: '',
        country: '',
        postalCode: ''
      },
      socialMedia: {
        facebook: '',
        twitter: '',
        linkedin: '',
        instagram: ''
      }
    },
    relationships: {
      father: '',
      mother: '',
      spouses: [],
      children: [],
      siblings: []
    },
    photos: [],
    documents: [],
    notes: '',
    tags: [],
    tree: '',
    position: {
      generation: 1,
      x: 0,
      y: 0
    },
    createdBy: '',
    createdAt: '',
    updatedAt: '',
    status: 'active'
  });

  const [editedPersonData, setEditedPersonData] = useState<Person>(personData);
  const [copyMessage, setCopyMessage] = useState<string | null>(null);

  // Fetch person data from API
  useEffect(() => {
    // Removed logging: useEffect triggered with ID
    const fetchPersonData = async () => {
      if (!id) {
        setError(language === 'ar' ? 'معرف الشخص مفقود' : 'Person ID is missing');
        setLoading(false);
        return;
      }

      // Check if ID is a valid number
      const personId = parseInt(id);
      if (isNaN(personId)) {
        setError(language === 'ar' ? 'معرف الشخص غير صالح' : 'Invalid person ID');
        setLoading(false);
        return;
      }

      try {
        setLoading(true);
        setError(null);
        // Removed logging: Fetching person data for ID
        
        // Fetch person data from API
        const personResponse = await treeService.getPersonById(personId);
        // Removed logging: Person response received
        
        // Check if personResponse is valid
        if (!personResponse) {
          throw new Error('Received empty response from API');
        }
        
        // Check the structure of the response
        // Removed logging: Person response type
        // Removed logging: Person response keys
        
        // Log tree store data for debugging
        // Removed logging: Tree store data
        
        // Helper function to get property value with multiple possible keys
        const getPropertyValue = (obj: any, ...keys: string[]): any => {
          for (const key of keys) {
            if (obj.hasOwnProperty(key)) {
              return obj[key];
            }
          }
          return undefined;
        };
        
        // Transform API data to match our interface
        // The API response might have different property names than our Person interface
        const transformedPerson: Person = {
          id: getPropertyValue(personResponse, 'id', 'Id')?.toString() || '',
          firstName: getPropertyValue(personResponse, 'firstName', 'FirstName', 'name') || '',
          middleName: getPropertyValue(personResponse, 'middleName', 'MiddleName') || '',
          lastName: getPropertyValue(personResponse, 'lastName', 'LastName') || '',
          nickname: getPropertyValue(personResponse, 'nickname', 'Nickname') || '',
          fullName: getPropertyValue(personResponse, 'fullName', 'FullName') || 
                   `${getPropertyValue(personResponse, 'firstName', 'FirstName') || ''} ${getPropertyValue(personResponse, 'lastName', 'LastName') || ''}`,
          displayName: getPropertyValue(personResponse, 'displayName', 'DisplayName') || 
                      `${getPropertyValue(personResponse, 'firstName', 'FirstName') || ''} ${getPropertyValue(personResponse, 'lastName', 'LastName') || ''}`,
          gender: ['male', 'female', 'unknown'].includes(getPropertyValue(personResponse, 'gender', 'Gender')) 
                  ? getPropertyValue(personResponse, 'gender', 'Gender') 
                  : 'unknown',
          birth: {
            date: getPropertyValue(personResponse, 'birth', 'Birth')?.date || 
                  getPropertyValue(personResponse, 'birth', 'Birth')?.Date || 
                  getPropertyValue(personResponse, 'birthDate') || '',
            place: {
              city: getPropertyValue(personResponse, 'birth', 'Birth')?.place?.city || 
                    getPropertyValue(personResponse, 'birth', 'Birth')?.Place?.City || 
                    getPropertyValue(personResponse, 'birthPlace') || '',
              state: getPropertyValue(personResponse, 'birth', 'Birth')?.place?.state || 
                     getPropertyValue(personResponse, 'birth', 'Birth')?.Place?.State || '',
              country: getPropertyValue(personResponse, 'birth', 'Birth')?.place?.country || 
                       getPropertyValue(personResponse, 'birth', 'Birth')?.Place?.Country || ''
            },
            description: getPropertyValue(personResponse, 'birth', 'Birth')?.description || 
                         getPropertyValue(personResponse, 'birth', 'Birth')?.Description || '',
            isEstimated: getPropertyValue(personResponse, 'birth', 'Birth')?.isEstimated || 
                         getPropertyValue(personResponse, 'birth', 'Birth')?.IsEstimated || false
          },
          death: getPropertyValue(personResponse, 'death', 'Death') ? {
            date: getPropertyValue(personResponse, 'death', 'Death')?.date || 
                  getPropertyValue(personResponse, 'death', 'Death')?.Date || 
                  getPropertyValue(personResponse, 'deathDate') || '',
            place: {
              city: getPropertyValue(personResponse, 'death', 'Death')?.place?.city || 
                    getPropertyValue(personResponse, 'death', 'Death')?.Place?.City || '',
              state: getPropertyValue(personResponse, 'death', 'Death')?.place?.state || 
                     getPropertyValue(personResponse, 'death', 'Death')?.Place?.State || '',
              country: getPropertyValue(personResponse, 'death', 'Death')?.place?.country || 
                       getPropertyValue(personResponse, 'death', 'Death')?.Place?.Country || ''
            },
            description: getPropertyValue(personResponse, 'death', 'Death')?.description || 
                         getPropertyValue(personResponse, 'death', 'Death')?.Description || '',
            isEstimated: getPropertyValue(personResponse, 'death', 'Death')?.isEstimated || 
                         getPropertyValue(personResponse, 'death', 'Death')?.IsEstimated || false
          } : undefined,
          isDeceased: !!getPropertyValue(personResponse, 'isDeceased', 'IsDeceased', 'isDead'),
          physical: {
            height: getPropertyValue(personResponse, 'physical', 'Physical')?.height || 
                    getPropertyValue(personResponse, 'physical', 'Physical')?.Height || '',
            weight: getPropertyValue(personResponse, 'physical', 'Physical')?.weight || 
                    getPropertyValue(personResponse, 'physical', 'Physical')?.Weight || '',
            eyeColor: getPropertyValue(personResponse, 'physical', 'Physical')?.eyeColor || 
                      getPropertyValue(personResponse, 'physical', 'Physical')?.EyeColor || '',
            hairColor: getPropertyValue(personResponse, 'physical', 'Physical')?.hairColor || 
                       getPropertyValue(personResponse, 'physical', 'Physical')?.HairColor || '',
            complexion: getPropertyValue(personResponse, 'physical', 'Physical')?.complexion || 
                        getPropertyValue(personResponse, 'physical', 'Physical')?.Complexion || '',
            distinguishingMarks: getPropertyValue(personResponse, 'physical', 'Physical')?.distinguishingMarks || 
                                 getPropertyValue(personResponse, 'physical', 'Physical')?.DistinguishingMarks || ''
          },
          occupation: Array.isArray(getPropertyValue(personResponse, 'occupation')) ? getPropertyValue(personResponse, 'occupation') : 
                      Array.isArray(getPropertyValue(personResponse, 'Occupation')) ? getPropertyValue(personResponse, 'Occupation') :
                      (getPropertyValue(personResponse, 'occupation') ? [getPropertyValue(personResponse, 'occupation')] : 
                      (getPropertyValue(personResponse, 'Occupation') ? [getPropertyValue(personResponse, 'Occupation')] : [])),
          education: Array.isArray(getPropertyValue(personResponse, 'education')) ? getPropertyValue(personResponse, 'education') : 
                     Array.isArray(getPropertyValue(personResponse, 'Education')) ? getPropertyValue(personResponse, 'Education') :
                     (getPropertyValue(personResponse, 'education') ? [getPropertyValue(personResponse, 'education')] : 
                     (getPropertyValue(personResponse, 'Education') ? [getPropertyValue(personResponse, 'Education')] : [])),
          contact: {
            email: getPropertyValue(personResponse, 'contact', 'Contact')?.email || 
                   getPropertyValue(personResponse, 'contact', 'Contact')?.Email || 
                   getPropertyValue(personResponse, 'email') || '',
            phone: getPropertyValue(personResponse, 'contact', 'Contact')?.phone || 
                   getPropertyValue(personResponse, 'contact', 'Contact')?.Phone || '',
            address: {
              street: getPropertyValue(personResponse, 'contact', 'Contact')?.address?.street || 
                      getPropertyValue(personResponse, 'contact', 'Contact')?.Address?.Street || '',
              city: getPropertyValue(personResponse, 'contact', 'Contact')?.address?.city || 
                    getPropertyValue(personResponse, 'contact', 'Contact')?.Address?.City || '',
              state: getPropertyValue(personResponse, 'contact', 'Contact')?.address?.state || 
                     getPropertyValue(personResponse, 'contact', 'Contact')?.Address?.State || '',
              country: getPropertyValue(personResponse, 'contact', 'Contact')?.address?.country || 
                       getPropertyValue(personResponse, 'contact', 'Contact')?.Address?.Country || '',
              postalCode: getPropertyValue(personResponse, 'contact', 'Contact')?.address?.postalCode || 
                          getPropertyValue(personResponse, 'contact', 'Contact')?.Address?.PostalCode || ''
            },
            socialMedia: {
              facebook: getPropertyValue(personResponse, 'contact', 'Contact')?.socialMedia?.facebook || 
                        getPropertyValue(personResponse, 'contact', 'Contact')?.SocialMedia?.Facebook || '',
              twitter: getPropertyValue(personResponse, 'contact', 'Contact')?.socialMedia?.twitter || 
                       getPropertyValue(personResponse, 'contact', 'Contact')?.SocialMedia?.Twitter || '',
              linkedin: getPropertyValue(personResponse, 'contact', 'Contact')?.socialMedia?.linkedin || 
                        getPropertyValue(personResponse, 'contact', 'Contact')?.SocialMedia?.Linkedin || '',
              instagram: getPropertyValue(personResponse, 'contact', 'Contact')?.socialMedia?.instagram || 
                         getPropertyValue(personResponse, 'contact', 'Contact')?.SocialMedia?.Instagram || ''
            }
          },
          relationships: getPropertyValue(personResponse, 'relationships', 'Relationships') || {
            father: '',
            mother: '',
            spouses: [],
            children: [],
            siblings: []
          },
          photos: getPropertyValue(personResponse, 'photos', 'Photos') || [],
          documents: getPropertyValue(personResponse, 'documents', 'Documents') || [],
          notes: getPropertyValue(personResponse, 'notes', 'Notes') || '',
          tags: getPropertyValue(personResponse, 'tags', 'Tags') || [],
          tree: getPropertyValue(personResponse, 'tree', 'Tree', 'familyTreeId') || '',
          position: {
            generation: getPropertyValue(personResponse, 'position', 'Position')?.generation || 
                        getPropertyValue(personResponse, 'position', 'Position')?.Generation || 1,
            x: getPropertyValue(personResponse, 'position', 'Position')?.x || 
               getPropertyValue(personResponse, 'position', 'Position')?.X || 0,
            y: getPropertyValue(personResponse, 'position', 'Position')?.y || 
               getPropertyValue(personResponse, 'position', 'Position')?.Y || 0,
            level: getPropertyValue(personResponse, 'position', 'Position')?.level || 
                   getPropertyValue(personResponse, 'position', 'Position')?.Level || 0
          },
          createdBy: getPropertyValue(personResponse, 'createdBy', 'CreatedBy') || '',
          createdAt: getPropertyValue(personResponse, 'createdAt', 'CreatedAt') || new Date().toISOString(),
          updatedAt: getPropertyValue(personResponse, 'updatedAt', 'UpdatedAt') || new Date().toISOString(),
          status: getPropertyValue(personResponse, 'status', 'Status') || 'active'
        };
        
        // Removed logging: Transformed person data
        setPersonData(transformedPerson);
        setEditedPersonData(transformedPerson);
      } catch (err: any) {
        // Removed console.error for error fetching person data
        setError(language === 'ar' ? 'فشل في تحميل بيانات الشخص' : 'Failed to load person data: ' + (err.message || 'Unknown error'));
      } finally {
        setLoading(false);
      }
    };

    fetchPersonData();
  }, [id, language]);

  // Improved tree matching function
  const findTreeById = (treeId: string) => {
    if (!treeId) return undefined;
    
    // Try multiple matching strategies
    return trees.find(t => t.id === treeId) || 
           trees.find(t => t.id.toString() === treeId) ||
           trees.find(t => parseInt(t.id) === parseInt(treeId)) ||
           (currentTree?.id === treeId ? currentTree : undefined) ||
           (currentTree?.id.toString() === treeId ? currentTree : undefined) ||
           (parseInt(currentTree?.id || '0') === parseInt(treeId) ? currentTree : undefined);
  };

  // Function to fetch a specific tree by ID
  const fetchTreeById = async (treeId: string) => {
    try {
      // Removed logging: Fetching tree by ID
      const tree = await treeService.getTreeById(parseInt(treeId));
      // Removed logging: Fetched tree
      return tree;
    } catch (error) {
      // Removed console.error for error fetching tree by ID
      return null;
    }
  };

  // Check if current user is the owner of the tree that contains this person
  const isTreeOwner = (() => {
    // Don't check permissions while loading
    if (loading || !user || !id) {
      // Removed logging: Permission check: Still loading or missing user/id
      return true;
    }
    
    // If we don't have person data yet, assume permission check will happen later
    if (!personData.tree) {
      // Removed logging: Permission check: No tree ID in person data yet
      return true;
    }
    
    // If trees haven't been loaded yet, assume permission
    if (trees.length === 0) {
      // Removed logging: Permission check: Trees not loaded yet
      return true;
    }
    
    // Find the tree that contains this person
    const personTreeId = personData.tree.toString();
    // Removed logging: Looking for tree with ID
    // Removed logging: Available trees
    // Removed logging: Current tree
    
    const tree = findTreeById(personTreeId);
    
    // Removed logging: Permission check - Tree lookup
    
    if (!tree) {
      // Removed logging: Permission check: Tree not found
      // If we can't find the tree, we'll assume the user has permission for now
      return true;
    }
    
    // Check if user is the owner
    const isOwner = tree.ownerId === user.id || tree.userRole === 'owner';
    // Removed logging: Permission check - Owner verification
    
    return isOwner;
  })();

  // Check permissions after data is loaded
  const hasPermission = (() => {
    // While loading, don't show permission error
    if (loading || !user || !id) {
      // Removed logging: Has permission: Still loading or missing user/id
      return true;
    }
    
    // If we don't have person data yet, assume permission
    if (!personData.tree) {
      // Removed logging: Has permission: No tree ID in person data yet
      return true;
    }
    
    // If trees haven't been loaded yet, assume permission
    if (trees.length === 0) {
      // Removed logging: Has permission: Trees not loaded yet
      return true;
    }
    
    // Find the tree that contains this person
    const personTreeId = personData.tree.toString();
    // Removed logging: Looking for tree with ID for permission check
    
    const tree = findTreeById(personTreeId);
    
    // Removed logging: Has permission - Tree lookup
    
    if (!tree) {
      // Removed logging: Has permission: Tree not found
      // If we can't find the tree, we'll assume the user has permission for now
      return true;
    }
    
    // Check if user is the owner or has edit permissions
    const hasPerm = tree.ownerId === user.id || tree.userRole === 'owner' || tree.userRole === 'editor';
    // Removed logging: Has permission - Permission verification
    
    return hasPerm;
  })();

  const handleSave = async () => {
    if (!id) return;
    
    // Check if user is authorized to edit
    if (!hasPermission) {
      setError(isRTL ? 'ليس لديك صلاحية لتعديل هذا الشخص' : 'You do not have permission to edit this person');
      return;
    }
    
    try {
      setLoading(true);
      
      // Update person data through API
      // Map the person data to the API required fields
      const updatedPerson = await treeService.updatePerson(
        parseInt(id),
        editedPersonData.firstName || '',
        editedPersonData.birth.date || '',
        editedPersonData.birth.place?.city || '',
        editedPersonData.occupation.length > 0 ? editedPersonData.occupation[0].title : '',
        editedPersonData.gender || 'unknown',
        parseInt(editedPersonData.tree) || 0
      );
      
      // Update local state
      setPersonData(editedPersonData);
      setIsEditing(false);
    } catch (err) {
      // Removed console.error for error updating person
      setError(language === 'ar' ? 'فشل في حفظ التغييرات' : 'Failed to save changes');
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
    setEditedPersonData(personData);
    setIsEditing(false);
  };

  const handleAvatarChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const result = e.target?.result as string;
        setEditedPersonData(prev => ({ ...prev, photos: [...prev.photos, { 
          id: Date.now().toString(),
          url: result,
          public_id: '',
          caption: '',
          description: '',
          date: new Date().toISOString(),
          location: '',
          tags: [],
          isPrimary: prev.photos.length === 0,
          uploadedBy: '',
          uploadedAt: new Date().toISOString(),
          size: file.size,
          dimensions: { width: 0, height: 0 }
        }] }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddPhoto = (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (files) {
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onload = (e) => {
          const result = e.target?.result as string;
          setEditedPersonData(prev => ({ 
            ...prev, 
            photos: [...prev.photos, { 
              id: Date.now().toString(),
              url: result,
              public_id: '',
              caption: '',
              description: '',
              date: new Date().toISOString(),
              location: '',
              tags: [],
              isPrimary: false,
              uploadedBy: '',
              uploadedAt: new Date().toISOString(),
              size: file.size,
              dimensions: { width: 0, height: 0 }
            }] 
          }));
        };
        reader.readAsDataURL(file);
      });
    }
  };

  const handleDeletePerson = async () => {
    if (!id) return;
    
    // Check if user is authorized to delete
    if (!hasPermission) {
      setError(isRTL ? 'ليس لديك صلاحية لحذف هذا الشخص' : 'You do not have permission to delete this person');
      return;
    }
    
    if (confirm(isRTL ? 'هل أنت متأكد من حذف هذا الشخص؟ هذا الإجراء لا يمكن التراجع عنه.' : 'Are you sure you want to delete this person? This action cannot be undone.')) {
      try {
        setLoading(true);
        await treeService.deletePerson(parseInt(id));
        navigate('/trees');
      } catch (err: any) {
        // Removed console.error for error deleting person
        const errorMessage = err.message || (language === 'ar' ? 'فشل في حذف الشخص' : 'Failed to delete person');
        setError(errorMessage);
        setLoading(false);
      }
    }
  };

  const calculateAge = (birthDate?: string, deathDate?: string) => {
    if (!birthDate) return '0';
    
    let birth: Date;
    try {
      // Handle different date formats that might come from the API
      if (birthDate.includes('T')) {
        // ISO date string
        birth = new Date(birthDate);
      } else if (birthDate.includes('-')) {
        // YYYY-MM-DD format
        const parts = birthDate.split('-');
        if (parts.length === 3) {
          birth = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
        } else {
          birth = new Date(birthDate);
        }
      } else if (birthDate.includes('/')) {
        // MM/DD/YYYY or DD/MM/YYYY format
        const parts = birthDate.split('/');
        if (parts.length === 3) {
          // Assuming MM/DD/YYYY format first
          birth = new Date(parseInt(parts[2]), parseInt(parts[0]) - 1, parseInt(parts[1]));
        } else {
          birth = new Date(birthDate);
        }
      } else {
        // Try to parse directly
        birth = new Date(birthDate);
      }
    } catch (e) {
      // Removed console.warn for error parsing birth date
      return '0';
    }
    
    // Check if the date is valid
    if (isNaN(birth.getTime())) {
      // Removed console.warn for invalid birth date
      return '0';
    }
    
    // Use death date if provided and valid, otherwise use current date
    let end: Date;
    if (deathDate && deathDate.trim() !== '') {
      try {
        if (deathDate.includes('T')) {
          end = new Date(deathDate);
        } else if (deathDate.includes('-')) {
          const parts = deathDate.split('-');
          if (parts.length === 3) {
            end = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
          } else {
            end = new Date(deathDate);
          }
        } else if (deathDate.includes('/')) {
          const parts = deathDate.split('/');
          if (parts.length === 3) {
            end = new Date(parseInt(parts[2]), parseInt(parts[0]) - 1, parseInt(parts[1]));
          } else {
            end = new Date(deathDate);
          }
        } else {
          end = new Date(deathDate);
        }
        
        // Check if death date is valid
        if (isNaN(end.getTime())) {
          // Removed console.warn for invalid death date
          end = new Date(); // Fall back to current date
        }
      } catch (e) {
        // Removed console.warn for error parsing death date
        end = new Date(); // Fall back to current date
      }
    } else {
      end = new Date();
    }
    
    // Calculate age
    let age = end.getFullYear() - birth.getFullYear();
    const monthDiff = end.getMonth() - birth.getMonth();
    
    // If birth month hasn't occurred yet this year, or if it's the same month but the day hasn't occurred yet
    if (monthDiff < 0 || (monthDiff === 0 && end.getDate() < birth.getDate())) {
      age--;
    }
    
    // Ensure age is not negative
    return age >= 0 ? age.toString() : '0';
  };

  const getGenderColor = (gender: string) => {
    return gender === 'male' ? 'bg-blue-100 text-blue-800' : 
           gender === 'female' ? 'bg-pink-100 text-pink-800' : 'bg-gray-100 text-gray-800';
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <div className="text-center">
          <Loader2 className="h-12 w-12 animate-spin text-primary mx-auto mb-4" />
          <p className="text-muted-foreground">
            {isRTL ? 'جاري تحميل ملف الشخص...' : 'Loading person profile...'}
          </p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-center py-12">
        <div className="mx-auto w-16 h-16 bg-destructive/10 rounded-full flex items-center justify-center mb-4">
          <AlertCircle className="h-8 w-8 text-destructive" />
        </div>
        <h2 className="text-2xl font-bold text-destructive mb-4">
          {error}
        </h2>
        <Button onClick={() => window.location.reload()}>
          {isRTL ? 'إعادة المحاولة' : 'Try Again'}
        </Button>
      </div>
    );
  }

  // Show error state for non-owners
  if (!hasPermission && !loading && user && personData.tree) {
    return (
      <div className="flex flex-col items-center justify-center h-64 space-y-4">
        <AlertTriangle className="h-12 w-12 text-destructive" />
        <p className="text-destructive text-center">
          {isRTL ? 'ليس لديك صلاحية لتعديل هذا الشخص' : 'You do not have permission to edit this person'}
        </p>
        <Button onClick={() => navigate(-1)}>
          {isRTL ? 'العودة' : 'Go Back'}
        </Button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className={`flex ${isMobile ? 'flex-col gap-3' : 'flex-col sm:flex-row sm:items-center'} justify-between`}>
        <div className="flex items-center gap-4">
          <Button
            variant="outline"
            onClick={() => navigate(-1)}
            className="flex items-center gap-2"
            size={isMobile ? "sm" : "default"}
          >
            <ArrowLeft className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
            <span className={isMobile ? 'hidden' : 'hidden xs:inline'}>{isRTL ? 'العودة' : 'Back'}</span>
          </Button>
          <div>
            <h1 className={`font-bold text-foreground ${isMobile ? 'text-lg' : 'text-xl sm:text-2xl'}`}>
              {isEditing ? (isRTL ? 'تعديل الشخص' : 'Edit Person') : (isRTL ? 'عرض الشخص' : 'View Person')}
            </h1>
            <p className={`text-muted-foreground ${isMobile ? 'text-xs' : 'text-xs sm:text-sm'}`}>
              {isRTL ? 'إدارة معلومات الشخص وبياناته' : 'Manage person information and data'}
            </p>
          </div>
        </div>
        <div className={`flex ${isMobile ? 'gap-1' : 'gap-2'}`}>
          <Button 
            variant="outline" 
            className="flex items-center gap-2"
            size={isMobile ? "sm" : "default"}
            onClick={() => {
              // Copy shareable link to clipboard
              const shareUrl = `${window.location.origin}/persons/${id}`;
              navigator.clipboard.writeText(shareUrl).then(() => {
                // Show success notification
                setCopyMessage(isRTL ? 'تم نسخ الرابط إلى الحافظة' : 'Link copied to clipboard');
                // Clear the message after 3 seconds
                setTimeout(() => setCopyMessage(null), 3000);
              }).catch(() => {
                // Fallback for older browsers
                const textArea = document.createElement('textarea');
                textArea.value = shareUrl;
                document.body.appendChild(textArea);
                textArea.select();
                document.execCommand('copy');
                document.body.removeChild(textArea);
                setCopyMessage(isRTL ? 'تم نسخ الرابط إلى الحافظة' : 'Link copied to clipboard');
                // Clear the message after 3 seconds
                setTimeout(() => setCopyMessage(null), 3000);
              });
            }}
          >
            <Share2 className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
            <span className={isMobile ? 'hidden' : 'hidden xs:inline'}>{isRTL ? 'مشاركة' : 'Share'}</span>
          </Button>
          <Button
            variant={isEditing ? "outline" : "default"}
            onClick={() => isEditing ? handleCancel() : setIsEditing(true)}
            className="flex items-center gap-2"
            disabled={!hasPermission} // Disable edit button for users without permission
            size={isMobile ? "sm" : "default"}
          >
            {isEditing ? (
              <>
                <X className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
                <span className={isMobile ? 'hidden' : 'hidden xs:inline'}>{isRTL ? 'إلغاء' : 'Cancel'}</span>
              </>
            ) : (
              <>
                <Edit className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
                <span className={isMobile ? 'hidden' : 'hidden xs:inline'}>{isRTL ? 'تعديل' : 'Edit'}</span>
              </>
            )}
          </Button>
        </div>
      </div>

      {/* Tabs */}
      <div className={`flex ${isMobile ? 'flex-wrap gap-1 p-1 bg-muted rounded-lg overflow-x-auto' : 'gap-1 border-b overflow-x-auto'}`}>
        {[
          { id: 'basic', label: isRTL ? 'المعلومات الأساسية' : 'Basic Info', icon: User }
        ].map(tab => (
          <Button
            key={tab.id}
            variant={activeTab === tab.id ? "default" : "ghost"}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex items-center gap-2 whitespace-nowrap ${isMobile ? 'text-xs py-2 px-3 flex-1 justify-center' : ''}`}
            size={isMobile ? "sm" : "default"}
          >
            {React.createElement(tab.icon, { className: `h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}` })}
            <span className={isMobile ? 'hidden' : 'hidden xs:inline'}>{tab.label}</span>
          </Button>
        ))}
      </div>

      {/* Display copy message */}
      {copyMessage && (
        <div className="bg-green-100 border border-green-200 rounded-lg p-3 mb-4">
          <p className="text-green-800 text-sm">{copyMessage}</p>
        </div>
      )}

      {/* Basic Info Tab */}
      {activeTab === 'basic' && (
        <Card>
          <CardHeader className={isMobile ? 'p-4' : ''}>
            <CardTitle className="flex items-center gap-2">
              <User className={`h-5 w-5 ${isMobile ? 'h-4 w-4' : ''}`} />
              {isRTL ? 'المعلومات الأساسية' : 'Basic Information'}
            </CardTitle>
          </CardHeader>
          <CardContent className={`space-y-6 ${isMobile ? 'p-4' : ''}`}>
            {/* Avatar */}
            {/* <div className="space-y-2">
              <label className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الصورة الشخصية' : 'Profile Picture'}</label>
              <div className="flex items-center gap-4">
                <div className={`rounded-full bg-gradient-to-br from-primary/20 to-primary/40 flex items-center justify-center overflow-hidden ${isMobile ? 'w-20 h-20' : 'w-24 h-24'}`}>
                  {(isEditing ? editedPersonData.photos : personData.photos).find(p => p.isPrimary) ? (
                    <img 
                      src={(isEditing ? editedPersonData.photos : personData.photos).find(p => p.isPrimary)?.url} 
                      alt="Avatar" 
                      className="w-full h-full object-cover"
                    />
                  ) : (
                    <User className={`text-primary ${isMobile ? 'h-10 w-10' : 'h-12 w-12'}`} />
                  )}
                </div>
                {isEditing && (
                  <Button
                    variant="outline"
                    onClick={() => fileInputRef.current?.click()}
                    className="flex items-center gap-2"
                    size={isMobile ? "sm" : "default"}
                  >
                    <Camera className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
                    <span className={isMobile ? 'hidden' : ''}>{isRTL ? 'تغيير الصورة' : 'Change Picture'}</span>
                  </Button>
                )}
                <input
                  ref={fileInputRef}
                  type="file"
                  accept="image/*"
                  onChange={handleAvatarChange}
                  className="hidden"
                />
              </div>
            </div> */}

            <div className={`grid ${isMobile ? 'grid-cols-1 gap-3' : 'grid-cols-1 md:grid-cols-2 gap-6'}`}>
              {/* Names */}
              <div className="space-y-2">
                <label className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الاسم الأول' : 'First Name'}</label>
                <Input
                  value={isEditing ? editedPersonData.firstName : personData.firstName}
                  onChange={(e) => setEditedPersonData(prev => ({ ...prev, firstName: e.target.value }))}
                  disabled={!isEditing}
                  placeholder={isRTL ? 'الاسم الأول' : 'First Name'}
                  className={isMobile ? 'text-sm py-2' : ''}
                />
              </div>

              <div className="space-y-2">
                <label className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'اسم الأب' : 'Middle Name'}</label>
                <Input
                  value={isEditing ? editedPersonData.middleName || '' : personData.middleName || ''}
                  onChange={(e) => setEditedPersonData(prev => ({ ...prev, middleName: e.target.value }))}
                  disabled={!isEditing}
                  placeholder={isRTL ? 'اسم الأب' : 'Middle Name'}
                  className={isMobile ? 'text-sm py-2' : ''}
                />
              </div>

              <div className="space-y-2">
                <label className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'اسم العائلة' : 'Last Name'}</label>
                <Input
                  value={isEditing ? editedPersonData.lastName : personData.lastName}
                  onChange={(e) => setEditedPersonData(prev => ({ ...prev, lastName: e.target.value }))}
                  disabled={!isEditing}
                  placeholder={isRTL ? 'اسم العائلة' : 'Last Name'}
                  className={isMobile ? 'text-sm py-2' : ''}
                />
              </div>

              <div className="space-y-2">
                <label className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الكنية' : 'Nickname'}</label>
                <Input
                  value={isEditing ? editedPersonData.nickname || '' : personData.nickname || ''}
                  onChange={(e) => setEditedPersonData(prev => ({ ...prev, nickname: e.target.value }))}
                  disabled={!isEditing}
                  placeholder={isRTL ? 'الكنية' : 'Nickname'}
                  className={isMobile ? 'text-sm py-2' : ''}
                />
              </div>

              {/* Gender */}
              <div className="space-y-2">
                <label className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الجنس' : 'Gender'}</label>
                <select
                  value={isEditing ? editedPersonData.gender : personData.gender}
                  onChange={(e) => setEditedPersonData(prev => ({ ...prev, gender: e.target.value as 'male' | 'female' | 'unknown' }))}
                  disabled={!isEditing}
                  className={`w-full px-3 border border-input rounded-md bg-background disabled:opacity-50 ${isMobile ? 'text-sm py-2' : 'py-2'}`}
                >
                  <option value="male">{isRTL ? 'ذكر' : 'Male'}</option>
                  <option value="female">{isRTL ? 'أنثى' : 'Female'}</option>
                  <option value="unknown">{isRTL ? 'غير محدد' : 'Not specified'}</option>
                </select>
              </div>

              {/* Status */}
              <div className="space-y-2">
                <label className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الحالة' : 'Status'}</label>
                <select
                  value={isEditing ? editedPersonData.isDeceased.toString() : personData.isDeceased.toString()}
                  onChange={(e) => setEditedPersonData(prev => ({ ...prev, isDeceased: e.target.value === 'true' }))}
                  disabled={!isEditing}
                  className={`w-full px-3 border border-input rounded-md bg-background disabled:opacity-50 ${isMobile ? 'text-sm py-2' : 'py-2'}`}
                >
                  <option value="false">{isRTL ? 'على قيد الحياة' : 'Alive'}</option>
                  <option value="true">{isRTL ? 'متوفى' : 'Deceased'}</option>
                </select>
              </div>

              {/* Birth Date */}
              <div className="space-y-2">
                <label className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'تاريخ الميلاد' : 'Birth Date'}</label>
                <Input
                  type="date"
                  value={isEditing ? editedPersonData.birth.date || '' : personData.birth.date || ''}
                  onChange={(e) => setEditedPersonData(prev => ({ 
                    ...prev, 
                    birth: { ...prev.birth, date: e.target.value }
                  }))}
                  disabled={!isEditing}
                  className={isMobile ? 'text-sm py-2' : ''}
                />
              </div>

              {/* Death Date */}
              {(!isEditing ? personData.isDeceased : editedPersonData.isDeceased) && (
                <div className="space-y-2">
                  <label className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'تاريخ الوفاة' : 'Death Date'}</label>
                  <Input
                    type="date"
                    value={isEditing ? editedPersonData.death?.date || '' : personData.death?.date || ''}
                    onChange={(e) => setEditedPersonData(prev => ({ 
                      ...prev, 
                      death: { ...prev.death || {}, date: e.target.value }
                    }))}
                    disabled={!isEditing}
                    className={isMobile ? 'text-sm py-2' : ''}
                  />
                </div>
              )}

              {/* Birth Place */}
              <div className="space-y-2">
                <label className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'مكان الميلاد' : 'Birth Place'}</label>
                <Input
                  value={isEditing ? editedPersonData.birth.place?.city || '' : personData.birth.place?.city || ''}
                  onChange={(e) => setEditedPersonData(prev => ({ 
                    ...prev, 
                    birth: { ...prev.birth, place: { ...prev.birth.place, city: e.target.value } }
                  }))}
                  disabled={!isEditing}
                  placeholder={isRTL ? 'مدينة الميلاد' : 'Birth City'}
                  className={isMobile ? 'text-sm py-2' : ''}
                />
              </div>

              {/* Death Place */}
              {(!isEditing ? personData.isDeceased : editedPersonData.isDeceased) && (
                <div className="space-y-2">
                  <label className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'مكان الوفاة' : 'Death Place'}</label>
                  <Input
                    value={isEditing ? editedPersonData.death?.place?.city || '' : personData.death?.place?.city || ''}
                    onChange={(e) => setEditedPersonData(prev => ({ 
                      ...prev, 
                      death: { ...prev.death || {}, place: { ...prev.death?.place, city: e.target.value } }
                    }))}
                    disabled={!isEditing}
                    placeholder={isRTL ? 'مدينة الوفاة' : 'Death City'}
                    className={isMobile ? 'text-sm py-2' : ''}
                  />
                </div>
              )}
            </div>

            {/* Notes */}
            <div className="space-y-2">
              <label className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الملاحظات' : 'Notes'}</label>
              <Textarea
                value={isEditing ? editedPersonData.notes || '' : personData.notes || ''}
                onChange={(e) => setEditedPersonData(prev => ({ ...prev, notes: e.target.value }))}
                disabled={!isEditing}
                placeholder={isRTL ? 'اكتب ملاحظات إضافية...' : 'Write additional notes...'}
                rows={isMobile ? 3 : 4}
                className={isMobile ? 'text-sm py-2' : ''}
              />
            </div>

            {isEditing && (
              <div className={`flex ${isMobile ? 'flex-col gap-2' : 'gap-3 pt-4'}`}>
                <Button onClick={handleSave} className="flex items-center gap-2" disabled={loading} size={isMobile ? "sm" : "default"}>
                  {loading ? (
                    <>
                      <Loader2 className={`animate-spin ${isMobile ? 'h-3 w-3 mr-1' : 'h-4 w-4 mr-2'}`} />
                      {isMobile ? (isRTL ? 'جاري الحفظ...' : 'Saving...') : (isRTL ? 'جاري الحفظ...' : 'Saving...')}
                    </>
                  ) : (
                    <>
                      <Save className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
                      {isMobile ? (isRTL ? 'حفظ' : 'Save') : (isRTL ? 'حفظ التغييرات' : 'Save Changes')}
                    </>
                  )}
                </Button>
                <Button variant="outline" onClick={handleCancel} disabled={loading} size={isMobile ? "sm" : "default"}>
                  {isMobile ? (isRTL ? 'إلغاء' : 'Cancel') : (isRTL ? 'إلغاء' : 'Cancel')}
                </Button>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Family Tab - REMOVED */}
      
      {/* Contact Info Tab - REMOVED */}

      {/* Education Tab - REMOVED */}
      
      {/* Work Tab - REMOVED */}
      
      {/* Media & Documents Tab - REMOVED */}
      
      {/* Medical Info Tab - REMOVED */}
      
      {/* Notes Tab - REMOVED */}

      {/* Delete Person Section */}
      {isEditing && (
        <Card className="border-destructive/20">
          <CardHeader className={isMobile ? 'p-4' : ''}>
            <CardTitle className="flex items-center gap-2 text-destructive">
              <AlertTriangle className={`h-5 w-5 ${isMobile ? 'h-4 w-4' : ''}`} />
              {isRTL ? 'منطقة الخطر' : 'Danger Zone'}
            </CardTitle>
          </CardHeader>
          <CardContent className={isMobile ? 'p-4' : ''}>
            <div className={`flex ${isMobile ? 'flex-col gap-3' : 'items-center justify-between'}`}>
              <div>
                <p className={`font-medium text-destructive ${isMobile ? 'text-sm' : ''}`}>{isRTL ? 'حذف الشخص' : 'Delete Person'}</p>
                <p className={`text-muted-foreground ${isMobile ? 'text-xs' : 'text-sm'}`}>
                  {isRTL ? 'حذف هذا الشخص وجميع بياناته نهائياً من الشجرة' : 'Permanently delete this person and all their data from the tree'}
                </p>
              </div>
              <Button 
                variant="destructive" 
                onClick={handleDeletePerson}
                className="flex items-center gap-2"
                disabled={loading}
                size={isMobile ? "sm" : "default"}
              >
                {loading ? (
                  <Loader2 className={`animate-spin ${isMobile ? 'h-3 w-3' : 'h-4 w-4'}`} />
                ) : (
                  <Trash2 className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
                )}
                {isMobile ? (isRTL ? 'حذف' : 'Delete') : (isRTL ? 'حذف' : 'Delete')}
              </Button>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
};

export default PersonEditPage;