import React, { useState } from 'react';
import { useUIStore } from '@/store/uiStore';
import { useAuthStore } from '@/store/authStore';
import { treeService } from '@/services/treeService';
import Modal from '@/components/ui/Modal';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { toast } from 'react-hot-toast';
import bilingualToast from '@/utils/bilingualToast';
import { 
  User, 
  Calendar, 
  MapPin, 
  Briefcase, 
  Users,
  Loader2
} from 'lucide-react';

interface TreePerson {
  id: string;
  firstName: string;
  firstNameEn: string;
  lastName: string;
  lastNameEn: string;
  gender: 'male' | 'female';
  birthDate?: string;
  birthPlace?: string;
  birthPlaceEn?: string;
  isAlive: boolean;
  parentIds?: string[];
  spouseIds?: string[];
  childrenIds?: string[];
  photo?: string;
  generation: number;
  position: { x: number; y: number };
  children?: TreePerson[];
}

interface JoinRequestModalProps {
  isOpen: boolean;
  onClose: () => void;
  treeId: string;
  treeName: string;
  treePersons: TreePerson[];
}

const JoinRequestModal: React.FC<JoinRequestModalProps> = ({ 
  isOpen, 
  onClose, 
  treeId,
  treeName,
  treePersons
}) => {
  // JoinRequestModal rendered with props
  
  const { language } = useUIStore();
  const { user } = useAuthStore();
  const isRTL = language === 'ar';
  
  // Log user authentication status for debugging
  React.useEffect(() => {
    // Log user authentication status for debugging
    if (isOpen) {
      // Additional debugging for auth state
      const storedUser = localStorage.getItem('user');
      const authToken = localStorage.getItem('authToken');
      
      if (storedUser) {
        try {
          const parsedUser = JSON.parse(storedUser);
        } catch (error) {
          // Error parsing stored user
        }
      }
    }
  }, [isOpen, user]);

  // Add effect to log when component mounts/unmounts
  React.useEffect(() => {
    // Component mounted
    return () => {
      // Component unmounted
    };
  }, []);

  // Add effect to log when isOpen changes
  React.useEffect(() => {
    // isOpen changed
  }, [isOpen]);

  // Add effect to log when component renders

  const [formData, setFormData] = useState({
    name: '',
    birthDate: '',
    birthPlace: '',
    gender: 'Male',
    occupation: '',
    relatedPersonId: '',
    relationshipType: ''
  });
  
  const [loading, setLoading] = useState(false);
  
  // Common relationship types
  const relationshipTypes = [
    { value: 'Father', label: isRTL ? 'أب' : 'Father' },
    { value: 'Mother', label: isRTL ? 'أم' : 'Mother' },
    { value: 'Son', label: isRTL ? 'ابن' : 'Son' },
    { value: 'Daughter', label: isRTL ? 'ابنة' : 'Daughter' },
    { value: 'Brother', label: isRTL ? 'أخ' : 'Brother' },
    { value: 'Sister', label: isRTL ? 'أخت' : 'Sister' },
    { value: 'Grandfather', label: isRTL ? 'جد' : 'Grandfather' },
    { value: 'Grandmother', label: isRTL ? 'جدة' : 'Grandmother' },
    { value: 'Grandson', label: isRTL ? 'حفيد' : 'Grandson' },
    { value: 'Granddaughter', label: isRTL ? 'حفيدة' : 'Granddaughter' },
    { value: 'Uncle', label: isRTL ? 'عم/خال' : 'Uncle' },
    { value: 'Aunt', label: isRTL ? 'عمة/خالة' : 'Aunt' },
    { value: 'Nephew', label: isRTL ? 'ابن الأخ/الخال' : 'Nephew' },
    { value: 'Niece', label: isRTL ? 'ابنة العم/الخال' : 'Niece' },
    { value: 'Cousin', label: isRTL ? 'ابن العم/الخال' : 'Cousin' },
    { value: 'Spouse', label: isRTL ? 'زوج/زوجة' : 'Spouse' }
  ];
  
  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };
  
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    
    try {
      // Validate required fields
      if (!formData.name || !formData.birthDate || !formData.birthPlace || 
          !formData.occupation || !formData.relatedPersonId || !formData.relationshipType) {
        bilingualToast.error({
          en: 'All fields are required',
          ar: 'جميع الحقول مطلوبة'
        });
        setLoading(false);
        return;
      }
      
      // Validate treeId
      const treeIdNum = parseInt(treeId);
      if (isNaN(treeIdNum) || treeIdNum <= 0) {
        bilingualToast.error({
          en: 'Invalid tree ID',
          ar: 'معرف الشجرة غير صالح'
        });
        setLoading(false);
        return;
      }
      
      // Validate relatedPersonId
      const relatedPersonIdNum = parseInt(formData.relatedPersonId);
      if (isNaN(relatedPersonIdNum) || relatedPersonIdNum <= 0) {
        bilingualToast.error({
          en: 'Invalid related person ID',
          ar: 'معرف الشخص المرتبط غير صالح'
        });
        setLoading(false);
        return;
      }
      
      // Get user ID with enhanced fallback (similar to TreeViewPage)
      const getUserId = (): string | null => {
        // Removed logging: JoinRequestModal - getUserId called - Current user state
        
        // Try to get user ID from auth store first
        if (user && typeof user === 'object' && (user as any).id !== undefined) {
          // Check if user.id is a non-empty string
          if (typeof (user as any).id === 'string' && (user as any).id.length > 0) {
            // Removed logging: Found valid user ID in auth store
            return (user as any).id;
          }
          // Check if user.id is a number (convert to string)
          if (typeof (user as any).id === 'number') {
            const userIdStr = (user as any).id.toString();
            if (userIdStr.length > 0) {
              // Removed logging: Found valid user ID (converted from number) in auth store
              return userIdStr;
            }
          }
        }
        
        // Fallback 1: Try to get user ID from localStorage
        try {
          const storedUser = localStorage.getItem('user');
          // Removed logging: Stored user from localStorage
          if (storedUser) {
            const parsedUser = JSON.parse(storedUser);
            if (parsedUser && parsedUser.id !== undefined) {
              // Check if parsedUser.id is a non-empty string
              if (typeof parsedUser.id === 'string' && parsedUser.id.length > 0) {
                // Removed logging: Using user ID from localStorage fallback
                return parsedUser.id;
              }
              // Check if parsedUser.id is a number (convert to string)
              if (typeof parsedUser.id === 'number') {
                const userIdStr = parsedUser.id.toString();
                if (userIdStr.length > 0) {
                  // Removed logging: Using user ID (converted from number) from localStorage fallback
                  return userIdStr;
                }
              }
            }
          }
        } catch (error) {
          // Removed error logging: Error parsing stored user for fallback
        }
        
        // Fallback 2: Try to get token and decode it
        try {
          const token = localStorage.getItem('authToken');
          // Removed logging: Token from localStorage
          if (token) {
            // Decode JWT token to get user ID
            const base64Url = token.split('.')[1];
            const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
            const jsonPayload = decodeURIComponent(atob(base64).split('').map(function(c) {
              return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
            }).join(''));
            
            const tokenData = JSON.parse(jsonPayload);
            // Removed logging: Token data
            
            // Try different possible user ID fields in token
            // Based on the logs, we see jti might be the user identifier
            const possibleIdFields = ['sub', 'nameid', 'userId', 'id', 'jti'];
            for (const field of possibleIdFields) {
              if (tokenData[field] !== undefined) {
                if (typeof tokenData[field] === 'string' && tokenData[field].length > 0) {
                  // Removed logging: Found user ID in token field
                  return tokenData[field];
                }
                // Also check if it's a number
                if (typeof tokenData[field] === 'number') {
                  const userIdStr = tokenData[field].toString();
                  if (userIdStr.length > 0) {
                    // Removed logging: Found user ID (converted from number) in token field
                    return userIdStr;
                  }
                }
              }
            }
          }
        } catch (error) {
          // Removed error logging: Error decoding token for fallback
        }
        
        // Removed logging: No valid user ID found
        return null;
      };
      
      // Get user ID
      const requesterId = getUserId();
      if (!requesterId) {
        bilingualToast.error({
          en: 'You must be logged in to send a join request',
          ar: 'يجب تسجيل الدخول لإرسال طلب انضمام'
        });
        setLoading(false);
        return;
      }
      
      // Create join request
      await treeService.createJoinRequest(
        treeIdNum,
        formData.name,
        formData.birthDate,
        formData.birthPlace,
        formData.gender,
        formData.occupation,
        relatedPersonIdNum,
        'Pending',
        requesterId,
        formData.relationshipType
      );
      
      bilingualToast.success({
        en: 'Join request sent successfully',
        ar: 'تم إرسال طلب الانضمام بنجاح'
      });
      onClose();
      
      // Reset form
      setFormData({
        name: '',
        birthDate: '',
        birthPlace: '',
        gender: 'Male',
        occupation: '',
        relatedPersonId: '',
        relationshipType: ''
      });
    } catch (error: any) {
      // Removed console.error for error submitting join request
      let errorMessage = isRTL ? `فشل في إرسال طلب الانضمام: ${error.message}` : `Failed to send join request: ${error.message}`;
      
      // Handle the specific case of a pending request already existing
      if (error.message && error.message.includes('A pending request already exists for this user and family tree')) {
        errorMessage = isRTL 
          ? 'لديك بالفعل طلب انضمام معلق لهذه الشجرة العائلية'
          : 'You already have a pending join request for this family tree';
      }
      
      bilingualToast.error({
        en: errorMessage,
        ar: errorMessage
      });
    } finally {
      setLoading(false);
    }
  };
  
  // Get person name based on language
  const getPersonName = (person: TreePerson) => {
    return isRTL 
      ? `${person.firstName} ${person.lastName}`
      : `${person.firstNameEn} ${person.lastNameEn}`;
  };
  
  return (
    <Modal isOpen={isOpen} onClose={onClose} title={isRTL ? `طلب الانضمام إلى ${treeName}` : `Join Request for ${treeName}`}>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium mb-1">
            {isRTL ? 'الاسم الكامل' : 'Full Name'}
          </label>
          <div className="relative">
            <User className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              name="name"
              value={formData.name}
              onChange={handleInputChange}
              placeholder={isRTL ? 'أدخل اسمك الكامل' : 'Enter your full name'}
              className="pl-10"
              required
            />
          </div>
        </div>
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium mb-1">
              {isRTL ? 'تاريخ الميلاد' : 'Birth Date'}
            </label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                type="date"
                name="birthDate"
                value={formData.birthDate}
                onChange={handleInputChange}
                className="pl-10"
                required
              />
            </div>
          </div>
          
          <div>
            <label className="block text-sm font-medium mb-1">
              {isRTL ? 'الجنس' : 'Gender'}
            </label>
            <select
              name="gender"
              value={formData.gender}
              onChange={handleInputChange}
              className="w-full border rounded-md px-3 py-2 text-sm bg-background text-foreground border-input"
              required
            >
              <option value="Male">{isRTL ? 'ذكر' : 'Male'}</option>
              <option value="Female">{isRTL ? 'أنثى' : 'Female'}</option>
            </select>
          </div>
        </div>
        
        <div>
          <label className="block text-sm font-medium mb-1">
            {isRTL ? 'مكان الميلاد' : 'Birth Place'}
          </label>
          <div className="relative">
            <MapPin className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              name="birthPlace"
              value={formData.birthPlace}
              onChange={handleInputChange}
              placeholder={isRTL ? 'أدخل مكان الميلاد' : 'Enter birth place'}
              className="pl-10"
              required
            />
          </div>
        </div>
        
        <div>
          <label className="block text-sm font-medium mb-1">
            {isRTL ? 'المهنة' : 'Occupation'}
          </label>
          <div className="relative">
            <Briefcase className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              name="occupation"
              value={formData.occupation}
              onChange={handleInputChange}
              placeholder={isRTL ? 'أدخل مهنتك' : 'Enter your occupation'}
              className="pl-10"
              required
            />
          </div>
        </div>
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium mb-1">
              {isRTL ? 'الشخص المرتبط' : 'Related Person'}
            </label>
            <div className="relative">
              <Users className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <select
                name="relatedPersonId"
                value={formData.relatedPersonId}
                onChange={handleInputChange}
                className="w-full border rounded-md px-10 py-2 text-sm bg-background text-foreground border-input"
                required
              >
                <option value="">{isRTL ? 'اختر الشخص' : 'Select Person'}</option>
                {treePersons.map(person => (
                  <option key={person.id} value={person.id}>
                    {getPersonName(person)}
                  </option>
                ))}
              </select>
            </div>
          </div>
          
          <div>
            <label className="block text-sm font-medium mb-1">
              {isRTL ? 'نوع العلاقة' : 'Relationship Type'}
            </label>
            <select
              name="relationshipType"
              value={formData.relationshipType}
              onChange={handleInputChange}
              className="w-full border rounded-md px-3 py-2 text-sm bg-background text-foreground border-input"
              required
            >
              <option value="">{isRTL ? 'اختر نوع العلاقة' : 'Select Relationship'}</option>
              {relationshipTypes.map(rel => (
                <option key={rel.value} value={rel.value}>
                  {rel.label}
                </option>
              ))}
            </select>
          </div>
        </div>
        
        <div className="flex justify-end gap-2 pt-4">
          <Button
            type="button"
            variant="outline"
            onClick={onClose}
            disabled={loading}
          >
            {isRTL ? 'إلغاء' : 'Cancel'}
          </Button>
          <Button
            type="submit"
            disabled={loading}
            className="flex items-center gap-2"
          >
            {loading && <Loader2 className="h-4 w-4 animate-spin" />}
            {isRTL ? 'إرسال الطلب' : 'Send Request'}
          </Button>
        </div>
      </form>
    </Modal>
  );
};

export default JoinRequestModal;