// Updated interfaces to match the actual API data structures
interface Person {
  id: string;
  firstName: string;
  firstNameEn?: string;
  lastName?: string;
  lastNameEn?: string;
  gender: 'male' | 'female';
  birthDate?: string;
  deathDate?: string;
  birthPlace?: string;
  birthPlaceEn?: string;
  isAlive: boolean;
  generation?: number;
  treeId: string;
  treeName?: string;
  treeNameEn?: string;
  photo?: string;
  occupation?: string;
  occupationEn?: string;
}

interface FamilyTree {
  id: string;
  name: string;
  nameEn?: string;
  description?: string;
  descriptionEn?: string;
  memberCount?: number;
  createdAt: string;
  isPublic?: boolean;
  owner?: {
    firstName: string;
    lastName: string;
  };
}

