import { useUIStore } from '@/store/uiStore';

/**
 * Utility functions for handling bilingual notifications
 */

// Type for bilingual messages
export type BilingualMessage = { en: string; ar: string };

// Type guard to check if a value is a bilingual message object
export const isBilingualMessage = (value: any): value is BilingualMessage => {
  return value && typeof value === 'object' && ('en' in value || 'ar' in value);
};

// Helper function to create bilingual messages
export const bilingual = (en: string, ar: string): BilingualMessage => {
  return { en, ar };
};

// Hook for showing notifications with automatic language detection
export const useNotifications = () => {
  const { language, showSuccess, showError, showWarning, showInfo } = useUIStore();
  
  const notifySuccess = (title: string | BilingualMessage, message?: string | BilingualMessage) => {
    showSuccess(title, message);
  };
  
  const notifyError = (title: string | BilingualMessage, message?: string | BilingualMessage) => {
    showError(title, message);
  };
  
  const notifyWarning = (title: string | BilingualMessage, message?: string | BilingualMessage) => {
    showWarning(title, message);
  };
  
  const notifyInfo = (title: string | BilingualMessage, message?: string | BilingualMessage) => {
    showInfo(title, message);
  };
  
  return {
    success: notifySuccess,
    error: notifyError,
    warning: notifyWarning,
    info: notifyInfo,
  };
};

// Utility function to get the appropriate message based on current language
export const getLocalizedMessage = (message: string | BilingualMessage, language: 'en' | 'ar'): string => {
  if (isBilingualMessage(message)) {
    return language === 'ar' ? message.ar : message.en;
  }
  return message as string;
};