import { useEffect, useState } from 'react';

interface MemoryInfo {
  deviceMemory?: number;
  totalJSHeapSize?: number;
  usedJSHeapSize?: number;
  jsHeapSizeLimit?: number;
  isLowMemory?: boolean;
}

export const useMemoryMonitor = () => {
  const [memoryInfo, setMemoryInfo] = useState<MemoryInfo>({});
  const [isSupported, setIsSupported] = useState(false);

  useEffect(() => {
    // Check if memory monitoring is supported
    const isSupported = 'deviceMemory' in navigator || 
                       ('memory' in performance && performance.memory);
    
    setIsSupported(!!isSupported);
    
    if (!isSupported) return;

    const updateMemoryInfo = () => {
      const info: MemoryInfo = {};
      
      // Device memory (in GB)
      if ('deviceMemory' in navigator) {
        info.deviceMemory = (navigator as any).deviceMemory;
      }
      
      // JS heap memory (Chrome only)
      if ('memory' in performance && (performance as any).memory) {
        const memory = (performance as any).memory;
        info.totalJSHeapSize = memory.totalJSHeapSize;
        info.usedJSHeapSize = memory.usedJSHeapSize;
        info.jsHeapSizeLimit = memory.jsHeapSizeLimit;
        info.isLowMemory = memory.usedJSHeapSize > memory.jsHeapSizeLimit * 0.8; // 80% threshold
      }
      
      setMemoryInfo(info);
    };

    // Update memory info immediately
    updateMemoryInfo();
    
    // Update periodically
    const interval = setInterval(updateMemoryInfo, 5000);
    
    return () => clearInterval(interval);
  }, []);

  return { memoryInfo, isSupported };
};

export default useMemoryMonitor;