import React from 'react';
import { useUIStore } from '@/store/uiStore';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';

const PrivacyPage: React.FC = () => {
  const { language } = useUIStore();
  const isRTL = language === 'ar';

  const privacyContent = {
    title: isRTL ? 'سياسة الخصوصية' : 'Privacy Policy',
    lastUpdated: isRTL ? 'آخر تحديث: 18 سبتمبر 2025' : 'Last Updated: September 18, 2025',
    introduction: {
      title: isRTL ? 'مقدمة' : 'Introduction',
      content: isRTL 
        ? 'في Nasabna ("نحن" أو "لنا" أو "لدينا")، نحن ملتزمون بحماية خصوصيتك. توضح سياسة الخصوصية هذه كيف نجمع ونستخدم ونحمي معلوماتك الشخصية عندما تستخدم موقعنا وخدماتنا.'
        : 'At Nasabna ("we," "us," or "our"), we are committed to protecting your privacy. This Privacy Policy explains how we collect, use, and protect your personal information when you use our website and services.'
    },
    informationCollection: {
      title: isRTL ? 'معلومات نجمعها' : 'Information We Collect',
      content: isRTL 
        ? 'قد نجمع أنواع المعلومات التالية: معلومات الحساب (الاسم والبريد الإلكتروني وتفاصيل الحساب)، معلومات العائلة (تفاصيل أفراد العائلة والصور والعلاقات)، معلومات التقنية (عنوان IP ومعلومات المتصفح وبيانات الاستخدام)'
        : 'We may collect the following types of information: Account Information (name, email, and account details), Family Information (family member details, photos, and relationships), Technical Information (IP address, browser information, and usage data)'
    },
    informationUse: {
      title: isRTL ? 'كيف نستخدم معلوماتك' : 'How We Use Your Information',
      content: isRTL 
        ? 'نستخدم معلوماتك لـ: توفير وتحسين خدماتنا، التواصل معك، تخصيص تجربتك، معالجة المعاملات، والامتثال للقوانين المعمول بها'
        : 'We use your information to: Provide and improve our services, Communicate with you, Personalize your experience, Process transactions, and Comply with applicable laws'
    },
    informationProtection: {
      title: isRTL ? 'حماية معلوماتك' : 'Protecting Your Information',
      content: isRTL 
        ? 'نستخدم تدابير أمنية متنوعة لحماية معلوماتك الشخصية، بما في ذلك التشفير وتقنيات الأمان الأخرى. ومع ذلك، لا يمكننا ضمان الأمان المطلق لنقل البيانات عبر الإنترنت.'
        : 'We use various security measures to protect your personal information, including encryption and other security technologies. However, we cannot guarantee absolute security for data transmission over the internet.'
    },
    informationSharing: {
      title: isRTL ? 'مشاركة المعلومات' : 'Information Sharing',
      content: isRTL 
        ? 'نحن لا نبيع أو نتاجر أو ننقل بطريقة أخرى معلوماتك الشخصية لأطراف ثالثة. قد نشارك معلوماتك مع مزودي خدمات موثوقين يساعدوننا في تشغيل موقعنا أو تقديم خدماتنا، بشرط أن يوافقوا على الالتزام بسياسات الخصوصية هذه.'
        : 'We do not sell, trade, or otherwise transfer your personal information to third parties. We may share your information with trusted service providers who help us operate our site or provide services, provided they agree to abide by these privacy policies.'
    },
    cookies: {
      title: isRTL ? 'ملفات تعريف الارتباط (Cookies)' : 'Cookies',
      content: isRTL 
        ? 'نستخدم ملفات تعريف الارتباط لتحسين تجربتك وتحليل استخدام الموقع. يمكنك تعيين متصفحك لرفض جميع ملفات تعريف الارتباط أو لإعلامك عند إرسال ملف تعريف ارتباط.'
        : 'We use cookies to improve your experience and analyze site usage. You can set your browser to refuse all cookies or to alert you when a cookie is being sent.'
    },
    dataRetention: {
      title: isRTL ? 'احتفاظ البيانات' : 'Data Retention',
      content: isRTL 
        ? 'نحتفظ بمعلوماتك طالما كان حسابك نشطًا أو كما هو مطلوب قانونًا. يمكنك طلب حذف حسابك في أي وقت، وسنقوم بمعالجة هذا الطلب وفقًا لسياساتنا والتزاماتنا القانونية.'
        : 'We retain your information for as long as your account is active or as needed for legal requirements. You may request account deletion at any time, and we will process this request according to our policies and legal obligations.'
    },
    yourRights: {
      title: isRTL ? 'حقوقك' : 'Your Rights',
      content: isRTL 
        ? 'لديك الحق في الوصول إلى معلوماتك الشخصية وتحديثها أو تصحيحها أو حذفها. يمكنك أيضًا الاعتراض على معالجة بياناتك أو طلب تقييدها أو نقلها.'
        : 'You have the right to access, update, correct, or delete your personal information. You may also object to data processing or request restriction or transfer of your data.'
    },
    childrenPrivacy: {
      title: isRTL ? 'خصوصية الأطفال' : 'Children\'s Privacy',
      content: isRTL 
        ? 'لا توجه خدماتنا للأطفال دون سن 13 عامًا. لا نجمع عن علم معلومات شخصية من الأطفال دون سن 13 عامًا.'
        : 'Our services are not directed to children under 13 years of age. We do not knowingly collect personal information from children under 13.'
    },
    changes: {
      title: isRTL ? 'تغييرات على سياسة الخصوصية' : 'Changes to Privacy Policy',
      content: isRTL 
        ? 'قد نقوم بتحديث سياسة الخصوصية هذه من وقت لآخر. سنقوم بإعلامك بأي تغييرات من خلال نشر السياسة الجديدة على هذه الصفحة وتحديث تاريخ "آخر تحديث".'
        : 'We may update this Privacy Policy from time to time. We will notify you of any changes by posting the new policy on this page and updating the "Last Updated" date.'
    },
    contact: {
      title: isRTL ? 'اتصل بنا' : 'Contact Us',
      content: isRTL 
        ? 'إذا كانت لديك أي أسئلة حول سياسة الخصوصية هذه، يرجى الاتصال بنا على support@nasabna.com'
        : 'If you have any questions about this Privacy Policy, please contact us at support@nasabna.com'
    }
  };

  return (
    <div className="min-h-screen bg-background">
      {/* Hero Section */}
      <section className="relative py-20 md:py-32 bg-gradient-to-br from-primary/10 via-primary/5 to-background overflow-hidden">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
          <div className="text-center max-w-4xl mx-auto">
            <h1 className="text-4xl sm:text-5xl lg:text-6xl font-bold text-foreground mb-6">
              {privacyContent.title}
            </h1>
            <p className="text-xl text-muted-foreground">
              {privacyContent.lastUpdated}
            </p>
          </div>
        </div>
      </section>

      {/* Privacy Content */}
      <section className="py-16">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8">
          <div className="max-w-4xl mx-auto">
            <Card>
              <CardHeader>
                <CardTitle className="text-2xl">{privacyContent.introduction.title}</CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-muted-foreground">
                  {privacyContent.introduction.content}
                </p>
              </CardContent>
            </Card>

            <div className="mt-8 space-y-8">
              <Card>
                <CardHeader>
                  <CardTitle>{privacyContent.informationCollection.title}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-muted-foreground">
                    {privacyContent.informationCollection.content}
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>{privacyContent.informationUse.title}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-muted-foreground">
                    {privacyContent.informationUse.content}
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>{privacyContent.informationProtection.title}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-muted-foreground">
                    {privacyContent.informationProtection.content}
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>{privacyContent.informationSharing.title}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-muted-foreground">
                    {privacyContent.informationSharing.content}
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>{privacyContent.cookies.title}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-muted-foreground">
                    {privacyContent.cookies.content}
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>{privacyContent.dataRetention.title}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-muted-foreground">
                    {privacyContent.dataRetention.content}
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>{privacyContent.yourRights.title}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-muted-foreground">
                    {privacyContent.yourRights.content}
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>{privacyContent.childrenPrivacy.title}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-muted-foreground">
                    {privacyContent.childrenPrivacy.content}
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>{privacyContent.changes.title}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-muted-foreground">
                    {privacyContent.changes.content}
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>{privacyContent.contact.title}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-muted-foreground">
                    {privacyContent.contact.content}
                  </p>
                </CardContent>
              </Card>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default PrivacyPage;