import React, { useState, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useUIStore } from '@/store/uiStore';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';
import { Input } from '@/components/ui/Input';
import { 
  CreditCard, 
  Lock, 
  Shield,
  Check,
  ArrowLeft,
  Calendar,
  User,
  Mail,
  Phone,
  MapPin,
  Building,
  Globe,
  AlertTriangle,
  Info,
  Star,
  Crown,
  TreePine,
  Zap,
  Gift,
  Percent,
  Clock,
  RefreshCw,
  CheckCircle,
  XCircle,
  Loader2
} from 'lucide-react';

import { subscriptionService } from '@/services/subscriptionService';

interface PaymentMethod {
  id: string;
  name: string;
  nameEn: string;
  icon: string;
  type: 'card';
}

interface PlanDetails {
  id: string;
  name: string;
  nameEn: string;
  price: number;
  originalPrice?: number;
  billingCycle: 'monthly' | 'yearly';
  features: string[];
  featuresEn: string[];
}

interface BillingInfo {
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  country: string;
  city: string;
  address: string;
  postalCode: string;
  vatNumber?: string;
}

interface PaymentInfo {
  cardNumber: string;
  expiryDate: string;
  cvv: string;
  cardholderName: string;
}

const CheckoutPage: React.FC = () => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { language } = useUIStore();
  const [currentStep, setCurrentStep] = useState<'plan' | 'billing' | 'payment' | 'processing' | 'success'>('plan');
  const [selectedPaymentMethod, setSelectedPaymentMethod] = useState<string>('card');
  const [promoCode, setPromoCode] = useState('');
  const [promoApplied, setPromoApplied] = useState(false);
  const [promoDiscount, setPromoDiscount] = useState(0);
  const [promoError, setPromoError] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const isRTL = language === 'ar';
  const planId = searchParams.get('plan') || 'premium';
  const billingCycle = searchParams.get('billing') as 'monthly' | 'yearly' || 'yearly';

  const [billingInfo, setBillingInfo] = useState<BillingInfo>({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    country: 'SA',
    city: '',
    address: '',
    postalCode: '',
    vatNumber: ''
  });

  const [paymentInfo, setPaymentInfo] = useState<PaymentInfo>({
    cardNumber: '',
    expiryDate: '',
    cvv: '',
    cardholderName: ''
  });

  // Mock plan data
  const planDetails: Record<string, PlanDetails> = {
    basic: {
      id: 'basic',
      name: 'أساسي',
      nameEn: 'Basic',
      price: billingCycle === 'monthly' ? 9.99 : 99.99,
      billingCycle,
      features: [
        'شجرة عائلة واحدة',
        'حتى 5 أشخاص لكل شجرة',
        '1 جيجابايت تخزين',
        'دعم البريد الإلكتروني'
      ],
      featuresEn: [
        '1 family tree',
        'Up to 5 people per tree',
        '1GB storage',
        'Email support'
      ]
    },
    premium: {
      id: 'premium',
      name: 'مميز',
      nameEn: 'Premium',
      price: billingCycle === 'monthly' ? 19.99 : 199.99,
      billingCycle,
      features: [
        '3 أشجار عائلة',
        'حتى 150 شخص لكل شجرة',
        '10 جيجابايت تخزين',
        'اقتراحات ذكية',
        'دعم أولوية'
      ],
      featuresEn: [
        '3 family trees',
        'Up to 150 people per tree',
        '10GB storage',
        'Smart suggestions',
        'Priority support'
      ]
    },
    family: {
      id: 'family',
      name: 'عائلي',
      nameEn: 'Family',
      price: billingCycle === 'monthly' ? 29.99 : 299.99,
      billingCycle,
      features: [
        'أشجار وأشخاص غير محدودة',
        'تخزين غير محدود',
        'اقتراحات ذكية',
        'دعم أولوية',
        'سمات مخصصة',
        'بحث متقدم'
      ],
      featuresEn: [
        'Unlimited trees & people',
        'Unlimited storage',
        'Smart suggestions',
        'Priority support',
        'Custom themes',
        'Advanced search'
      ]
    }
  };

  const paymentMethods: PaymentMethod[] = [
    { id: 'card', name: 'بطاقة ائتمانية', nameEn: 'Credit Card', icon: '💳', type: 'card' }
  ];

  const currentPlan = planDetails[planId];

  // Redirect users to registration
  useEffect(() => {
    // No need to redirect anymore since free plan was removed
  }, []);

  const calculateTotal = () => {
    if (!currentPlan) return 0;
    const subtotal = currentPlan.price;
    const discount = promoApplied ? (subtotal * promoDiscount / 100) : 0;
    const vat = (subtotal - discount) * 0.15; // 15% VAT
    return subtotal - discount + vat;
  };

  const calculateVAT = () => {
    if (!currentPlan) return 0;
    const subtotal = currentPlan.price;
    const discount = promoApplied ? (subtotal * promoDiscount / 100) : 0;
    return (subtotal - discount) * 0.15;
  };

  const handleApplyPromo = () => {
    // Mock promo code validation
    const validPromoCodes = {
      'FAMILY20': 20,
      'SAVE15': 15,
      'WELCOME10': 10
    };

    if (validPromoCodes[promoCode as keyof typeof validPromoCodes]) {
      setPromoApplied(true);
      setPromoDiscount(validPromoCodes[promoCode as keyof typeof validPromoCodes]);
      setPromoError(null); // Clear any previous error
    } else {
      setPromoError(isRTL ? 'كود الخصم غير صحيح' : 'Invalid promo code');
      // Clear the error after 3 seconds
      setTimeout(() => setPromoError(null), 3000);
    }
  };

  const handleSubscribe = async () => {
    if (!currentPlan) return;
    
    try {
      setIsProcessing(true);
      setError(null);
      
      // Convert billingCycle to the expected format
      const billingCycleParam = billingCycle === 'monthly' ? 'month' : 'year';
      
      // Use the subscription service to subscribe
      const response = await subscriptionService.subscribe(currentPlan.id, billingCycleParam);
      
      // Check if this is a simulated subscription
      if (response && response.message && response.message.includes('simulated')) {
        // Show a warning in the UI instead of using alert
        setError('This is a simulation. In a production environment, you would be redirected to a payment processor.');
      }
      
      // Navigate to success page
      setCurrentStep('success');
    } catch (err: any) {
      // Subscription error: err
      // Provide a more user-friendly error message
      if (err.response && err.response.status === 404) {
        setError('Subscription service is not available. This is a simulation environment.');
        // Still navigate to success page to simulate the flow
        setCurrentStep('success');
      } else {
        setError(err.message || 'Failed to process subscription');
      }
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePayment = async () => {
    // For now, we'll just call handleSubscribe directly
    // In a real implementation, you would integrate with a payment provider
    await handleSubscribe();
  };

  const formatPrice = (price: number) => {
    return `${price} ${isRTL ? 'ريال' : 'SAR'}`;
  };

  const formatCardNumber = (value: string) => {
    const v = value.replace(/\s+/g, '').replace(/[^0-9]/gi, '');
    const matches = v.match(/\d{4,16}/g);
    const match = matches && matches[0] || '';
    const parts = [];
    for (let i = 0, len = match.length; i < len; i += 4) {
      parts.push(match.substring(i, i + 4));
    }
    if (parts.length) {
      return parts.join(' ');
    } else {
      return v;
    }
  };

  const formatExpiryDate = (value: string) => {
    const v = value.replace(/\s+/g, '').replace(/[^0-9]/gi, '');
    if (v.length >= 2) {
      return v.substring(0, 2) + '/' + v.substring(2, 4);
    }
    return v;
  };

  if (!currentPlan) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <AlertTriangle className="h-16 w-16 text-destructive mx-auto mb-4" />
          <h1 className="text-2xl font-bold mb-2">
            {isRTL ? 'خطة غير موجودة' : 'Plan Not Found'}
          </h1>
          <p className="text-muted-foreground mb-4">
            {isRTL ? 'الخطة المطلوبة غير متاحة' : 'The requested plan is not available'}
          </p>
          <Button onClick={() => navigate('/subscription/plans')}>
            {isRTL ? 'العودة للخطط' : 'Back to Plans'}
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      {/* Header */}
      <div className="flex items-center gap-4">
        <Button
          variant="outline"
          onClick={() => navigate('/subscription/plans')}
          className="flex items-center gap-2"
        >
          <ArrowLeft className="h-4 w-4" />
          {isRTL ? 'العودة للخطط' : 'Back to Plans'}
        </Button>
        <div>
          <h1 className="text-2xl font-bold text-foreground">
            {isRTL ? 'إتمام الاشتراك' : 'Complete Subscription'}
          </h1>
          <p className="text-sm text-muted-foreground">
            {isRTL ? 'أكمل عملية الدفع لتفعيل اشتراكك' : 'Complete payment to activate your subscription'}
          </p>
        </div>
      </div>

      {/* Progress Steps */}
      <div className="flex items-center justify-center space-x-4 rtl:space-x-reverse mb-8">
        {[
          { id: 'plan', label: isRTL ? 'الخطة' : 'Plan', icon: TreePine },
          { id: 'billing', label: isRTL ? 'الفوترة' : 'Billing', icon: User },
          { id: 'payment', label: isRTL ? 'الدفع' : 'Payment', icon: CreditCard },
          { id: 'success', label: isRTL ? 'مكتمل' : 'Complete', icon: CheckCircle }
        ].map((step, index) => (
          <div key={step.id} className="flex items-center">
            <div className={`flex items-center justify-center w-10 h-10 rounded-full border-2 ${
              currentStep === step.id 
                ? 'bg-primary text-primary-foreground border-primary' 
                : ['plan', 'billing', 'payment', 'success'].indexOf(currentStep) > index
                ? 'bg-primary text-primary-foreground border-primary'
                : 'bg-background text-muted-foreground border-muted'
            }`}>
              {React.createElement(step.icon, { className: "h-5 w-5" })}
            </div>
            <span className={`ml-2 text-sm ${
              currentStep === step.id ? 'text-primary font-medium' : 'text-muted-foreground'
            }`}>
              {step.label}
            </span>
            {index < 3 && (
              <div className={`w-8 h-0.5 mx-4 ${
                ['plan', 'billing', 'payment', 'success'].indexOf(currentStep) > index
                  ? 'bg-primary'
                  : 'bg-muted'
              }`} />
            )}
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Main Content */}
        <div className="lg:col-span-2 space-y-6">
          {/* Plan Review Step */}
          {currentStep === 'plan' && (
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <TreePine className="h-5 w-5" />
                  {isRTL ? 'مراجعة الخطة' : 'Plan Review'}
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-6">
                <div className="flex items-center justify-between p-4 border rounded-lg">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-primary/10 rounded-full flex items-center justify-center">
                      {currentPlan.id === 'professional' ? (
                        <Crown className="h-6 w-6 text-primary" />
                      ) : (
                        <Star className="h-6 w-6 text-primary" />
                      )}
                    </div>
                    <div>
                      <h3 className="font-semibold text-lg">
                        {isRTL ? currentPlan.name : currentPlan.nameEn}
                      </h3>
                      <p className="text-sm text-muted-foreground">
                        {billingCycle === 'monthly' 
                          ? (isRTL ? 'اشتراك شهري' : 'Monthly subscription')
                          : (isRTL ? 'اشتراك سنوي' : 'Yearly subscription')
                        }
                      </p>
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="flex items-center gap-2">
                      <span className="text-2xl font-bold">
                        {formatPrice(currentPlan.price)}
                      </span>
                      {currentPlan.originalPrice && (
                        <span className="text-lg text-muted-foreground line-through">
                          {formatPrice(currentPlan.originalPrice)}
                        </span>
                      )}
                    </div>
                    {currentPlan.originalPrice && (
                      <Badge className="bg-green-100 text-green-800">
                        <Gift className="h-3 w-3 mr-1" />
                        {isRTL ? 'وفر 25%' : 'Save 25%'}
                      </Badge>
                    )}
                  </div>
                </div>

                <div>
                  <h4 className="font-medium mb-3">{isRTL ? 'المميزات المشمولة:' : 'Included Features:'}</h4>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                    {(isRTL ? currentPlan.features : currentPlan.featuresEn).map((feature, index) => (
                      <div key={index} className="flex items-center gap-2">
                        <Check className="h-4 w-4 text-green-600" />
                        <span className="text-sm">{feature}</span>
                      </div>
                    ))}
                  </div>
                </div>

                <Button 
                  onClick={() => setCurrentStep('billing')}
                  className="w-full"
                  size="lg"
                >
                  {isRTL ? 'متابعة للفوترة' : 'Continue to Billing'}
                </Button>
              </CardContent>
            </Card>
          )}

          {/* Billing Information Step */}
          {currentStep === 'billing' && (
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <User className="h-5 w-5" />
                  {isRTL ? 'معلومات الفوترة' : 'Billing Information'}
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'الاسم الأول *' : 'First Name *'}</label>
                    <Input
                      value={billingInfo.firstName}
                      onChange={(e) => setBillingInfo(prev => ({ ...prev, firstName: e.target.value }))}
                      placeholder={isRTL ? 'الاسم الأول' : 'First Name'}
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'اسم العائلة *' : 'Last Name *'}</label>
                    <Input
                      value={billingInfo.lastName}
                      onChange={(e) => setBillingInfo(prev => ({ ...prev, lastName: e.target.value }))}
                      placeholder={isRTL ? 'اسم العائلة' : 'Last Name'}
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'البريد الإلكتروني *' : 'Email *'}</label>
                    <Input
                      type="email"
                      value={billingInfo.email}
                      onChange={(e) => setBillingInfo(prev => ({ ...prev, email: e.target.value }))}
                      placeholder={isRTL ? 'البريد الإلكتروني' : 'Email'}
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'رقم الهاتف *' : 'Phone Number *'}</label>
                    <Input
                      value={billingInfo.phone}
                      onChange={(e) => setBillingInfo(prev => ({ ...prev, phone: e.target.value }))}
                      placeholder={isRTL ? 'رقم الهاتف' : 'Phone Number'}
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'الدولة *' : 'Country *'}</label>
                    <select
                      value={billingInfo.country}
                      onChange={(e) => setBillingInfo(prev => ({ ...prev, country: e.target.value }))}
                      className="w-full px-3 py-2 border border-input rounded-md bg-background"
                    >
                      <option value="SA">{isRTL ? 'السعودية' : 'Saudi Arabia'}</option>
                      <option value="AE">{isRTL ? 'الإمارات' : 'UAE'}</option>
                      <option value="KW">{isRTL ? 'الكويت' : 'Kuwait'}</option>
                      <option value="QA">{isRTL ? 'قطر' : 'Qatar'}</option>
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'المدينة *' : 'City *'}</label>
                    <Input
                      value={billingInfo.city}
                      onChange={(e) => setBillingInfo(prev => ({ ...prev, city: e.target.value }))}
                      placeholder={isRTL ? 'المدينة' : 'City'}
                      required
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-medium">{isRTL ? 'العنوان *' : 'Address *'}</label>
                  <Input
                    value={billingInfo.address}
                    onChange={(e) => setBillingInfo(prev => ({ ...prev, address: e.target.value }))}
                    placeholder={isRTL ? 'العنوان' : 'Address'}
                    required
                  />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'الرمز البريدي' : 'Postal Code'}</label>
                    <Input
                      value={billingInfo.postalCode}
                      onChange={(e) => setBillingInfo(prev => ({ ...prev, postalCode: e.target.value }))}
                      placeholder={isRTL ? 'الرمز البريدي' : 'Postal Code'}
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'الرقم الضريبي (اختياري)' : 'VAT Number (Optional)'}</label>
                    <Input
                      value={billingInfo.vatNumber || ''}
                      onChange={(e) => setBillingInfo(prev => ({ ...prev, vatNumber: e.target.value }))}
                      placeholder={isRTL ? 'الرقم الضريبي' : 'VAT Number'}
                    />
                  </div>
                </div>

                <div className="flex gap-4">
                  <Button 
                    variant="outline"
                    onClick={() => setCurrentStep('plan')}
                  >
                    {isRTL ? 'السابق' : 'Previous'}
                  </Button>
                  <Button 
                    onClick={() => setCurrentStep('payment')}
                    className="flex-1"
                    disabled={!billingInfo.firstName || !billingInfo.lastName || !billingInfo.email || !billingInfo.phone}
                  >
                    {isRTL ? 'متابعة للدفع' : 'Continue to Payment'}
                  </Button>
                </div>
              </CardContent>
            </Card>
          )}

          {/* Payment Step */}
          {currentStep === 'payment' && (
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <CreditCard className="h-5 w-5" />
                  {isRTL ? 'معلومات الدفع' : 'Payment Information'}
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-6">
                {/* Payment Methods */}
                <div>
                  <h4 className="font-medium mb-3">{isRTL ? 'طريقة الدفع' : 'Payment Method'}</h4>
                  <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                    {paymentMethods.map(method => (
                      <div
                        key={method.id}
                        className={`p-3 border rounded-lg cursor-pointer transition-all hover:shadow-sm ${
                          selectedPaymentMethod === method.id
                            ? 'border-primary bg-primary/5'
                            : 'border-muted hover:border-primary/50'
                        }`}
                        onClick={() => setSelectedPaymentMethod(method.id)}
                      >
                        <div className="text-center">
                          <div className="text-2xl mb-1">{method.icon}</div>
                          <p className="text-sm font-medium">
                            {isRTL ? method.name : method.nameEn}
                          </p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Card Payment Form */}
                {selectedPaymentMethod === 'card' && (
                  <div className="space-y-4">
                    <div className="space-y-2">
                      <label className="text-sm font-medium">{isRTL ? 'رقم البطاقة *' : 'Card Number *'}</label>
                      <Input
                        value={paymentInfo.cardNumber}
                        onChange={(e) => setPaymentInfo(prev => ({ 
                          ...prev, 
                          cardNumber: formatCardNumber(e.target.value) 
                        }))}
                        placeholder="1234 5678 9012 3456"
                        maxLength={19}
                        required
                      />
                    </div>
                    
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-sm font-medium">{isRTL ? 'تاريخ الانتهاء *' : 'Expiry Date *'}</label>
                        <Input
                          value={paymentInfo.expiryDate}
                          onChange={(e) => setPaymentInfo(prev => ({ 
                            ...prev, 
                            expiryDate: formatExpiryDate(e.target.value) 
                          }))}
                          placeholder="MM/YY"
                          maxLength={5}
                          required
                        />
                      </div>
                      <div className="space-y-2">
                        <label className="text-sm font-medium">{isRTL ? 'رمز الأمان *' : 'CVV *'}</label>
                        <Input
                          value={paymentInfo.cvv}
                          onChange={(e) => setPaymentInfo(prev => ({ 
                            ...prev, 
                            cvv: e.target.value.replace(/\D/g, '').substring(0, 4) 
                          }))}
                          placeholder="123"
                          maxLength={4}
                          required
                        />
                      </div>
                    </div>
                    
                    <div className="space-y-2">
                      <label className="text-sm font-medium">{isRTL ? 'اسم حامل البطاقة *' : 'Cardholder Name *'}</label>
                      <Input
                        value={paymentInfo.cardholderName}
                        onChange={(e) => setPaymentInfo(prev => ({ ...prev, cardholderName: e.target.value }))}
                        placeholder={isRTL ? 'الاسم كما هو مكتوب على البطاقة' : 'Name as written on card'}
                        required
                      />
                    </div>
                  </div>
                )}

                <div className="flex gap-4">
                  <Button 
                    variant="outline"
                    onClick={() => setCurrentStep('billing')}
                  >
                    {isRTL ? 'السابق' : 'Previous'}
                  </Button>
                  <Button 
                    onClick={handlePayment}
                    className="flex-1 flex items-center gap-2"
                    disabled={
                      selectedPaymentMethod === 'card' &&
                      (!paymentInfo.cardNumber || !paymentInfo.expiryDate || !paymentInfo.cvv || !paymentInfo.cardholderName)
                    }
                  >
                    <Lock className="h-4 w-4" />
                    {isRTL ? 'إتمام الدفع' : 'Complete Payment'}
                  </Button>
                </div>
              </CardContent>
            </Card>
          )}

          {/* Processing Step */}
          {currentStep === 'processing' && (
            <Card>
              <CardContent className="p-12 text-center">
                <Loader2 className="h-16 w-16 animate-spin text-primary mx-auto mb-6" />
                <h3 className="text-xl font-semibold mb-2">
                  {isRTL ? 'جاري معالجة الدفع...' : 'Processing Payment...'}
                </h3>
                <p className="text-muted-foreground">
                  {isRTL 
                    ? 'يرجى الانتظار، لا تغلق هذه الصفحة'
                    : 'Please wait, do not close this page'
                  }
                </p>
              </CardContent>
            </Card>
          )}

          {/* Success Step */}
          {currentStep === 'success' && (
            <Card>
              <CardContent className="p-12 text-center">
                <CheckCircle className="h-16 w-16 text-green-600 mx-auto mb-6" />
                <h3 className="text-2xl font-bold mb-2">
                  {isRTL ? 'تم الاشتراك بنجاح!' : 'Subscription Successful!'}
                </h3>
                <p className="text-muted-foreground mb-6">
                  {isRTL 
                    ? 'مرحباً بك في خطة ' + currentPlan.name + '! يمكنك الآن الاستمتاع بجميع المميزات.'
                    : 'Welcome to ' + currentPlan.nameEn + ' plan! You can now enjoy all features.'
                  }
                </p>
                <div className="flex gap-4 justify-center">
                  <Button onClick={() => navigate('/dashboard')}>
                    {isRTL ? 'الذهاب للوحة التحكم' : 'Go to Dashboard'}
                  </Button>
                  <Button variant="outline" onClick={() => navigate('/trees')}>
                    {isRTL ? 'إنشاء شجرة عائلية' : 'Create Family Tree'}
                  </Button>
                </div>
              </CardContent>
            </Card>
          )}
        </div>

        {/* Order Summary Sidebar */}
        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Info className="h-5 w-5" />
                {isRTL ? 'ملخص الطلب' : 'Order Summary'}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex justify-between">
                <span>{isRTL ? 'الخطة:' : 'Plan:'}</span>
                <span className="font-medium">
                  {isRTL ? currentPlan.name : currentPlan.nameEn}
                </span>
              </div>
              
              <div className="flex justify-between">
                <span>{isRTL ? 'دورة الفوترة:' : 'Billing Cycle:'}</span>
                <span>
                  {billingCycle === 'monthly' 
                    ? (isRTL ? 'شهري' : 'Monthly')
                    : (isRTL ? 'سنوي' : 'Yearly')
                  }
                </span>
              </div>

              <div className="border-t pt-4">
                <div className="flex justify-between">
                  <span>{isRTL ? 'المبلغ الفرعي:' : 'Subtotal:'}</span>
                  <span>{formatPrice(currentPlan.price)}</span>
                </div>
                
                {promoApplied && (
                  <div className="flex justify-between text-green-600">
                    <span>{isRTL ? 'خصم الكوبون:' : 'Promo Discount:'}</span>
                    <span>-{formatPrice(currentPlan.price * promoDiscount / 100)}</span>
                  </div>
                )}
                
                <div className="flex justify-between">
                  <span>{isRTL ? 'ضريبة القيمة المضافة (15%):' : 'VAT (15%):'}</span>
                  <span>{formatPrice(calculateVAT())}</span>
                </div>
                
                <div className="flex justify-between font-bold text-lg border-t pt-2 mt-2">
                  <span>{isRTL ? 'المجموع:' : 'Total:'}</span>
                  <span>{formatPrice(calculateTotal())}</span>
                </div>
              </div>

              {/* Promo Code */}
              {!promoApplied && currentStep !== 'success' && (
                <div className="border-t pt-4">
                  <div className="flex gap-2">
                    <Input
                      value={promoCode}
                      onChange={(e) => setPromoCode(e.target.value.toUpperCase())}
                      placeholder={isRTL ? 'كود الخصم' : 'Promo Code'}
                      className="flex-1"
                    />
                    <Button 
                      variant="outline" 
                      onClick={handleApplyPromo}
                      disabled={!promoCode}
                    >
                      {isRTL ? 'تطبيق' : 'Apply'}
                    </Button>
                  </div>
                </div>
              )}

              {promoApplied && (
                <div className="flex items-center gap-2 text-green-600 text-sm">
                  <Check className="h-4 w-4" />
                  <span>{isRTL ? 'تم تطبيق كود الخصم' : 'Promo code applied'}</span>
                </div>
              )}

              {promoError && (
                <p className="text-sm text-destructive mt-2">
                  {promoError}
                </p>
              )}
            </CardContent>
          </Card>

          {/* Security Info */}
          <Card>
            <CardContent className="p-4">
              <div className="flex items-start gap-3">
                <Shield className="h-5 w-5 text-green-600 mt-0.5" />
                <div>
                  <h4 className="font-medium text-sm mb-1">
                    {isRTL ? 'دفع آمن' : 'Secure Payment'}
                  </h4>
                  <p className="text-xs text-muted-foreground">
                    {isRTL 
                      ? 'جميع المعاملات محمية بتشفير SSL 256-bit'
                      : 'All transactions are protected with 256-bit SSL encryption'
                    }
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Money Back Guarantee */}
          <Card>
            <CardContent className="p-4">
              <div className="flex items-start gap-3">
                <RefreshCw className="h-5 w-5 text-blue-600 mt-0.5" />
                <div>
                  <h4 className="font-medium text-sm mb-1">
                    {isRTL ? 'ضمان استرداد الأموال' : 'Money Back Guarantee'}
                  </h4>
                  <p className="text-xs text-muted-foreground">
                    {isRTL 
                      ? 'ضمان استرداد كامل خلال 30 يوم'
                      : '30-day full refund guarantee'
                    }
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
};

export default CheckoutPage;