import React, { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { Tree, Person } from '@/types';
import { treeService } from '@/services/treeService';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Textarea } from '@/components/ui/Textarea';
import { Card } from '@/components/ui/Card';
import { useMobile } from '@/hooks/useMobile'; // Add mobile hook import

interface PersonCreateFormProps {
  trees?: Tree[];
  onCancel?: () => void;
  onSuccess?: (personId: string) => void;
}

interface FormData {
  treeId: string;
  relatedPersonId: string;
  relationship: 'father' | 'mother' | 'spouse' | 'child' | 'sibling';
  fullName: string;
  gender: 'male' | 'female' | 'unknown';
  birthDate: string;
  birthPlace: string;
  occupation: string;
  isDeceased: boolean;
  deathDate: string;
}

// Define a specific type for persons in the dropdown to handle potential API response differences
interface DropdownPerson {
  id: string;
  firstName?: string;
  lastName?: string;
  fullName?: string;
  displayName?: string;
  fullArabicName?: string;
  arabicName?: {
    firstName?: string;
    lastName?: string;
  };
}

const PersonCreateForm: React.FC<PersonCreateFormProps> = ({ 
  trees = [], 
  onCancel, 
  onSuccess 
}) => {
  const [persons, setPersons] = useState<DropdownPerson[]>([]);
  const [loading, setLoading] = useState(false);
  const [personsLoading, setPersonsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const { isMobile } = useMobile(); // Add mobile detection
  
  const { register, handleSubmit, watch, setValue, formState: { errors } } = useForm<FormData>({
    defaultValues: {
      treeId: '',
      relatedPersonId: '',
      relationship: 'child',
      fullName: '',
      gender: 'unknown',
      birthDate: '',
      birthPlace: '',
      occupation: '',
      isDeceased: false,
      deathDate: ''
    }
  });
  
  const selectedTreeId = watch('treeId');
  const isDeceased = watch('isDeceased');
  
  // Load persons when a tree is selected
  useEffect(() => {
    const loadPersons = async () => {
      if (!selectedTreeId) {
        setPersons([]);
        return;
      }
      
      try {
        setPersonsLoading(true);
        const personsInTreeResponse: any = await treeService.getPersonsInTree(Number(selectedTreeId));
        
        // Debug: Log the raw API response
        console.log('Raw persons API response:', personsInTreeResponse);
        
        // Handle case where response might be wrapped in a data property
        let personsData: any[] = [];
        if (Array.isArray(personsInTreeResponse)) {
          personsData = personsInTreeResponse;
        } else if (personsInTreeResponse && typeof personsInTreeResponse === 'object') {
          // Check if it has a data property that is an array
          const responseObj = personsInTreeResponse as any;
          if (responseObj.data && Array.isArray(responseObj.data)) {
            personsData = responseObj.data;
          }
        }
        
        // Debug: Log the processed persons data
        console.log('Processed persons data:', personsData);
        
        // Properly map the persons to DropdownPerson type
        const dropdownPersons: DropdownPerson[] = personsData.map((person: any) => {
          // Handle different possible API response formats
          const id = person.id?.toString() || 
                    person.ID?.toString() || 
                    person.Id?.toString() || 
                    person.personId?.toString() || 
                    '';
          
          // Extract name fields with more flexibility
          const firstName = person.firstName || person.FirstName || person.firstname || person.firstNameEn || person.firstName_en || '';
          const lastName = person.lastName || person.LastName || person.lastname || person.lastNameEn || person.lastName_en || '';
          const fullName = person.fullName || person.FullName || person.fullname || person.name || '';
          const displayName = person.displayName || person.DisplayName || person.displayname || '';
          const fullArabicName = person.fullArabicName || person.FullArabicName || person.fullarabicname || '';
          const arabicName = person.arabicName || person.ArabicName || person.arabicname || null;
          
          const dropdownPerson: DropdownPerson = {
            id,
            firstName: firstName || undefined,
            lastName: lastName || undefined,
            fullName: fullName || undefined,
            displayName: displayName || undefined,
            fullArabicName: fullArabicName || undefined,
            arabicName: arabicName || undefined
          };
          
          // Debug: Log each person mapping
          console.log('Mapped person:', dropdownPerson);
          
          return dropdownPerson;
        });
        
        setPersons(dropdownPersons);
      } catch (err) {
        console.error('Error loading persons:', err);
        setError('Failed to load persons in selected tree');
      } finally {
        setPersonsLoading(false);
      }
    };
    
    loadPersons();
  }, [selectedTreeId]);
  
  const onSubmit = async (data: FormData) => {
    try {
      setLoading(true);
      setError(null);
      
      // Add person to tree
      const newPerson = await treeService.addPersonToTree(
        data.fullName,
        data.birthDate,
        data.birthPlace,
        data.occupation,
        data.gender,
        data.deathDate,
        data.isDeceased,
        Number(data.treeId)
      );
      
      // If a relationship is specified, add it
      if (data.relatedPersonId && data.relationship) {
        try {
          await treeService.addRelationship(
            Number(data.relatedPersonId),
            Number(newPerson.id),
            data.relationship
          );
        } catch (relationshipError) {
          // Don't fail the whole operation if relationship creation fails
        }
      }
      
      onSuccess?.(newPerson.id);
    } catch (err: any) {
      setError(err.message || 'Failed to create person');
    } finally {
      setLoading(false);
    }
  };
  
  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
      <div className={`grid grid-cols-1 ${isMobile ? 'gap-4' : 'md:grid-cols-2 gap-6'}`}>
        {/* Tree Selection */}
        <div className={isMobile ? '' : 'md:col-span-2'}>
          <label className="block text-sm font-medium text-foreground mb-2">
            {isMobile ? 'Select Tree' : 'Select Tree'}
          </label>
          <select
            {...register('treeId', { required: 'Tree is required' })}
            className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
            disabled={loading}
          >
            <option value="">Select a tree</option>
            {trees.map(tree => (
              <option key={tree.id} value={tree.id}>
                {tree.name}
              </option>
            ))}
          </select>
          {errors.treeId && (
            <p className="mt-1 text-sm text-red-500">{errors.treeId.message}</p>
          )}
        </div>
        
        {/* Person Selection */}
        <div className={isMobile ? '' : 'md:col-span-2'}>
          <label className="block text-sm font-medium text-foreground mb-2">
            {isMobile ? 'Related Person' : 'Related Person (Optional)'}
          </label>
          <select
            {...register('relatedPersonId')}
            className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
            disabled={loading || personsLoading || !selectedTreeId}
          >
            <option value="">Select a person</option>
            {persons.map((person: any) => {
              // Create a safe display name that handles undefined values
              let displayName = `Person ${person.id || 'Unknown'}`;
              
              // Try to get the best name representation with more flexibility
              const firstName = person.firstName || person.FirstName || person.firstname || '';
              const lastName = person.lastName || person.LastName || person.lastname || '';
              const fullName = person.fullName || person.FullName || person.fullname || person.name || '';
              const displayNameField = person.displayName || person.DisplayName || person.displayname || '';
              const fullArabicName = person.fullArabicName || person.FullArabicName || person.fullarabicname || '';
              const arabicName = person.arabicName || person.ArabicName || person.arabicname || null;
              
              // Debug: Log the extracted fields for each person
              console.log('Person field extraction:', { firstName, lastName, fullName, displayNameField, fullArabicName, arabicName, id: person.id });
              
              // Priority order for display name:
              // 1. fullName
              // 2. displayName
              // 3. firstName + lastName
              // 4. fullArabicName
              // 5. arabicName parts
              // 6. Fallback to "Person {id}"
              
              if (fullName && typeof fullName === 'string' && fullName.trim() !== '') {
                displayName = fullName;
              } else if (displayNameField && typeof displayNameField === 'string' && displayNameField.trim() !== '') {
                displayName = displayNameField;
              } else if ((firstName && typeof firstName === 'string' && firstName.trim() !== '') || 
                         (lastName && typeof lastName === 'string' && lastName.trim() !== '')) {
                const fName = firstName || '';
                const lName = lastName || '';
                displayName = `${fName} ${lName}`.trim();
              } else if (fullArabicName && typeof fullArabicName === 'string' && fullArabicName.trim() !== '') {
                displayName = fullArabicName;
              } else if (arabicName && typeof arabicName === 'object') {
                const arabicFirstName = arabicName.firstName || arabicName.FirstName || arabicName.firstname || '';
                const arabicLastName = arabicName.lastName || arabicName.LastName || arabicName.lastname || '';
                const arabicNameStr = `${arabicFirstName || ''} ${arabicLastName || ''}`.trim();
                if (arabicNameStr) {
                  displayName = arabicNameStr;
                }
              }
              
              return (
                <option key={person.id} value={person.id}>
                  {displayName}
                </option>
              );
            })}
          </select>
          {personsLoading && (
            <p className="mt-1 text-sm text-muted-foreground">Loading persons...</p>
          )}
        </div>
        
        {/* Relationship Selection */}
        <div className={isMobile ? '' : 'md:col-span-2'}>
          <label className="block text-sm font-medium text-foreground mb-2">
            {isMobile ? 'Relationship' : 'Relationship (Optional)'}
          </label>
          <select
            {...register('relationship')}
            className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
            disabled={loading}
          >
            <option value="father">Father</option>
            <option value="mother">Mother</option>
            <option value="spouse">Spouse</option>
            <option value="child">Child</option>
            <option value="sibling">Sibling</option>
          </select>
        </div>
        
        {/* Full Name */}
        <div className={isMobile ? '' : 'md:col-span-2'}>
          <label className="block text-sm font-medium text-foreground mb-2">
            Full Name *
          </label>
          <Input
            {...register('fullName', { required: 'Full name is required' })}
            placeholder="Enter full name"
            disabled={loading}
          />
          {errors.fullName && (
            <p className="mt-1 text-sm text-red-500">{errors.fullName.message}</p>
          )}
        </div>
        
        {/* Gender */}
        <div>
          <label className="block text-sm font-medium text-foreground mb-2">
            Gender
          </label>
          <select
            {...register('gender')}
            className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
            disabled={loading}
          >
            <option value="unknown">Unknown</option>
            <option value="male">Male</option>
            <option value="female">Female</option>
          </select>
        </div>
        
        {/* Birth Date */}
        <div>
          <label className="block text-sm font-medium text-foreground mb-2">
            Birth Date
          </label>
          <Input
            type="date"
            {...register('birthDate')}
            disabled={loading}
          />
        </div>
        
        {/* Birth Place */}
        <div className={isMobile ? '' : 'md:col-span-2'}>
          <label className="block text-sm font-medium text-foreground mb-2">
            Birth Place
          </label>
          <Input
            {...register('birthPlace')}
            placeholder="Enter birth place"
            disabled={loading}
          />
        </div>
        
        {/* Occupation */}
        <div className={isMobile ? '' : 'md:col-span-2'}>
          <label className="block text-sm font-medium text-foreground mb-2">
            Occupation
          </label>
          <Input
            {...register('occupation')}
            placeholder="Enter occupation"
            disabled={loading}
          />
        </div>
        
        {/* Is Deceased */}
        <div className={`flex items-center ${isMobile ? '' : 'md:col-span-2'}`}>
          <input
            type="checkbox"
            {...register('isDeceased')}
            id="isDeceased"
            className="h-4 w-4 rounded border-input text-primary focus:ring-primary"
            disabled={loading}
          />
          <label htmlFor="isDeceased" className="ml-2 block text-sm text-foreground">
            Is Deceased
          </label>
        </div>
        
        {/* Death Date */}
        {isDeceased && (
          <div>
            <label className="block text-sm font-medium text-foreground mb-2">
              Death Date
            </label>
            <Input
              type="date"
              {...register('deathDate')}
              disabled={loading}
            />
          </div>
        )}
      </div>
      
      {/* Error Message */}
      {error && (
        <div className="rounded-md bg-red-50 p-4">
          <div className="flex">
            <div className="flex-shrink-0">
              <svg className="h-5 w-5 text-red-400" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
              </svg>
            </div>
            <div className="ml-3">
              <h3 className="text-sm font-medium text-red-800">Error</h3>
              <div className="mt-2 text-sm text-red-700">
                <p>{error}</p>
              </div>
            </div>
          </div>
        </div>
      )}
      
      {/* Form Actions */}
      <div className={`flex ${isMobile ? 'flex-col gap-2' : 'justify-end space-x-3'}`}>
        <Button
          type="button"
          variant="outline"
          onClick={onCancel}
          disabled={loading}
          className={isMobile ? 'w-full' : ''}
        >
          Cancel
        </Button>
        <Button
          type="submit"
          loading={loading}
          className={isMobile ? 'w-full' : ''}
        >
          Create Person
        </Button>
      </div>
    </form>
  );
};

export default PersonCreateForm;