import React, { useState } from 'react';
import { useUIStore } from '@/store/uiStore';
import { treeService } from '@/services/treeService';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Textarea } from '@/components/ui/Textarea';
import { Loader2 } from 'lucide-react';
import Modal from '@/components/ui/Modal';
import { useMobile } from '@/hooks/useMobile'; // Add mobile hook import

interface TreeFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (tree: any) => void;
  initialData?: {
    id?: string;
    name?: string;
    description?: string;
    descriptionEn?: string;
    isPublic?: boolean;
  };
  mode: 'create' | 'edit';
}

const TreeFormModal: React.FC<TreeFormModalProps> = ({ 
  isOpen, 
  onClose, 
  onSubmit,
  initialData,
  mode
}) => {
  const { language } = useUIStore();
  const { isMobile } = useMobile(); // Add mobile detection
  const isRTL = language === 'ar';
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  
  const [formData, setFormData] = useState({
    name: initialData?.name || '',
    description: initialData?.description || '',
    descriptionEn: initialData?.descriptionEn || '',
    isPublic: initialData?.isPublic !== undefined ? initialData.isPublic : true
  });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    
    try {
      // Validate required fields
      if (!formData.name.trim()) {
        throw new Error(isRTL ? 'اسم الشجرة مطلوب' : 'Tree name is required');
      }
      
      let result;
      if (mode === 'create') {
        // Create new tree
        result = await treeService.createTree(
          formData.name,
          !formData.isPublic, // Convert to isPrivate for API
          isRTL ? formData.description : formData.descriptionEn
        );
      } else {
        // Edit existing tree
        if (!initialData?.id) {
          throw new Error(isRTL ? 'معرف الشجرة مفقود' : 'Tree ID is missing');
        }
        
        result = await treeService.updateTree(
          parseInt(initialData.id),
          formData.name,
          !formData.isPublic, // Convert to isPrivate for API
          isRTL ? formData.description : formData.descriptionEn
        );
      }
      
      onSubmit(result);
      onClose();
    } catch (err: any) {
      // Removed console.error for error saving tree
      let errorMessage = isRTL ? 'فشل في حفظ الشجرة' : 'Failed to save tree';
      
      // Check for specific error conditions
      if (err.response) {
        // Handle 400 status code specifically for duplicate names
        if (err.response.status === 400) {
          // Check if it's a duplicate name error based on common patterns
          if (err.response.data?.message) {
            const message = err.response.data.message.toLowerCase();
            if (message.includes('duplicate') || 
                message.includes('already exists') ||
                message.includes('in use') ||
                message.includes('unique')) {
              errorMessage = isRTL 
                ? 'اسم الشجرة مستخدم بالفعل. يرجى اختيار اسم مختلف.' 
                : 'Tree name is already in use. Please choose a different name.';
            } else {
              errorMessage += `: ${err.response.data.message}`;
            }
          } else {
            // Generic 400 error message
            errorMessage = isRTL 
                ? 'اسم الشجرة مستخدم بالفعل. يرجى اختيار اسم مختلف.' 
                : 'Tree name is already in use. Please choose a different name.';
          }
        } else if (err.response.data?.message) {
          errorMessage += `: ${err.response.data.message}`;
        }
      } else if (err.message) {
        errorMessage += `: ${err.message}`;
      }
      setError(errorMessage);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={mode === 'create' 
        ? (isMobile ? (isRTL ? 'شجرة جديدة' : 'New Tree') : (isRTL ? 'إنشاء شجرة جديدة' : 'Create New Tree'))
        : (isMobile ? (isRTL ? 'تعديل الشجرة' : 'Edit Tree') : (isRTL ? 'تعديل الشجرة' : 'Edit Tree'))}
      size={isMobile ? "xl" : "md"}
    >
      <form onSubmit={handleSubmit} className="space-y-4">
        {error && (
          <div className="bg-destructive/10 border border-destructive/20 rounded-lg p-3">
            <p className="text-destructive text-sm">{error}</p>
          </div>
        )}
        
        <div className={`grid grid-cols-1 ${isMobile ? 'gap-3' : 'md:grid-cols-2 gap-4'}`}>
          <div className="space-y-2">
            <label className="text-sm font-medium">
              {isMobile ? (isRTL ? 'الاسم' : 'Name') : (isRTL ? 'اسم الشجرة *' : 'Tree Name *')}
            </label>
            <Input
              value={formData.name}
              onChange={(e) => setFormData(prev => ({ ...prev, name: e.target.value }))}
              placeholder={isMobile ? (isRTL ? 'اسم الشجرة' : 'Tree Name') : (isRTL ? 'اسم الشجرة' : 'Tree Name')}
              required
              disabled={isLoading}
              className={isMobile ? 'text-sm py-2' : ''}
            />
          </div>
          

        </div>
        
        <div className="space-y-2">
          <label className="text-sm font-medium">
            {isMobile ? (isRTL ? 'وصف' : 'Description') : (isRTL ? 'وصف الشجرة' : 'Tree Description')}
          </label>
          <Textarea
            value={isRTL ? formData.description : formData.descriptionEn}
            onChange={(e) => setFormData(prev => ({ 
              ...prev, 
              [isRTL ? 'description' : 'descriptionEn']: e.target.value 
            }))}
            placeholder={isMobile ? (isRTL ? 'وصف الشجرة' : 'Tree Description') : (isRTL ? 'وصف الشجرة' : 'Tree Description')}
            rows={isMobile ? 3 : 3}
            disabled={isLoading}
            className={isMobile ? 'text-sm py-2' : ''}
          />
        </div>
        
        <div className={`flex items-center justify-between p-3 border rounded-lg ${isMobile ? 'p-2' : ''}`}>
          <div>
            <p className={`font-medium ${isMobile ? 'text-sm' : ''}`}>
              {isMobile ? (isRTL ? 'شجرة عامة' : 'Public Tree') : (isRTL ? 'شجرة عامة' : 'Public Tree')}
            </p>
            <p className={`text-sm text-muted-foreground ${isMobile ? 'text-xs' : ''}`}>
              {isMobile ? (isRTL ? 'يمكن للجميع رؤية الشجرة' : 'Everyone can view the tree') : (isRTL ? 'يمكن للجميع رؤية الشجرة' : 'Everyone can view the tree')}
            </p>
          </div>
          <Button
            variant={formData.isPublic ? "default" : "outline"}
            size={isMobile ? "sm" : "default"}
            onClick={() => setFormData(prev => ({ ...prev, isPublic: !prev.isPublic }))}
            disabled={isLoading}
            type="button"
          >
            {formData.isPublic ? (isRTL ? 'عامة' : 'Public') : (isRTL ? 'خاصة' : 'Private')}
          </Button>
        </div>
        
        <div className={`flex ${isMobile ? 'flex-col gap-2' : 'gap-3 pt-4'}`}>
          <Button 
            type="submit" 
            className={`flex items-center gap-2 ${isMobile ? 'w-full' : ''}`}
            disabled={isLoading}
            size={isMobile ? "sm" : "default"}
          >
            {isLoading ? (
              <Loader2 className={`animate-spin ${isMobile ? 'h-3 w-3' : 'h-4 w-4'}`} />
            ) : null}
            {mode === 'create' 
              ? (isMobile ? (isRTL ? 'إنشاء' : 'Create') : (isRTL ? 'إنشاء الشجرة' : 'Create Tree'))
              : (isMobile ? (isRTL ? 'حفظ' : 'Save') : (isRTL ? 'حفظ التغييرات' : 'Save Changes'))}
          </Button>
          <Button 
            variant="outline" 
            onClick={onClose}
            disabled={isLoading}
            type="button"
            className={isMobile ? 'w-full' : ''}
            size={isMobile ? "sm" : "default"}
          >
            {isMobile ? (isRTL ? 'إلغاء' : 'Cancel') : (isRTL ? 'إلغاء' : 'Cancel')}
          </Button>
        </div>
      </form>
    </Modal>
  );
};

export default TreeFormModal;