import React from 'react';
import { useUIStore } from '@/store/uiStore';
import Toast from './Toast';

const ToastContainer: React.FC = () => {
  const { notifications, removeNotification } = useUIStore();
  
  // Only show the last 3 notifications to prevent cluttering
  const visibleNotifications = notifications.slice(-3);

  return (
    <div 
      className="fixed top-4 left-1/2 transform -translate-x-1/2 z-50 space-y-2 w-full px-4 flex flex-col items-center"
      style={{ direction: 'ltr' }} // Toasts should always appear in the same position regardless of RTL
    >
      {visibleNotifications.map((notification) => (
        <Toast
          key={notification.id}
          notification={notification}
          onClose={removeNotification}
        />
      ))}
    </div>
  );
};

export default ToastContainer;