import React, { useState, useEffect, useRef } from 'react';
import { useParams } from 'react-router-dom';
import { useUIStore } from '@/store/uiStore';
import { treeService } from '@/services/treeService';
import FamilyTreeVisualization from '@/components/trees/FamilyTreeVisualization';
import { Card } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Loader2, TreePine, AlertCircle, Minimize } from 'lucide-react';
import { useMobile } from '@/hooks/useMobile';
import { decryptString } from '@/utils/encryption';

interface TreePerson {
  id: string;
  firstName: string;
  lastName: string;
  gender: 'male' | 'female';
  birthDate?: string;
  birthPlace?: string;
  isAlive: boolean;
  parentIds?: string[];
  spouseIds?: string[];
  childrenIds?: string[];
  photo?: string;
  generation: number;
  position: { x: number; y: number };
}

interface FamilyTree {
  id: string;
  name: string;
  nameEn: string;
  description: string;
  descriptionEn: string;
  rootPersonId: string;
  persons: TreePerson[];
  createdAt: string;
  updatedAt: string;
}

const SharedTreePage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const { language } = useUIStore();
  const [tree, setTree] = useState<FamilyTree | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showStartScreen, setShowStartScreen] = useState(true);
  const [showTree, setShowTree] = useState(false);
  const treeContainerRef = useRef<HTMLDivElement>(null);
  const isRTL = language === 'ar';
  const { isMobile } = useMobile();

  // Function to enter fullscreen on user interaction
  const enterFullscreen = async () => {
    try {
      if (document.documentElement.requestFullscreen) {
        await document.documentElement.requestFullscreen();
      } else if ((document.documentElement as any).webkitRequestFullscreen) {
        await (document.documentElement as any).webkitRequestFullscreen();
      } else if ((document.documentElement as any).msRequestFullscreen) {
        await (document.documentElement as any).msRequestFullscreen();
      }
      setIsFullscreen(true);
      setShowStartScreen(false);
      // Add a small delay to ensure proper rendering
      setTimeout(() => {
        setShowTree(true);
      }, 100);
    } catch (err) {
      // Could not enter fullscreen: err
      // Continue without fullscreen if it fails
      setShowStartScreen(false);
      // Add a small delay to ensure proper rendering
      setTimeout(() => {
        setShowTree(true);
      }, 100);
    }
  };

  // Handle fullscreen change events
  useEffect(() => {
    const handleFullscreenChange = () => {
      const fullscreenElement =
        document.fullscreenElement ||
        (document as any).webkitFullscreenElement ||
        (document as any).msFullscreenElement;

      setIsFullscreen(!!fullscreenElement);
      if (!!fullscreenElement) {
        // Add a small delay to ensure proper rendering
        setTimeout(() => {
          setShowTree(true);
        }, 100);
      }
    };

    document.addEventListener('fullscreenchange', handleFullscreenChange);
    document.addEventListener('webkitfullscreenchange', handleFullscreenChange);
    document.addEventListener('msfullscreenchange', handleFullscreenChange);

    return () => {
      document.removeEventListener('fullscreenchange', handleFullscreenChange);
      document.removeEventListener('webkitfullscreenchange', handleFullscreenChange);
      document.removeEventListener('msfullscreenchange', handleFullscreenChange);
    };
  }, []);

  // Fetch tree data
  useEffect(() => {
    const fetchTreeData = async () => {
      if (!id) {
        setError(isRTL ? 'معرف الشجرة مفقود' : 'Tree ID is missing');
        setIsLoading(false);
        return;
      }

      // Decrypt the tree ID if it's encrypted
      let decryptedId = id;
      try {
        decryptedId = await decryptString(id);
      } catch (decryptError) {
        // If decryption fails, assume it's already a plain ID
        // Removed console.warn for decryption error
      }

      try {
        setIsLoading(true);
        setError(null);

        // Fetch persons in the tree
        const persons = await treeService.getPersonsInTree(Number(decryptedId));

        // Try to fetch tree metadata
        let treeData = null;
        try {
          const fetchedTree = await treeService.getTreeById(Number(decryptedId));
          if (fetchedTree && fetchedTree.data) {
            treeData = {
              id: fetchedTree.data.id.toString(),
              name: fetchedTree.data.name || (isRTL ? 'شجرة العائلة' : 'Family Tree'),
              nameEn: fetchedTree.data.name || 'Family Tree',
              description: fetchedTree.data.description || '',
              descriptionEn: fetchedTree.data.description || '',
              createdAt: fetchedTree.data.createdAt || new Date().toISOString(),
              updatedAt: fetchedTree.data.updatedAt || new Date().toISOString(),
            };
          }
        } catch (treeError) {
          // Could not fetch tree metadata: treeError
          // Continue with default tree data
        }

        // Get relationships
        let relationships: any[] = [];
        try {
          relationships = await treeService.getRelationships();
        } catch (relError) {
          // Could not fetch relationships: relError
        }

        // Process relationships to build parent-child maps
        const childToParentMap = new Map<string, string[]>();
        const parentToChildMap = new Map<string, string[]>();
        const spouseMap = new Map<string, string[]>(); // Add spouse map

        if (relationships && Array.isArray(relationships)) {
          relationships.forEach(rel => {
            // Extract person IDs
            const personId = rel.personId?.toString();
            const relatedPersonId = rel.relatedPersonId?.toString();
            
            // Validate that both persons exist in our tree
            const personExists = persons.some(p => p.id.toString() === personId);
            const relatedPersonExists = persons.some(p => p.id.toString() === relatedPersonId);
            
            if (!personExists || !relatedPersonExists) {
              // Skipping relationship - person exists: personExists, related person exists: relatedPersonExists
              return;
            }
            
            // Handle parent-child relationships based on relationship type
            // Parent/Child relationships
            if (['Father', 'father', 'Mother', 'mother', 'Parent', 'parent'].includes(rel.relationshipType)) {
              // personId is the child, relatedPersonId is the parent
              const childId = personId;
              const parentId = relatedPersonId;
              
              // Add to child -> parent map
              if (!childToParentMap.has(childId)) {
                childToParentMap.set(childId, []);
              }
              childToParentMap.get(childId)?.push(parentId);
              
              // Add to parent -> child map
              if (!parentToChildMap.has(parentId)) {
                parentToChildMap.set(parentId, []);
              }
              parentToChildMap.get(parentId)?.push(childId);
              
              // Comprehensive parent-child relationship: Parent parentId -> Child childId
            } 
            // Child/Son/Daughter relationships
            else if (['Child', 'child', 'Son', 'son', 'Daughter', 'daughter'].includes(rel.relationshipType)) {
              // personId is the parent, relatedPersonId is the child
              const parentId = personId;
              const childId = relatedPersonId;
              
              // Add to child -> parent map
              if (!childToParentMap.has(childId)) {
                childToParentMap.set(childId, []);
              }
              childToParentMap.get(childId)?.push(parentId);
              
              // Add to parent -> child map
              if (!parentToChildMap.has(parentId)) {
                parentToChildMap.set(parentId, []);
              }
              parentToChildMap.get(parentId)?.push(childId);
              
              // Comprehensive child-parent relationship: Parent parentId -> Child childId
            }
            // Spouse relationships
            else if (['Spouse', 'spouse', 'Husband', 'husband', 'Wife', 'wife'].includes(rel.relationshipType)) {
              // Both persons are spouses of each other - we'll handle this in visualization
              // Spouse relationship: personId <-> relatedPersonId
              
              // Add to spouse map (bidirectional)
              if (!spouseMap.has(personId)) {
                spouseMap.set(personId, []);
              }
              if (!spouseMap.get(personId)?.includes(relatedPersonId)) {
                spouseMap.get(personId)?.push(relatedPersonId);
              }
              
              if (!spouseMap.has(relatedPersonId)) {
                spouseMap.set(relatedPersonId, []);
              }
              if (!spouseMap.get(relatedPersonId)?.includes(personId)) {
                spouseMap.get(relatedPersonId)?.push(personId);
              }
            }
            // Handle any other relationship types that might indicate parent-child relationships
            else {
              // Try to infer relationship direction from context
              // If we can't determine the relationship type clearly, we'll try both directions
              const childId = personId;
              const parentId = relatedPersonId;
              
              // Add to child -> parent map
              if (!childToParentMap.has(childId)) {
                childToParentMap.set(childId, []);
              }
              childToParentMap.get(childId)?.push(parentId);
              
              // Add to parent -> child map
              if (!parentToChildMap.has(parentId)) {
                parentToChildMap.set(parentId, []);
              }
              parentToChildMap.get(parentId)?.push(childId);
              
              // Inferred parent-child relationship: Parent parentId -> Child childId
            }
          });
        }

        // Process relationships that might be embedded in person objects
        persons.forEach(person => {
          // Processing person: person.id, person.firstName, person.lastName
          // Person as any: person as any
          
          // Check for parent IDs in various possible fields
          const parentIdFields = ['parentId', 'parent_id', 'fatherId', 'father_id', 'motherId', 'mother_id'];
          
          parentIdFields.forEach(field => {
            if ((person as any)[field] && (person as any)[field] !== '0' && (person as any)[field] !== 0) {
              const parentId = (person as any)[field].toString();
              const childId = person.id.toString();
              
              // Only process if parent exists in this tree
              const parentExists = persons.some(p => p.id.toString() === parentId);
              if (parentExists) {
                // Add to child -> parent map
                if (!childToParentMap.has(childId)) {
                  childToParentMap.set(childId, []);
                }
                childToParentMap.get(childId)?.push(parentId);
                
                // Add to parent -> child map
                if (!parentToChildMap.has(parentId)) {
                  parentToChildMap.set(parentId, []);
                }
                parentToChildMap.get(parentId)?.push(childId);
                
                // Parent ID from field: Parent parentId -> Child childId
              }
            }
          });
          
          // Check for array of parent IDs
          if ((person as any).parentIds && Array.isArray((person as any).parentIds)) {
            // Found parentIds array: (person as any).parentIds
            (person as any).parentIds.forEach((parentId: any) => {
              if (parentId && parentId !== '0' && parentId !== 0) {
                const childId = person.id.toString();
                
                // Only process if parent exists in this tree
                const parentExists = persons.some(p => p.id.toString() === parentId.toString());
                if (parentExists) {
                  // Add to child -> parent map
                  if (!childToParentMap.has(childId)) {
                    childToParentMap.set(childId, []);
                  }
                  childToParentMap.get(childId)?.push(parentId.toString());
                  
                  // Add to parent -> child map
                  if (!parentToChildMap.has(parentId.toString())) {
                    parentToChildMap.set(parentId.toString(), []);
                  }
                  parentToChildMap.get(parentId.toString())?.push(childId);
                  
                  // Parent ID from parentIds array: Parent parentId -> Child childId
                }
              }
            });
          }
          
          // Check for spouse relationships in the person's relationships object
          if (person.relationships && person.relationships.spouses) {
            // Processing spouse relationships for person: person.id
            person.relationships.spouses.forEach((spouse: any) => {
              let spouseId: string | null = null;
              
              // Spouse can be either a Person object or a string ID
              if (typeof spouse === 'string') {
                spouseId = spouse;
              } else if (typeof spouse === 'object' && spouse?.person) {
                // Handle spouse.person as either a Person object or string ID
                if (typeof spouse.person === 'string') {
                  spouseId = spouse.person;
                } else if (typeof spouse.person === 'object' && (spouse.person as any).id) {
                  spouseId = (spouse.person as any).id.toString();
                }
              } else if (typeof spouse === 'object' && spouse?.id) {
                spouseId = (spouse as any).id.toString();
              }
              
              if (spouseId) {
                const personId = person.id.toString();
                const spouseExists = persons.some(p => p.id.toString() === spouseId);
                
                if (spouseExists && spouseId !== personId) {
                  // Check if this spouse relationship already exists to prevent duplicates
                  const existingSpouseIds = spouseMap.get(personId) || [];
                  if (!existingSpouseIds.includes(spouseId)) {
                    // Add to spouse map (bidirectional)
                    if (!spouseMap.has(personId)) {
                      spouseMap.set(personId, []);
                    }
                    spouseMap.get(personId)?.push(spouseId);
                    
                    if (!spouseMap.has(spouseId)) {
                      spouseMap.set(spouseId, []);
                    }
                    spouseMap.get(spouseId)?.push(personId);
                    
                    // Spouse relationship from relationships.spouses: personId <-> spouseId
                  }
                }
              }
            });
          }
          
          // Check for parent relationships in the person's relationships object
          if (person.relationships) {
            // Processing relationships for person: person.id
            // Check for father
            if (person.relationships.father) {
              let fatherId: string | null = null;
              
              // Father can be either a Person object or a string ID
              if (typeof person.relationships.father === 'string') {
                fatherId = person.relationships.father;
              } else if (typeof person.relationships.father === 'object' && (person.relationships.father as any).id) {
                fatherId = (person.relationships.father as any).id.toString();
              }
              
              if (fatherId) {
                const childId = person.id.toString();
                const parentExists = persons.some(p => p.id.toString() === fatherId);
                
                if (parentExists) {
                  // Add to child -> parent map
                  if (!childToParentMap.has(childId)) {
                    childToParentMap.set(childId, []);
                  }
                  childToParentMap.get(childId)?.push(fatherId);
                  
                  // Add to parent -> child map
                  if (!parentToChildMap.has(fatherId)) {
                    parentToChildMap.set(fatherId, []);
                  }
                  parentToChildMap.get(fatherId)?.push(childId);
                  
                  // Father relationship: Parent fatherId -> Child childId
                }
              }
            }
            
            // Check for mother
            if (person.relationships.mother) {
              let motherId: string | null = null;
              
              // Mother can be either a Person object or a string ID
              if (typeof person.relationships.mother === 'string') {
                motherId = person.relationships.mother;
              } else if (typeof person.relationships.mother === 'object' && (person.relationships.mother as any).id) {
                motherId = (person.relationships.mother as any).id.toString();
              }
              
              if (motherId) {
                const childId = person.id.toString();
                const parentExists = persons.some(p => p.id.toString() === motherId);
                
                if (parentExists) {
                  // Add to child -> parent map
                  if (!childToParentMap.has(childId)) {
                    childToParentMap.set(childId, []);
                  }
                  childToParentMap.get(childId)?.push(motherId);
                  
                  // Add to parent -> child map
                  if (!parentToChildMap.has(motherId)) {
                    parentToChildMap.set(motherId, []);
                  }
                  parentToChildMap.get(motherId)?.push(childId);
                  
                  // Mother relationship: Parent motherId -> Child childId
                }
              }
            }
          }
        });
        
        // Ensure we also check for any person that might be a parent of others
        // This handles cases where a person might not have explicit relationships but is referenced as a parent
        persons.forEach(person => {
          const personId = person.id.toString();
          
          // Check if this person is referenced as a parent by any other person
          persons.forEach(otherPerson => {
            const otherPersonId = otherPerson.id.toString();
            
            // Skip self
            if (personId === otherPersonId) return;
            
            // Check if otherPerson has this person as a parent
            const otherPersonAny = otherPerson as any;
            const parentIds = otherPersonAny.parentIds || otherPersonAny.parents || otherPersonAny.parent_ids || [];
            
            // Check if this person is listed as a parent
            const isParent = parentIds.some((parentId: any) => {
              const parentIdStr = typeof parentId === 'object' && parentId.id ? parentId.id.toString() : parentId.toString();
              return parentIdStr === personId;
            });
            
            if (isParent) {
              // Ensure the parent-child relationship is properly mapped
              const childId = otherPersonId;
              const parentId = personId;
              
              // Add to child -> parent map
              if (!childToParentMap.has(childId)) {
                childToParentMap.set(childId, []);
              }
              if (!childToParentMap.get(childId)?.includes(parentId)) {
                childToParentMap.get(childId)?.push(parentId);
              }
              
              // Add to parent -> child map
              if (!parentToChildMap.has(parentId)) {
                parentToChildMap.set(parentId, []);
              }
              if (!parentToChildMap.get(parentId)?.includes(childId)) {
                parentToChildMap.get(parentId)?.push(childId);
              }
              
              // Verified parent-child relationship: Parent parentId -> Child childId
            }
          });
        });

        // Create tree object
        const fetchedTree: FamilyTree = {
          id: decryptedId,
          name: treeData?.name || (isRTL ? 'شجرة العائلة' : 'Family Tree'),
          nameEn: treeData?.nameEn || 'Family Tree',
          description: treeData?.description || '',
          descriptionEn: treeData?.descriptionEn || '',
          rootPersonId: (() => {
            // First, try to find a person who is explicitly marked as root
            for (const person of persons) {
              if ((person as any).isRoot) {
                return person.id.toString();
              }
            }
            
            // Find a person who is not a child (has no parents) to use as root
            for (const person of persons) {
              const personId = person.id.toString();
              if (!childToParentMap.has(personId)) {
                return personId;
              }
            }
            
            // Fallback to first person if no root found
            return persons.length > 0 ? persons[0].id.toString() : '1';
          })(),
          persons: persons.map((person: any) => {
            let firstName = '';
            let lastName = '';
            if (person.name) {
              const nameParts = person.name.split(' ');
              firstName = nameParts[0] || '';
              lastName = nameParts.slice(1).join(' ') || '';
            }

            const parentIds = childToParentMap.get(person.id.toString()) || [];
            const spouseIds = spouseMap.get(person.id.toString()) || []; // Use spouseMap instead of person.spouseIds
            const childrenIds = parentToChildMap.get(person.id.toString()) || [];

            // Ensure gender is strictly 'male' or 'female'
            let gender: 'male' | 'female' = 'male';
            if (person.gender === 'female') {
              gender = 'female';
            }

            return {
              id: person.id.toString(),
              firstName: person.firstName || firstName || person.name || '',
              lastName: person.lastName || lastName || '',
              gender: gender,
              birthDate: person.birth?.date || person.birthDate || '',
              birthPlace: person.birth?.place?.city || person.birthPlace || '',
              isAlive: !person.isDeceased,
              photo: person.primaryPhoto?.url || person.photo || person.photoUrl || '/api/placeholder/100/100',
              generation: person.position?.generation || 0,
              position: {
                x: person.position?.x || 0,
                y: person.position?.y || 0
              },
              parentIds: parentIds.map((id: string) => id.toString()),
              spouseIds: spouseIds.map((id: string) => id.toString()), // Include spouse IDs
              childrenIds: childrenIds.map((id: string) => id.toString())
            };
          }),
          createdAt: treeData?.createdAt || new Date().toISOString(),
          updatedAt: treeData?.updatedAt || new Date().toISOString(),
        };

        setTree(fetchedTree);
      } catch (err: any) {
        // Error fetching shared tree: err
        setError(
          err.response?.status === 404
            ? (isRTL ? 'الشجرة غير موجودة' : 'Tree not found')
            : (isRTL ? 'فشل في تحميل الشجرة' : 'Failed to load tree')
        );
      } finally {
        setIsLoading(false);
      }
    };

    fetchTreeData();
  }, [id, isRTL]);

  const exitFullscreen = () => {
    if (document.exitFullscreen) {
      document.exitFullscreen();
    } else if ((document as any).webkitExitFullscreen) {
      (document as any).webkitExitFullscreen();
    } else if ((document as any).msExitFullscreen) {
      (document as any).msExitFullscreen();
    }
  };

  if (isLoading) {
    return (
      <div className="fixed inset-0 bg-background flex items-center justify-center z-50">
        <div className="text-center">
          <Loader2 className={`text-muted-foreground mx-auto mb-4 animate-spin ${isMobile ? 'h-8 w-8' : 'h-12 w-12'}`} />
          <p className={`text-muted-foreground ${isMobile ? 'text-sm' : ''}`}>
            {isRTL ? 'جاري تحميل الشجرة...' : 'Loading tree...'}
          </p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="fixed inset-0 bg-background flex items-center justify-center z-50">
        <div className={`text-center p-4 ${isMobile ? 'p-2' : ''}`}>
          <AlertCircle className={`text-destructive mx-auto mb-4 ${isMobile ? 'h-8 w-8' : 'h-12 w-12'}`} />
          <h2 className={`font-semibold mb-2 ${isMobile ? 'text-lg' : 'text-xl'}`}>
            {isRTL ? 'خطأ' : 'Error'}
          </h2>
          <p className={`text-muted-foreground mb-4 ${isMobile ? 'text-sm' : ''}`}>
            {error}
          </p>
          <Button onClick={() => window.history.back()} size={isMobile ? "sm" : "default"}>
            {isRTL ? 'العودة' : 'Go Back'}
          </Button>
        </div>
      </div>
    );
  }

  if (!tree) {
    return (
      <div className="fixed inset-0 bg-background flex items-center justify-center z-50">
        <div className={`text-center p-4 ${isMobile ? 'p-2' : ''}`}>
          <TreePine className={`text-muted-foreground mx-auto mb-4 ${isMobile ? 'h-8 w-8' : 'h-12 w-12'}`} />
          <p className={`text-muted-foreground ${isMobile ? 'text-sm' : ''}`}>
            {isRTL ? 'لم يتم العثور على الشجرة' : 'Tree not found'}
          </p>
        </div>
      </div>
    );
  }

  // Show start screen if not in fullscreen yet
  if (showStartScreen) {
    return (
      <div className="fixed inset-0 bg-background flex items-center justify-center z-50">
        <div className={`text-center mx-auto ${isMobile ? 'p-4 max-w-sm' : 'p-6 max-w-md'}`}>
          <TreePine className={`text-primary mx-auto mb-6 ${isMobile ? 'h-12 w-12' : 'h-16 w-16'}`} />
          <h1 className={`font-bold mb-4 ${isMobile ? 'text-xl' : 'text-2xl'}`}>
            {isRTL ? 'عرض شجرة العائلة' : 'View Family Tree'}
          </h1>
          <p className={`text-muted-foreground mb-6 ${isMobile ? 'text-sm' : ''}`}>
            {isRTL
              ? 'انقر على الزر أدناه لبدء عرض الشجرة في وضع ملء الشاشة'
              : 'Click the button below to start viewing the family tree in fullscreen mode'
            }
          </p>
          <div className={`space-y-4 ${isMobile ? 'space-y-3' : ''}`}>
            <Button
              onClick={enterFullscreen}
              size={isMobile ? "default" : "lg"}
              className="w-full"
            >
              {isRTL ? 'ابدأ العرض' : 'Start Viewing'}
            </Button>
            <Button
              variant="outline"
              onClick={() => window.history.back()}
              size={isMobile ? "default" : "lg"}
              className="w-full"
            >
              {isRTL ? 'العودة' : 'Go Back'}
            </Button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div ref={treeContainerRef} className="fixed inset-0 bg-background z-50">
      {/* Header overlay */}
      <div className="absolute top-4 left-4 right-4 z-10 flex items-center justify-between">
        <div className={`bg-background/80 backdrop-blur-sm rounded-lg px-4 py-2 ${isMobile ? 'px-3 py-1.5' : ''}`}>
          <h1 className={`font-semibold ${isMobile ? 'text-base' : 'text-lg'}`}>
            {isRTL ? tree.name : tree.nameEn}
          </h1>
          <p className={`text-muted-foreground ${isMobile ? 'text-xs' : 'text-sm'}`}>
            {tree.persons.length} {isRTL ? (tree.persons.length === 1 ? 'عضو' : 'أعضاء') : (tree.persons.length === 1 ? 'member' : 'members')}
          </p>
        </div>

        <Button
          variant="outline"
          size={isMobile ? "sm" : "sm"}
          onClick={isFullscreen ? exitFullscreen : enterFullscreen}
          className={`bg-background/80 backdrop-blur-sm ${isMobile ? 'h-8 px-2 text-xs' : ''}`}
        >
          {isFullscreen ? (
            <>
              <Minimize className={`h-4 w-4 ${isMobile ? 'h-3 w-3 mr-1' : 'mr-2'}`} />
              <span className={isMobile ? 'hidden' : ''}>
                {isRTL ? 'الخروج من ملء الشاشة' : 'Exit Fullscreen'}
              </span>
            </>
          ) : (
            <>
              <TreePine className={`h-4 w-4 ${isMobile ? 'h-3 w-3 mr-1' : 'mr-2'}`} />
              <span className={isMobile ? 'hidden' : ''}>
                {isRTL ? 'ملء الشاشة' : 'Fullscreen'}
              </span>
            </>
          )}
        </Button>
      </div>

      {/* Tree visualization */}
      <div className="w-full h-full pt-20">
        <Card className="w-full h-full border-0 rounded-none">
          <div className="w-full h-full shared-tree-container">
            {showTree && (
              <FamilyTreeVisualization
                persons={tree.persons as any}
                rootPersonId={tree.rootPersonId}
                onSelectPerson={() => {}} // No selection handler for shared view
                onEditPerson={() => {}} // No editing for shared view
                onDeletePerson={() => {}} // No deleting for shared view
                onAddChild={() => {}} // No adding for shared view
                onAddSpouse={() => {}} // No adding for shared view
              />
            )}
          </div>
        </Card>
      </div>
    </div>
  );
};

export default SharedTreePage;