import React, { useState, useEffect } from 'react';
import { 
  useNavigate 
} from 'react-router-dom';
import { useUIStore } from '@/store/uiStore';
import { subscriptionService } from '@/services/subscriptionService';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';
import { Input } from '@/components/ui/Input';
import { 
  Crown, 
  Star, 
  Calendar, 
  CreditCard, 
  User, 
  Settings, 
  Bell, 
  Download, 
  Pause, 
  Play, 
  X, 
  Check, 
  Clock, 
  AlertTriangle, 
  ExternalLink,
  ChevronRight,
  History,
  Loader2,
  TrendingUp,
  TrendingDown,
  Receipt,
  RefreshCw,
  Database,
  Cloud,
  TreePine,
  Users,
  Edit,
  Info,
  FileText
} from 'lucide-react';
import { Subscription } from '@/types';

const SubscriptionManagePage: React.FC = () => {
  const navigate = useNavigate();
  const { language } = useUIStore();
  const [activeTab, setActiveTab] = useState<'overview' | 'billing' | 'usage' | 'invoices'>('overview');
  const [showCancelDialog, setShowCancelDialog] = useState(false);
  const [subscription, setSubscription] = useState<Subscription | null>(null);
  const [usage, setUsage] = useState<any>(null);
  const [invoices, setInvoices] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const isRTL = language === 'ar';

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [sub, usageData, invoiceData] = await Promise.all([
        subscriptionService.getCurrentSubscription(),
        subscriptionService.getUsage(),
        subscriptionService.getInvoices()
      ]);
      
      setSubscription(sub);
      setUsage(usageData);
      setInvoices(invoiceData);
    } catch (err) {
      setError('Failed to load subscription data');
      // Error fetching data: err
    } finally {
      setLoading(false);
    }
  };

  const formatPrice = (price: number, currency: string = 'USD') => {
    return `${currency} ${price.toFixed(2)}`;
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString(isRTL ? 'ar-SA' : 'en-US');
  };

  const getStatusBadge = (status: string) => {
    const statusConfig = {
      active: { 
        color: 'bg-green-100 text-green-800', 
        label: isRTL ? 'نشط' : 'Active',
        icon: Check
      },
      cancelled: { 
        color: 'bg-red-100 text-red-800', 
        label: isRTL ? 'ملغي' : 'Cancelled',
        icon: X
      },
      expired: { 
        color: 'bg-gray-100 text-gray-800', 
        label: isRTL ? 'منتهي' : 'Expired',
        icon: Clock
      },
      paused: { 
        color: 'bg-yellow-100 text-yellow-800', 
        label: isRTL ? 'متوقف' : 'Paused',
        icon: Pause
      }
    };

    const config = statusConfig[status as keyof typeof statusConfig] || statusConfig.active;
    return (
      <Badge className={config.color}>
        {React.createElement(config.icon, { className: "h-3 w-3 mr-1" })}
        {config.label}
      </Badge>
    );
  };

  const getUsagePercentage = (current: number, limit: number | 'unlimited') => {
    if (limit === 'unlimited') return 0;
    return Math.min((current / limit) * 100, 100);
  };

  const getUsageColor = (percentage: number) => {
    if (percentage >= 90) return 'bg-red-500';
    if (percentage >= 70) return 'bg-yellow-500';
    return 'bg-green-500';
  };

  const handleCancelSubscription = async () => {
    try {
      await subscriptionService.cancelSubscription();
      // Refresh data after cancellation
      fetchData();
      setShowCancelDialog(false);
    } catch (err) {
      // Error cancelling subscription: err
    }
  };

  const handlePauseSubscription = async () => {
    try {
      await subscriptionService.pauseSubscription();
      // Refresh data after pausing
      fetchData();
    } catch (err) {
      // Error pausing subscription: err
    }
  };

  const handleResumeSubscription = async () => {
    try {
      await subscriptionService.resumeSubscription();
      // Refresh data after resuming
      fetchData();
    } catch (err) {
      // Error resuming subscription: err
    }
  };

  const handleUpgradePlan = () => {
    navigate('/subscription/plans?upgrade=true');
  };

  const handleDowngradePlan = () => {
    navigate('/subscription/plans?downgrade=true');
  };

  const handleUpdatePayment = () => {
    navigate('/subscription/payment-methods');
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="space-y-6">
        <div className="text-center py-12">
          <div className="text-destructive mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
          <h3 className="text-lg font-semibold text-foreground mb-2">
            {isRTL ? 'خطأ في تحميل البيانات' : 'Error Loading Data'}
          </h3>
          <p className="text-muted-foreground mb-4">
            {error}
          </p>
          <Button onClick={fetchData}>
            {isRTL ? 'إعادة المحاولة' : 'Try Again'}
          </Button>
        </div>
      </div>
    );
  }

  // If no subscription, show a message
  if (!subscription) {
    return (
      <div className="space-y-6">
        <div className="text-center py-12">
          <Crown className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-foreground mb-2">
            {isRTL ? 'لا يوجد اشتراك نشط' : 'No Active Subscription'}
          </h3>
          <p className="text-muted-foreground mb-4">
            {isRTL 
              ? 'ليس لديك اشتراك نشط حالياً. اختر خطة لبدء الاستخدام.'
              : 'You don\'t have an active subscription. Choose a plan to get started.'
            }
          </p>
          <Button onClick={() => navigate('/subscription/plans')}>
            {isRTL ? 'اختر خطة' : 'Choose Plan'}
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">
            {isRTL ? 'إدارة الاشتراك' : 'Subscription Management'}
          </h1>
          <p className="text-sm text-muted-foreground">
            {isRTL ? 'إدارة خطة الاشتراك والفوترة' : 'Manage your subscription plan and billing'}
          </p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-1 border-b overflow-x-auto">
        {[
          { id: 'overview', label: isRTL ? 'نظرة عامة' : 'Overview', icon: Crown },
          { id: 'billing', label: isRTL ? 'الفوترة' : 'Billing', icon: CreditCard },
          { id: 'usage', label: isRTL ? 'الاستخدام' : 'Usage', icon: TrendingUp },
          { id: 'invoices', label: isRTL ? 'الفواتير' : 'Invoices', icon: Receipt }
        ].map(tab => (
          <Button
            key={tab.id}
            variant={activeTab === tab.id ? "default" : "ghost"}
            onClick={() => setActiveTab(tab.id as any)}
            className="flex items-center gap-2 whitespace-nowrap"
          >
            {React.createElement(tab.icon, { className: "h-4 w-4" })}
            {tab.label}
          </Button>
        ))}
      </div>

      {/* Overview Tab */}
      {activeTab === 'overview' && (
        <div className="space-y-6">
          {/* Current Plan */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Crown className="h-5 w-5" />
                {isRTL ? 'الخطة الحالية' : 'Current Plan'}
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-4">
                  <div className="w-16 h-16 bg-primary/10 rounded-full flex items-center justify-center">
                    <Star className="h-8 w-8 text-primary" />
                  </div>
                  <div>
                    <h3 className="text-2xl font-bold">
                      {isRTL ? 
                        (subscription.plan === 'basic' ? 'الأساسية' : 
                         subscription.plan === 'premium' ? 'المميزة' : 'العائلية') : 
                        subscription.plan}
                    </h3>
                    <p className="text-muted-foreground">
                      {subscription.billing.interval === 'month' 
                        ? (isRTL ? 'اشتراك شهري' : 'Monthly subscription')
                        : (isRTL ? 'اشتراك سنوي' : 'Yearly subscription')
                      }
                    </p>
                    <div className="flex items-center gap-2 mt-1">
                      {getStatusBadge(subscription.status)}
                      {subscription.cancelAtPeriodEnd && (
                        <Badge className="bg-blue-100 text-blue-800">
                          <RefreshCw className="h-3 w-3 mr-1" />
                          {isRTL ? 'تجديد تلقائي' : 'Auto Renew'}
                        </Badge>
                      )}
                    </div>
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-3xl font-bold">
                    {formatPrice(subscription.billing.amount, subscription.billing.currency)}
                  </div>
                  <p className="text-sm text-muted-foreground">
                    {subscription.billing.interval === 'month' 
                      ? (isRTL ? 'شهرياً' : 'per month')
                      : (isRTL ? 'سنوياً' : 'per year')
                    }
                  </p>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
                <div className="p-4 border rounded-lg">
                  <div className="flex items-center gap-2 mb-2">
                    <Calendar className="h-4 w-4 text-primary" />
                    <span className="font-medium text-sm">
                      {isRTL ? 'تاريخ البداية' : 'Start Date'}
                    </span>
                  </div>
                  <p className="text-lg font-semibold">{formatDate(subscription.currentPeriodStart)}</p>
                </div>
                
                <div className="p-4 border rounded-lg">
                  <div className="flex items-center gap-2 mb-2">
                    <Clock className="h-4 w-4 text-primary" />
                    <span className="font-medium text-sm">
                      {isRTL ? 'تاريخ الانتهاء' : 'End Date'}
                    </span>
                  </div>
                  <p className="text-lg font-semibold">{formatDate(subscription.currentPeriodEnd)}</p>
                </div>
                
                <div className="p-4 border rounded-lg">
                  <div className="flex items-center gap-2 mb-2">
                    <RefreshCw className="h-4 w-4 text-primary" />
                    <span className="font-medium text-sm">
                      {isRTL ? 'الفوترة التالية' : 'Next Billing'}
                    </span>
                  </div>
                  <p className="text-lg font-semibold">{formatDate(subscription.currentPeriodEnd)}</p>
                </div>
              </div>

              <div className="flex flex-wrap gap-3">
                <Button onClick={handleUpgradePlan} className="flex items-center gap-2">
                  <TrendingUp className="h-4 w-4" />
                  {isRTL ? 'ترقية الخطة' : 'Upgrade Plan'}
                </Button>
                <Button variant="outline" onClick={handleDowngradePlan} className="flex items-center gap-2">
                  <TrendingDown className="h-4 w-4" />
                  {isRTL ? 'تخفيض الخطة' : 'Downgrade Plan'}
                </Button>
                {subscription.status === 'active' ? (
                  <Button variant="outline" onClick={handlePauseSubscription} className="flex items-center gap-2">
                    <Pause className="h-4 w-4" />
                    {isRTL ? 'إيقاف مؤقت' : 'Pause'}
                  </Button>
                ) : subscription.status === 'past_due' ? (
                  <Button variant="outline" onClick={handleResumeSubscription} className="flex items-center gap-2">
                    <Play className="h-4 w-4" />
                    {isRTL ? 'استئناف' : 'Resume'}
                  </Button>
                ) : null}
                <Button 
                  variant="destructive" 
                  onClick={() => setShowCancelDialog(true)}
                  className="flex items-center gap-2"
                >
                  <X className="h-4 w-4" />
                  {isRTL ? 'إلغاء الاشتراك' : 'Cancel Subscription'}
                </Button>
              </div>
            </CardContent>
          </Card>

          {/* Quick Stats */}
          {usage && (
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <Card>
                <CardContent className="p-4">
                  <div className="flex items-center gap-3">
                    <TreePine className="h-8 w-8 text-primary" />
                    <div>
                      <p className="text-2xl font-bold">{usage.trees.current}</p>
                      <p className="text-sm text-muted-foreground">
                        {isRTL ? 'أشجار العائلة' : 'Family Trees'}
                      </p>
                    </div>
                  </div>
                </CardContent>
              </Card>
              
              <Card>
                <CardContent className="p-4">
                  <div className="flex items-center gap-3">
                    <Users className="h-8 w-8 text-primary" />
                    <div>
                      <p className="text-2xl font-bold">{usage.members.current}</p>
                      <p className="text-sm text-muted-foreground">
                        {isRTL ? 'أعضاء العائلة' : 'Family Members'}
                      </p>
                    </div>
                  </div>
                </CardContent>
              </Card>
              
              <Card>
                <CardContent className="p-4">
                  <div className="flex items-center gap-3">
                    <Database className="h-8 w-8 text-primary" />
                    <div>
                      <p className="text-2xl font-bold">{usage.storage.current} {usage.storage.unit}</p>
                      <p className="text-sm text-muted-foreground">
                        {isRTL ? 'التخزين المستخدم' : 'Storage Used'}
                      </p>
                    </div>
                  </div>
                </CardContent>
              </Card>
              
              <Card>
                <CardContent className="p-4">
                  <div className="flex items-center gap-3">
                    <Cloud className="h-8 w-8 text-primary" />
                    <div>
                      <p className="text-2xl font-bold">{usage.photos.current}</p>
                      <p className="text-sm text-muted-foreground">
                        {isRTL ? 'الصور المرفوعة' : 'Photos Uploaded'}
                      </p>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </div>
          )}
        </div>
      )}

      {/* Billing Tab */}
      {activeTab === 'billing' && (
        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <CreditCard className="h-5 w-5" />
                {isRTL ? 'طريقة الدفع' : 'Payment Method'}
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex items-center justify-between p-4 border rounded-lg">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-primary/10 rounded-lg flex items-center justify-center">
                    <CreditCard className="h-6 w-6 text-primary" />
                  </div>
                  <div>
                    <p className="font-medium">
                      {/* Mock payment method data */}
                      Visa •••• 1234
                    </p>
                    <p className="text-sm text-muted-foreground">
                      {isRTL ? 'تنتهي في' : 'Expires'} 12/26
                    </p>
                  </div>
                </div>
                <Button variant="outline" onClick={handleUpdatePayment}>
                  <Edit className="h-4 w-4 mr-2" />
                  {isRTL ? 'تحديث' : 'Update'}
                </Button>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Settings className="h-5 w-5" />
                {isRTL ? 'إعدادات الفوترة' : 'Billing Settings'}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'التجديد التلقائي' : 'Auto Renewal'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'تجديد الاشتراك تلقائياً عند انتهاء المدة' : 'Automatically renew subscription when it expires'}
                  </p>
                </div>
                <Button
                  variant={subscription.cancelAtPeriodEnd ? "outline" : "default"}
                  onClick={() => {
                    // Toggle auto renewal
                    // Toggle auto renewal
                  }}
                >
                  {subscription.cancelAtPeriodEnd ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')}
                </Button>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'إشعارات الفوترة' : 'Billing Notifications'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'تلقي إشعارات عبر البريد الإلكتروني قبل الفوترة' : 'Receive email notifications before billing'}
                  </p>
                </div>
                <Button variant="default">
                  {isRTL ? 'مفعل' : 'On'}
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Usage Tab */}
      {activeTab === 'usage' && usage && (
        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <TrendingUp className="h-5 w-5" />
                {isRTL ? 'استخدام الموارد' : 'Resource Usage'}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-6">
              {/* Trees Usage */}
              <div>
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                    <TreePine className="h-4 w-4 text-primary" />
                    <span className="font-medium">{isRTL ? 'أشجار العائلة' : 'Family Trees'}</span>
                  </div>
                  <span className="text-sm text-muted-foreground">
                    {usage.trees.current} / {usage.trees.limit === 0 ? '∞' : usage.trees.limit}
                  </span>
                </div>
                {usage.trees.limit !== 0 && (
                  <div className="w-full bg-secondary rounded-full h-2">
                    <div 
                      className={`h-2 rounded-full ${getUsageColor(getUsagePercentage(usage.trees.current, usage.trees.limit))}`}
                      style={{ width: `${getUsagePercentage(usage.trees.current, usage.trees.limit)}%` }}
                    />
                  </div>
                )}
              </div>

              {/* Members Usage */}
              <div>
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                    <Users className="h-4 w-4 text-primary" />
                    <span className="font-medium">{isRTL ? 'أعضاء العائلة' : 'Family Members'}</span>
                  </div>
                  <span className="text-sm text-muted-foreground">
                    {usage.members.current} / {usage.members.limit === 0 ? '∞' : usage.members.limit}
                  </span>
                </div>
                {usage.members.limit !== 0 && (
                  <div className="w-full bg-secondary rounded-full h-2">
                    <div 
                      className={`h-2 rounded-full ${getUsageColor(getUsagePercentage(usage.members.current, usage.members.limit))}`}
                      style={{ width: `${getUsagePercentage(usage.members.current, usage.members.limit)}%` }}
                    />
                  </div>
                )}
              </div>

              {/* Storage Usage */}
              <div>
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                    <Database className="h-4 w-4 text-primary" />
                    <span className="font-medium">{isRTL ? 'التخزين' : 'Storage'}</span>
                  </div>
                  <span className="text-sm text-muted-foreground">
                    {usage.storage.current} {usage.storage.unit} / {usage.storage.limit} {usage.storage.unit}
                  </span>
                </div>
                <div className="w-full bg-secondary rounded-full h-2">
                  <div 
                    className={`h-2 rounded-full ${getUsageColor(getUsagePercentage(usage.storage.current, usage.storage.limit))}`}
                    style={{ width: `${getUsagePercentage(usage.storage.current, usage.storage.limit)}%` }}
                  />
                </div>
              </div>

              {/* Photos Usage */}
              <div>
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                    <Cloud className="h-4 w-4 text-primary" />
                    <span className="font-medium">{isRTL ? 'الصور' : 'Photos'}</span>
                  </div>
                  <span className="text-sm text-muted-foreground">
                    {usage.photos.current} / {usage.photos.limit === 'unlimited' ? '∞' : usage.photos.limit}
                  </span>
                </div>
                {usage.photos.limit === 'unlimited' ? (
                  <div className="flex items-center gap-2 text-green-600">
                    <Check className="h-4 w-4" />
                    <span className="text-sm">{isRTL ? 'غير محدود' : 'Unlimited'}</span>
                  </div>
                ) : (
                  <div className="w-full bg-secondary rounded-full h-2">
                    <div 
                      className={`h-2 rounded-full ${getUsageColor(getUsagePercentage(usage.photos.current, usage.photos.limit))}`}
                      style={{ width: `${getUsagePercentage(usage.photos.current, usage.photos.limit)}%` }}
                    />
                  </div>
                )}
              </div>
            </CardContent>
          </Card>

          {/* Usage Tips */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Info className="h-5 w-5" />
                {isRTL ? 'نصائح لتوفير المساحة' : 'Storage Tips'}
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-3">
                <div className="flex items-start gap-3">
                  <Check className="h-4 w-4 text-green-600 mt-0.5" />
                  <p className="text-sm">
                    {isRTL 
                      ? 'ضغط الصور قبل الرفع لتوفير مساحة التخزين'
                      : 'Compress images before uploading to save storage space'
                    }
                  </p>
                </div>
                <div className="flex items-start gap-3">
                  <Check className="h-4 w-4 text-green-600 mt-0.5" />
                  <p className="text-sm">
                    {isRTL 
                      ? 'حذف الصور المكررة أو غير المستخدمة'
                      : 'Delete duplicate or unused photos'
                    }
                  </p>
                </div>
                <div className="flex items-start gap-3">
                  <Check className="h-4 w-4 text-green-600 mt-0.5" />
                  <p className="text-sm">
                    {isRTL 
                      ? 'استخدام تنسيقات الصور المضغوطة مثل JPEG'
                      : 'Use compressed image formats like JPEG'
                    }
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Invoices Tab */}
      {activeTab === 'invoices' && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Receipt className="h-5 w-5" />
              {isRTL ? 'سجل الفواتير' : 'Invoice History'}
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {invoices.length > 0 ? (
                invoices.map(invoice => (
                  <div key={invoice.id} className="flex items-center justify-between p-4 border rounded-lg">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-primary/10 rounded-lg flex items-center justify-center">
                        <FileText className="h-5 w-5 text-primary" />
                      </div>
                      <div>
                        <p className="font-medium">
                          {isRTL ? invoice.description : invoice.description}
                        </p>
                        <p className="text-sm text-muted-foreground">
                          {formatDate(invoice.date)} • {formatPrice(invoice.amount)}
                        </p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <Badge className={
                        invoice.status === 'paid' 
                          ? 'bg-green-100 text-green-800'
                          : invoice.status === 'pending'
                          ? 'bg-yellow-100 text-yellow-800'
                          : 'bg-red-100 text-red-800'
                      }>
                        {invoice.status === 'paid' 
                          ? (isRTL ? 'مدفوع' : 'Paid')
                          : invoice.status === 'pending'
                          ? (isRTL ? 'معلق' : 'Pending')
                          : (isRTL ? 'فشل' : 'Failed')
                        }
                      </Badge>
                      <Button variant="outline" size="sm">
                        <Download className="h-4 w-4 mr-2" />
                        {isRTL ? 'تحميل' : 'Download'}
                      </Button>
                    </div>
                  </div>
                ))
              ) : (
                <div className="text-center py-8">
                  <Receipt className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                  <p className="text-muted-foreground">
                    {isRTL ? 'لا توجد فواتير سابقة' : 'No previous invoices'}
                  </p>
                </div>
              )}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Cancel Subscription Dialog */}
      {showCancelDialog && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <Card className="w-full max-w-md mx-4">
            <CardHeader>
              <CardTitle className="flex items-center gap-2 text-destructive">
                <AlertTriangle className="h-5 w-5" />
                {isRTL ? 'إلغاء الاشتراك' : 'Cancel Subscription'}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <p className="text-muted-foreground">
                {isRTL 
                  ? 'هل أنت متأكد من إلغاء اشتراكك؟ ستفقد الوصول لجميع المميزات المدفوعة في نهاية الفترة الحالية.'
                  : 'Are you sure you want to cancel your subscription? You will lose access to all premium features at the end of the current period.'
                }
              </p>
              <div className="flex gap-3">
                <Button 
                  variant="outline" 
                  onClick={() => setShowCancelDialog(false)}
                  className="flex-1"
                >
                  {isRTL ? 'إلغاء' : 'Cancel'}
                </Button>
                <Button 
                  variant="destructive" 
                  onClick={handleCancelSubscription}
                  className="flex-1"
                >
                  {isRTL ? 'تأكيد الإلغاء' : 'Confirm Cancel'}
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      )}
    </div>
  );
};

export default SubscriptionManagePage;