import React, { useState, useRef, useEffect } from 'react';
import { useUIStore } from '@/store/uiStore';
import { useAuthStore } from '@/store/authStore';
import { apiService } from '@/services/api';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';
import { Input } from '@/components/ui/Input';
import { Textarea } from '@/components/ui/Textarea';
import { 
  User, 
  Mail, 
  Phone, 
  MapPin, 
  Calendar, 
  Edit, 
  Save, 
  X, 
  Camera,
  Shield,
  Key,
  Bell,
  Globe,
  Trash2,
  Download,
  Upload,
  Eye,
  EyeOff,
  Check,
  AlertTriangle,
  Crown,
  TreePine,
  Users,
  Activity,
  Loader2
} from 'lucide-react';
import { User as UserType } from '@/types';
import { useNotifications } from '@/utils/notifications';

// Extend the User type to include bio if needed
interface ExtendedUser extends UserType {
  bio?: string;
}

const ProfilePage: React.FC = () => {
  const { language } = useUIStore();
  const { user, updateUser } = useAuthStore();
  const { success: notifySuccess, error: notifyError } = useNotifications();
  const [isEditing, setIsEditing] = useState(false);
  const [activeTab, setActiveTab] = useState<'profile' | 'security' | 'privacy' | 'subscription'>('profile');
  const [showPasswordChange, setShowPasswordChange] = useState(false);
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showCurrentPassword, setShowCurrentPassword] = useState(false);
  const [showNewPassword, setShowNewPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isRTL = language === 'ar';

  // Initialize profile with real user data
  const [profile, setProfile] = useState<ExtendedUser | null>(user as ExtendedUser);
  const [editedProfile, setEditedProfile] = useState<Partial<ExtendedUser>>({});

  // Security settings state with proper typing
  const [securitySettings, setSecuritySettings] = useState({
    twoFactorEnabled: user?.privacy?.showOnlineStatus ? true : false,
    emailNotifications: user?.notifications?.email?.newSuggestions ? true : false,
    smsNotifications: user?.notifications?.email?.marketing ? true : false,
    publicProfile: user?.privacy?.profileVisibility === 'public',
    allowSearching: user?.privacy?.allowSearchEngines ? true : false
  });

  // Fetch user data on component mount
  useEffect(() => {
    const fetchUserProfile = async () => {
      try {
        setLoading(true);
        const userData = await apiService.getProfile();
        setProfile(userData as ExtendedUser);
        setEditedProfile(userData as ExtendedUser);
        updateUser(userData);
      } catch (err) {
        notifyError(
          { 
            en: 'Failed to load profile data', 
            ar: 'فشل في تحميل بيانات الملف الشخصي' 
          }
        );
      } finally {
        setLoading(false);
      }
    };

    if (!user) {
      fetchUserProfile();
    } else {
      setProfile(user as ExtendedUser);
      setEditedProfile(user as ExtendedUser);
    }
  }, [user, updateUser, isRTL, notifyError]);

  const handleSaveProfile = async () => {
    try {
      setLoading(true);
      
      // Prepare data for API call
      const profileData = {
        userName: editedProfile.firstName || '', // Use firstName as the single name field
        displayName: editedProfile.firstName || '', // Use firstName as display name
        phoneNumber: editedProfile.phone || '',
        age: editedProfile.dateOfBirth ? 
          Math.floor((Date.now() - new Date(editedProfile.dateOfBirth).getTime()) / (1000 * 365 * 24 * 60 * 60)).toString() : '',
        nationality: editedProfile.country || '',
        nidOrPassport: '',
        city: editedProfile.city || '',
        country: editedProfile.country || ''
      };
      
      // Call API to update profile
      const updatedUser = await apiService.createOrUpdateProfile(
        profileData.userName,
        profileData.displayName,
        profileData.phoneNumber,
        profileData.age,
        profileData.nationality,
        profileData.nidOrPassport,
        profileData.city,
        profileData.country
      );
      
      // Update local state and store
      setProfile(prev => ({ ...prev, ...editedProfile } as ExtendedUser));
      updateUser({ ...user, ...editedProfile } as UserType);
      setIsEditing(false);
      notifySuccess(
        { 
          en: 'Profile updated successfully', 
          ar: 'تم تحديث الملف الشخصي بنجاح' 
        }
      );
    } catch (err) {
      notifyError(
        { 
          en: 'Failed to update profile', 
          ar: 'فشل في تحديث الملف الشخصي' 
        }
      );
    } finally {
      setLoading(false);
    }
  };

  const handleCancelEdit = () => {
    setEditedProfile(profile || {});
    setIsEditing(false);
  };

  const handleAvatarChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      try {
        setLoading(true);
        const formData = new FormData();
        formData.append('picture', file);
        
        const response = await apiService.uploadProfilePicture(formData);
        
        // Update profile with new avatar
        const updatedProfile = { ...profile, avatar: response.data } as ExtendedUser;
        setProfile(updatedProfile);
        setEditedProfile(updatedProfile);
        updateUser({ ...user, avatar: response.data } as UserType);
        notifySuccess(
          { 
            en: 'Profile picture updated successfully', 
            ar: 'تم تحديث الصورة الشخصية بنجاح' 
          }
        );
      } catch (err) {
        notifyError(
          { 
            en: 'Failed to update profile picture', 
            ar: 'فشل في تحديث الصورة الشخصية' 
          }
        );
      } finally {
        setLoading(false);
      }
    }
  };

  const handleDeleteAvatar = async () => {
    try {
      setLoading(true);
      await apiService.deleteProfilePicture();
      
      // Update profile without avatar
      const updatedProfile = { ...profile, avatar: undefined } as ExtendedUser;
      setProfile(updatedProfile);
      setEditedProfile(updatedProfile);
      updateUser({ ...user, avatar: undefined } as UserType);
      notifySuccess(
        { 
          en: 'Profile picture deleted successfully', 
          ar: 'تم حذف الصورة الشخصية بنجاح' 
        }
      );
    } catch (err) {
      notifyError(
        { 
          en: 'Failed to delete profile picture', 
          ar: 'فشل في حذف الصورة الشخصية' 
        }
      );
    } finally {
      setLoading(false);
    }
  };

  const handlePasswordChange = async () => {
    if (newPassword !== confirmPassword) {
      notifyError(
        { 
          en: 'Passwords do not match', 
          ar: 'كلمات المرور غير متطابقة' 
        }
      );
      return;
    }
    
    try {
      setLoading(true);
      
      // Note: This would need to be implemented in the API service
      // For now, we'll just simulate the call
      await new Promise(resolve => setTimeout(resolve, 1000));
      
      setShowPasswordChange(false);
      setCurrentPassword('');
      setNewPassword('');
      setConfirmPassword('');
      notifySuccess(
        { 
          en: 'Password changed successfully', 
          ar: 'تم تغيير كلمة المرور بنجاح' 
        }
      );
    } catch (err) {
      notifyError(
        { 
          en: 'Failed to change password', 
          ar: 'فشل في تغيير كلمة المرور' 
        }
      );
    } finally {
      setLoading(false);
    }
  };

  const getSubscriptionBadge = (subscription: string) => {
    const badges = {
      premium: { variant: 'default' as const, text: isRTL ? 'مميز' : 'Premium', icon: Crown },
      basic: { variant: 'secondary' as const, text: isRTL ? 'أساسي' : 'Basic', icon: User },
      family: { variant: 'secondary' as const, text: isRTL ? 'عائلي' : 'Family', icon: Users }
    };
    return badges[subscription as keyof typeof badges] || badges.basic;
  };

  const formatFileSize = (sizeInGB: number) => {
    return `${sizeInGB.toFixed(1)} GB`;
  };

  const getStoragePercentage = () => {
    if (!profile?.stats) return 0;
    return (profile.stats.storageUsed / 1000) * 100; // Assuming 1000GB limit
  };

  if (loading && !profile) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (!profile) {
    return (
      <div className="text-center py-12">
        <div className="mx-auto w-16 h-16 bg-destructive/10 rounded-full flex items-center justify-center mb-4">
          <AlertTriangle className="h-8 w-8 text-destructive" />
        </div>
        <h2 className="text-2xl font-bold text-destructive mb-4">
          {isRTL ? 'فشل في تحميل الملف الشخصي' : 'Failed to load profile'}
        </h2>
        <Button onClick={() => window.location.reload()}>
          {isRTL ? 'إعادة المحاولة' : 'Try Again'}
        </Button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Profile Header */}
      <Card>
        <CardContent className="pt-6">
          <div className="flex flex-col lg:flex-row items-start gap-6">
            {/* Avatar */}
            <div className="relative flex-shrink-0">
              <div className="w-24 h-24 rounded-full bg-gradient-to-br from-primary/20 to-primary/40 flex items-center justify-center overflow-hidden mx-auto lg:mx-0">
                {profile.avatar?.url ? (
                  <img 
                    src={profile.avatar.url} 
                    alt="Profile" 
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <User className="h-12 w-12 text-primary" />
                )}
              </div>
              {isEditing && (
                <div className="absolute -bottom-2 -right-2 flex gap-1">
                  <Button
                    size="sm"
                    variant="outline"
                    className="h-8 w-8 rounded-full p-0"
                    onClick={() => fileInputRef.current?.click()}
                  >
                    <Camera className="h-4 w-4" />
                  </Button>
                  {profile.avatar?.url && (
                    <Button
                      size="sm"
                      variant="destructive"
                      className="h-8 w-8 rounded-full p-0"
                      onClick={handleDeleteAvatar}
                    >
                      <X className="h-4 w-4" />
                    </Button>
                  )}
                </div>
              )}
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={handleAvatarChange}
                className="hidden"
              />
            </div>

            {/* Profile Info and Stats */}
            <div className="flex-1 w-full">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-4">
                <div className="flex-1">
                  <div className="flex flex-wrap items-center gap-2 mb-2">
                    <h1 className="text-2xl font-bold text-foreground">
                      {profile.firstName} {/* Display only the first name field which now contains the full name */}
                    </h1>
                    {profile.isEmailVerified && (
                      <Badge variant="success" className="flex items-center gap-1">
                        <Check className="h-3 w-3" />
                        {isRTL ? 'موثق' : 'Verified'}
                      </Badge>
                    )}
                    {profile.subscription && (
                      <Badge {...getSubscriptionBadge(profile.subscription.plan)} className="flex items-center gap-1">
                        {React.createElement(getSubscriptionBadge(profile.subscription.plan).icon, { className: "h-3 w-3" })}
                        {getSubscriptionBadge(profile.subscription.plan).text}
                      </Badge>
                    )}
                  </div>

                  <div className="space-y-1 text-sm text-muted-foreground">
                    <div className="flex items-center gap-2">
                      <Mail className="h-4 w-4 flex-shrink-0" />
                      <span className="truncate">{profile.email}</span>
                    </div>
                    {(profile.city || profile.country) && (
                      <div className="flex items-center gap-2">
                        <MapPin className="h-4 w-4 flex-shrink-0" />
                        <span>{profile.city}{profile.city && profile.country ? ', ' : ''}{profile.country}</span>
                      </div>
                    )}
                    <div className="flex items-center gap-2">
                      <Calendar className="h-4 w-4 flex-shrink-0" />
                      <span>
                        {isRTL ? 'انضم في' : 'Joined'} {new Date(profile.createdAt).toLocaleDateString(isRTL ? 'ar-SA' : 'en-US')}
                      </span>
                    </div>
                  </div>
                </div>

                {/* Stats - moved here for better mobile layout */}
                <div className="flex gap-6 text-center justify-center md:justify-end">
                  <div>
                    <div className="text-2xl font-bold text-primary">{profile.stats?.treesCreated || 0}</div>
                    <div className="text-xs text-muted-foreground">{isRTL ? 'أشجار' : 'Trees'}</div>
                  </div>
                  <div>
                    <div className="text-2xl font-bold text-primary">{profile.stats?.totalPeople || 0}</div>
                    <div className="text-xs text-muted-foreground">{isRTL ? 'أعضاء' : 'Members'}</div>
                  </div>
                  <div>
                    <div className="text-2xl font-bold text-primary">{formatFileSize(profile.stats?.storageUsed || 0)}</div>
                    <div className="text-xs text-muted-foreground">{isRTL ? 'مستخدم' : 'Used'}</div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Tabs */}
      <div className="flex flex-wrap gap-1 border-b">
        {[
          { id: 'profile', label: isRTL ? 'الملف الشخصي' : 'Profile', icon: User },
          // { id: 'security', label: isRTL ? 'الأمان' : 'Security', icon: Shield },
          // { id: 'privacy', label: isRTL ? 'الخصوصية' : 'Privacy', icon: Eye },
          { id: 'subscription', label: isRTL ? 'الاشتراك' : 'Subscription', icon: Crown }
        ].map((tab) => (
          <button
            key={tab.id}
            className={`flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-t-md transition-colors ${
              activeTab === tab.id
                ? 'bg-card text-foreground border-b-2 border-primary'
                : 'text-muted-foreground hover:text-foreground'
            }`}
            onClick={() => setActiveTab(tab.id as any)}
          >
            {React.createElement(tab.icon, { className: "h-4 w-4" })}
            {tab.label}
          </button>
        ))}
      </div>

      {/* Profile Tab */}
      {activeTab === 'profile' && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <User className="h-5 w-5" />
              {isRTL ? 'معلومات الملف الشخصي' : 'Profile Information'}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            {!isEditing ? (
              <div className="space-y-4">
                <div className="flex justify-end">
                  <Button onClick={() => setIsEditing(true)} className="flex items-center gap-2">
                    <Edit className="h-4 w-4" />
                    {isRTL ? 'تعديل الملف الشخصي' : 'Edit Profile'}
                  </Button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-4">
                    <div>
                      <label className="text-sm font-medium text-muted-foreground">{isRTL ? 'الاسم الكامل' : 'Full Name'}</label>
                      <p className="font-medium">{profile.firstName}</p>
                    </div>

                    <div>
                      <label className="text-sm font-medium text-muted-foreground">{isRTL ? 'البريد الإلكتروني' : 'Email Address'}</label>
                      <p className="font-medium">{profile.email}</p>
                    </div>

                    <div>
                      <label className="text-sm font-medium text-muted-foreground">{isRTL ? 'رقم الهاتف' : 'Phone Number'}</label>
                      <p className="font-medium">{profile.phone || (isRTL ? 'غير محدد' : 'Not specified')}</p>
                    </div>
                  </div>

                  <div className="space-y-4">
                    <div>
                      <label className="text-sm font-medium text-muted-foreground">{isRTL ? 'تاريخ الميلاد' : 'Date of Birth'}</label>
                      <p className="font-medium">
                        {profile.dateOfBirth 
                          ? new Date(profile.dateOfBirth).toLocaleDateString(isRTL ? 'ar-SA' : 'en-US')
                          : (isRTL ? 'غير محدد' : 'Not specified')
                        }
                      </p>
                    </div>

                    <div>
                      <label className="text-sm font-medium text-muted-foreground">{isRTL ? 'الجنس' : 'Gender'}</label>
                      <p className="font-medium">
                        {profile.gender === 'male' ? (isRTL ? 'ذكر' : 'Male') : 
                         profile.gender === 'female' ? (isRTL ? 'أنثى' : 'Female') : 
                         (isRTL ? 'غير محدد' : 'Not specified')}
                      </p>
                    </div>

                    <div>
                      <label className="text-sm font-medium text-muted-foreground">{isRTL ? 'الموقع' : 'Location'}</label>
                      <p className="font-medium">
                        {profile.city || profile.country 
                          ? `${profile.city || ''}${profile.city && profile.country ? ', ' : ''}${profile.country || ''}`
                          : (isRTL ? 'غير محدد' : 'Not specified')
                        }
                      </p>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'الاسم الكامل' : 'Full Name'}</label>
                    <Input
                      value={editedProfile.firstName || ''}
                      onChange={(e) => setEditedProfile(prev => ({ ...prev, firstName: e.target.value }))}
                      placeholder={isRTL ? 'الاسم الكامل' : 'Full name'}
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'البريد الإلكتروني' : 'Email Address'}</label>
                    <Input
                      value={editedProfile.email || ''}
                      onChange={(e) => setEditedProfile(prev => ({ ...prev, email: e.target.value }))}
                      type="email"
                      placeholder={isRTL ? 'البريد الإلكتروني' : 'Email address'}
                      disabled // Email should not be editable
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'رقم الهاتف' : 'Phone Number'}</label>
                    <Input
                      value={editedProfile.phone || ''}
                      onChange={(e) => setEditedProfile(prev => ({ ...prev, phone: e.target.value }))}
                      type="tel"
                      placeholder={isRTL ? 'رقم الهاتف' : 'Phone number'}
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'تاريخ الميلاد' : 'Date of Birth'}</label>
                    <Input
                      type="date"
                      value={editedProfile.dateOfBirth?.split('T')[0] || ''}
                      onChange={(e) => setEditedProfile(prev => ({ ...prev, dateOfBirth: e.target.value }))}
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'الجنس' : 'Gender'}</label>
                    <select
                      value={editedProfile.gender || ''}
                      onChange={(e) => setEditedProfile(prev => ({ ...prev, gender: e.target.value as any }))}
                      className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
                    >
                      <option value="">{isRTL ? 'اختر الجنس' : 'Select gender'}</option>
                      <option value="male">{isRTL ? 'ذكر' : 'Male'}</option>
                      <option value="female">{isRTL ? 'أنثى' : 'Female'}</option>
                    </select>
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'البلد' : 'Country'}</label>
                    <Input
                      value={editedProfile.country || ''}
                      onChange={(e) => setEditedProfile(prev => ({ ...prev, country: e.target.value }))}
                      placeholder={isRTL ? 'البلد' : 'Country'}
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'المدينة' : 'City'}</label>
                    <Input
                      value={editedProfile.city || ''}
                      onChange={(e) => setEditedProfile(prev => ({ ...prev, city: e.target.value }))}
                      placeholder={isRTL ? 'المدينة' : 'City'}
                    />
                  </div>
                </div>

                <div className="flex flex-col sm:flex-row gap-3 pt-4">
                  <Button onClick={handleSaveProfile} disabled={loading} className="flex items-center gap-2 w-full sm:w-auto">
                    {loading ? (
                      <Loader2 className="h-4 w-4 animate-spin" />
                    ) : (
                      <Save className="h-4 w-4" />
                    )}
                    {isRTL ? 'حفظ التغييرات' : 'Save Changes'}
                  </Button>
                  <Button variant="outline" onClick={handleCancelEdit} disabled={loading} className="w-full sm:w-auto">
                    {isRTL ? 'إلغاء' : 'Cancel'}
                  </Button>
                </div>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Security Tab */}
      {activeTab === 'security' && (
        <div className="space-y-6">
          {/* Password Change */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Key className="h-5 w-5" />
                {isRTL ? 'تغيير كلمة المرور' : 'Change Password'}
              </CardTitle>
            </CardHeader>
            <CardContent>
              {!showPasswordChange ? (
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 p-4 rounded-lg border bg-card">
                  <div>
                    <p className="font-medium">{isRTL ? 'كلمة المرور' : 'Password'}</p>
                    <p className="text-sm text-muted-foreground">
                      {isRTL ? 'آخر تغيير منذ 3 أشهر' : 'Last changed 3 months ago'}
                    </p>
                  </div>
                  <Button onClick={() => setShowPasswordChange(true)} className="w-full sm:w-auto">
                    {isRTL ? 'تغيير' : 'Change'}
                  </Button>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'كلمة المرور الحالية' : 'Current Password'}</label>
                    <div className="relative">
                      <Input
                        type={showCurrentPassword ? "text" : "password"}
                        value={currentPassword}
                        onChange={(e) => setCurrentPassword(e.target.value)}
                        placeholder={isRTL ? 'كلمة المرور الحالية' : 'Current password'}
                      />
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        className="absolute right-2 top-1/2 transform -translate-y-1/2 h-8 w-8 p-0"
                        onClick={() => setShowCurrentPassword(!showCurrentPassword)}
                      >
                        {showCurrentPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                      </Button>
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'كلمة المرور الجديدة' : 'New Password'}</label>
                    <div className="relative">
                      <Input
                        type={showNewPassword ? "text" : "password"}
                        value={newPassword}
                        onChange={(e) => setNewPassword(e.target.value)}
                        placeholder={isRTL ? 'كلمة المرور الجديدة' : 'New password'}
                      />
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        className="absolute right-2 top-1/2 transform -translate-y-1/2 h-8 w-8 p-0"
                        onClick={() => setShowNewPassword(!showNewPassword)}
                      >
                        {showNewPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                      </Button>
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium">{isRTL ? 'تأكيد كلمة المرور' : 'Confirm Password'}</label>
                    <Input
                      type="password"
                      value={confirmPassword}
                      onChange={(e) => setConfirmPassword(e.target.value)}
                      placeholder={isRTL ? 'تأكيد كلمة المرور' : 'Confirm password'}
                    />
                  </div>

                  <div className="flex flex-col sm:flex-row gap-3">
                    <Button onClick={handlePasswordChange} disabled={loading} className="w-full sm:w-auto">
                      {loading ? (
                        <Loader2 className="h-4 w-4 animate-spin mr-2" />
                      ) : null}
                      {isRTL ? 'تحديث كلمة المرور' : 'Update Password'}
                    </Button>
                    <Button variant="outline" onClick={() => setShowPasswordChange(false)} disabled={loading} className="w-full sm:w-auto">
                      {isRTL ? 'إلغاء' : 'Cancel'}
                    </Button>
                  </div>
                </div>
              )}
            </CardContent>
          </Card>

          {/* Two-Factor Authentication */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Shield className="h-5 w-5" />
                {isRTL ? 'المصادقة الثنائية' : 'Two-Factor Authentication'}
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 p-4 rounded-lg border bg-card">
                <div>
                  <p className="font-medium">{isRTL ? 'المصادقة الثنائية' : 'Two-Factor Authentication'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'أضف طبقة حماية إضافية لحسابك' : 'Add an extra layer of security to your account'}
                  </p>
                </div>
                <Button
                  variant={securitySettings.twoFactorEnabled ? "destructive" : "default"}
                  onClick={() => setSecuritySettings(prev => ({ ...prev, twoFactorEnabled: !prev.twoFactorEnabled }))}
                  className="w-full sm:w-auto"
                >
                  {securitySettings.twoFactorEnabled 
                    ? (isRTL ? 'إيقاف' : 'Disable')
                    : (isRTL ? 'تفعيل' : 'Enable')
                  }
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Privacy Tab */}
      {activeTab === 'privacy' && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Eye className="h-5 w-5" />
              {isRTL ? 'إعدادات الخصوصية' : 'Privacy Settings'}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            {/* Notifications */}
            <div>
              <h3 className="font-medium mb-4 flex items-center gap-2">
                <Bell className="h-4 w-4" />
                {isRTL ? 'الإشعارات' : 'Notifications'}
              </h3>
              <div className="space-y-4">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 p-3 rounded-lg border bg-card">
                  <div>
                    <p className="font-medium">{isRTL ? 'إشعارات البريد الإلكتروني' : 'Email Notifications'}</p>
                    <p className="text-sm text-muted-foreground">
                      {isRTL ? 'تلقي إشعارات عبر البريد الإلكتروني' : 'Receive notifications via email'}
                    </p>
                  </div>
                  <Button
                    variant={securitySettings.emailNotifications ? "default" : "outline"}
                    size="sm"
                    onClick={() => setSecuritySettings(prev => ({ ...prev, emailNotifications: !prev.emailNotifications }))}
                    className="w-full sm:w-auto"
                  >
                    {securitySettings.emailNotifications ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')}
                  </Button>
                </div>

                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 p-3 rounded-lg border bg-card">
                  <div>
                    <p className="font-medium">{isRTL ? 'إشعارات الرسائل النصية' : 'SMS Notifications'}</p>
                    <p className="text-sm text-muted-foreground">
                      {isRTL ? 'تلقي إشعارات عبر الرسائل النصية' : 'Receive notifications via SMS'}
                    </p>
                  </div>
                  <Button
                    variant={securitySettings.smsNotifications ? "default" : "outline"}
                    size="sm"
                    onClick={() => setSecuritySettings(prev => ({ ...prev, smsNotifications: !prev.smsNotifications }))}
                    className="w-full sm:w-auto"
                  >
                    {securitySettings.smsNotifications ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')}
                  </Button>
                </div>
              </div>
            </div>

            {/* Profile Visibility */}
            <div>
              <h3 className="font-medium mb-4 flex items-center gap-2">
                <Globe className="h-4 w-4" />
                {isRTL ? 'رؤية الملف الشخصي' : 'Profile Visibility'}
              </h3>
              <div className="space-y-4">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 p-3 rounded-lg border bg-card">
                  <div>
                    <p className="font-medium">{isRTL ? 'الملف الشخصي العام' : 'Public Profile'}</p>
                    <p className="text-sm text-muted-foreground">
                      {isRTL ? 'اجعل ملفك الشخصي مرئيًا للجميع' : 'Make your profile visible to everyone'}
                    </p>
                  </div>
                  <Button
                    variant={securitySettings.publicProfile ? "default" : "outline"}
                    size="sm"
                    onClick={() => setSecuritySettings(prev => ({ ...prev, publicProfile: !prev.publicProfile }))}
                    className="w-full sm:w-auto"
                  >
                    {securitySettings.publicProfile ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')}
                  </Button>
                </div>

                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 p-3 rounded-lg border bg-card">
                  <div>
                    <p className="font-medium">{isRTL ? 'السماح بالبحث' : 'Allow Searching'}</p>
                    <p className="text-sm text-muted-foreground">
                      {isRTL ? 'السماح للآخرين بالبحث عنك' : 'Allow others to search for you'}
                    </p>
                  </div>
                  <Button
                    variant={securitySettings.allowSearching ? "default" : "outline"}
                    size="sm"
                    onClick={() => setSecuritySettings(prev => ({ ...prev, allowSearching: !prev.allowSearching }))}
                    className="w-full sm:w-auto"
                  >
                    {securitySettings.allowSearching ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')}
                  </Button>
                </div>
              </div>
            </div>

            {/* Danger Zone */}
            <div>
              <h3 className="font-medium mb-4 flex items-center gap-2 text-destructive">
                <AlertTriangle className="h-4 w-4" />
                {isRTL ? 'منطقة الخطر' : 'Danger Zone'}
              </h3>
              <div className="space-y-4">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 p-3 rounded-lg border border-destructive/20 bg-destructive/5">
                  <div>
                    <p className="font-medium text-destructive">{isRTL ? 'حذف الحساب' : 'Delete Account'}</p>
                    <p className="text-sm text-muted-foreground">
                      {isRTL ? 'حذف حسابك بشكل دائم وإلغاء الاشتراك' : 'Permanently delete your account and cancel subscription'}
                    </p>
                  </div>
                  <Button variant="destructive" className="w-full sm:w-auto">
                    {isRTL ? 'حذف الحساب' : 'Delete Account'}
                  </Button>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Subscription Tab */}
      {activeTab === 'subscription' && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Crown className="h-5 w-5" />
              {isRTL ? 'تفاصيل الاشتراك' : 'Subscription Details'}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            {profile.subscription ? (
              <>
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 p-4 rounded-lg border bg-card">
                  <div>
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-medium capitalize">{profile.subscription.plan}</h3>
                      <Badge {...getSubscriptionBadge(profile.subscription.plan)}>
                        {getSubscriptionBadge(profile.subscription.plan).text}
                      </Badge>
                    </div>
                    <p className="text-sm text-muted-foreground">
                      {isRTL ? 'الاشتراك نشط' : 'Subscription is active'}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="font-medium">
                      {profile.subscription.billing.amount} {profile.subscription.billing.currency.toUpperCase()}
                    </p>
                    <p className="text-sm text-muted-foreground">
                      {profile.subscription.billing.interval === 'month' 
                        ? (isRTL ? 'شهريًا' : 'per month') 
                        : (isRTL ? 'سنويًا' : 'per year')}
                    </p>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-4">
                    <h3 className="font-medium">{isRTL ? 'الفواتير' : 'Billing'}</h3>
                    <div className="space-y-3">
                      <div className="flex items-center justify-between p-3 rounded-lg border bg-card">
                        <div>
                          <p className="font-medium">{isRTL ? 'فاتورة أبريل 2023' : 'April 2023 Bill'}</p>
                          <p className="text-sm text-muted-foreground">{isRTL ? 'مدفوعة' : 'Paid'}</p>
                        </div>
                        <Button variant="outline" size="sm" className="flex items-center gap-1">
                          <Download className="h-4 w-4" />
                          {isRTL ? 'تحميل' : 'Download'}
                        </Button>
                      </div>
                      <div className="flex items-center justify-between p-3 rounded-lg border bg-card">
                        <div>
                          <p className="font-medium">{isRTL ? 'فاتورة مارس 2023' : 'March 2023 Bill'}</p>
                          <p className="text-sm text-muted-foreground">{isRTL ? 'مدفوعة' : 'Paid'}</p>
                        </div>
                        <Button variant="outline" size="sm" className="flex items-center gap-1">
                          <Download className="h-4 w-4" />
                          {isRTL ? 'تحميل' : 'Download'}
                        </Button>
                      </div>
                    </div>
                  </div>

                  <div className="space-y-4">
                    <h3 className="font-medium">{isRTL ? 'الإحصائيات' : 'Usage Statistics'}</h3>
                    <div className="space-y-4">
                      <div>
                        <div className="flex justify-between text-sm mb-1">
                          <span>{isRTL ? 'الأشجار' : 'Trees'}</span>
                          <span>{profile.stats?.treesCreated || 0} / {profile.subscription.limits.trees}</span>
                        </div>
                        <div className="w-full bg-muted rounded-full h-2">
                          <div 
                            className="bg-primary h-2 rounded-full" 
                            style={{ width: `${Math.min(100, ((profile.stats?.treesCreated || 0) / profile.subscription.limits.trees) * 100)}%` }}
                          ></div>
                        </div>
                      </div>

                      <div>
                        <div className="flex justify-between text-sm mb-1">
                          <span>{isRTL ? 'الأعضاء' : 'Members'}</span>
                          <span>{profile.stats?.totalPeople || 0} / {profile.subscription.limits.people}</span>
                        </div>
                        <div className="w-full bg-muted rounded-full h-2">
                          <div 
                            className="bg-primary h-2 rounded-full" 
                            style={{ width: `${Math.min(100, ((profile.stats?.totalPeople || 0) / profile.subscription.limits.people) * 100)}%` }}
                          ></div>
                        </div>
                      </div>

                      <div>
                        <div className="flex justify-between text-sm mb-1">
                          <span>{isRTL ? 'التخزين' : 'Storage'}</span>
                          <span>{formatFileSize(profile.stats?.storageUsed || 0)} / {profile.subscription.limits.storage} GB</span>
                        </div>
                        <div className="w-full bg-muted rounded-full h-2">
                          <div 
                            className="bg-primary h-2 rounded-full" 
                            style={{ width: `${getStoragePercentage()}%` }}
                          ></div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="flex flex-col sm:flex-row gap-3 pt-4">
                  <Button className="w-full sm:w-auto">
                    {isRTL ? 'تغيير خطة الاشتراك' : 'Change Plan'}
                  </Button>
                  <Button variant="outline" className="w-full sm:w-auto">
                    {isRTL ? 'إلغاء الاشتراك' : 'Cancel Subscription'}
                  </Button>
                </div>
              </>
            ) : (
              <div className="text-center py-8">
                <Crown className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                <h3 className="text-lg font-medium mb-2">{isRTL ? 'لا يوجد اشتراك نشط' : 'No Active Subscription'}</h3>
                <p className="text-muted-foreground mb-6">
                  {isRTL ? 'ابدأ اشتراكك الآن لفتح جميع الميزات' : 'Start your subscription now to unlock all features'}
                </p>
                <Button>
                  {isRTL ? 'اختر خطة' : 'Choose Plan'}
                </Button>
              </div>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
};

export default ProfilePage;
