import React from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { useUIStore } from '@/store/uiStore';
import { Button } from '@/components/ui/Button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { CheckCircle, AlertCircle, Mail, Loader2 } from 'lucide-react';
import { authService } from '@/services/auth';
import toast from 'react-hot-toast';
import bilingualToast from '@/utils/bilingualToast';
import { useMobile } from '@/hooks/useMobile';

const VerifyEmailPage: React.FC = () => {
  const [searchParams] = useSearchParams();
  const { language } = useUIStore();
  const [isLoading, setIsLoading] = React.useState(true);
  const [isSuccess, setIsSuccess] = React.useState(false);
  const [isError, setIsError] = React.useState(false);
  const [errorMessage, setErrorMessage] = React.useState('');
  const [isResending, setIsResending] = React.useState(false);
  const { isMobile } = useMobile();

  const token = searchParams.get('token');

  React.useEffect(() => {
    if (token) {
      verifyEmail(token);
    } else {
      setIsLoading(false);
      setIsError(true);
      setErrorMessage(
        language === 'ar' 
          ? 'رمز التحقق مفقود'
          : 'Verification token is missing'
      );
    }
  }, [token, language]);

  const verifyEmail = async (token: string) => {
    try {
      await authService.verifyEmail(token);
      setIsSuccess(true);
      bilingualToast.success({
        en: 'Email verified successfully',
        ar: 'تم تأكيد البريد الإلكتروني بنجاح'
      });
    } catch (error: any) {
      setIsError(true);
      const message = error?.message || (
        language === 'ar' 
          ? 'فشل في تأكيد البريد الإلكتروني'
          : 'Email verification failed'
      );
      setErrorMessage(message);
      bilingualToast.error({
        en: message,
        ar: message
      });
    } finally {
      setIsLoading(false);
    }
  };

  const resendVerificationEmail = async () => {
    setIsResending(true);
    try {
      await authService.resendVerificationEmail();
      bilingualToast.success({
        en: 'Verification email sent again',
        ar: 'تم إرسال بريد التأكيد مرة أخرى'
      });
    } catch (error: any) {
      const message = error?.message || (
        language === 'ar' 
          ? 'فشل في إرسال بريد التأكيد'
          : 'Failed to send verification email'
      );
      bilingualToast.error({
        en: message,
        ar: message
      });
    } finally {
      setIsResending(false);
    }
  };

  // Loading state
  if (isLoading) {
    return (
      <Card className={`w-full ${isMobile ? 'max-w-md mx-4' : 'max-w-md'}`}>
        <CardHeader className="space-y-1 text-center">
          <div className="mx-auto w-12 h-12 bg-primary/10 rounded-full flex items-center justify-center mb-4">
            <Loader2 className="h-6 w-6 text-primary animate-spin" />
          </div>
          <CardTitle className={`text-2xl font-bold ${isMobile ? 'text-xl' : ''}`}>
            {language === 'ar' ? 'جاري التحقق...' : 'Verifying...'}
          </CardTitle>
          <CardDescription>
            {language === 'ar' 
              ? 'يرجى الانتظار بينما نتحقق من بريدك الإلكتروني'
              : 'Please wait while we verify your email address'
            }
          </CardDescription>
        </CardHeader>
      </Card>
    );
  }

  // Success state
  if (isSuccess) {
    return (
      <Card className={`w-full ${isMobile ? 'max-w-md mx-4' : 'max-w-md'}`}>
        <CardHeader className="space-y-1 text-center">
          <div className="mx-auto w-12 h-12 bg-green-100 rounded-full flex items-center justify-center mb-4">
            <CheckCircle className="h-6 w-6 text-green-600" />
          </div>
          <CardTitle className={`text-2xl font-bold ${isMobile ? 'text-xl' : ''}`}>
            {language === 'ar' ? 'تم التأكيد بنجاح!' : 'Email Verified!'}
          </CardTitle>
          <CardDescription>
            {language === 'ar' 
              ? 'تم تأكيد بريدك الإلكتروني بنجاح. يمكنك الآن الوصول إلى جميع ميزات الموقع.'
              : 'Your email has been successfully verified. You can now access all features.'
            }
          </CardDescription>
        </CardHeader>
        
        <CardContent className="space-y-4">
          <div className={`text-center space-y-4 ${isMobile ? 'text-sm' : ''}`}>
            <p className="text-sm text-muted-foreground">
              {language === 'ar' 
                ? 'مرحباً بك في Nasabna! ابدأ في بناء شجرة عائلتك الآن.'
                : 'Welcome to Nasabna! Start building your family tree now.'
              }
            </p>
          </div>

          <div className="space-y-3">
            <Button asChild className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}>
              <Link to="/dashboard">
                {language === 'ar' ? 'الذهاب إلى لوحة التحكم' : 'Go to Dashboard'}
              </Link>
            </Button>
            
            <Button asChild variant="outline" className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}>
              <Link to="/login">
                {language === 'ar' ? 'تسجيل الدخول' : 'Sign In'}
              </Link>
            </Button>
          </div>
        </CardContent>
      </Card>
    );
  }

  // Error state
  if (isError) {
    return (
      <Card className={`w-full ${isMobile ? 'max-w-md mx-4' : 'max-w-md'}`}>
        <CardHeader className="space-y-1 text-center">
          <div className="mx-auto w-12 h-12 bg-red-100 rounded-full flex items-center justify-center mb-4">
            <AlertCircle className="h-6 w-6 text-red-600" />
          </div>
          <CardTitle className={`text-2xl font-bold ${isMobile ? 'text-xl' : ''}`}>
            {language === 'ar' ? 'فشل التحقق' : 'Verification Failed'}
          </CardTitle>
          <CardDescription>
            {errorMessage}
          </CardDescription>
        </CardHeader>
        
        <CardContent className="space-y-4">
          <div className={`text-center space-y-4 ${isMobile ? 'text-sm' : ''}`}>
            <p className="text-sm text-muted-foreground">
              {language === 'ar' 
                ? 'قد يكون الرابط منتهي الصلاحية أو تم استخدامه من قبل.'
                : 'The verification link may have expired or already been used.'
              }
            </p>
          </div>

          <div className="space-y-3">
            <Button
              onClick={resendVerificationEmail}
              className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}
              loading={isResending}
              loadingText={language === 'ar' ? 'جاري الإرسال...' : 'Sending...'}
            >
              <Mail className={`w-4 h-4 ${isMobile ? 'mr-1' : 'mr-2'}`} />
              {language === 'ar' ? 'إرسال بريد تأكيد جديد' : 'Send New Verification Email'}
            </Button>
            
            <Button asChild variant="outline" className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}>
              <Link to="/login">
                {language === 'ar' ? 'العودة لتسجيل الدخول' : 'Back to Sign In'}
              </Link>
            </Button>
          </div>

          {/* Help text */}
          <div className={`mt-6 text-center ${isMobile ? 'text-sm' : ''}`}>
            <p className="text-sm text-muted-foreground">
              {language === 'ar' 
                ? 'تحتاج مساعدة؟ '
                : 'Need help? '
              }
              <Link
                to="/contact"
                className="text-primary hover:text-primary/80 underline"
              >
                {language === 'ar' ? 'اتصل بنا' : 'Contact support'}
              </Link>
            </p>
          </div>
        </CardContent>
      </Card>
    );
  }

  return null;
};

export default VerifyEmailPage;