import { create } from 'zustand';
import { devtools, persist } from 'zustand/middleware';
import { UIStore, Notification } from '@/types';

export const useUIStore = create<UIStore>()(
  devtools(
    persist(
      (set, get) => ({
        theme: 'auto',
        language: 'en',
        sidebarOpen: false,
        notifications: [],

        // Set theme
        setTheme: (theme: 'light' | 'dark' | 'auto') => {
          set({ theme });
          
          // Apply theme to document
          const root = document.documentElement;
          
          if (theme === 'auto') {
            // Use system preference
            const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
            root.classList.toggle('dark', prefersDark);
          } else {
            root.classList.toggle('dark', theme === 'dark');
          }
        },

        // Set language
        setLanguage: (language: 'en' | 'ar') => {
          set({ language });
          
          // Apply language to document
          const root = document.documentElement;
          root.setAttribute('lang', language);
          root.setAttribute('dir', language === 'ar' ? 'rtl' : 'ltr');
          
          // Store in localStorage for API requests
          localStorage.setItem('language', language);
        },

        // Toggle sidebar
        setSidebarOpen: (open: boolean) => {
          set({ sidebarOpen: open });
        },

        // Add notification
        addNotification: (notification: Omit<Notification, 'id'>) => {
          const id = Math.random().toString(36).substr(2, 9);
          const newNotification: Notification = {
            ...notification,
            id,
          };
          
          set((state) => ({
            notifications: [...state.notifications, newNotification],
          }));
          
          // Auto-remove notification after duration
          if (notification.duration !== 0) {
            const duration = notification.duration || 5000;
            setTimeout(() => {
              get().removeNotification(id);
            }, duration);
          }
          
          return id;
        },

        // Remove notification
        removeNotification: (id: string) => {
          set((state) => ({
            notifications: state.notifications.filter((n) => n.id !== id),
          }));
        },

        // Clear all notifications
        clearNotifications: () => {
          set({ notifications: [] });
        },

        // Show success notification
        showSuccess: (title: string | { en: string; ar: string }, message?: string | { en: string; ar: string }) => {
          return get().addNotification({
            type: 'success',
            title,
            message: message || '',
          });
        },

        // Show error notification
        showError: (title: string | { en: string; ar: string }, message?: string | { en: string; ar: string }) => {
          return get().addNotification({
            type: 'error',
            title,
            message: message || '',
            duration: 0, // Don't auto-remove error notifications
          });
        },

        // Show warning notification
        showWarning: (title: string | { en: string; ar: string }, message?: string | { en: string; ar: string }) => {
          return get().addNotification({
            type: 'warning',
            title,
            message: message || '',
          });
        },

        // Show info notification
        showInfo: (title: string | { en: string; ar: string }, message?: string | { en: string; ar: string }) => {
          return get().addNotification({
            type: 'info',
            title,
            message: message || '',
          });
        },

        // Initialize UI state
        initialize: () => {
          const state = get();
          
          // Apply theme
          state.setTheme(state.theme);
          
          // Apply language
          state.setLanguage(state.language);
          
          // Listen for system theme changes
          if (state.theme === 'auto') {
            const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
            const handleChange = (e: MediaQueryListEvent) => {
              if (get().theme === 'auto') {
                document.documentElement.classList.toggle('dark', e.matches);
              }
            };
            
            mediaQuery.addEventListener('change', handleChange);
            
            // Cleanup function (if needed)
            return () => mediaQuery.removeEventListener('change', handleChange);
          }
        },

        // Toggle theme
        toggleTheme: () => {
          const currentTheme = get().theme;
          const newTheme = currentTheme === 'light' ? 'dark' : 'light';
          get().setTheme(newTheme);
        },

        // Toggle language
        toggleLanguage: () => {
          const currentLanguage = get().language;
          const newLanguage = currentLanguage === 'en' ? 'ar' : 'en';
          get().setLanguage(newLanguage);
        },

        // Get current direction based on language
        getDirection: () => {
          return get().language === 'ar' ? 'rtl' : 'ltr';
        },

        // Check if current theme is dark
        isDark: () => {
          const theme = get().theme;
          if (theme === 'auto') {
            return window.matchMedia('(prefers-color-scheme: dark)').matches;
          }
          return theme === 'dark';
        },

        // Check if current language is RTL
        isRTL: () => {
          return get().language === 'ar';
        },

        // Get notification count by type
        getNotificationCount: (type?: Notification['type']) => {
          const notifications = get().notifications;
          if (type) {
            return notifications.filter((n) => n.type === type).length;
          }
          return notifications.length;
        },

        // Get unread notifications (assuming all are unread for now)
        getUnreadNotifications: () => {
          return get().notifications;
        },

        // Mark notification as read (placeholder for future implementation)
        markAsRead: (id: string) => {
          // This could be extended to track read status
          // Removed console.log for marking notification as read
        },

        // Bulk actions
        removeAllNotifications: () => {
          set({ notifications: [] });
        },

        removeNotificationsByType: (type: Notification['type']) => {
          set((state) => ({
            notifications: state.notifications.filter((n) => n.type !== type),
          }));
        },
      }),
      {
        name: 'ui-storage',
        partialize: (state) => ({
          theme: state.theme,
          language: state.language,
          sidebarOpen: state.sidebarOpen,
        }),
      }
    ),
    {
      name: 'ui-store',
    }
  )
);

// Initialize UI state on app start
if (typeof window !== 'undefined') {
  // Auto-initialize will happen through the persist middleware
}

export default useUIStore;