import React from 'react';
import { Link } from 'react-router-dom';
import { Button } from '@/components/ui/Button';
import { useUIStore } from '@/store/uiStore';
import { Menu, X, Globe, Sun, Moon } from 'lucide-react';
import Footer from '@/pages/footer/Footer';

interface PublicLayoutProps {
  children: React.ReactNode;
}

const PublicLayout: React.FC<PublicLayoutProps> = ({ children }) => {
  const [mobileMenuOpen, setMobileMenuOpen] = React.useState(false);
  const { language, theme, setLanguage, setTheme } = useUIStore();

  const navigation = [
    { name: 'Home', nameAr: 'الرئيسية', href: '/' },
    { name: 'Features', nameAr: 'المميزات', href: '/features' },
    { name: 'Pricing', nameAr: 'الأسعار', href: '/subscription/plans' },
    { name: 'About', nameAr: 'من نحن', href: '/about' },
  ];

  const toggleLanguage = () => {
    setLanguage(language === 'en' ? 'ar' : 'en');
  };

  const toggleTheme = () => {
    setTheme(theme === 'light' ? 'dark' : 'light');
  };

  // Close mobile menu when resizing to desktop
  React.useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 1024) { // lg breakpoint
        setMobileMenuOpen(false);
      }
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <header className="bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60 sticky top-0 z-40 w-full border-b border-border/40">
        <nav className="mx-auto flex max-w-7xl items-center justify-between p-6 lg:px-8" aria-label="Global">
          {/* Logo */}
          <div className="flex lg:flex-1">
            <Link to="/" className="-m-1.5 p-1.5">
              <span className="sr-only">{language === 'ar' ? 'نسبنا' : 'Nasabna'}</span>
              <div className="flex items-center space-x-2">
                <svg
                  className="h-8 w-8 text-primary"
                  viewBox="0 0 100 100"
                  fill="none"
                  xmlns="http://www.w3.org/2000/svg"
                >
                  <circle cx="50" cy="50" r="45" stroke="currentColor" strokeWidth="2" fill="none" opacity="0.3"/>
                  <path d="M50 20 L35 35 L50 50 L65 35 Z" fill="currentColor"/>
                  <path d="M35 35 L20 50 L35 65 L50 50 Z" fill="currentColor" opacity="0.8"/>
                  <path d="M65 35 L80 50 L65 65 L50 50 Z" fill="currentColor" opacity="0.8"/>
                  <path d="M35 65 L50 80 L65 65 L50 50 Z" fill="currentColor" opacity="0.6"/>
                  <circle cx="50" cy="35" r="3" fill="currentColor"/>
                  <circle cx="35" cy="50" r="3" fill="currentColor"/>
                  <circle cx="65" cy="50" r="3" fill="currentColor"/>
                  <circle cx="50" cy="65" r="3" fill="currentColor"/>
                </svg>
                <span className="text-xl font-bold text-foreground">
                  {language === 'ar' ? 'نسبنا' : 'Nasabna'}
                </span>
              </div>
            </Link>
          </div>

          {/* Mobile menu button */}
          <div className="flex lg:hidden">
            <button
              type="button"
              className="-m-2.5 inline-flex items-center justify-center rounded-md p-2.5 text-muted-foreground"
              onClick={() => setMobileMenuOpen(true)}
            >
              <span className="sr-only">Open main menu</span>
              <Menu className="h-6 w-6" aria-hidden="true" />
            </button>
          </div>

          {/* Desktop navigation */}
          <div className="hidden lg:flex lg:gap-x-12">
            {navigation.map((item) => (
              <Link
                key={item.name}
                to={item.href}
                className="text-sm font-semibold leading-6 text-muted-foreground hover:text-foreground transition-colors"
              >
                {language === 'ar' ? item.nameAr : item.name}
              </Link>
            ))}
          </div>

          {/* Right side buttons */}
          <div className="hidden lg:flex lg:flex-1 lg:justify-end lg:items-center lg:space-x-4">
            {/* Theme toggle */}
            <Button
              variant="ghost"
              size="icon"
              onClick={toggleTheme}
              className="h-9 w-9"
            >
              {theme === 'light' ? (
                <Moon className="h-4 w-4" />
              ) : (
                <Sun className="h-4 w-4" />
              )}
            </Button>

            {/* Language toggle */}
            <Button
              variant="ghost"
              size="icon"
              onClick={toggleLanguage}
              className="h-9 w-9"
            >
              <Globe className="h-4 w-4" />
            </Button>

            {/* Auth buttons */}
            <Button asChild variant="ghost">
              <Link to="/login">
                {language === 'ar' ? 'تسجيل الدخول' : 'Sign In'}
              </Link>
            </Button>
            <Button asChild>
              <Link to="/register">
                {language === 'ar' ? 'إنشاء حساب' : 'Get Started'}
              </Link>
            </Button>
          </div>
        </nav>
      </header>

      {/* Mobile menu - Completely separate from header */}
      {mobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 z-50">
          <div 
            className="fixed inset-0 bg-background/80 backdrop-blur-sm"
            onClick={() => setMobileMenuOpen(false)}
          />
          <div className="fixed inset-y-0 right-0 z-50 w-full overflow-y-auto bg-background px-6 py-6 sm:max-w-sm sm:ring-1 sm:ring-border/10">
            <div className="flex items-center justify-between">
              <Link to="/" className="-m-1.5 p-1.5" onClick={() => setMobileMenuOpen(false)}>
                <span className="sr-only">{language === 'ar' ? 'نسبنا' : 'Nasabna'}</span>
                <div className="flex items-center space-x-2">
                  <svg
                    className="h-8 w-8 text-primary"
                    viewBox="0 0 100 100"
                    fill="none"
                    xmlns="http://www.w3.org/2000/svg"
                  >
                    <circle cx="50" cy="50" r="45" stroke="currentColor" strokeWidth="2" fill="none" opacity="0.3"/>
                    <path d="M50 20 L35 35 L50 50 L65 35 Z" fill="currentColor"/>
                    <path d="M35 35 L20 50 L35 65 L50 50 Z" fill="currentColor" opacity="0.8"/>
                    <path d="M65 35 L80 50 L65 65 L50 50 Z" fill="currentColor" opacity="0.8"/>
                    <path d="M35 65 L50 80 L65 65 L50 50 Z" fill="currentColor" opacity="0.6"/>
                    <circle cx="50" cy="35" r="3" fill="currentColor"/>
                    <circle cx="35" cy="50" r="3" fill="currentColor"/>
                    <circle cx="65" cy="50" r="3" fill="currentColor"/>
                    <circle cx="50" cy="65" r="3" fill="currentColor"/>
                  </svg>
                  <span className="text-xl font-bold text-foreground">
                    {language === 'ar' ? 'نسبنا' : 'Nasabna'}
                  </span>
                </div>
              </Link>
              <button
                type="button"
                className="-m-2.5 rounded-md p-2.5 text-muted-foreground"
                onClick={() => setMobileMenuOpen(false)}
              >
                <span className="sr-only">Close menu</span>
                <X className="h-6 w-6" aria-hidden="true" />
              </button>
            </div>
            <div className="mt-6 flow-root">
              <div className="-my-6 divide-y divide-border/10">
                <div className="space-y-2 py-6">
                  {navigation.map((item) => (
                    <Link
                      key={item.name}
                      to={item.href}
                      className="-mx-3 block rounded-lg px-3 py-2 text-base font-semibold leading-7 text-foreground hover:bg-muted"
                      onClick={() => setMobileMenuOpen(false)}
                    >
                      {language === 'ar' ? item.nameAr : item.name}
                    </Link>
                  ))}
                </div>
                <div className="py-6 space-y-4">
                  <div className="flex items-center justify-between">
                    <span className="text-sm font-medium">Theme</span>
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={(e) => {
                        e.stopPropagation();
                        toggleTheme();
                      }}
                      className="h-9 w-9"
                    >
                      {theme === 'light' ? (
                        <Moon className="h-4 w-4" />
                      ) : (
                        <Sun className="h-4 w-4" />
                      )}
                    </Button>
                  </div>
                  <div className="flex items-center justify-between">
                    <span className="text-sm font-medium">Language</span>
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={(e) => {
                        e.stopPropagation();
                        toggleLanguage();
                      }}
                      className="h-9 w-9"
                    >
                      <Globe className="h-4 w-4" />
                    </Button>
                  </div>
                  <div className="space-y-2">
                    <Button asChild variant="outline" className="w-full" onClick={() => setMobileMenuOpen(false)}>
                      <Link to="/login">
                        {language === 'ar' ? 'تسجيل الدخول' : 'Sign In'}
                      </Link>
                    </Button>
                    <Button asChild className="w-full" onClick={() => setMobileMenuOpen(false)}>
                      <Link to="/register">
                        {language === 'ar' ? 'إنشاء حساب' : 'Get Started'}
                      </Link>
                    </Button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Main content */}
      <main>{children}</main>

      {/* Footer */}
      <Footer />
    </div>
  );
};

export default PublicLayout;