import React from 'react';
import Modal from '@/components/ui/Modal';
import PersonCreateForm from '@/components/forms/PersonCreateForm';
import { Tree } from '@/types';

interface PersonFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  trees?: Tree[];
  onSuccess?: (personId: string) => void;
}

const PersonFormModal: React.FC<PersonFormModalProps> = ({ 
  isOpen, 
  onClose, 
  trees,
  onSuccess
}) => {
  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Add New Person"
      size="lg"
    >
      <div className="p-4">
        <PersonCreateForm 
          trees={trees}
          onCancel={onClose}
          onSuccess={(personId) => {
            onSuccess?.(personId);
            onClose();
          }}
        />
      </div>
    </Modal>
  );
};

export default PersonFormModal;