import React from 'react';
import { Link, useNavigate, useSearchParams } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useUIStore } from '@/store/uiStore';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { Lock, CheckCircle, AlertCircle } from 'lucide-react';
import { authService } from '@/services/auth';
import toast from 'react-hot-toast';
import bilingualToast from '@/utils/bilingualToast';
import { useMobile } from '@/hooks/useMobile';

const resetPasswordSchema = z.object({
  password: z.string()
    .min(8, 'Password must be at least 8 characters')
    .regex(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/, 'Password must contain at least one uppercase letter, one lowercase letter, and one number'),
  confirmPassword: z.string(),
}).refine((data) => data.password === data.confirmPassword, {
  message: "Passwords don't match",
  path: ["confirmPassword"],
});

type ResetPasswordFormData = z.infer<typeof resetPasswordSchema>;

const ResetPasswordPage: React.FC = () => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { language } = useUIStore();
  const [isLoading, setIsLoading] = React.useState(false);
  const [isSuccess, setIsSuccess] = React.useState(false);
  const [isValidToken, setIsValidToken] = React.useState(true);
  const { isMobile } = useMobile();

  const token = searchParams.get('token');

  const {
    register,
    handleSubmit,
    formState: { errors },
    watch,
  } = useForm<ResetPasswordFormData>({
    resolver: zodResolver(resetPasswordSchema),
  });

  const password = watch('password');

  React.useEffect(() => {
    if (!token) {
      setIsValidToken(false);
    }
  }, [token]);

  const onSubmit = async (data: ResetPasswordFormData) => {
    if (!token) return;

    setIsLoading(true);
    try {
      await authService.resetPassword('', token, data.password, data.confirmPassword);
      setIsSuccess(true);
      bilingualToast.success({
        en: 'Password reset successfully',
        ar: 'تم إعادة تعيين كلمة المرور بنجاح'
      });
    } catch (error: any) {
      const message = error?.message || (
        language === 'ar' 
          ? 'حدث خطأ أثناء إعادة تعيين كلمة المرور'
          : 'Failed to reset password'
      );
      bilingualToast.error({
        en: message,
        ar: message
      });
      
      if (error?.message?.includes('invalid') || error?.message?.includes('expired')) {
        setIsValidToken(false);
      }
    } finally {
      setIsLoading(false);
    }
  };

  // Password strength indicator
  const getPasswordStrength = (password: string) => {
    if (!password) return { strength: 0, label: '' };
    
    let strength = 0;
    const checks = [
      password.length >= 8,
      /[a-z]/.test(password),
      /[A-Z]/.test(password),
      /\d/.test(password),
      /[!@#$%^&*(),.?":{}|<>]/.test(password),
    ];
    
    strength = checks.filter(Boolean).length;
    
    const labels = {
      en: ['Very Weak', 'Weak', 'Fair', 'Good', 'Strong'],
      ar: ['ضعيف جداً', 'ضعيف', 'متوسط', 'جيد', 'قوي'],
    };
    
    return {
      strength,
      label: labels[language][Math.max(0, strength - 1)] || '',
    };
  };

  const passwordStrength = getPasswordStrength(password || '');

  // Invalid token state
  if (!isValidToken) {
    return (
      <Card className={`w-full ${isMobile ? 'max-w-md mx-4' : 'max-w-md'}`}>
        <CardHeader className="space-y-1 text-center">
          <div className="mx-auto w-12 h-12 bg-red-100 rounded-full flex items-center justify-center mb-4">
            <AlertCircle className="h-6 w-6 text-red-600" />
          </div>
          <CardTitle className={`text-2xl font-bold ${isMobile ? 'text-xl' : ''}`}>
            {language === 'ar' ? 'رابط غير صالح' : 'Invalid Link'}
          </CardTitle>
          <CardDescription>
            {language === 'ar' 
              ? 'رابط إعادة تعيين كلمة المرور غير صالح أو منتهي الصلاحية'
              : 'The password reset link is invalid or has expired'
            }
          </CardDescription>
        </CardHeader>
        
        <CardContent className="space-y-4">
          <div className={`text-center space-y-4 ${isMobile ? 'text-sm' : ''}`}>
            <p className="text-sm text-muted-foreground">
              {language === 'ar' 
                ? 'يرجى طلب رابط جديد لإعادة تعيين كلمة المرور.'
                : 'Please request a new password reset link.'
              }
            </p>
          </div>

          <div className="space-y-3">
            <Button asChild className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}>
              <Link to="/forgot-password">
                {language === 'ar' ? 'طلب رابط جديد' : 'Request New Link'}
              </Link>
            </Button>
            
            <Button asChild variant="outline" className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}>
              <Link to="/login">
                {language === 'ar' ? 'العودة لتسجيل الدخول' : 'Back to Sign In'}
              </Link>
            </Button>
          </div>
        </CardContent>
      </Card>
    );
  }

  // Success state
  if (isSuccess) {
    return (
      <Card className={`w-full ${isMobile ? 'max-w-md mx-4' : 'max-w-md'}`}>
        <CardHeader className="space-y-1 text-center">
          <div className="mx-auto w-12 h-12 bg-green-100 rounded-full flex items-center justify-center mb-4">
            <CheckCircle className="h-6 w-6 text-green-600" />
          </div>
          <CardTitle className={`text-2xl font-bold ${isMobile ? 'text-xl' : ''}`}>
            {language === 'ar' ? 'تم إعادة تعيين كلمة المرور' : 'Password Reset Complete'}
          </CardTitle>
          <CardDescription>
            {language === 'ar' 
              ? 'تم إعادة تعيين كلمة المرور بنجاح. يمكنك الآن تسجيل الدخول بكلمة المرور الجديدة.'
              : 'Your password has been successfully reset. You can now sign in with your new password.'
            }
          </CardDescription>
        </CardHeader>
        
        <CardContent>
          <Button 
            asChild 
            className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}
            onClick={() => navigate('/login')}
          >
            <Link to="/login">
              {language === 'ar' ? 'تسجيل الدخول' : 'Sign In'}
            </Link>
          </Button>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className={`w-full ${isMobile ? 'max-w-md mx-4' : 'max-w-md'}`}>
      <CardHeader className="space-y-1">
        <CardTitle className={`text-2xl font-bold text-center ${isMobile ? 'text-xl' : ''}`}>
          {language === 'ar' ? 'إعادة تعيين كلمة المرور' : 'Reset Password'}
        </CardTitle>
        <CardDescription className="text-center">
          {language === 'ar' 
            ? 'أدخل كلمة المرور الجديدة'
            : 'Enter your new password'
          }
        </CardDescription>
      </CardHeader>
      
      <CardContent>
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          {/* Password field */}
          <div className="space-y-2">
            <Input
              {...register('password')}
              type="password"
              placeholder={language === 'ar' ? 'كلمة المرور الجديدة' : 'New password'}
              leftIcon={<Lock className="h-4 w-4" />}
              showPasswordToggle
              error={errors.password?.message}
              disabled={isLoading}
              className={isMobile ? 'text-sm' : ''}
            />
            
            {/* Password strength indicator */}
            {password && (
              <div className="space-y-2">
                <div className="flex items-center space-x-2">
                  <div className="flex-1 bg-muted rounded-full h-2">
                    <div
                      className={`h-2 rounded-full transition-all duration-300 ${
                        passwordStrength.strength <= 2 
                          ? 'bg-destructive' 
                          : passwordStrength.strength <= 3 
                          ? 'bg-yellow-500' 
                          : 'bg-green-500'
                      }`}
                      style={{ width: `${(passwordStrength.strength / 5) * 100}%` }}
                    />
                  </div>
                  <span className={`text-xs text-muted-foreground min-w-0 ${isMobile ? 'text-xs' : ''}`}>
                    {passwordStrength.label}
                  </span>
                </div>
              </div>
            )}
          </div>

          {/* Confirm password field */}
          <Input
            {...register('confirmPassword')}
            type="password"
            placeholder={language === 'ar' ? 'تأكيد كلمة المرور' : 'Confirm new password'}
            leftIcon={<Lock className="h-4 w-4" />}
            showPasswordToggle
            error={errors.confirmPassword?.message}
            disabled={isLoading}
            className={isMobile ? 'text-sm' : ''}
          />

          {/* Submit button */}
          <Button
            type="submit"
            className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}
            loading={isLoading}
            loadingText={language === 'ar' ? 'جاري إعادة التعيين...' : 'Resetting...'}
          >
            {language === 'ar' ? 'إعادة تعيين كلمة المرور' : 'Reset Password'}
          </Button>
        </form>

        {/* Back to login */}
        <div className="mt-6 text-center">
          <Button asChild variant="ghost" className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}>
            <Link to="/login">
              {language === 'ar' ? 'العودة لتسجيل الدخول' : 'Back to Sign In'}
            </Link>
          </Button>
        </div>
      </CardContent>
    </Card>
  );
};

export default ResetPasswordPage;