import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { subscriptionService } from '@/services/subscriptionService';
import { SubscriptionPlan } from '@/types';
import { Crown, Check, Star, Zap, Users, Shield, Loader2 } from 'lucide-react';

const SubscriptionPage: React.FC = () => {
  const { t, i18n } = useTranslation();
  const navigate = useNavigate();
  const [selectedPlan, setSelectedPlan] = useState<'basic' | 'premium' | 'family'>('premium');
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const isRTL = i18n.language === 'ar';

  useEffect(() => {
    fetchPlans();
  }, []);

  const fetchPlans = async () => {
    try {
      setLoading(true);
      const fetchedPlans = await subscriptionService.getSubscriptionPlans();
      setPlans(fetchedPlans);
      
      // Set the default selected plan based on the popular flag
      const popularPlan = fetchedPlans.find(plan => plan.popular);
      if (popularPlan) {
        setSelectedPlan(popularPlan.id as 'basic' | 'premium' | 'family');
      }
    } catch (err) {
      setError('Failed to load subscription plans');
      // Error fetching plans: err
    } finally {
      setLoading(false);
    }
  };

  const handleSubscribe = async (planId: string) => {
    try {
      // Navigate to checkout page with selected plan
      navigate(`/subscription/checkout?plan=${planId}&billing=year`);
    } catch (err) {
      // Error initiating subscription: err
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50 py-12 px-4 flex items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50 py-12 px-4 flex items-center justify-center">
        <div className="text-center">
          <div className="text-destructive mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
          <h3 className="text-lg font-semibold text-foreground mb-2">
            {isRTL ? 'خطأ في تحميل البيانات' : 'Error Loading Data'}
          </h3>
          <p className="text-muted-foreground mb-4">
            {error}
          </p>
          <button 
            onClick={fetchPlans}
            className="px-4 py-2 bg-primary text-primary-foreground rounded-md hover:bg-primary/90"
          >
            {isRTL ? 'إعادة المحاولة' : 'Try Again'}
          </button>
        </div>
      </div>
    );
  }

  const planData = plans.map(plan => ({
    id: plan.id,
    name: isRTL ? (plan.id === 'basic' ? 'الأساسية' : plan.id === 'premium' ? 'المميزة' : 'العائلية') : plan.name,
    price: isRTL ? `${(plan.price.year / 12).toFixed(0)} ج.م` : `$${plan.price.year}`,
    period: isRTL ? 'شهرياً' : 'per month',
    icon: plan.id === 'basic' ? Star : plan.id === 'premium' ? Crown : Users,
    color: plan.id === 'basic' ? 'bg-blue-500' : plan.id === 'premium' ? 'bg-purple-500' : 'bg-green-500',
    popular: plan.popular,
    features: [
      isRTL ? (plan.id === 'basic' ? 'حتى ١٠٠ فرد في الشجرة' : plan.id === 'premium' ? 'أفراد غير محدودين' : 'كل مميزات الخطة المميزة') : 
              (plan.id === 'basic' ? 'Up to 100 family members' : plan.id === 'premium' ? 'Unlimited family members' : 'All Premium features'),
      isRTL ? (plan.id === 'basic' ? 'تخزين ١ جيجا للصور' : plan.id === 'premium' ? 'تخزين ١٠ جيجا للصور' : 'تخزين ٥٠ جيجا للصور') : 
              (plan.id === 'basic' ? '1GB photo storage' : plan.id === 'premium' ? '10GB photo storage' : '50GB photo storage'),
      isRTL ? (plan.id === 'basic' ? 'دعم فني أساسي' : plan.id === 'premium' ? 'دعم فني مميز' : 'حتى ٥ مستخدمين') : 
              (plan.id === 'basic' ? 'Basic support' : plan.id === 'premium' ? 'Priority support' : 'Up to 5 users'),
      isRTL ? (plan.id === 'basic' ? 'تصدير PDF' : plan.id === 'premium' ? 'تصدير متعدد الصيغ' : 'مشاركة الأشجار') : 
              (plan.id === 'basic' ? 'PDF export' : plan.id === 'premium' ? 'Multiple export formats' : 'Tree sharing'),
      ...(plan.id === 'premium' || plan.id === 'family' ? [
        isRTL ? (plan.id === 'premium' ? 'أدوات بحث متقدمة' : 'تعاون جماعي') : 
                (plan.id === 'premium' ? 'Advanced search tools' : 'Collaborative editing')
      ] : []),
      ...(plan.id === 'premium' || plan.id === 'family' ? [
        isRTL ? (plan.id === 'premium' ? 'تقارير تفصيلية' : 'نسخ احتياطية تلقائية') : 
                (plan.id === 'premium' ? 'Detailed reports' : 'Automatic backups')
      ] : [])
    ],
  }));

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50 py-12 px-4">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="text-center mb-16">
          <div className="flex items-center justify-center mb-4">
            <Crown className="h-12 w-12 text-purple-600 mr-3" />
            <h1 className="text-4xl font-bold text-gray-900">
              {isRTL ? 'خطط الاشتراك' : 'Subscription Plans'}
            </h1>
          </div>
          <p className="text-xl text-gray-600 max-w-3xl mx-auto">
            {isRTL 
              ? 'اختر الخطة المناسبة لك واستمتع بجميع مميزات موقع شجرة العائلة'
              : 'Choose the perfect plan for you and enjoy all the features of our family tree platform'
            }
          </p>
        </div>

        {/* Plans Grid */}
        <div className="grid md:grid-cols-3 gap-8 mb-16">
          {planData.map((plan) => {
            const Icon = plan.icon;
            const isSelected = selectedPlan === plan.id;
            
            return (
              <div
                key={plan.id}
                className={`relative bg-white rounded-2xl shadow-xl overflow-hidden transition-all duration-300 hover:shadow-2xl ${
                  isSelected ? 'ring-4 ring-purple-500 scale-105' : ''
                } ${plan.popular ? 'border-2 border-purple-500' : 'border border-gray-200'}`}
              >
                {plan.popular && (
                  <div className="absolute top-0 left-1/2 transform -translate-x-1/2 -translate-y-1/2">
                    <div className="bg-purple-500 text-white px-4 py-1 rounded-full text-sm font-semibold">
                      {isRTL ? 'الأكثر شعبية' : 'Most Popular'}
                    </div>
                  </div>
                )}

                <div className="p-8">
                  {/* Plan Header */}
                  <div className="text-center mb-8">
                    <div className={`inline-flex items-center justify-center w-16 h-16 rounded-full ${plan.color} text-white mb-4`}>
                      <Icon className="h-8 w-8" />
                    </div>
                    <h3 className="text-2xl font-bold text-gray-900 mb-2">{plan.name}</h3>
                    <div className="text-4xl font-bold text-gray-900 mb-1">{plan.price}</div>
                    <div className="text-gray-500">{plan.period}</div>
                  </div>

                  {/* Features */}
                  <ul className="space-y-4 mb-8">
                    {plan.features.map((feature, index) => (
                      <li key={index} className="flex items-start">
                        <Check className="h-5 w-5 text-green-500 mr-3 mt-0.5 flex-shrink-0" />
                        <span className="text-gray-700">{feature}</span>
                      </li>
                    ))}
                  </ul>

                  {/* Subscribe Button */}
                  <button
                    onClick={() => {
                      setSelectedPlan(plan.id as any);
                      handleSubscribe(plan.id);
                    }}
                    className={`w-full py-3 px-6 rounded-lg font-semibold transition-all duration-200 ${
                      isSelected
                        ? 'bg-purple-600 text-white hover:bg-purple-700'
                        : 'bg-gray-100 text-gray-900 hover:bg-gray-200'
                    }`}
                  >
                    {isRTL ? 'اختيار الخطة' : 'Choose Plan'}
                  </button>
                </div>
              </div>
            );
          })}
        </div>

        {/* Features Section */}
        <div className="bg-white rounded-2xl shadow-xl p-8 mb-16">
          <h2 className="text-3xl font-bold text-center text-gray-900 mb-12">
            {isRTL ? 'لماذا تختار خدمتنا؟' : 'Why Choose Our Service?'}
          </h2>
          
          <div className="grid md:grid-cols-3 gap-8">
            <div className="text-center">
              <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-blue-100 text-blue-600 mb-4">
                <Zap className="h-8 w-8" />
              </div>
              <h3 className="text-xl font-semibold text-gray-900 mb-2">
                {isRTL ? 'سرعة وأداء' : 'Fast & Reliable'}
              </h3>
              <p className="text-gray-600">
                {isRTL 
                  ? 'منصة سريعة وموثوقة لإدارة شجرة عائلتك بكفاءة عالية'
                  : 'Lightning-fast platform for managing your family tree efficiently'
                }
              </p>
            </div>

            <div className="text-center">
              <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-green-100 text-green-600 mb-4">
                <Shield className="h-8 w-8" />
              </div>
              <h3 className="text-xl font-semibold text-gray-900 mb-2">
                {isRTL ? 'أمان وخصوصية' : 'Secure & Private'}
              </h3>
              <p className="text-gray-600">
                {isRTL 
                  ? 'بياناتك محمية بأعلى معايير الأمان والخصوصية'
                  : 'Your data is protected with the highest security standards'
                }
              </p>
            </div>

            <div className="text-center">
              <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-purple-100 text-purple-600 mb-4">
                <Users className="h-8 w-8" />
              </div>
              <h3 className="text-xl font-semibold text-gray-900 mb-2">
                {isRTL ? 'مشاركة عائلية' : 'Family Collaboration'}
              </h3>
              <p className="text-gray-600">
                {isRTL 
                  ? 'شارك شجرة عائلتك مع أفراد العائلة وتعاونوا معاً'
                  : 'Share your family tree and collaborate with family members'
                }
              </p>
            </div>
          </div>
        </div>

        {/* FAQ Section */}
        <div className="bg-gray-50 rounded-2xl p-8">
          <h2 className="text-3xl font-bold text-center text-gray-900 mb-8">
            {isRTL ? 'الأسئلة الشائعة' : 'Frequently Asked Questions'}
          </h2>
          
          <div className="max-w-3xl mx-auto space-y-6">
            <div className="bg-white rounded-lg p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-2">
                {isRTL ? 'هل يمكنني تغيير خطتي لاحقاً؟' : 'Can I change my plan later?'}
              </h3>
              <p className="text-gray-600">
                {isRTL 
                  ? 'نعم، يمكنك ترقية أو تخفيض خطتك في أي وقت من إعدادات الحساب.'
                  : 'Yes, you can upgrade or downgrade your plan anytime from your account settings.'
                }
              </p>
            </div>

            <div className="bg-white rounded-lg p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-2">
                {isRTL ? 'هل هناك فترة تجريبية مجانية؟' : 'Is there a free trial?'}
              </h3>
              <p className="text-gray-600">
                {isRTL 
                  ? 'نعم، نوفر فترة تجريبية مجانية لمدة ١٤ يوماً لجميع الخطط المدفوعة.'
                  : 'Yes, we offer a 14-day free trial for all paid plans.'
                }
              </p>
            </div>

            <div className="bg-white rounded-lg p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-2">
                {isRTL ? 'كيف يمكنني إلغاء اشتراكي؟' : 'How can I cancel my subscription?'}
              </h3>
              <p className="text-gray-600">
                {isRTL 
                  ? 'يمكنك إلغاء اشتراكك في أي وقت من إعدادات الحساب، وستحتفظ بالوصول حتى نهاية فترة الفوترة.'
                  : 'You can cancel your subscription anytime from account settings, and you\'ll retain access until the end of your billing period.'
                }
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SubscriptionPage;