import { useUIStore } from '@/store/uiStore';

/**
 * A drop-in replacement for react-hot-toast that supports bilingual messages
 * This maintains the same API as react-hot-toast but uses our custom notification system
 */

// Type for the toast function return value
interface ToastPromise {
  dismiss: () => void;
}

// Toast options interface
interface ToastOptions {
  duration?: number;
  position?: 'top-left' | 'top-center' | 'top-right' | 'bottom-left' | 'bottom-center' | 'bottom-right';
  // We'll ignore these for now as our system handles styling differently
  style?: Record<string, any>;
  className?: string;
  icon?: React.ReactNode;
}

// Create a hook-based toast instance
export const useBilingualToast = () => {
  const { showSuccess, showError, showWarning, showInfo } = useUIStore();
  
  const toast = {
    success: (message: string | { en: string; ar: string }, options?: ToastOptions) => {
      showSuccess(message, '');
      return { dismiss: () => {} } as ToastPromise;
    },
    
    error: (message: string | { en: string; ar: string }, options?: ToastOptions) => {
      showError(message, '');
      return { dismiss: () => {} } as ToastPromise;
    },
    
    warning: (message: string | { en: string; ar: string }, options?: ToastOptions) => {
      showWarning(message, '');
      return { dismiss: () => {} } as ToastPromise;
    },
    
    info: (message: string | { en: string; ar: string }, options?: ToastOptions) => {
      showInfo(message, '');
      return { dismiss: () => {} } as ToastPromise;
    },
    
    // For custom toasts, we'll map to our info notification
    custom: (content: React.ReactNode, options?: ToastOptions) => {
      // This is a simplified implementation - in a real app, you might want to 
      // create a more sophisticated custom toast system
      showInfo(typeof content === 'string' ? content : 'Custom notification', '');
      return { dismiss: () => {} } as ToastPromise;
    },
    
    // Dismiss all notifications
    dismiss: () => {
      // Our system doesn't currently support dismissing individual toasts by ID
      // This would need to be implemented in the UI store if needed
    },
    
    // Promise helper
    promise: async <T,>(
      promise: Promise<T>,
      messages: {
        loading: string | { en: string; ar: string };
        success: string | { en: string; ar: string };
        error: string | { en: string; ar: string };
      },
      options?: ToastOptions
    ) => {
      // Show loading message
      const loadingToast = toast.loading(messages.loading);
      
      try {
        const result = await promise;
        loadingToast.dismiss();
        toast.success(messages.success);
        return result;
      } catch (err) {
        loadingToast.dismiss();
        toast.error(messages.error);
        throw err;
      }
    },
    
    // Loading toast (maps to info with a loading indicator concept)
    loading: (message: string | { en: string; ar: string }, options?: ToastOptions) => {
      showInfo(message, '');
      return { dismiss: () => {} } as ToastPromise;
    }
  };
  
  return toast;
};

// Export a default instance for direct usage (without hooks)
// This version accesses the store directly without hooks
const directToast = {
  success: (message: string | { en: string; ar: string }, options?: ToastOptions) => {
    const { showSuccess } = useUIStore.getState();
    showSuccess(message, '');
    return { dismiss: () => {} } as ToastPromise;
  },
  
  error: (message: string | { en: string; ar: string }, options?: ToastOptions) => {
    const { showError } = useUIStore.getState();
    showError(message, '');
    return { dismiss: () => {} } as ToastPromise;
  },
  
  warning: (message: string | { en: string; ar: string }, options?: ToastOptions) => {
    const { showWarning } = useUIStore.getState();
    showWarning(message, '');
    return { dismiss: () => {} } as ToastPromise;
  },
  
  info: (message: string | { en: string; ar: string }, options?: ToastOptions) => {
    const { showInfo } = useUIStore.getState();
    showInfo(message, '');
    return { dismiss: () => {} } as ToastPromise;
  },
  
  // For custom toasts, we'll map to our info notification
  custom: (content: React.ReactNode, options?: ToastOptions) => {
    const { showInfo } = useUIStore.getState();
    showInfo(typeof content === 'string' ? content : 'Custom notification', '');
    return { dismiss: () => {} } as ToastPromise;
  },
  
  // Dismiss all notifications
  dismiss: () => {
    // Our system doesn't currently support dismissing individual toasts by ID
    // This would need to be implemented in the UI store if needed
  },
  
  // Promise helper
  promise: async <T,>(
    promise: Promise<T>,
    messages: {
      loading: string | { en: string; ar: string };
      success: string | { en: string; ar: string };
      error: string | { en: string; ar: string };
    },
    options?: ToastOptions
  ) => {
    // Show loading message
    const loadingToast = directToast.loading(messages.loading);
    
    try {
      const result = await promise;
      loadingToast.dismiss();
      directToast.success(messages.success);
      return result;
    } catch (err) {
      loadingToast.dismiss();
      directToast.error(messages.error);
      throw err;
    }
  },
  
  // Loading toast (maps to info with a loading indicator concept)
  loading: (message: string | { en: string; ar: string }, options?: ToastOptions) => {
    const { showInfo } = useUIStore.getState();
    showInfo(message, '');
    return { dismiss: () => {} } as ToastPromise;
  }
};

// Export the default toast instance for direct usage
export default directToast;