import React from 'react';
import { Link } from 'react-router-dom';
import { useUIStore } from '@/store/uiStore';
import { Button } from '@/components/ui/Button';
import { Globe, Sun, Moon } from 'lucide-react';

interface AuthLayoutProps {
  children: React.ReactNode;
}

const AuthLayout: React.FC<AuthLayoutProps> = ({ children }) => {
  const { language, theme, setLanguage, setTheme } = useUIStore();

  const toggleLanguage = () => {
    setLanguage(language === 'en' ? 'ar' : 'en');
  };

  const toggleTheme = () => {
    setTheme(theme === 'light' ? 'dark' : 'light');
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-primary/5 via-background to-primary/5">
      {/* Header */}
      <header className="absolute top-0 left-0 right-0 z-10">
        <div className="flex items-center justify-between p-6">
          {/* Logo */}
          <Link to="/" className="flex items-center space-x-2">
            <svg
              className="h-8 w-8 text-primary"
              viewBox="0 0 100 100"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
            >
              <circle cx="50" cy="50" r="45" stroke="currentColor" strokeWidth="2" fill="none" opacity="0.3"/>
              <path d="M50 20 L35 35 L50 50 L65 35 Z" fill="currentColor"/>
              <path d="M35 35 L20 50 L35 65 L50 50 Z" fill="currentColor" opacity="0.8"/>
              <path d="M65 35 L80 50 L65 65 L50 50 Z" fill="currentColor" opacity="0.8"/>
              <path d="M35 65 L50 80 L65 65 L50 50 Z" fill="currentColor" opacity="0.6"/>
              <circle cx="50" cy="35" r="3" fill="currentColor"/>
              <circle cx="35" cy="50" r="3" fill="currentColor"/>
              <circle cx="65" cy="50" r="3" fill="currentColor"/>
              <circle cx="50" cy="65" r="3" fill="currentColor"/>
            </svg>
            <span className="text-xl font-bold text-foreground">
              {language === 'ar' ? 'نسبنا' : 'Nasabna'}
            </span>
          </Link>

          {/* Controls */}
          <div className="flex items-center space-x-2">
            {/* Theme toggle */}
            <Button
              variant="ghost"
              size="icon"
              onClick={toggleTheme}
              className="h-9 w-9"
            >
              {theme === 'light' ? (
                <Moon className="h-4 w-4" />
              ) : (
                <Sun className="h-4 w-4" />
              )}
            </Button>

            {/* Language toggle */}
            <Button
              variant="ghost"
              size="icon"
              onClick={toggleLanguage}
              className="h-9 w-9"
            >
              <Globe className="h-4 w-4" />
            </Button>
          </div>
        </div>
      </header>

      {/* Main content */}
      <div className="flex min-h-screen">
        {/* Left side - Branding */}
        <div className="hidden lg:flex lg:flex-1 lg:flex-col lg:justify-center lg:px-8">
          <div className="mx-auto max-w-md">
            <div className="text-center">
              <svg
                className="mx-auto h-24 w-24 text-primary mb-8"
                viewBox="0 0 100 100"
                fill="none"
                xmlns="http://www.w3.org/2000/svg"
              >
                <circle cx="50" cy="50" r="45" stroke="currentColor" strokeWidth="2" fill="none" opacity="0.3"/>
                <path d="M50 20 L35 35 L50 50 L65 35 Z" fill="currentColor"/>
                <path d="M35 35 L20 50 L35 65 L50 50 Z" fill="currentColor" opacity="0.8"/>
                <path d="M65 35 L80 50 L65 65 L50 50 Z" fill="currentColor" opacity="0.8"/>
                <path d="M35 65 L50 80 L65 65 L50 50 Z" fill="currentColor" opacity="0.6"/>
                <circle cx="50" cy="35" r="3" fill="currentColor"/>
                <circle cx="35" cy="50" r="3" fill="currentColor"/>
                <circle cx="65" cy="50" r="3" fill="currentColor"/>
                <circle cx="50" cy="65" r="3" fill="currentColor"/>
              </svg>
              
              <h1 className="text-3xl font-bold text-foreground mb-4">
                {language === 'ar' ? 'نسبنا' : 'Nasabna'}
              </h1>
              
              <p className="text-lg text-muted-foreground mb-8">
                {language === 'ar' 
                  ? 'اكتشف تاريخ عائلتك وابن شجرة نسبك مع منصتنا الشاملة'
                  : 'Discover your family history and build your genealogy with our comprehensive platform'
                }
              </p>

              {/* Features list */}
              <div className="space-y-4 text-left">
                <div className="flex items-center space-x-3">
                  <div className="flex-shrink-0 w-2 h-2 bg-primary rounded-full"></div>
                  <span className="text-sm text-muted-foreground">
                    {language === 'ar' ? 'دعم كامل للغة العربية' : 'Full Arabic language support'}
                  </span>
                </div>
                <div className="flex items-center space-x-3">
                  <div className="flex-shrink-0 w-2 h-2 bg-primary rounded-full"></div>
                  <span className="text-sm text-muted-foreground">
                    {language === 'ar' ? 'أشجار عائلة تفاعلية' : 'Interactive family trees'}
                  </span>
                </div>
                <div className="flex items-center space-x-3">
                  <div className="flex-shrink-0 w-2 h-2 bg-primary rounded-full"></div>
                  <span className="text-sm text-muted-foreground">
                    {language === 'ar' ? 'مشاركة آمنة مع العائلة' : 'Secure family sharing'}
                  </span>
                </div>
                <div className="flex items-center space-x-3">
                  <div className="flex-shrink-0 w-2 h-2 bg-primary rounded-full"></div>
                  <span className="text-sm text-muted-foreground">
                    {language === 'ar' ? 'حفظ الصور والوثائق' : 'Photo and document storage'}
                  </span>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Right side - Auth form */}
        <div className="flex flex-1 flex-col justify-center px-6 py-12 lg:px-8">
          <div className="mx-auto w-full max-w-md">
            {children}
          </div>
        </div>
      </div>

      {/* Footer */}
      <footer className="absolute bottom-0 left-0 right-0 p-6">
        <div className="text-center">
          <p className="text-xs text-muted-foreground">
            &copy; 2024 {language === 'ar' ? 'نسبنا' : 'Nasabna'}. {language === 'ar' ? 'جميع الحقوق محفوظة' : 'All rights reserved'}.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default AuthLayout;