  // Function to calculate generations based on parent-child relationships
  const calculateGenerations = (members: FamilyMember[], relationships: any[]): FamilyMember[] => {
    // Create a map of member IDs to member objects for easy lookup
    const memberMap = new Map<string, FamilyMember>();
    members.forEach(member => {
      memberMap.set(member.id, { ...member, generation: 1 }); // Default to generation 1
    });
    
    // Create a map of child IDs to their parent IDs
    const parentMap = new Map<string, string>();
    
    // Process relationships to find parent-child connections
    relationships.forEach(rel => {
      // Assuming the API returns relationships with personId and relatedPersonId
      // and a relationshipType field
      if (rel.relationshipType?.toLowerCase() === 'child') {
        // rel.personId is the parent, rel.relatedPersonId is the child
        parentMap.set(rel.relatedPersonId?.toString() || '', rel.personId?.toString() || '');
      } else if (rel.relationshipType?.toLowerCase() === 'parent') {
        // rel.personId is the child, rel.relatedPersonId is the parent
        parentMap.set(rel.personId?.toString() || '', rel.relatedPersonId?.toString() || '');
      }
    });
    
    // Find root members (those without parents)
    const rootMembers = members.filter(member => !parentMap.has(member.id));
    
    // Set generation for root members to 1
    rootMembers.forEach(member => {
      const updatedMember = memberMap.get(member.id);
      if (updatedMember) {
        updatedMember.generation = 1;
        memberMap.set(member.id, updatedMember);
      }
    });
    
    // Calculate generations for all other members using BFS
    const queue: { memberId: string; generation: number }[] = 
      rootMembers.map(member => ({ memberId: member.id, generation: 1 }));
    
    // Keep track of visited members to avoid infinite loops
    const visited = new Set<string>();
    rootMembers.forEach(member => visited.add(member.id));
    
    while (queue.length > 0) {
      const { memberId, generation } = queue.shift()!;
      
      // Find all children of this member
      parentMap.forEach((parentId, childId) => {
        if (parentId === memberId && !visited.has(childId)) {
          // This child belongs to the current member
          const childMember = memberMap.get(childId);
          if (childMember) {
            childMember.generation = generation + 1;
            memberMap.set(childId, childMember);
            visited.add(childId);
            queue.push({ memberId: childId, generation: generation + 1 });
          }
        }
      });
    }
    
    // Convert map back to array
    return Array.from(memberMap.values());
  };

