import React, { useState, useEffect } from 'react';
import { useUIStore } from '@/store/uiStore';
import { treeService } from '@/services/treeService';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Loader2 } from 'lucide-react';
import Modal from '@/components/ui/Modal';
import { useMobile } from '@/hooks/useMobile';

interface PersonFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (person: any) => void;
  familyTreeId: string;
  familyMembers: any[];
  initialData?: {
    id?: string;
    name?: string;
    gender?: 'male' | 'female' | 'unknown';
    birthDate?: string;
    deathDate?: string;
    birthPlace?: string;
    birthPlaceEn?: string;
    occupation?: string;
    occupationEn?: string;
    isAlive?: boolean;
  };
  initialRelationshipData?: {
    parentId: string;
    relationshipType: string;
  } | null;
  mode: 'create' | 'edit';
}

const PersonFormModal: React.FC<PersonFormModalProps> = ({ 
  isOpen, 
  onClose, 
  onSubmit,
  familyTreeId,
  familyMembers,
  initialData,
  initialRelationshipData,
  mode
}) => {
  const { language } = useUIStore();
  const { isMobile } = useMobile();
  const isRTL = language === 'ar';
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  
  const [formData, setFormData] = useState({
    name: initialData?.name || '',
    gender: initialData?.gender || 'male',
    birthDate: initialData?.birthDate || '',
    deathDate: initialData?.deathDate || '',
    birthPlace: initialData?.birthPlace || '',
    birthPlaceEn: initialData?.birthPlaceEn || '',
    occupation: initialData?.occupation || '',
    occupationEn: initialData?.occupationEn || '',
    isAlive: initialData?.isAlive !== undefined ? initialData.isAlive : true,
    parentId: initialRelationshipData?.parentId || '',
    relationshipType: initialRelationshipData?.relationshipType || ''
  });

  useEffect(() => {
    if (initialData) {
      setFormData(prev => ({
        ...prev,
        name: initialData.name || '',
        gender: initialData.gender || 'male',
        birthDate: initialData.birthDate || '',
        deathDate: initialData.deathDate || '',
        birthPlace: initialData.birthPlace || '',
        birthPlaceEn: initialData.birthPlaceEn || '',
        occupation: initialData.occupation || '',
        occupationEn: initialData.occupationEn || '',
        isAlive: initialData.isAlive !== undefined ? initialData.isAlive : true
      }));
    }
    
    // Set initial relationship data if provided
    if (initialRelationshipData) {
      setFormData(prev => ({
        ...prev,
        parentId: initialRelationshipData.parentId || '',
        relationshipType: initialRelationshipData.relationshipType || ''
      }));
    }
  }, [initialData, initialRelationshipData]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    
    try {
      // Validate required fields
      if (!formData.name.trim()) {
        throw new Error(isRTL ? 'يرجى إدخال اسم العضو' : 'Please enter a member name');
      }
      
      let result;
      if (mode === 'create') {
        // Create new person
        result = await treeService.addPersonToTree(
          formData.name,
          formData.birthDate || '', // Ensure we send empty string if undefined
          isRTL ? (formData.birthPlace || '') : (formData.birthPlaceEn || ''),
          isRTL ? (formData.occupation || '') : (formData.occupationEn || ''),
          formData.gender || 'unknown',
          formData.deathDate || '',
          !formData.isAlive, // Convert isAlive to isDeceased
          parseInt(familyTreeId)
        );
        
        // Add relationship if specified
        if (formData.parentId && formData.relationshipType) {
          try {
            let apiRelationshipType = '';
            switch (formData.relationshipType) {
              case 'father':
                apiRelationshipType = 'Father';
                break;
              case 'mother':
                apiRelationshipType = 'Mother';
                break;
              case 'spouse':
                apiRelationshipType = 'Spouse';
                break;
              case 'child':
                apiRelationshipType = 'Child';
                break;
              default:
                apiRelationshipType = formData.relationshipType;
            }
            
            await treeService.addRelationship(
              parseInt(formData.parentId),
              parseInt(result.id),
              apiRelationshipType
            );
          } catch (relationshipError) {
            // Removed console.error for error adding relationship
            // We don't want to fail the whole operation if relationship fails
          }
        }
      } else {
        // Edit existing person
        if (!initialData?.id) {
          throw new Error(isRTL ? 'حدث خطأ أثناء تحديث بيانات العضو. يرجى المحاولة مرة أخرى' : 'Error updating member data. Please try again');
        }
        
        // Removed logging: Updating person with data
        
        result = await treeService.updatePerson(
          parseInt(initialData.id),
          formData.name,
          formData.birthDate || '', // Ensure we send empty string if undefined
          isRTL ? (formData.birthPlace || '') : (formData.birthPlaceEn || ''),
          isRTL ? (formData.occupation || '') : (formData.occupationEn || ''),
          formData.gender || 'unknown',
          parseInt(familyTreeId) // Add familyTreeId parameter
        );
      }
      
      onSubmit(result);
      onClose();
    } catch (err: any) {
      // Removed console.error for error saving person
      let errorMessage = isRTL ? 'حدث خطأ أثناء حفظ بيانات العضو. يرجى المحاولة مرة أخرى' : 'Error saving member data. Please try again';
      
      // Handle specific error cases with user-friendly messages
      if (err.response?.status === 400) {
        errorMessage = isRTL ? 'يرجى التحقق من البيانات المدخلة' : 'Please check the entered data';
      } else if (err.response?.status === 401) {
        errorMessage = isRTL ? 'يجب تسجيل الدخول لتنفيذ هذا الإجراء' : 'You must be logged in to perform this action';
      } else if (err.response?.status === 403) {
        errorMessage = isRTL ? 'ليس لديك الصلاحية لتنفيذ هذا الإجراء' : 'You do not have permission to perform this action';
      } else if (err.response?.status === 404) {
        errorMessage = isRTL ? 'لم يتم العثور على العضو المطلوب' : 'The requested member was not found';
      } else if (err.response?.status === 500) {
        errorMessage = isRTL ? 'حدث خطأ في الخادم. يرجى المحاولة مرة أخرى لاحقًا' : 'Server error. Please try again later';
      } else if (err.message) {
        // Handle network errors and other client-side issues
        if (err.message.includes('Network Error')) {
          errorMessage = isRTL ? 'خطأ في الشبكة. يرجى التحقق من اتصالك بالإنترنت' : 'Network error. Please check your internet connection';
        } else if (err.message.includes('timeout')) {
          errorMessage = isRTL ? 'انتهت مهلة الطلب. يرجى المحاولة مرة أخرى' : 'Request timeout. Please try again';
        }
      }
      
      setError(errorMessage);
      // Removed alert for better UX - error is displayed in the UI
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={mode === 'create' 
        ? (isMobile ? (isRTL ? 'إضافة عضو' : 'Add Member') : (isRTL ? 'إضافة عضو جديد' : 'Add New Member'))
        : (isMobile ? (isRTL ? 'تعديل العضو' : 'Edit Member') : (isRTL ? 'تعديل العضو' : 'Edit Member'))}
      size={isMobile ? "xl" : "lg"}
    >
      <form onSubmit={handleSubmit} className="space-y-4">
        {error && (
          <div className="bg-destructive/10 border border-destructive/20 rounded-lg p-3">
            <p className="text-destructive text-sm">{error}</p>
          </div>
        )}
        
        <div className={`grid grid-cols-1 ${isMobile ? 'gap-3' : 'md:grid-cols-2 gap-4'}`}>
          <div className="space-y-2 md:col-span-2">
            <label className="text-sm font-medium">
              {isMobile ? (isRTL ? 'اسم العضو' : 'Member Name') : (isRTL ? 'اسم العضو *' : 'Member Name *')}
            </label>
            <Input
              value={formData.name}
              onChange={(e) => setFormData(prev => ({ ...prev, name: e.target.value }))}
              placeholder={isMobile ? (isRTL ? 'اسم العضو' : 'Member Name') : (isRTL ? 'اسم العضو' : 'Member Name')}
              required
              disabled={isLoading}
              className={isMobile ? 'text-sm py-2' : ''}
            />
          </div>
          
          <div className="space-y-2">
            <label className="text-sm font-medium">
              {isMobile ? (isRTL ? 'الجنس' : 'Gender') : (isRTL ? 'الجنس' : 'Gender')}
            </label>
            <select
              value={formData.gender}
              onChange={(e) => setFormData(prev => ({ ...prev, gender: e.target.value as any }))}
              className={`w-full px-3 py-2 border border-input rounded-md bg-background ${
                formData.gender === 'female' 
                  ? 'focus:ring-pink-500 focus:border-pink-500' 
                  : formData.gender === 'male' 
                    ? 'focus:ring-blue-500 focus:border-blue-500' 
                    : ''
              } ${isMobile ? 'text-sm py-2' : ''}`}
              disabled={isLoading}
            >
              <option value="male">{isRTL ? 'ذكر' : 'Male'}</option>
              <option value="female">{isRTL ? 'أنثى' : 'Female'}</option>
              <option value="unknown">{isRTL ? 'غير محدد' : 'Unknown'}</option>
            </select>
          </div>
          
          <div className="space-y-2">
            <label className="text-sm font-medium">
              {isMobile ? (isRTL ? 'تاريخ الميلاد' : 'Birth Date') : (isRTL ? 'تاريخ الميلاد' : 'Birth Date')}
            </label>
            <Input
              type="date"
              value={formData.birthDate}
              onChange={(e) => setFormData(prev => ({ ...prev, birthDate: e.target.value }))}
              disabled={isLoading}
              className={isMobile ? 'text-sm py-2' : ''}
            />
          </div>
          
          {!formData.isAlive && (
            <div className="space-y-2">
              <label className="text-sm font-medium">
                {isMobile ? (isRTL ? 'تاريخ الوفاة' : 'Death Date') : (isRTL ? 'تاريخ الوفاة' : 'Death Date')}
              </label>
              <Input
                type="date"
                value={formData.deathDate}
                onChange={(e) => setFormData(prev => ({ ...prev, deathDate: e.target.value }))}
                disabled={isLoading}
                className={isMobile ? 'text-sm py-2' : ''}
              />
            </div>
          )}
          
          <div className="space-y-2">
            <label className="text-sm font-medium">
              {isMobile ? (isRTL ? 'مكان الميلاد' : 'Birth Place') : (isRTL ? 'مكان الميلاد' : 'Birth Place')}
            </label>
            <Input
              value={isRTL ? formData.birthPlace : formData.birthPlaceEn}
              onChange={(e) => setFormData(prev => ({ 
                ...prev, 
                [isRTL ? 'birthPlace' : 'birthPlaceEn']: e.target.value 
              }))}
              placeholder={isMobile ? (isRTL ? 'مكان الميلاد' : 'Birth Place') : (isRTL ? 'مكان الميلاد' : 'Birth Place')}
              disabled={isLoading}
              className={isMobile ? 'text-sm py-2' : ''}
            />
          </div>
          
          <div className="space-y-2">
            <label className="text-sm font-medium">
              {isMobile ? (isRTL ? 'المهنة' : 'Occupation') : (isRTL ? 'المهنة' : 'Occupation')}
            </label>
            <Input
              value={isRTL ? formData.occupation : formData.occupationEn}
              onChange={(e) => setFormData(prev => ({ 
                ...prev, 
                [isRTL ? 'occupation' : 'occupationEn']: e.target.value 
              }))}
              placeholder={isMobile ? (isRTL ? 'المهنة' : 'Occupation') : (isRTL ? 'المهنة' : 'Occupation')}
              disabled={isLoading}
              className={isMobile ? 'text-sm py-2' : ''}
            />
          </div>
          
          <div className="space-y-2">
            <label className="text-sm font-medium">
              {isMobile ? (isRTL ? 'على قيد الحياة' : 'Alive') : (isRTL ? 'على قيد الحياة' : 'Alive')}
            </label>
            <div className="flex items-center">
              <input
                type="checkbox"
                checked={formData.isAlive}
                onChange={(e) => setFormData(prev => ({ ...prev, isAlive: e.target.checked }))}
                disabled={isLoading}
                className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`}
              />
              <span className={`ml-2 ${isMobile ? 'text-sm' : ''}`}>{isRTL ? 'نعم' : 'Yes'}</span>
            </div>
          </div>
        </div>
        
        {mode === 'create' && (
          <>
            <div className={`border-t pt-4 ${isMobile ? 'pt-3' : ''}`}>
              <h3 className={`font-medium mb-3 ${isMobile ? 'text-base' : ''}`}>
                {isMobile ? (isRTL ? 'العلاقات' : 'Relations') : (isRTL ? 'العلاقات' : 'Relationships')}
              </h3>
              
              <div className={`grid grid-cols-1 ${isMobile ? 'gap-3' : 'md:grid-cols-2 gap-4'}`}>
                <div className="space-y-2">
                  <label className="text-sm font-medium">
                    {isMobile ? (isRTL ? 'الوالد' : 'Parent') : (isRTL ? 'الوالد' : 'Parent')}
                  </label>
                  <select
                    value={formData.parentId}
                    onChange={(e) => setFormData(prev => ({ ...prev, parentId: e.target.value }))}
                    className={`w-full px-3 py-2 border border-input rounded-md bg-background ${isMobile ? 'text-sm py-2' : ''}`}
                    disabled={isLoading}
                  >
                    <option value="">{isMobile ? (isRTL ? 'اختر والد' : 'Select Parent') : (isRTL ? 'اختر والد' : 'Select Parent')}</option>
                    {familyMembers.map(member => (
                      <option key={member.id} value={member.id}>
                        {isRTL ? `${member.firstName} ${member.lastName}` : `${member.firstNameEn} ${member.lastNameEn}`}
                      </option>
                    ))}
                  </select>
                </div>
                
                <div className="space-y-2">
                  <label className="text-sm font-medium">
                    {isMobile ? (isRTL ? 'نوع العلاقة' : 'Relation Type') : (isRTL ? 'نوع العلاقة' : 'Relationship Type')}
                  </label>
                  <select
                    value={formData.relationshipType}
                    onChange={(e) => setFormData(prev => ({ ...prev, relationshipType: e.target.value }))}
                    className={`w-full px-3 py-2 border border-input rounded-md bg-background ${isMobile ? 'text-sm py-2' : ''}`}
                    disabled={isLoading || !formData.parentId}
                  >
                    <option value="">{isMobile ? (isRTL ? 'اختر نوع العلاقة' : 'Select Type') : (isRTL ? 'اختر نوع العلاقة' : 'Select Relationship Type')}</option>
                    <option value="father">{isRTL ? 'أب' : 'Father'}</option>
                    <option value="mother">{isRTL ? 'أم' : 'Mother'}</option>
                    <option value="spouse">{isRTL ? 'زوج/زوجة' : 'Spouse'}</option>
                    <option value="child">{isRTL ? 'طفل' : 'Child'}</option>
                  </select>
                </div>
              </div>
            </div>
          </>
        )}
        
        <div className={`flex ${isMobile ? 'flex-col gap-2' : 'gap-3 pt-4'}`}>
          <Button 
            type="submit" 
            className={`flex items-center gap-2 ${isMobile ? 'w-full' : ''}`}
            disabled={isLoading}
            size={isMobile ? "sm" : "default"}
          >
            {isLoading ? (
              <Loader2 className={`animate-spin ${isMobile ? 'h-3 w-3' : 'h-4 w-4'}`} />
            ) : null}
            {mode === 'create' 
              ? (isMobile ? (isRTL ? 'إضافة' : 'Add') : (isRTL ? 'إضافة العضو' : 'Add Member'))
              : (isMobile ? (isRTL ? 'حفظ' : 'Save') : (isRTL ? 'حفظ التغييرات' : 'Save Changes'))}
          </Button>
          <Button 
            variant="outline" 
            onClick={onClose}
            disabled={isLoading}
            type="button"
            className={isMobile ? 'w-full' : ''}
            size={isMobile ? "sm" : "default"}
          >
            {isMobile ? (isRTL ? 'إلغاء' : 'Cancel') : (isRTL ? 'إلغاء' : 'Cancel')}
          </Button>
        </div>
      </form>
    </Modal>
  );
};

export default PersonFormModal;