import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useAuthStore } from '@/store/authStore';
import { useUIStore } from '@/store/uiStore';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { User, Mail, Lock, Check, AlertCircle } from 'lucide-react';
import toast from 'react-hot-toast';
import bilingualToast from '@/utils/bilingualToast';
import { useMobile } from '@/hooks/useMobile';

// Create a function to generate the schema based on language
const getRegisterSchema = (language: 'en' | 'ar') => z.object({
  name: z.string().min(2, language === 'ar' ? 'يجب أن يكون الاسم مكوناً من حرفين على الأقل' : 'Name must be at least 2 characters'),
  email: z.string().email(language === 'ar' ? 'الرجاء إدخال عنوان بريد إلكتروني صحيح' : 'Please enter a valid email address'),
  password: z.string()
    .min(8, language === 'ar' ? 'يجب أن تكون كلمة المرور مكونة من 8 أحرف على الأقل' : 'Password must be at least 8 characters')
    .regex(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/, language === 'ar' ? 'يجب أن تحتوي كلمة المرور على حرف كبير وحرف صغير ورقم واحد على الأقل' : 'Password must contain at least one uppercase letter, one lowercase letter, and one number'),
  confirmPassword: z.string(),
  acceptTerms: z.boolean({
    required_error: language === 'ar' ? 'يجب أن توافق على الشروط والأحكام' : 'You must accept the terms and conditions'
  }).refine(val => val === true, {
    message: language === 'ar' ? 'يجب أن توافق على الشروط والأحكام' : 'You must accept the terms and conditions'
  }),
}).refine((data) => data.password === data.confirmPassword, {
  message: language === 'ar' ? "كلمات المرور غير متطابقة" : "Passwords don't match",
  path: ["confirmPassword"],
});

type RegisterFormData = z.infer<ReturnType<typeof getRegisterSchema>>;

const RegisterPage: React.FC = () => {
  const navigate = useNavigate();
  const { register: registerUser, isLoading } = useAuthStore();
  const { language } = useUIStore();
  const { isMobile } = useMobile();

  // Create schema based on current language
  const registerSchema = getRegisterSchema(language);

  const {
    register,
    handleSubmit,
    formState: { errors },
    watch,
  } = useForm<RegisterFormData>({
    resolver: zodResolver(registerSchema),
    defaultValues: {
      acceptTerms: false,
    },
  });

  const password = watch('password');
  const acceptTerms = watch('acceptTerms');

  const onSubmit = async (data: RegisterFormData) => {
    try {
      // Map the single name field to firstName for the API
      await registerUser({
        name: data.name,
        firstName: data.name,
        lastName: '', // Keep empty for API compatibility
        email: data.email,
        password: data.password,
        confirmPassword: data.confirmPassword,
        language: language,
        acceptTerms: data.acceptTerms,
      });
      bilingualToast.success({
        en: 'Account created successfully',
        ar: 'تم إنشاء الحساب بنجاح'
      });
      navigate('/dashboard');
    } catch (error: any) {
      // Check if the error is related to username uniqueness
      if (error?.message?.includes('username') || error?.message?.includes('Username')) {
        bilingualToast.error({
          en: 'This username is already taken. Please choose another one.',
          ar: 'اسم المستخدم مأخوذ بالفعل. يرجى اختيار اسم آخر.'
        });
      } else {
        const message = error?.message || (language === 'ar' ? 'حدث خطأ أثناء إنشاء الحساب' : 'Registration failed');
        bilingualToast.error({
          en: message,
          ar: message
        });
      }
    }
  };

  // Password strength indicator
  const getPasswordStrength = (password: string) => {
    if (!password) return { strength: 0, label: '' };
    
    let strength = 0;
    const checks = [
      password.length >= 8,
      /[a-z]/.test(password),
      /[A-Z]/.test(password),
      /\d/.test(password),
      /[!@#$%^&*(),.?":{}|<>]/.test(password),
    ];
    
    strength = checks.filter(Boolean).length;
    
    const labels = {
      en: ['Very Weak', 'Weak', 'Fair', 'Good', 'Strong'],
      ar: ['ضعيف جداً', 'ضعيف', 'متوسط', 'جيد', 'قوي'],
    };
    
    return {
      strength,
      label: labels[language][Math.max(0, strength - 1)] || '',
    };
  };

  const passwordStrength = getPasswordStrength(password || '');

  return (
    <Card className={`w-full ${isMobile ? 'max-w-md mx-4' : 'max-w-md'}`}>
      <CardHeader className="space-y-1">
        <CardTitle className={`text-2xl font-bold text-center ${isMobile ? 'text-xl' : ''}`}>
          {language === 'ar' ? 'إنشاء حساب جديد' : 'Create Account'}
        </CardTitle>
        <CardDescription className="text-center">
          {language === 'ar' 
            ? 'أدخل بياناتك لإنشاء حساب جديد'
            : 'Enter your information to create a new account'
          }
        </CardDescription>
      </CardHeader>
      
      <CardContent>
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          {/* Name field */}
          <div className="space-y-2">
            <Input
              {...register('name')}
              placeholder={language === 'ar' ? 'الاسم الكامل' : 'Full name'}
              leftIcon={<User className="h-4 w-4" />}
              error={errors.name?.message}
              disabled={isLoading}
              className={isMobile ? 'text-sm' : ''}
            />
            {/* Note about name uniqueness */}
            <div className="flex items-start space-x-2">
              <AlertCircle className="h-4 w-4 text-muted-foreground flex-shrink-0 mt-0.5" />
              <p className="text-sm text-muted-foreground">
                {language === 'ar' 
                  ? 'يجب أن يكون الاسم فريدًا' 
                  : 'Name should be unique'}
              </p>
            </div>
          </div>

          {/* Email field */}
          <Input
            {...register('email')}
            type="email"
            placeholder={language === 'ar' ? 'البريد الإلكتروني' : 'Email address'}
            leftIcon={<Mail className="h-4 w-4" />}
            error={errors.email?.message}
            disabled={isLoading}
            className={isMobile ? 'text-sm' : ''}
          />

          {/* Password field */}
          <div className="space-y-2">
            <Input
              {...register('password')}
              type="password"
              placeholder={language === 'ar' ? 'كلمة المرور' : 'Password'}
              leftIcon={<Lock className="h-4 w-4" />}
              showPasswordToggle
              error={errors.password?.message}
              disabled={isLoading}
              className={isMobile ? 'text-sm' : ''}
            />
            
            {/* Password strength indicator */}
            {password && (
              <div className="space-y-2">
                <div className="flex items-center space-x-2">
                  <div className="flex-1 bg-muted rounded-full h-2">
                    <div
                      className={`h-2 rounded-full transition-all duration-300 ${
                        passwordStrength.strength <= 2 
                          ? 'bg-destructive' 
                          : passwordStrength.strength <= 3 
                          ? 'bg-yellow-500' 
                          : 'bg-green-500'
                      }`}
                      style={{ width: `${(passwordStrength.strength / 5) * 100}%` }}
                    />
                  </div>
                  <span className={`text-xs text-muted-foreground min-w-0 ${isMobile ? 'text-xs' : ''}`}>
                    {passwordStrength.label}
                  </span>
                </div>
              </div>
            )}
          </div>

          {/* Confirm password field */}
          <Input
            {...register('confirmPassword')}
            type="password"
            placeholder={language === 'ar' ? 'تأكيد كلمة المرور' : 'Confirm password'}
            leftIcon={<Lock className="h-4 w-4" />}
            showPasswordToggle
            error={errors.confirmPassword?.message}
            disabled={isLoading}
            className={isMobile ? 'text-sm' : ''}
          />

          {/* Terms and conditions */}
          <div className={`flex items-start space-x-2 ${isMobile ? 'text-sm' : ''}`}>
            <div className="flex items-center h-5">
              <input
                {...register('acceptTerms')}
                type="checkbox"
                className="h-4 w-4 rounded border-border text-primary focus:ring-primary focus:ring-offset-0"
                disabled={isLoading}
              />
            </div>
            <div className="text-sm">
              <label className="text-muted-foreground">
                {language === 'ar' ? 'أوافق على ' : 'I agree to the '}
                <Link to="/terms" className="text-primary hover:text-primary/80 underline">
                  {language === 'ar' ? 'الشروط والأحكام' : 'Terms and Conditions'}
                </Link>
                {language === 'ar' ? ' و' : ' and '}
                <Link to="/privacy" className="text-primary hover:text-primary/80 underline">
                  {language === 'ar' ? 'سياسة الخصوصية' : 'Privacy Policy'}
                </Link>
              </label>
              {errors.acceptTerms && (
                <p className="text-sm text-destructive mt-1">
                  {errors.acceptTerms.message}
                </p>
              )}
            </div>
          </div>

          {/* Submit button */}
          <Button
            type="submit"
            className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}
            loading={isLoading}
            loadingText={language === 'ar' ? 'جاري إنشاء الحساب...' : 'Creating account...'}
            disabled={!acceptTerms}
          >
            {language === 'ar' ? 'إنشاء الحساب' : 'Create Account'}
          </Button>
        </form>

        {/* Divider */}
        <div className="relative my-6">
          <div className="absolute inset-0 flex items-center">
            <span className="w-full border-t border-border" />
          </div>
          <div className="relative flex justify-center text-xs uppercase">
            <span className="bg-background px-2 text-muted-foreground">
              {language === 'ar' ? 'أو' : 'or'}
            </span>
          </div>
        </div>

        {/* Sign in link */}
        <div className={`text-center ${isMobile ? 'text-sm' : ''}`}>
          <p className="text-sm text-muted-foreground">
            {language === 'ar' ? 'لديك حساب بالفعل؟ ' : 'Already have an account? '}
            <Link
              to="/login"
              className="text-primary hover:text-primary/80 underline font-medium"
            >
              {language === 'ar' ? 'تسجيل الدخول' : 'Sign in'}
            </Link>
          </p>
        </div>
      </CardContent>
    </Card>
  );
};

export default RegisterPage;