import React, { useState, useEffect } from 'react';
import { useUIStore } from '@/store/uiStore';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { toast } from 'react-hot-toast';
import bilingualToast from '@/utils/bilingualToast';
import { 
  Users, 
  Clock, 
  CheckCircle, 
  XCircle, 
  UserCheck, 
  UserX,
  Calendar,
  MapPin,
  Briefcase,
  Loader2,
  AlertCircle
} from 'lucide-react';
import { apiService } from '@/services/api';

interface JoinRequest {
  id: number;
  familyTreeId: number;
  name: string;
  birthDate: string;
  birthPlace: string;
  gender: string;
  occupation: string;
  relatedPersonId: number;
  status: string;
  requesterId: string;
  relationshipType: string;
  createdAt: string;
}

const ManageJoinRequestsPage: React.FC = () => {
  const { language } = useUIStore();
  const [requests, setRequests] = useState<JoinRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetchJoinRequests();
  }, []);

  const fetchJoinRequests = async () => {
    try {
      setLoading(true);
      setError(null);
      
      // Fetch all join requests for admin
      const response = await apiService.getAllJoinRequests();
      
      // Handle response correctly
      let allRequests: any[] = [];
      if (Array.isArray(response)) {
        allRequests = response;
      } else if (response && typeof response === 'object' && 'data' in response) {
        allRequests = Array.isArray(response.data) ? response.data : [];
      } else {
        allRequests = [];
      }
      
      // Process requests with proper mapping
      const processedRequests: JoinRequest[] = allRequests.map(request => {
        // Extract fields with proper handling of different naming conventions
        const id = request.id ?? request.Id ?? request['ID'] ?? 0;
        const familyTreeId = request.familyTreeId ?? request.FamilyTreeId ?? 0;
        const name = request.name ?? request.Name ?? '';
        const birthDate = request.birthDate ?? request.BirthDate ?? '';
        const birthPlace = request.birthPlace ?? request.BirthPlace ?? '';
        const gender = request.gender ?? request.Gender ?? '';
        const occupation = request.occupation ?? request.Occupation ?? '';
        const relatedPersonId = request.relatedPersonId ?? request.RelatedPersonId ?? 0;
        const status = request.status ?? request.Status ?? 'Pending';
        const requesterId = request.requesterId ?? request.RequesterId ?? '';
        const relationshipType = request.relationshipType ?? request.RelationshipType ?? '';
        const createdAt = request.createdAt ?? request.CreatedAt ?? new Date().toISOString();
        
        return {
          id,
          familyTreeId,
          name,
          birthDate,
          birthPlace,
          gender,
          occupation,
          relatedPersonId,
          status,
          requesterId,
          relationshipType,
          createdAt
        };
      }).filter(request => request.id > 0); // Only include requests with valid IDs
      
      setRequests(processedRequests);
    } catch (error: any) {
      // Removed console.error for failed to fetch join requests
      setError(language === 'ar' ? 'فشل في تحميل طلبات الانضمام' : 'Failed to load join requests');
    } finally {
      setLoading(false);
    }
  };

  const acceptRequest = async (id: number) => {
    try {
      await apiService.acceptJoinRequest(id);
      bilingualToast.success({
        en: 'Request accepted successfully',
        ar: 'تم قبول الطلب بنجاح'
      });
      // Refresh the requests list
      fetchJoinRequests();
    } catch (error: any) {
      // Removed console.error for failed to accept request
      bilingualToast.error({
        en: 'Failed to accept request',
        ar: 'فشل في قبول الطلب'
      });
    }
  };

  const rejectRequest = async (id: number) => {
    try {
      await apiService.rejectJoinRequest(id);
      bilingualToast.success({
        en: 'Request rejected successfully',
        ar: 'تم رفض الطلب بنجاح'
      });
      // Refresh the requests list
      fetchJoinRequests();
    } catch (error: any) {
      // Removed console.error for failed to reject request
      bilingualToast.error({
        en: 'Failed to reject request',
        ar: 'فشل في رفض الطلب'
      });
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status.toLowerCase()) {
      case 'pending':
        return (
          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-yellow-100 text-yellow-800">
            <Clock className="h-3 w-3 mr-1" />
            {language === 'ar' ? 'قيد الانتظار' : 'Pending'}
          </span>
        );
      case 'accepted':
        return (
          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
            <CheckCircle className="h-3 w-3 mr-1" />
            {language === 'ar' ? 'مقبول' : 'Accepted'}
          </span>
        );
      case 'rejected':
        return (
          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-800">
            <XCircle className="h-3 w-3 mr-1" />
            {language === 'ar' ? 'مرفوض' : 'Rejected'}
          </span>
        );
      default:
        return (
          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800">
            {status}
          </span>
        );
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="h-12 w-12 animate-spin text-primary" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="text-center">
          <div className="mx-auto w-16 h-16 bg-destructive/10 rounded-full flex items-center justify-center mb-4">
            <AlertCircle className="h-8 w-8 text-destructive" />
          </div>
          <h2 className="text-2xl font-bold text-destructive mb-4">
            {error}
          </h2>
          <Button onClick={fetchJoinRequests}>
            {language === 'ar' ? 'إعادة المحاولة' : 'Try Again'}
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-2xl font-bold">
          {language === 'ar' ? 'إدارة طلبات الانضمام' : 'Manage Join Requests'}
        </h1>
        <Button onClick={fetchJoinRequests} variant="outline" size="sm">
          {language === 'ar' ? 'تحديث' : 'Refresh'}
        </Button>
      </div>
      
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Users className="h-5 w-5" />
            {language === 'ar' ? 'إدارة طلبات الانضمام' : 'Manage Join Requests'}
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {requests.length === 0 ? (
              <div className="text-center py-12">
                <Users className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                <h3 className="text-lg font-medium mb-1">
                  {language === 'ar' ? 'لا توجد طلبات' : 'No Requests Found'}
                </h3>
                <p className="text-muted-foreground">
                  {language === 'ar' ? 'لا توجد طلبات انضمام حالياً' : 'No join requests found currently'}
                </p>
              </div>
            ) : (
              requests.map((request) => (
                <div key={request.id} className="border rounded-lg p-4">
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-2">
                        <h3 className="font-medium">{request.name}</h3>
                        {getStatusBadge(request.status)}
                      </div>
                      
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
                        <div className="flex items-center gap-2">
                          <Calendar className="h-4 w-4 text-muted-foreground" />
                          <span>
                            {new Date(request.birthDate).toLocaleDateString(language === 'ar' ? 'ar-SA' : 'en-US')}
                          </span>
                        </div>
                        
                        <div className="flex items-center gap-2">
                          <MapPin className="h-4 w-4 text-muted-foreground" />
                          <span>{request.birthPlace}</span>
                        </div>
                        
                        <div className="flex items-center gap-2">
                          <Briefcase className="h-4 w-4 text-muted-foreground" />
                          <span>{request.occupation}</span>
                        </div>
                        
                        <div className="flex items-center gap-2">
                          <Users className="h-4 w-4 text-muted-foreground" />
                          <span>{request.relationshipType}</span>
                        </div>
                      </div>
                      
                      <div className="mt-2 text-xs text-muted-foreground">
                        {language === 'ar' ? 'طلب بواسطة:' : 'Requested by:'} {request.requesterId}
                      </div>
                      
                      <div className="mt-1 text-xs text-muted-foreground">
                        {language === 'ar' ? 'معرف الشجرة:' : 'Tree ID:'} {request.familyTreeId}
                      </div>
                    </div>
                    
                    {request.status.toLowerCase() === 'pending' && (
                      <div className="flex gap-2">
                        <Button
                          variant="default"
                          size="sm"
                          onClick={() => acceptRequest(request.id)}
                          className="flex items-center gap-1"
                        >
                          <UserCheck className="h-4 w-4" />
                          {language === 'ar' ? 'قبول' : 'Accept'}
                        </Button>
                        <Button
                          variant="destructive"
                          size="sm"
                          onClick={() => rejectRequest(request.id)}
                          className="flex items-center gap-1"
                        >
                          <UserX className="h-4 w-4" />
                          {language === 'ar' ? 'رفض' : 'Reject'}
                        </Button>
                      </div>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

export default ManageJoinRequestsPage;