import React from 'react';
import { Link } from 'react-router-dom';
import { Button } from '@/components/ui/Button';
import { useUIStore } from '@/store/uiStore';
import { Home, ArrowLeft } from 'lucide-react';

const NotFoundPage: React.FC = () => {
  const { language } = useUIStore();

  return (
    <div className="min-h-screen flex items-center justify-center bg-background px-4">
      <div className="max-w-md w-full text-center">
        {/* 404 Illustration */}
        <div className="mb-8">
          <div className="mx-auto w-32 h-32 bg-primary/10 rounded-full flex items-center justify-center mb-6">
            <svg
              className="w-16 h-16 text-primary"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M9.172 16.172a4 4 0 015.656 0M9 12h6m-6-4h6m2 5.291A7.962 7.962 0 0112 15c-2.34 0-4.291-1.007-5.691-2.709M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9"
              />
            </svg>
          </div>
          
          <h1 className="text-6xl font-bold text-primary mb-4">404</h1>
        </div>

        {/* Error message */}
        <div className="mb-8">
          <h2 className="text-2xl font-semibold text-foreground mb-4">
            {language === 'ar' ? 'الصفحة غير موجودة' : 'Page Not Found'}
          </h2>
          <p className="text-muted-foreground mb-6">
            {language === 'ar' 
              ? 'عذراً، الصفحة التي تبحث عنها غير موجودة أو تم نقلها إلى مكان آخر.'
              : "Sorry, the page you're looking for doesn't exist or has been moved to another location."
            }
          </p>
        </div>

        {/* Action buttons */}
        <div className="space-y-4">
          <Button asChild className="w-full">
            <Link to="/">
              <Home className="w-4 h-4 mr-2" />
              {language === 'ar' ? 'العودة للرئيسية' : 'Go Home'}
            </Link>
          </Button>
          
          <Button asChild variant="outline" className="w-full">
            <Link to="#" onClick={() => window.history.back()}>
              <ArrowLeft className="w-4 h-4 mr-2" />
              {language === 'ar' ? 'العودة للخلف' : 'Go Back'}
            </Link>
          </Button>
        </div>

        {/* Help text */}
        <div className="mt-8 pt-8 border-t border-border">
          <p className="text-sm text-muted-foreground">
            {language === 'ar' 
              ? 'إذا كنت تعتقد أن هذا خطأ، يرجى '
              : 'If you think this is an error, please '
            }
            <Link 
              to="/contact" 
              className="text-primary hover:text-primary/80 underline"
            >
              {language === 'ar' ? 'اتصل بنا' : 'contact us'}
            </Link>
            .
          </p>
        </div>
      </div>
    </div>
  );
};

export default NotFoundPage;