import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useUIStore } from '@/store/uiStore';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';
import { 
  Star,
  Check,
  TreePine,
  Globe
} from 'lucide-react';

const SubscriptionPlansPage: React.FC = () => {
  const navigate = useNavigate();
  const { language } = useUIStore();
  const [billingCycle, setBillingCycle] = useState<'monthly' | 'yearly'>('yearly');
  const [selectedPlan, setSelectedPlan] = useState<string>('');
  const [currency, setCurrency] = useState<'USD' | 'EGP' | 'AED' | 'SAR'>('USD');

  const isRTL = language === 'ar';

  // Currency conversion rates (approximate)
  const currencyRates = {
    USD: 1,
    EGP: 30.9, // 1 USD ≈ 30.9 EGP
    AED: 3.67, // 1 USD ≈ 3.67 AED
    SAR: 3.75  // 1 USD ≈ 3.75 SAR
  };

  // Currency symbols
  const currencySymbols = {
    USD: '$',
    EGP: 'E£',
    AED: 'د.إ',
    SAR: 'ر.س'
  };

  // Plans data with monthly/yearly pricing
  const plans = [
    {
      id: 'basic',
      name: 'Basic',
      nameAr: 'أساسي',
      price: {
        monthly: 9.99,
        yearly: 99.99
      },
      period: '/month',
      periodAr: '/شهر',
      periodYearly: '/year',
      periodYearlyAr: '/سنة',
      description: 'Perfect for individuals',
      descriptionAr: 'مثالي للأفراد',
      features: [
        '1 family tree',
        'Up to 5 people per tree',
        '1GB storage',
        'Email support'
      ],
      featuresAr: [
        'شجرة عائلة واحدة',
        'حتى 5 أشخاص لكل شجرة',
        '1 جيجابايت تخزين',
        'دعم البريد الإلكتروني'
      ],
      popular: false,
    },
    {
      id: 'premium',
      name: 'Premium',
      nameAr: 'مميز',
      price: {
        monthly: 19.99,
        yearly: 199.99
      },
      period: '/month',
      periodAr: '/شهر',
      periodYearly: '/year',
      periodYearlyAr: '/سنة',
      description: 'Great for growing families',
      descriptionAr: 'رائع للعائلات المتنامية',
      features: [
        '3 family trees',
        'Up to 150 people per tree',
        '10GB storage',
        'Smart suggestions',
        'Priority support'
      ],
      featuresAr: [
        '3 أشجار عائلة',
        'حتى 150 شخص لكل شجرة',
        '10 جيجابايت تخزين',
        'اقتراحات ذكية',
        'دعم أولوية'
      ],
      popular: true,
    },
    {
      id: 'family',
      name: 'Family',
      nameAr: 'عائلي',
      price: {
        monthly: 29.99,
        yearly: 299.99
      },
      period: '/month',
      periodAr: '/شهر',
      periodYearly: '/year',
      periodYearlyAr: '/سنة',
      description: 'Perfect for large families',
      descriptionAr: 'مثالي للعائلات الكبيرة',
      features: [
        'Unlimited trees & people',
        'Unlimited storage',
        'Smart suggestions',
        'Priority support',
        'Custom themes',
        'Advanced search'
      ],
      featuresAr: [
        'أشجار وأشخاص غير محدودة',
        'تخزين غير محدود',
        'اقتراحات ذكية',
        'دعم أولوية',
        'سمات مخصصة',
        'بحث متقدم'
      ],
      popular: false,
    },
  ];

  const handleSelectPlan = (planId: string) => {
    setSelectedPlan(planId);
    // الانتقال لصفحة الدفع
    navigate(`/subscription/checkout?plan=${planId}&billing=${billingCycle}`);
  };

  const convertPrice = (price: number) => {
    if (price === 0) return 0;
    return price * currencyRates[currency];
  };

  const formatPrice = (price: number) => {
    if (price === 0) return isRTL ? 'مجاني' : 'Free';
    const convertedPrice = convertPrice(price);
    return `${currencySymbols[currency]}${convertedPrice.toFixed(2)}`;
  };

  const getPeriod = () => {
    if (billingCycle === 'monthly') {
      return isRTL ? '/شهر' : '/month';
    }
    return isRTL ? '/سنة' : '/year';
  };

  return (
    <div className="space-y-8 py-8">
      {/* Header */}
      <div className="text-center space-y-4">
        <h1 className="text-3xl font-bold tracking-tight text-foreground">
          {isRTL ? 'اختر خطتك' : 'Choose Your Plan'}
        </h1>
        <p className="text-lg text-muted-foreground max-w-2xl mx-auto">
          {isRTL 
            ? 'اختر الخطة التي تناسب احتياجات عائلتك. جميع الخطط تشمل ميزاتنا الأساسية.'
            : 'Choose the plan that fits your family needs. All plans include our core features.'}
        </p>
      </div>

      {/* Currency and Billing Toggle */}
      <div className="flex flex-col items-center gap-4">
        {/* Currency Selector */}
        <div className="flex items-center gap-2">
          <Globe className="h-5 w-5 text-muted-foreground" />
          <select
            value={currency}
            onChange={(e) => setCurrency(e.target.value as 'USD' | 'EGP' | 'AED' | 'SAR')}
            className="border rounded-md px-3 py-2 text-sm bg-background text-foreground border-input"
          >
            <option value="USD">USD ($)</option>
            <option value="EGP">EGP (E£)</option>
            <option value="AED">AED (د.إ)</option>
            <option value="SAR">SAR (ر.س)</option>
          </select>
        </div>

        {/* Billing Toggle */}
        <div className="inline-flex items-center rounded-full bg-muted p-1">
          <button
            onClick={() => setBillingCycle('monthly')}
            className={`px-4 py-2 text-sm font-medium rounded-full transition-colors ${
              billingCycle === 'monthly'
                ? 'bg-background text-foreground shadow-sm'
                : 'text-muted-foreground hover:text-foreground'
            }`}
          >
            {isRTL ? 'شهري' : 'Monthly'}
          </button>
          <button
            onClick={() => setBillingCycle('yearly')}
            className={`px-4 py-2 text-sm font-medium rounded-full transition-colors relative ${
              billingCycle === 'yearly'
                ? 'bg-background text-foreground shadow-sm'
                : 'text-muted-foreground hover:text-foreground'
            }`}
          >
            {isRTL ? 'سنوي' : 'Yearly'}
            <Badge className="absolute -top-2 -right-2 bg-green-500 text-white text-xs">
              {isRTL ? 'وفر 20%' : 'Save 20%'}
            </Badge>
          </button>
        </div>
      </div>

      {/* Plans Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-5xl mx-auto">
        {plans.map((plan) => (
          <Card 
            key={plan.id} 
            className={`relative ${plan.popular ? 'ring-2 ring-primary shadow-lg scale-105' : ''}`}
          >
            {plan.popular && (
              <div className={`absolute -top-4 left-1/2 transform -translate-x-1/2 ${isRTL ? 'flex-row-reverse' : ''}`}>
                <div className="bg-primary text-primary-foreground px-4 py-1 rounded-full text-sm font-medium flex items-center">
                  <Star className={`h-4 w-4 ${isRTL ? 'ml-1' : 'mr-1'}`} />
                  {isRTL ? 'الأكثر شعبية' : 'Most Popular'}
                </div>
              </div>
            )}
            
            <CardHeader className="text-center">
              <CardTitle className="text-2xl">
                {isRTL ? plan.nameAr : plan.name}
              </CardTitle>
              <div className="mt-4">
                <span className="text-4xl font-bold text-foreground">
                  {formatPrice(billingCycle === 'monthly' ? plan.price.monthly : plan.price.yearly)}
                </span>
                <span className="text-muted-foreground">
                  {getPeriod()}
                </span>
              </div>
              <CardDescription className="mt-2">
                {isRTL ? plan.descriptionAr : plan.description}
              </CardDescription>
            </CardHeader>
            
            <CardContent>
              <ul className="space-y-3 mb-8">
                {(isRTL ? plan.featuresAr : plan.features).map((feature, featureIndex) => (
                  <li key={featureIndex} className="flex items-center">
                    <Check className={`h-5 w-5 text-primary ${isRTL ? 'ml-3' : 'mr-3'} flex-shrink-0`} />
                    <span className="text-sm">{feature}</span>
                  </li>
                ))}
              </ul>
              
              <Button 
                asChild 
                className="w-full" 
                variant={plan.popular ? 'default' : 'outline'}
              >
                <Link to={`/subscription/checkout?plan=${plan.id}&billing=${billingCycle}`}>
                  {isRTL ? 'اختر الخطة' : 'Choose Plan'}
                </Link>
              </Button>
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
};

export default SubscriptionPlansPage;