// Use environment variable for baseURL to work in both development and production
const apiClient: AxiosInstance = axios.create({
  baseURL: import.meta.env.VITE_API_BASE_URL || 'https://qabael.premiumasp.net/api', // Use env var or fallback to direct API URL
  timeout: 30000, // Increased timeout to 30 seconds
  headers: {
    'Content-Type': 'application/json',
  },
  // Add resource management settings
  maxRedirects: 5,
  maxContentLength: 50 * 1024 * 1024, // 50MB max content length
  maxBodyLength: 50 * 1024 * 1024, // 50MB max body length
});

// Create a separate client for public endpoints that don't require authentication
const publicApiClient: AxiosInstance = axios.create({
  baseURL: import.meta.env.VITE_API_BASE_URL || 'https://qabael.premiumasp.net/api',
  timeout: 30000,
  headers: {
    'Content-Type': 'application/json',
  },
  maxRedirects: 5,
  maxContentLength: 50 * 1024 * 1024,
  maxBodyLength: 50 * 1024 * 1024,
});

// Request interceptor for public client - no auth token
publicApiClient.interceptors.request.use(
  (config) => {
    // Log request details for debugging
    // Removed console.log for public API request
    return config;
  },
  (error) => {
    // Removed console.error for public API request error
    return Promise.reject(error);
  }
);

// Response interceptor for public client
publicApiClient.interceptors.response.use(
  (response: AxiosResponse) => {
    // Removed console.log for public API response
    return response;
  },
  (error) => {
    // Removed console.error for public API response error
    if (error.response) {
      // Removed console.error statements for error response data
    } else if (error.request) {
      // Removed console.error for error request
    } else {
      // Removed console.error for error message
    }
    return Promise.reject(error);
  }
);

// Request interceptor to add auth token
apiClient.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('authToken');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    // Request details are handled internally
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Response interceptor to handle errors
apiClient.interceptors.response.use(
  (response: AxiosResponse) => {
    return response;
  },
  (error) => {
    if (error.response?.status === 401) {
      // Handle unauthorized access
      localStorage.removeItem('authToken');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

