import React, { useState, useEffect } from 'react';
import { useUIStore } from '@/store/uiStore';
import { useAuthStore } from '@/store/authStore';
import { useMobile } from '@/hooks/useMobile'; // Added import for mobile detection
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';
import { Input } from '@/components/ui/Input';
import { Textarea } from '@/components/ui/Textarea';
import { 
  Settings, 
  Save, 
  Globe,
  Moon,
  Sun,
  Bell,
  Shield,
  Database,
  Download,
  Upload,
  Trash2,
  Eye,
  EyeOff,
  Lock,
  Unlock,
  Palette,
  Languages,
  Volume2,
  VolumeX,
  Smartphone,
  Monitor,
  Tablet,
  Wifi,
  WifiOff,
  RefreshCw,
  AlertTriangle,
  Check,
  Info,
  User,
  Mail,
  Phone,
  MapPin,
  Calendar,
  Clock,
  Zap,
  HardDrive,
  Cloud,
  FileText,
  Image,
  Video,
  Edit,
  Loader2
} from 'lucide-react';
import { useNotifications } from '@/utils/notifications';

interface AppSettings {
  language: 'ar' | 'en';
  theme: 'light' | 'dark' | 'system';
  notifications: {
    email: boolean;
    push: boolean;
    sound: boolean;
    familyUpdates: boolean;
    newMembers: boolean;
    birthdays: boolean;
    anniversaries: boolean;
  };
  privacy: {
    profileVisibility: 'public' | 'family' | 'private';
    allowSearch: boolean;
    showOnlineStatus: boolean;
    allowDirectMessages: boolean;
  };
  display: {
    dateFormat: 'dd/mm/yyyy' | 'mm/dd/yyyy' | 'yyyy-mm-dd';
    timeFormat: '12h' | '24h';
    fontSize: 'small' | 'medium' | 'large';
    compactMode: boolean;
  };
  backup: {
    autoBackup: boolean;
    backupFrequency: 'daily' | 'weekly' | 'monthly';
    cloudSync: boolean;
  };
}

const SettingsPage: React.FC = () => {
  const { isMobile } = useMobile(); // Added mobile detection hook
  const { language, setLanguage, theme, setTheme } = useUIStore(); // Added setTheme to destructuring
  const { success: notifySuccess, error: notifyError } = useNotifications();
  const { user, updateNotificationSettings, updatePrivacySettings } = useAuthStore();
  const [activeTab, setActiveTab] = useState<'general' | 'notifications' | 'privacy' | 'display' | 'backup' | 'account'>('general');
  const [hasChanges, setHasChanges] = useState(false);
  const [saving, setSaving] = useState(false);

  const isRTL = language === 'ar';

  // Initialize settings with user data and UI store values
  const [settings, setSettings] = useState<AppSettings>({
    language: language,
    theme: theme === 'auto' ? 'system' : theme,
    notifications: {
      email: user?.notifications?.email?.newSuggestions ?? true,
      push: user?.notifications?.push?.enabled ?? true,
      sound: true,
      familyUpdates: true,
      newMembers: true,
      birthdays: true,
      anniversaries: true
    },
    privacy: {
      profileVisibility: user?.privacy?.profileVisibility ?? 'family',
      allowSearch: user?.privacy?.allowSearchEngines ?? true,
      showOnlineStatus: user?.privacy?.showOnlineStatus ?? true,
      allowDirectMessages: true
    },
    display: {
      dateFormat: 'dd/mm/yyyy',
      timeFormat: '24h',
      fontSize: 'medium',
      compactMode: false
    },
    backup: {
      autoBackup: true,
      backupFrequency: 'weekly',
      cloudSync: true
    }
  });

  // Update settings when user data or UI store changes
  useEffect(() => {
    if (user) {
      setSettings(prev => ({
        ...prev,
        notifications: {
          ...prev.notifications,
          email: user.notifications?.email?.newSuggestions ?? true,
          push: user.notifications?.push?.enabled ?? true
        },
        privacy: {
          ...prev.privacy,
          profileVisibility: user.privacy?.profileVisibility ?? 'family',
          allowSearch: user.privacy?.allowSearchEngines ?? true,
          showOnlineStatus: user.privacy?.showOnlineStatus ?? true
        }
      }));
    }
  }, [user]);

  // Update settings when UI store changes
  useEffect(() => {
    setSettings(prev => ({
      ...prev,
      language: language,
      theme: theme === 'auto' ? 'system' : theme
    }));
  }, [language, theme]);

  const handleSettingChange = (section: keyof AppSettings, key: string, value: any) => {
    setSettings(prev => ({
      ...prev,
      [section]: {
        ...(prev[section] as any),
        [key]: value
      }
    }));
    setHasChanges(true);
  };

  const handleLanguageChange = (newLanguage: 'ar' | 'en') => {
    setLanguage(newLanguage);
    setSettings(prev => ({ ...prev, language: newLanguage }));
    setHasChanges(true);
  };

  const handleThemeChange = (newTheme: 'light' | 'dark' | 'system') => {
    const themeValue = newTheme === 'system' ? 'auto' : newTheme;
    setTheme(themeValue);
    setSettings(prev => ({ ...prev, theme: newTheme }));
    setHasChanges(true);
  };

  const handleSaveSettings = async () => {
    setSaving(true);
    
    try {
      // Save notification settings
      await updateNotificationSettings({
        email: {
          newSuggestions: settings.notifications.email,
          treeUpdates: settings.notifications.familyUpdates,
          subscriptionUpdates: settings.notifications.newMembers,
          marketing: settings.notifications.anniversaries
        },
        push: {
          enabled: settings.notifications.push
        }
      });
      
      // Save privacy settings
      await updatePrivacySettings({
        profileVisibility: settings.privacy.profileVisibility,
        allowSearchEngines: settings.privacy.allowSearch,
        showOnlineStatus: settings.privacy.showOnlineStatus
      });
      
      setHasChanges(false);
      notifySuccess(
        { 
          en: 'Settings saved successfully', 
          ar: 'تم حفظ الإعدادات بنجاح' 
        }
      );
    } catch (error: any) {
      // Error saving settings: error
      notifyError(
        { 
          en: 'Failed to save settings', 
          ar: 'فشل في حفظ الإعدادات' 
        }
      );
    } finally {
      setSaving(false);
    }
  };

  const handleResetSettings = () => {
    if (confirm(isRTL ? 'هل أنت متأكد من إعادة تعيين جميع الإعدادات؟' : 'Are you sure you want to reset all settings?')) {
      // إعادة تعيين الإعدادات للقيم الافتراضية
      setSettings({
        language: language,
        theme: theme === 'auto' ? 'system' : theme,
        notifications: {
          email: user?.notifications?.email?.newSuggestions ?? true,
          push: user?.notifications?.push?.enabled ?? true,
          sound: true,
          familyUpdates: true,
          newMembers: true,
          birthdays: true,
          anniversaries: true
        },
        privacy: {
          profileVisibility: user?.privacy?.profileVisibility ?? 'family',
          allowSearch: user?.privacy?.allowSearchEngines ?? true,
          showOnlineStatus: user?.privacy?.showOnlineStatus ?? true,
          allowDirectMessages: true
        },
        display: {
          dateFormat: 'dd/mm/yyyy',
          timeFormat: '24h',
          fontSize: 'medium',
          compactMode: false
        },
        backup: {
          autoBackup: true,
          backupFrequency: 'weekly',
          cloudSync: true
        }
      });
      setHasChanges(true);
    }
  };

  const handleExportData = () => {
    // تصدير البيانات
    // Exporting data...
  };

  const handleImportData = () => {
    // استيراد البيانات
    // Importing data...
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">
            {isRTL ? 'الإعدادات' : 'Settings'}
          </h1>
          <p className="text-sm text-muted-foreground">
            {isRTL ? 'إدارة إعدادات التطبيق والحساب' : 'Manage application and account settings'}
          </p>
        </div>
        {hasChanges && (
          <Button 
            onClick={handleSaveSettings} 
            disabled={saving}
            className="flex items-center gap-2"
            size={isMobile ? "icon" : "default"}
          >
            {saving ? (
              <>
                <Loader2 className="h-4 w-4 animate-spin" />
                {!isMobile && (isRTL ? 'جاري الحفظ...' : 'Saving...')}
              </>
            ) : (
              <>
                <Save className="h-4 w-4" />
                {!isMobile && (isRTL ? 'حفظ التغييرات' : 'Save Changes')}
              </>
            )}
          </Button>
        )}
      </div>

      {/* Tabs */}
      <div className="flex gap-1 border-b overflow-x-auto">
        {[
          { id: 'general', label: isRTL ? 'عام' : 'General', icon: Settings },
          // { id: 'notifications', label: isRTL ? 'الإشعارات' : 'Notifications', icon: Bell },
          // { id: 'privacy', label: isRTL ? 'الخصوصية' : 'Privacy', icon: Shield },
          // { id: 'display', label: isRTL ? 'العرض' : 'Display', icon: Monitor },
          // { id: 'backup', label: isRTL ? 'النسخ الاحتياطي' : 'Backup', icon: Database },
          { id: 'account', label: isRTL ? 'الحساب' : 'Account', icon: User }
        ].map(tab => (
          <Button
            key={tab.id}
            variant={activeTab === tab.id ? "default" : "ghost"}
            onClick={() => setActiveTab(tab.id as any)}
            className="flex items-center gap-2 whitespace-nowrap"
            size={isMobile ? "icon" : "default"} // Added mobile size adjustment
            title={isMobile ? tab.label : undefined} // Show tooltip on mobile
          >
            {React.createElement(tab.icon, { className: "h-4 w-4" })}
            {!isMobile && tab.label} {/* Hide text on mobile */}
          </Button>
        ))}
      </div>

      {/* General Settings Tab */}
      {activeTab === 'general' && (
        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Languages className="h-5 w-5" />
                {isRTL ? 'اللغة والمنطقة' : 'Language & Region'}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'لغة التطبيق' : 'Application Language'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'اختر لغة واجهة التطبيق' : 'Choose the application interface language'}
                  </p>
                </div>
                <div className="flex gap-2">
                  <Button
                    variant={settings.language === 'ar' ? "default" : "outline"}
                    size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                    onClick={() => handleLanguageChange('ar')}
                    title={isMobile ? "العربية" : undefined} // Show tooltip on mobile
                  >
                    {isMobile ? "ع" : "العربية"} {/* Show only first letter on mobile */}
                  </Button>
                  <Button
                    variant={settings.language === 'en' ? "default" : "outline"}
                    size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                    onClick={() => handleLanguageChange('en')}
                    title={isMobile ? "English" : undefined} // Show tooltip on mobile
                  >
                    {isMobile ? "En" : "English"} {/* Show abbreviation on mobile */}
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Palette className="h-5 w-5" />
                {isRTL ? 'المظهر' : 'Appearance'}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'نمط المظهر' : 'Theme Mode'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'اختر نمط المظهر المفضل' : 'Choose your preferred theme mode'}
                  </p>
                </div>
                <div className="flex gap-2">
                  <Button
                    variant={settings.theme === 'light' ? "default" : "outline"}
                    size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                    onClick={() => handleThemeChange('light')}
                    className="flex items-center gap-2"
                    title={isMobile ? (isRTL ? 'فاتح' : 'Light') : undefined} // Show tooltip on mobile
                  >
                    <Sun className="h-4 w-4" />
                    {!isMobile && (isRTL ? 'فاتح' : 'Light')} {/* Hide text on mobile */}
                  </Button>
                  <Button
                    variant={settings.theme === 'dark' ? "default" : "outline"}
                    size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                    onClick={() => handleThemeChange('dark')}
                    className="flex items-center gap-2"
                    title={isMobile ? (isRTL ? 'داكن' : 'Dark') : undefined} // Show tooltip on mobile
                  >
                    <Moon className="h-4 w-4" />
                    {!isMobile && (isRTL ? 'داكن' : 'Dark')} {/* Hide text on mobile */}
                  </Button>
                  <Button
                    variant={settings.theme === 'system' ? "default" : "outline"}
                    size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                    onClick={() => handleThemeChange('system')}
                    className="flex items-center gap-2"
                    title={isMobile ? (isRTL ? 'النظام' : 'System') : undefined} // Show tooltip on mobile
                  >
                    <Monitor className="h-4 w-4" />
                    {!isMobile && (isRTL ? 'النظام' : 'System')} {/* Hide text on mobile */}
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Notifications Tab */}
      {activeTab === 'notifications' && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Bell className="h-5 w-5" />
              {isRTL ? 'إعدادات الإشعارات' : 'Notification Settings'}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            <div className="space-y-4">
              <h3 className="font-medium">{isRTL ? 'طرق الإشعار' : 'Notification Methods'}</h3>
              
              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'إشعارات البريد الإلكتروني' : 'Email Notifications'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'تلقي الإشعارات عبر البريد الإلكتروني' : 'Receive notifications via email'}
                  </p>
                </div>
                <Button
                  variant={settings.notifications.email ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('notifications', 'email', !settings.notifications.email)}
                  title={isMobile ? (settings.notifications.email ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')) : undefined} // Show tooltip on mobile
                >
                  {isMobile ? (
                    settings.notifications.email ? (isRTL ? 'م' : 'ON') : (isRTL ? 'ط' : 'OFF') // Show abbreviated text on mobile
                  ) : (
                    settings.notifications.email ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')
                  )}
                </Button>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'الإشعارات المنبثقة' : 'Push Notifications'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'تلقي الإشعارات المنبثقة على الجهاز' : 'Receive push notifications on device'}
                  </p>
                </div>
                <Button
                  variant={settings.notifications.push ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('notifications', 'push', !settings.notifications.push)}
                  title={isMobile ? (settings.notifications.push ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')) : undefined} // Show tooltip on mobile
                >
                  {isMobile ? (
                    settings.notifications.push ? (isRTL ? 'م' : 'ON') : (isRTL ? 'ط' : 'OFF') // Show abbreviated text on mobile
                  ) : (
                    settings.notifications.push ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')
                  )}
                </Button>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'الأصوات' : 'Sound Notifications'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'تشغيل الأصوات مع الإشعارات' : 'Play sounds with notifications'}
                  </p>
                </div>
                <Button
                  variant={settings.notifications.sound ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('notifications', 'sound', !settings.notifications.sound)}
                  className="flex items-center gap-2"
                  title={isMobile ? (settings.notifications.sound ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')) : undefined} // Show tooltip on mobile
                >
                  {settings.notifications.sound ? <Volume2 className="h-4 w-4" /> : <VolumeX className="h-4 w-4" />}
                  {!isMobile && (
                    settings.notifications.sound ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')
                  )}
                </Button>
              </div>
            </div>

            <div className="border-t pt-6 space-y-4">
              <h3 className="font-medium">{isRTL ? 'أنواع الإشعارات' : 'Notification Types'}</h3>
              
              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'تحديثات العائلة' : 'Family Updates'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'إشعارات عند إضافة أو تعديل أعضاء العائلة' : 'Notifications when family members are added or updated'}
                  </p>
                </div>
                <Button
                  variant={settings.notifications.familyUpdates ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('notifications', 'familyUpdates', !settings.notifications.familyUpdates)}
                  title={isMobile ? (settings.notifications.familyUpdates ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')) : undefined} // Show tooltip on mobile
                >
                  {isMobile ? (
                    settings.notifications.familyUpdates ? (isRTL ? 'م' : 'ON') : (isRTL ? 'ط' : 'OFF') // Show abbreviated text on mobile
                  ) : (
                    settings.notifications.familyUpdates ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')
                  )}
                </Button>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'أعضاء جدد' : 'New Members'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'إشعارات عند انضمام أعضاء جدد للشجرة' : 'Notifications when new members join the tree'}
                  </p>
                </div>
                <Button
                  variant={settings.notifications.newMembers ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('notifications', 'newMembers', !settings.notifications.newMembers)}
                  title={isMobile ? (settings.notifications.newMembers ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')) : undefined} // Show tooltip on mobile
                >
                  {isMobile ? (
                    settings.notifications.newMembers ? (isRTL ? 'م' : 'ON') : (isRTL ? 'ط' : 'OFF') // Show abbreviated text on mobile
                  ) : (
                    settings.notifications.newMembers ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')
                  )}
                </Button>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'أعياد الميلاد' : 'Birthdays'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'تذكيرات بأعياد ميلاد أفراد العائلة' : 'Reminders for family members birthdays'}
                  </p>
                </div>
                <Button
                  variant={settings.notifications.birthdays ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('notifications', 'birthdays', !settings.notifications.birthdays)}
                  title={isMobile ? (settings.notifications.birthdays ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')) : undefined} // Show tooltip on mobile
                >
                  {isMobile ? (
                    settings.notifications.birthdays ? (isRTL ? 'م' : 'ON') : (isRTL ? 'ط' : 'OFF') // Show abbreviated text on mobile
                  ) : (
                    settings.notifications.birthdays ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')
                  )}
                </Button>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'الذكريات السنوية' : 'Anniversaries'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'تذكيرات بالذكريات السنوية المهمة' : 'Reminders for important anniversaries'}
                  </p>
                </div>
                <Button
                  variant={settings.notifications.anniversaries ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('notifications', 'anniversaries', !settings.notifications.anniversaries)}
                  title={isMobile ? (settings.notifications.anniversaries ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')) : undefined} // Show tooltip on mobile
                >
                  {isMobile ? (
                    settings.notifications.anniversaries ? (isRTL ? 'م' : 'ON') : (isRTL ? 'ط' : 'OFF') // Show abbreviated text on mobile
                  ) : (
                    settings.notifications.anniversaries ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')
                  )}
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Privacy Tab */}
      {activeTab === 'privacy' && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Shield className="h-5 w-5" />
              {isRTL ? 'إعدادات الخصوصية' : 'Privacy Settings'}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'ظهور الملف الشخصي' : 'Profile Visibility'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'من يمكنه رؤية ملفك الشخصي' : 'Who can see your profile'}
                  </p>
                </div>
                <select
                  value={settings.privacy.profileVisibility}
                  onChange={(e) => handleSettingChange('privacy', 'profileVisibility', e.target.value)}
                  className="px-3 py-2 border border-input rounded-md bg-background"
                >
                  <option value="public">{isRTL ? 'عام' : 'Public'}</option>
                  <option value="family">{isRTL ? 'العائلة فقط' : 'Family Only'}</option>
                  <option value="private">{isRTL ? 'خاص' : 'Private'}</option>
                </select>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'السماح بالبحث' : 'Allow Search'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'السماح للآخرين بالعثور عليك في البحث' : 'Allow others to find you in search'}
                  </p>
                </div>
                <Button
                  variant={settings.privacy.allowSearch ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('privacy', 'allowSearch', !settings.privacy.allowSearch)}
                  title={isMobile ? (settings.privacy.allowSearch ? (isRTL ? 'مسموح' : 'Allowed') : (isRTL ? 'ممنوع' : 'Blocked')) : undefined} // Show tooltip on mobile
                >
                  {isMobile ? (
                    settings.privacy.allowSearch ? (isRTL ? 'م' : 'ON') : (isRTL ? 'ط' : 'OFF') // Show abbreviated text on mobile
                  ) : (
                    settings.privacy.allowSearch ? (isRTL ? 'مسموح' : 'Allowed') : (isRTL ? 'ممنوع' : 'Blocked')
                  )}
                </Button>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'إظهار حالة الاتصال' : 'Show Online Status'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'إظهار ما إذا كنت متصلاً أم لا' : 'Show whether you are online or not'}
                  </p>
                </div>
                <Button
                  variant={settings.privacy.showOnlineStatus ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('privacy', 'showOnlineStatus', !settings.privacy.showOnlineStatus)}
                  className="flex items-center gap-2"
                  title={isMobile ? (settings.privacy.showOnlineStatus ? (isRTL ? 'ظاهر' : 'Visible') : (isRTL ? 'مخفي' : 'Hidden')) : undefined} // Show tooltip on mobile
                >
                  {settings.privacy.showOnlineStatus ? <Eye className="h-4 w-4" /> : <EyeOff className="h-4 w-4" />}
                  {!isMobile && (
                    settings.privacy.showOnlineStatus ? (isRTL ? 'ظاهر' : 'Visible') : (isRTL ? 'مخفي' : 'Hidden')
                  )}
                </Button>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'السماح بالرسائل المباشرة' : 'Allow Direct Messages'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'السماح للآخرين بإرسال رسائل مباشرة إليك' : 'Allow others to send you direct messages'}
                  </p>
                </div>
                <Button
                  variant={settings.privacy.allowDirectMessages ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('privacy', 'allowDirectMessages', !settings.privacy.allowDirectMessages)}
                  title={isMobile ? (settings.privacy.allowDirectMessages ? (isRTL ? 'مسموح' : 'Allowed') : (isRTL ? 'ممنوع' : 'Blocked')) : undefined} // Show tooltip on mobile
                >
                  {isMobile ? (
                    settings.privacy.allowDirectMessages ? (isRTL ? 'م' : 'ON') : (isRTL ? 'ط' : 'OFF') // Show abbreviated text on mobile
                  ) : (
                    settings.privacy.allowDirectMessages ? (isRTL ? 'مسموح' : 'Allowed') : (isRTL ? 'ممنوع' : 'Blocked')
                  )}
                </Button>
              </div>
            </div>

            <div className="p-4 bg-secondary/50 rounded-lg">
              <div className="flex items-start gap-3">
                <Info className="h-5 w-5 text-primary mt-0.5" />
                <div>
                  <p className="font-medium text-sm">
                    {isRTL ? 'معلومات الخصوصية' : 'Privacy Information'}
                  </p>
                  <p className="text-sm text-muted-foreground mt-1">
                    {isRTL 
                      ? 'نحن نحترم خصوصيتك ونحمي بياناتك الشخصية. يمكنك تغيير هذه الإعدادات في أي وقت.'
                      : 'We respect your privacy and protect your personal data. You can change these settings at any time.'}
                  </p>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Display Tab */}
      {activeTab === 'display' && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Monitor className="h-5 w-5" />
              {isRTL ? 'إعدادات العرض' : 'Display Settings'}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'تنسيق التاريخ' : 'Date Format'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'اختر تنسيق عرض التواريخ' : 'Choose how dates are displayed'}
                  </p>
                </div>
                <select
                  value={settings.display.dateFormat}
                  onChange={(e) => handleSettingChange('display', 'dateFormat', e.target.value)}
                  className="px-3 py-2 border border-input rounded-md bg-background"
                >
                  <option value="dd/mm/yyyy">DD/MM/YYYY</option>
                  <option value="mm/dd/yyyy">MM/DD/YYYY</option>
                  <option value="yyyy-mm-dd">YYYY-MM-DD</option>
                </select>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'تنسيق الوقت' : 'Time Format'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'اختر تنسيق عرض الوقت' : 'Choose how time is displayed'}
                  </p>
                </div>
                <div className="flex gap-2">
                  <Button
                    variant={settings.display.timeFormat === '12h' ? "default" : "outline"}
                    size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                    onClick={() => handleSettingChange('display', 'timeFormat', '12h')}
                    title={isMobile ? "12h" : undefined} // Show tooltip on mobile
                  >
                    {isMobile ? "12" : "12h"} {/* Show abbreviated text on mobile */}
                  </Button>
                  <Button
                    variant={settings.display.timeFormat === '24h' ? "default" : "outline"}
                    size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                    onClick={() => handleSettingChange('display', 'timeFormat', '24h')}
                    title={isMobile ? "24h" : undefined} // Show tooltip on mobile
                  >
                    {isMobile ? "24" : "24h"} {/* Show abbreviated text on mobile */}
                  </Button>
                </div>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'حجم الخط' : 'Font Size'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'اختر حجم الخط المناسب' : 'Choose your preferred font size'}
                  </p>
                </div>
                <div className="flex gap-2">
                  <Button
                    variant={settings.display.fontSize === 'small' ? "default" : "outline"}
                    size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                    onClick={() => handleSettingChange('display', 'fontSize', 'small')}
                    title={isMobile ? (isRTL ? 'صغير' : 'Small') : undefined} // Show tooltip on mobile
                  >
                    {isMobile ? (isRTL ? 'ص' : 'S') : (isRTL ? 'صغير' : 'Small')} {/* Show abbreviated text on mobile */}
                  </Button>
                  <Button
                    variant={settings.display.fontSize === 'medium' ? "default" : "outline"}
                    size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                    onClick={() => handleSettingChange('display', 'fontSize', 'medium')}
                    title={isMobile ? (isRTL ? 'متوسط' : 'Medium') : undefined} // Show tooltip on mobile
                  >
                    {isMobile ? (isRTL ? 'م' : 'M') : (isRTL ? 'متوسط' : 'Medium')} {/* Show abbreviated text on mobile */}
                  </Button>
                  <Button
                    variant={settings.display.fontSize === 'large' ? "default" : "outline"}
                    size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                    onClick={() => handleSettingChange('display', 'fontSize', 'large')}
                    title={isMobile ? (isRTL ? 'كبير' : 'Large') : undefined} // Show tooltip on mobile
                  >
                    {isMobile ? (isRTL ? 'ك' : 'L') : (isRTL ? 'كبير' : 'Large')} {/* Show abbreviated text on mobile */}
                  </Button>
                </div>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'الوضع المضغوط' : 'Compact Mode'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'عرض المزيد من المحتوى في مساحة أقل' : 'Show more content in less space'}
                  </p>
                </div>
                <Button
                  variant={settings.display.compactMode ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('display', 'compactMode', !settings.display.compactMode)}
                  title={isMobile ? (settings.display.compactMode ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')) : undefined} // Show tooltip on mobile
                >
                  {isMobile ? (
                    settings.display.compactMode ? (isRTL ? 'م' : 'ON') : (isRTL ? 'ط' : 'OFF') // Show abbreviated text on mobile
                  ) : (
                    settings.display.compactMode ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')
                  )}
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Backup Tab */}
      {activeTab === 'backup' && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Database className="h-5 w-5" />
              {isRTL ? 'النسخ الاحتياطي والمزامنة' : 'Backup & Sync'}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'النسخ الاحتياطي التلقائي' : 'Auto Backup'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'إنشاء نسخ احتياطية تلقائية من بياناتك' : 'Automatically create backups of your data'}
                  </p>
                </div>
                <Button
                  variant={settings.backup.autoBackup ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('backup', 'autoBackup', !settings.backup.autoBackup)}
                  title={isMobile ? (settings.backup.autoBackup ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')) : undefined} // Show tooltip on mobile
                >
                  {isMobile ? (
                    settings.backup.autoBackup ? (isRTL ? 'م' : 'ON') : (isRTL ? 'ط' : 'OFF') // Show abbreviated text on mobile
                  ) : (
                    settings.backup.autoBackup ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')
                  )}
                </Button>
              </div>

              {settings.backup.autoBackup && (
                <div className="flex items-center justify-between">
                  <div>
                    <p className="font-medium">{isRTL ? 'تكرار النسخ الاحتياطي' : 'Backup Frequency'}</p>
                    <p className="text-sm text-muted-foreground">
                      {isRTL ? 'كم مرة يتم إنشاء النسخ الاحتياطية' : 'How often backups are created'}
                    </p>
                  </div>
                  <select
                    value={settings.backup.backupFrequency}
                    onChange={(e) => handleSettingChange('backup', 'backupFrequency', e.target.value)}
                    className="px-3 py-2 border border-input rounded-md bg-background"
                  >
                    <option value="daily">{isRTL ? 'يومياً' : 'Daily'}</option>
                    <option value="weekly">{isRTL ? 'أسبوعياً' : 'Weekly'}</option>
                    <option value="monthly">{isRTL ? 'شهرياً' : 'Monthly'}</option>
                  </select>
                </div>
              )}

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{isRTL ? 'المزامنة السحابية' : 'Cloud Sync'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'مزامنة البيانات مع التخزين السحابي' : 'Sync data with cloud storage'}
                  </p>
                </div>
                <Button
                  variant={settings.backup.cloudSync ? "default" : "outline"}
                  size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
                  onClick={() => handleSettingChange('backup', 'cloudSync', !settings.backup.cloudSync)}
                  className="flex items-center gap-2"
                  title={isMobile ? (settings.backup.cloudSync ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')) : undefined} // Show tooltip on mobile
                >
                  <Cloud className="h-4 w-4" />
                  {!isMobile && (
                    settings.backup.cloudSync ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')
                  )}
                </Button>
              </div>
            </div>

            <div className="border-t pt-6 space-y-4">
              <h3 className="font-medium">{isRTL ? 'إدارة البيانات' : 'Data Management'}</h3>
              
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <Button
                  variant="outline"
                  onClick={handleExportData}
                  className="flex items-center gap-2 h-auto p-4"
                  size={isMobile ? "icon" : "default"} // Added mobile size adjustment
                >
                  <Download className="h-5 w-5" />
                  {!isMobile && (
                    <div className="text-left">
                      <p className="font-medium">{isRTL ? 'تصدير البيانات' : 'Export Data'}</p>
                      <p className="text-sm text-muted-foreground">
                        {isRTL ? 'تحميل نسخة من جميع بياناتك' : 'Download a copy of all your data'}
                      </p>
                    </div>
                  )}
                </Button>

                <Button
                  variant="outline"
                  onClick={handleImportData}
                  className="flex items-center gap-2 h-auto p-4"
                  size={isMobile ? "icon" : "default"} // Added mobile size adjustment
                >
                  <Upload className="h-5 w-5" />
                  {!isMobile && (
                    <div className="text-left">
                      <p className="font-medium">{isRTL ? 'استيراد البيانات' : 'Import Data'}</p>
                      <p className="text-sm text-muted-foreground">
                        {isRTL ? 'رفع واستيراد بيانات من ملف' : 'Upload and import data from file'}
                      </p>
                    </div>
                  )}
                </Button>
              </div>

              <div className="p-4 bg-secondary/50 rounded-lg">
                <div className="flex items-start gap-3">
                  <HardDrive className="h-5 w-5 text-primary mt-0.5" />
                  <div>
                    <p className="font-medium text-sm">
                      {isRTL ? 'معلومات التخزين' : 'Storage Information'}
                    </p>
                    <p className="text-sm text-muted-foreground mt-1">
                      {isRTL ? 'المساحة المستخدمة: 2.3 جيجابايت من 10 جيجابايت' : 'Used space: 2.3 GB of 10 GB'}
                    </p>
                    <div className="w-full bg-secondary rounded-full h-2 mt-2">
                      <div className="bg-primary h-2 rounded-full" style={{ width: '23%' }}></div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Account Tab */}
      {activeTab === 'account' && (
        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <User className="h-5 w-5" />
                {isRTL ? 'معلومات الحساب' : 'Account Information'}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-sm font-medium">{isRTL ? 'الاسم الكامل' : 'Full Name'}</label>
                  <Input value={`${user?.firstName || ''} ${user?.lastName || ''}`} disabled className="bg-secondary/50" />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium">{isRTL ? 'البريد الإلكتروني' : 'Email'}</label>
                  <Input value={user?.email || ''} disabled className="bg-secondary/50" />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium">{isRTL ? 'رقم الهاتف' : 'Phone Number'}</label>
                  <Input value={user?.phone || ''} disabled className="bg-secondary/50" />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium">{isRTL ? 'تاريخ الانضمام' : 'Join Date'}</label>
                  <Input value={user?.createdAt ? new Date(user.createdAt).toLocaleDateString() : ''} disabled className="bg-secondary/50" />
                </div>
              </div>
              <Button variant="outline" className="flex items-center gap-2" size={isMobile ? "icon" : "default"}>
                <Edit className="h-4 w-4" />
                {!isMobile && (isRTL ? 'تعديل المعلومات' : 'Edit Information')}
              </Button>
            </CardContent>
          </Card>

          <Card className="border-destructive/20">
            <CardHeader>
              <CardTitle className="flex items-center gap-2 text-destructive">
                <AlertTriangle className="h-5 w-5" />
                {isRTL ? 'منطقة الخطر' : 'Danger Zone'}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium text-destructive">{isRTL ? 'إعادة تعيين الإعدادات' : 'Reset Settings'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'إعادة جميع الإعدادات إلى القيم الافتراضية' : 'Reset all settings to default values'}
                  </p>
                </div>
                <Button variant="outline" onClick={handleResetSettings} className="flex items-center gap-2" size={isMobile ? "icon" : "default"}>
                  <RefreshCw className="h-4 w-4" />
                  {!isMobile && (isRTL ? 'إعادة تعيين' : 'Reset')}
                </Button>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium text-destructive">{isRTL ? 'حذف الحساب' : 'Delete Account'}</p>
                  <p className="text-sm text-muted-foreground">
                    {isRTL ? 'حذف الحساب وجميع البيانات نهائياً' : 'Permanently delete account and all data'}
                  </p>
                </div>
                <Button variant="destructive" className="flex items-center gap-2" size={isMobile ? "icon" : "default"}>
                  <Trash2 className="h-4 w-4" />
                  {!isMobile && (isRTL ? 'حذف الحساب' : 'Delete Account')}
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Save Changes Banner */}
      {hasChanges && (
        <div className="fixed bottom-4 left-1/2 transform -translate-x-1/2 bg-primary text-primary-foreground px-6 py-3 rounded-lg shadow-lg flex items-center gap-3">
          <Info className="h-5 w-5" />
          <span>{isRTL ? 'لديك تغييرات غير محفوظة' : 'You have unsaved changes'}</span>
          <Button
            variant="secondary"
            size={isMobile ? "icon" : "sm"} // Added mobile size adjustment
            onClick={handleSaveSettings}
            disabled={saving}
            className="flex items-center gap-2"
          >
            {saving ? (
              <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
              <>
                <Save className="h-4 w-4" />
                {!isMobile && (isRTL ? 'حفظ' : 'Save')} {/* Hide text on mobile */}
              </>
            )}
          </Button>
        </div>
      )}
    </div>
  );
};

export default SettingsPage;