import React from 'react';
import { Link } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useUIStore } from '@/store/uiStore';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { Mail, ArrowLeft, CheckCircle } from 'lucide-react';
import { authService } from '@/services/auth';
import toast from 'react-hot-toast';
import bilingualToast from '@/utils/bilingualToast';
import { useMobile } from '@/hooks/useMobile';

const forgotPasswordSchema = z.object({
  email: z.string().email('Please enter a valid email address'),
});

type ForgotPasswordFormData = z.infer<typeof forgotPasswordSchema>;

const ForgotPasswordPage: React.FC = () => {
  const { language } = useUIStore();
  const [isLoading, setIsLoading] = React.useState(false);
  const [emailSent, setEmailSent] = React.useState(false);
  const { isMobile } = useMobile();

  const {
    register,
    handleSubmit,
    formState: { errors },
    getValues,
  } = useForm<ForgotPasswordFormData>({
    resolver: zodResolver(forgotPasswordSchema),
  });

  const onSubmit = async (data: ForgotPasswordFormData) => {
    setIsLoading(true);
    try {
      await authService.forgotPassword(data.email);
      // Always show success for security reasons (to prevent email enumeration)
      setEmailSent(true);
      bilingualToast.success({
        en: 'Password reset link sent to your email',
        ar: 'تم إرسال رابط إعادة تعيين كلمة المرور إلى بريدك الإلكتروني'
      });
    } catch (error: any) {
      // Even if there's an error, we'll show the success screen to prevent email enumeration
      setEmailSent(true);
      // We don't show error messages to the user for security reasons
      // Removed console.error for forgot password error
    } finally {
      setIsLoading(false);
    }
  };

  if (emailSent) {
    return (
      <Card className={`w-full ${isMobile ? 'max-w-md mx-4' : 'max-w-md'}`}>
        <CardHeader className="space-y-1 text-center">
          <div className="mx-auto w-12 h-12 bg-green-100 rounded-full flex items-center justify-center mb-4">
            <CheckCircle className="h-6 w-6 text-green-600" />
          </div>
          <CardTitle className={`text-2xl font-bold ${isMobile ? 'text-xl' : ''}`}>
            {language === 'ar' ? 'تم إرسال البريد الإلكتروني' : 'Email Sent'}
          </CardTitle>
          <CardDescription>
            {language === 'ar' 
              ? 'تحقق من بريدك الإلكتروني للحصول على رابط إعادة تعيين كلمة المرور'
              : 'Check your email for a password reset link'
            }
          </CardDescription>
        </CardHeader>
        
        <CardContent className="space-y-4">
          <div className={`text-center space-y-4 ${isMobile ? 'text-sm' : ''}`}>
            <p className="text-sm text-muted-foreground">
              {language === 'ar' 
                ? `تم إرسال رابط إعادة تعيين كلمة المرور إلى:`
                : 'We sent a password reset link to:'
              }
            </p>
            <p className="font-medium text-foreground">
              {getValues('email')}
            </p>
            <p className="text-sm text-muted-foreground">
              {language === 'ar' 
                ? 'إذا لم تجد البريد الإلكتروني، تحقق من مجلد الرسائل غير المرغوب فيها.'
                : "If you don't see the email, check your spam folder."
              }
            </p>
          </div>

          <div className="space-y-3">
            <Button
              onClick={() => setEmailSent(false)}
              variant="outline"
              className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}
            >
              {language === 'ar' ? 'إرسال مرة أخرى' : 'Send Again'}
            </Button>
            
            <Button asChild variant="ghost" className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}>
              <Link to="/login" className="flex items-center justify-center">
                <ArrowLeft className={`w-4 h-4 ${isMobile ? 'mr-1' : 'mr-2'}`} />
                {language === 'ar' ? 'العودة لتسجيل الدخول' : 'Back to Sign In'}
              </Link>
            </Button>
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className={`w-full ${isMobile ? 'max-w-md mx-4' : 'max-w-md'}`}>
      <CardHeader className="space-y-1">
        <CardTitle className={`text-2xl font-bold text-center ${isMobile ? 'text-xl' : ''}`}>
          {language === 'ar' ? 'نسيت كلمة المرور؟' : 'Forgot Password?'}
        </CardTitle>
        <CardDescription className="text-center">
          {language === 'ar' 
            ? 'أدخل بريدك الإلكتروني وسنرسل لك رابط إعادة تعيين كلمة المرور'
            : 'Enter your email address and we\'ll send you a password reset link'
          }
        </CardDescription>
      </CardHeader>
      
      <CardContent>
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          {/* Email field */}
          <Input
            {...register('email')}
            type="email"
            placeholder={language === 'ar' ? 'البريد الإلكتروني' : 'Email address'}
            leftIcon={<Mail className="h-4 w-4" />}
            error={errors.email?.message}
            disabled={isLoading}
            className={isMobile ? 'text-sm' : ''}
          />

          {/* Submit button */}
          <Button
            type="submit"
            className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}
            loading={isLoading}
            loadingText={language === 'ar' ? 'جاري الإرسال...' : 'Sending...'}
          >
            {language === 'ar' ? 'إرسال رابط إعادة التعيين' : 'Send Reset Link'}
          </Button>
        </form>

        {/* Back to login */}
        <div className="mt-6 text-center">
          <Button asChild variant="ghost" className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}>
            <Link to="/login" className="flex items-center justify-center">
              <ArrowLeft className={`w-4 h-4 ${isMobile ? 'mr-1' : 'mr-2'}`} />
              {language === 'ar' ? 'العودة لتسجيل الدخول' : 'Back to Sign In'}
            </Link>
          </Button>
        </div>

        {/* Help text */}
        <div className={`mt-6 text-center ${isMobile ? 'text-sm' : ''}`}>
          <p className="text-sm text-muted-foreground">
            {language === 'ar' 
              ? 'تذكرت كلمة المرور؟ '
              : 'Remember your password? '
            }
            <Link
              to="/login"
              className="text-primary hover:text-primary/80 underline font-medium"
            >
              {language === 'ar' ? 'تسجيل الدخول' : 'Sign in'}
            </Link>
          </p>
        </div>
      </CardContent>
    </Card>
  );
};

export default ForgotPasswordPage;