import { apiService } from './api';
import { Tree, Person } from '@/types';

export const treeService = {
  // Get all trees for the current user
  getTrees: async (): Promise<Tree[]> => {
    try {
      const response = await apiService.getTrees();
      return response || [];
    } catch (error) {
      throw error;
    }
  },

  // Get all public trees
  getPublicTrees: async (): Promise<Tree[]> => {
    try {
      const response = await apiService.getAllPublicTrees();
      return response || [];
    } catch (error) {
      throw error;
    }
  },

  // Create a new tree
  createTree: async (name: string, isPrivate: boolean, description: string): Promise<Tree> => {
    try {
      const response = await apiService.addTree(name, isPrivate, description);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  // Get a specific tree by ID
  getTreeById: async (id: number): Promise<any> => {
    try {
      const response = await apiService.getTreeById(id);
      return response;
    } catch (error) {
      throw error;
    }
  },

  // Update a tree
  updateTree: async (id: number, name: string, isPrivate: boolean, description: string): Promise<Tree> => {
    try {
      // Validate inputs
      if (!id || id <= 0) {
        throw new Error('Invalid tree ID');
      }
      
      if (!name || name.trim() === '') {
        throw new Error('Tree name is required');
      }
      
      // Removed console.log for updating tree with params
      
      const response = await apiService.updateTree(id, name.trim(), isPrivate, description?.trim() || '');
      return response.data;
    } catch (error: any) {
      // Removed console.error for error updating tree
      if (error.response) {
        // Removed console.error for error response
        // Handle authorization errors specifically
        if (error.response.status === 403) {
          throw new Error('You do not have permission to edit this tree');
        }
        throw new Error(`Failed to update tree: ${JSON.stringify(error.response.data)}`);
      } else {
        throw new Error('Failed to update tree: ' + (error.message || 'Unknown error'));
      }
    }
  },

  // Delete a tree
  deleteTree: async (id: number): Promise<void> => {
    try {
      await apiService.deleteTree(id);
    } catch (error) {
      throw error;
    }
  },

  // Upload tree photo
  uploadTreePhoto: async (treeId: number, file: File): Promise<any> => {
    try {
      const formData = new FormData();
      formData.append('picture', file);
      formData.append('FamilyTreeId', treeId.toString());
      
      const response = await apiService.uploadTreePhoto(formData);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  // Delete tree photo
  deleteTreePhoto: async (id: number): Promise<void> => {
    try {
      await apiService.deleteTreePhoto(id);
    } catch (error) {
      throw error;
    }
  },

  // Get persons in a tree
  getPersonsInTree: async (familyTreeId: number): Promise<Person[]> => {
    try {
      const response = await apiService.getPersonsInTree(familyTreeId);
      return response || [];
    } catch (error) {
      throw error;
    }
  },

  // Add a person to a tree
  addPersonToTree: async (
    name: string,
    birthDate: string,
    birthPlace: string,
    occupation: string,
    gender: string,
    deathDate: string,
    isDeceased: boolean,
    familyTreeId: number
  ): Promise<Person> => {
    try {
      // Removed console.log for adding person to tree with params
      
      const response = await apiService.addPerson(
        name,
        birthDate,
        birthPlace,
        occupation,
        gender,
        deathDate,
        isDeceased,
        familyTreeId
      );
      
      // Removed console.log for API response
      return response.data;
    } catch (error: any) {
      // Removed console.error for error in addPersonToTree
      if (error.response) {
        // Removed console.error for error response
        // Throw the original error so we can handle it properly in the UI
        throw error;
      } else {
        throw error;
      }
    }
  },

  // Update a person
  updatePerson: async (
    id: number,
    name: string,
    birthDate: string,
    birthPlace: string,
    occupation: string,
    gender: string,
    familyTreeId: number // Add familyTreeId parameter
  ): Promise<Person> => {
    try {
      // Removed console.log for updating person with data
      
      const response = await apiService.updatePerson(id, name, birthDate, birthPlace, occupation, gender, familyTreeId);
      // Check if response and response.data exist before returning
      if (!response) {
        throw new Error('No response from server');
      }
      if (!response.data) {
        throw new Error('No data in response');
      }
      return response.data;
    } catch (error: any) {
      // Removed console.error for error updating person in treeService
      if (error.response) {
        // Removed console.error for error response status
        // Removed console.error for error response data
        // Removed console.error for error response headers
        // Handle authorization errors specifically
        if (error.response.status === 403) {
          throw new Error('You do not have permission to edit this person');
        }
        throw new Error(`Failed to update person: ${JSON.stringify(error.response.data)}`);
      } else {
        throw new Error('Failed to update person: ' + (error.message || 'Unknown error'));
      }
    }
  },

  // Get a person by ID
  getPersonById: async (id: number): Promise<Person> => {
    try {
      // Removed console.log for fetching person with ID
      
      // Try the standard approach first
      const response = await apiService.getPersonById(id);
      // Removed console.log for standard API response
      
      // Handle different response formats
      // The API might return the person data directly or wrapped in a response object
      if (response) {
        // Check if response is already the person data
        if (typeof response === 'object' && 
            (response.hasOwnProperty('id') || 
             response.hasOwnProperty('firstName') || 
             response.hasOwnProperty('lastName'))) {
          // Response is the person data directly
          return response as Person;
        }
        // Check if response has a data property containing the person
        else if (response.hasOwnProperty('data')) {
          return response.data as Person;
        }
        // If we can't determine the structure, return the response as-is
        else {
          // Removed console.warn for unexpected response format
          return response as Person;
        }
      } else {
        throw new Error('Empty response from API');
      }
    } catch (error: any) {
      // Removed console.error for error in getPersonById
      // Removed console.error for error response
      
      // If we get a 404, try to get all persons and find the one we're looking for
      if (error.response?.status === 404) {
        try {
          // Removed console.log for person not found directly, trying to fetch all persons
          const allPersons = await treeService.getAllPersons();
          // Removed console.log for all persons
          
          const person = allPersons.find(p => 
            p.id && (parseInt(p.id.toString()) === id || p.id.toString() === id.toString())
          );
          
          if (person) {
            // Removed console.log for found person in all persons list
            return person;
          }
        } catch (allPersonsError) {
          // Removed console.error for error fetching all persons
        }
      }
      
      // Re-throw the original error with more context
      if (error.response) {
        throw new Error(`API Error: ${error.response.status} - ${JSON.stringify(error.response.data)}`);
      } else {
        throw new Error(`Network Error: ${error.message || 'Unknown error'}`);
      }
    }
  },

  // Delete a person
  deletePerson: async (id: number): Promise<void> => {
    try {
      await apiService.deletePerson(id);
    } catch (error: any) {
      // Provide more detailed error information
      if (error.response) {
        // Server responded with error status
        const errorMessage = error.response.data?.message || 
                            error.response.data?.error || 
                            JSON.stringify(error.response.data);
        throw new Error(`Server error: ${error.response.status} - ${errorMessage || 'Unknown server error'}`);
      } else if (error.request) {
        // Request was made but no response received
        throw new Error('Network error: No response received from server. Please check your internet connection and try again.');
      } else {
        // Something else happened
        throw new Error(`Request setup error: ${error.message}`);
      }
    }
  },

  // Upload person photo
  uploadPersonPhoto: async (personId: number, file: File): Promise<any> => {
    try {
      const formData = new FormData();
      formData.append('picture', file);
      formData.append('PersonId', personId.toString());
      
      const response = await apiService.uploadPersonPicture(formData);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  // Delete person photo
  deletePersonPhoto: async (id: number): Promise<void> => {
    try {
      await apiService.deletePersonPicture(id);
    } catch (error) {
      throw error;
    }
  },

  // Add relationship
  addRelationship: async (personId: number, relatedPersonId: number, relationshipType: string): Promise<any> => {
    try {
      const response = await apiService.addRelationship(personId, relatedPersonId, relationshipType);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  // Get relationships
  getRelationships: async (): Promise<any[]> => {
    try {
      const response = await apiService.getRelationships();
      return response || [];
    } catch (error) {
      throw error;
    }
  },

  // Delete relationship
  deleteRelationship: async (id: number): Promise<void> => {
    try {
      await apiService.deleteRelationship(id);
    } catch (error) {
      throw error;
    }
  },
  
  // Get all persons across all trees
  getAllPersons: async (): Promise<Person[]> => {
    try {
      // First get all trees
      const trees = await treeService.getTrees();
      
      // Get all persons from all trees
      const allPersons: Person[] = [];
      
      for (const tree of trees) {
        try {
          const persons = await treeService.getPersonsInTree(parseInt(tree.id));
          allPersons.push(...persons);
        } catch (error) {
          // Removed console.error for error fetching persons for tree
          // Continue with other trees even if one fails
        }
      }
      
      return allPersons;
    } catch (error) {
      throw error;
    }
  },
  
  // Search persons by query
  searchPersons: async (query: string): Promise<Person[]> => {
    try {
      const allPersons = await treeService.getAllPersons();
      
      if (!query) return allPersons;
      
      const searchLower = query.toLowerCase();
      return allPersons.filter(person => {
        return (
          (person.firstName && person.firstName.toLowerCase().includes(searchLower)) ||
          (person.lastName && person.lastName.toLowerCase().includes(searchLower)) ||
          (person.birth && person.birth.place && person.birth.place.city && person.birth.place.city.toLowerCase().includes(searchLower)) ||
          (person.occupation && person.occupation.some(occ => occ.title.toLowerCase().includes(searchLower)))
        );
      });
    } catch (error) {
      throw error;
    }
  },
  
  // Search trees by query
  searchTrees: async (query: string): Promise<Tree[]> => {
    try {
      const userTrees = await treeService.getTrees();
      const publicTrees = await treeService.getPublicTrees();
      
      // Combine trees and remove duplicates by ID
      // A tree might appear in both user trees and public trees if it belongs to the user and is public
      const allTreesMap = new Map<string, Tree>();
      
      // Add user trees first
      userTrees.forEach(tree => allTreesMap.set(tree.id.toString(), tree));
      
      // Add public trees, but don't override user trees (to preserve user relationship data)
      publicTrees.forEach(tree => {
        if (!allTreesMap.has(tree.id.toString())) {
          allTreesMap.set(tree.id.toString(), tree);
        }
      });
      
      const allTreesData = Array.from(allTreesMap.values());
      
      if (!query) return allTreesData;
      
      const searchLower = query.toLowerCase();
      return allTreesData.filter(tree => {
        return (
          (tree.name && tree.name.toLowerCase().includes(searchLower)) ||
          (tree.description && tree.description.toLowerCase().includes(searchLower))
        );
      });
    } catch (error) {
      throw error;
    }
  },
  
  // Create join request for foreign tree
  createJoinRequest: async (
    familyTreeId: number,
    name: string,
    birthDate: string,
    birthPlace: string,
    gender: string,
    occupation: string,
    relatedPersonId: number,
    status: string,
    requesterId: string,
    relationshipType: string
  ): Promise<any> => {
    try {
      // Removed console.log for creating join request with data

      // Use the apiService directly
      const response = await apiService.createJoinRequest(
        familyTreeId,
        name,
        birthDate,
        birthPlace,
        gender,
        occupation,
        relatedPersonId,
        status,
        requesterId,
        relationshipType
      );
      
      return response;
    } catch (error: any) {
      // Removed console.error for error creating join request in treeService
      
      // Provide more detailed error information
      if (error.response) {
        // The request was made and the server responded with a status code
        // that falls out of the range of 2xx
        const errorMessage = error.response.data?.message || error.response.data?.error || JSON.stringify(error.response.data);
        throw new Error(`Server error: ${error.response.status} - ${errorMessage || 'Unknown server error'}`);
      } else if (error.request) {
        // The request was made but no response was received
        throw new Error('Network error: No response received from server. Please check your internet connection and try again.');
      } else {
        // Something happened in setting up the request that triggered an Error
        throw new Error(`Request setup error: ${error.message}`);
      }
    }
  },

  // Fetch incoming join requests for a specific tree (for tree owners)
  getIncomingJoinRequests: async (treeId: number): Promise<any[]> => {
    try {
      const response = await apiService.getJoinRequestsByTree(treeId);
      
      // Handle response correctly
      let requests: any[] = [];
      if (Array.isArray(response)) {
        requests = response;
      } else if (response && typeof response === 'object' && 'data' in response) {
        requests = Array.isArray(response.data) ? response.data : [];
      } else {
        requests = [];
      }
      
      return requests;
    } catch (error: any) {
      // Removed console.error for error fetching incoming join requests
      throw new Error(`Failed to fetch incoming join requests: ${error.message}`);
    }
  },

  // Fetch outgoing join requests (requests made by current user)
  getOutgoingJoinRequests: async (requesterId: string): Promise<any[]> => {
    try {
      const response = await apiService.getJoinRequestsByRequester(requesterId);
      
      // Handle response correctly
      let requests: any[] = [];
      if (Array.isArray(response)) {
        requests = response;
      } else if (response && typeof response === 'object' && 'data' in response) {
        requests = Array.isArray(response.data) ? response.data : [];
      } else {
        requests = [];
      }
      
      return requests;
    } catch (error: any) {
      // Removed console.error for error fetching outgoing join requests
      throw new Error(`Failed to fetch outgoing join requests: ${error.message}`);
    }
  },

  // Accept a join request
  acceptJoinRequest: async (id: number): Promise<any> => {
    try {
      const response = await apiService.acceptJoinRequest(id);
      return response;
    } catch (error: any) {
      // Removed console.error for error accepting join request
      throw new Error(`Failed to accept join request: ${error.message}`);
    }
  },

  // Reject a join request
  rejectJoinRequest: async (id: number): Promise<any> => {
    try {
      const response = await apiService.rejectJoinRequest(id);
      return response;
    } catch (error: any) {
      // Removed console.error for error rejecting join request
      throw new Error(`Failed to reject join request: ${error.message}`);
    }
  },

};

export default treeService;