import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuthStore } from '@/store/authStore';
import { useUIStore } from '@/store/uiStore';
import { useTreeStore } from '@/store/treeStore';
import { treeService } from '@/services/treeService';
import { Button } from '@/components/ui/Button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { 
  Users, 
  Plus, 
  Search, 
  Camera, 
  FileText, 
  TrendingUp,
  Calendar,
  Star,
  ArrowRight,
  Activity,
  AlertCircle,
  RefreshCw,
  X,
  UserPlus,
  TreePine,
  Image,
  Settings
} from 'lucide-react';
import { Tree, Person } from '@/types';
import { useMemoryMonitor } from '@/hooks/useMemoryMonitor';
import TreeFormModal from '@/components/trees/TreeFormModal';
import PersonFormModal from '@/components/forms/PersonFormModal';

const DashboardPage: React.FC = () => {
  const { user, getCurrentUser } = useAuthStore();
  const { language, showError } = useUIStore();
  const { trees, fetchTrees } = useTreeStore();
  const navigate = useNavigate();
  const { memoryInfo, isSupported } = useMemoryMonitor();
  
  const [stats, setStats] = useState({
    trees: 0,
    people: 0,
    photos: 0,
    documents: 0,
  });
  
  const [recentActivity, setRecentActivity] = useState<any[]>([]);
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [initialLoad, setInitialLoad] = useState(true);

  const [showTreeForm, setShowTreeForm] = useState(false);
  const [showPersonForm, setShowPersonForm] = useState(false);
  
  // Ensure we have the latest user data when dashboard loads
  useEffect(() => {
    const fetchUserData = async () => {
      try {
        await getCurrentUser();
      } catch (err) {
        // Show friendly error notification instead of console log
        showError(
          { 
            en: 'Failed to update user data', 
            ar: 'فشل في تحديث بيانات المستخدم' 
          },
          { 
            en: 'An error occurred while updating your user information', 
            ar: 'حدث خطأ أثناء تحديث معلومات المستخدم الخاصة بك' 
          }
        );
      }
    };

    if (!user?.firstName) {
      fetchUserData();
    }
  }, [getCurrentUser, user?.firstName, language, showError]);

  // Fetch data from API
  const fetchData = async (retryCount = 0) => {
    try {
      setError(null);
      
      // Check if browser has sufficient resources
      // @ts-ignore: deviceMemory is not in TypeScript's Navigator interface but exists in some browsers
      if (navigator.deviceMemory && navigator.deviceMemory < 2) {
        // Low memory warning handled by banner, no need for notification
      }
      
      // Only show loading spinner for initial load
      if (initialLoad) {
        setLoading(true);
      }
      
      // Fetch current user to ensure we have up-to-date data
      await getCurrentUser();
      
      // Fetch trees with timeout handling
      await Promise.race([
        fetchTrees(),
        new Promise((_, reject) => 
          setTimeout(() => reject(new Error('Request timeout')), 35000)
        )
      ]);
      
      // Calculate stats based on real data
      const treeCount = trees.length;
      let peopleCount = 0;
      let photoCount = 0;
      let documentCount = 0;
      
      // Calculate totals from trees
      trees.forEach(tree => {
        peopleCount += tree.stats?.totalPeople || 0;
        photoCount += tree.stats?.totalPhotos || 0;
        documentCount += tree.stats?.totalDocuments || 0;
      });
      
      setStats({
        trees: treeCount,
        people: peopleCount,
        photos: photoCount,
        documents: documentCount,
      });
      
      // Mock recent activity - in a real app, this would come from API
      const mockActivity = [
        {
          id: 1,
          type: 'person_added',
          message: language === 'ar' ? 'تم إضافة أحمد محمد إلى شجرة العائلة' : 'Added Ahmed Mohamed to Family Tree',
          time: '2 hours ago',
          icon: Users,
        },
        {
          id: 2,
          type: 'photo_uploaded',
          message: language === 'ar' ? 'تم رفع صورة جديدة لفاطمة علي' : 'Uploaded new photo for Fatima Ali',
          time: '1 day ago',
          icon: Camera,
        },
        {
          id: 3,
          type: 'tree_created',
          message: language === 'ar' ? 'تم إنشاء شجرة عائلة جديدة' : 'Created new family tree',
          time: '3 days ago',
          icon: Plus,
        },
      ];
      
      setRecentActivity(mockActivity);
      
      // Mock suggestions - in a real app, this would come from API
      const mockSuggestions = [
        {
          id: 1,
          type: 'missing_parent',
          title: language === 'ar' ? 'أضف معلومات الوالدين' : 'Add Parent Information',
          description: language === 'ar' ? 'أضف معلومات والدي أحمد محمد' : 'Add parent information for Ahmed Mohamed',
          priority: 'high' as const,
        },
        {
          id: 2,
          type: 'missing_photo',
          title: language === 'ar' ? 'أضف صورة شخصية' : 'Add Profile Photo',
          description: language === 'ar' ? 'أضف صورة لفاطمة علي' : 'Add a photo for Fatima Ali',
          priority: 'medium' as const,
        },
        {
          id: 3,
          type: 'missing_birth_date',
          title: language === 'ar' ? 'أضف تاريخ الميلاد' : 'Add Birth Date',
          description: language === 'ar' ? 'أضف تاريخ ميلاد محمد أحمد' : 'Add birth date for Mohamed Ahmed',
          priority: 'low' as const,
        },
      ];
      
      setSuggestions(mockSuggestions);
    } catch (err: any) {
      // More specific error messages based on error type
      if (err.code === 'ECONNABORTED' || err.message.includes('timeout')) {
        const errorMessage = language === 'ar' 
          ? 'انتهت مهلة الاتصال. يرجى التحقق من اتصالك بالإنترنت أو المحاولة مرة أخرى.' 
          : 'Connection timeout. Please check your internet connection and try again.';
        setError(errorMessage);
        showError(
          { 
            en: 'Connection Timeout', 
            ar: 'انتهت مهلة الاتصال' 
          },
          { 
            en: 'Connection timeout. Please check your internet connection and try again.', 
            ar: 'انتهت مهلة الاتصال. يرجى التحقق من اتصالك بالإنترنت أو المحاولة مرة أخرى.' 
          }
        );
      } else if (err.code === 'ERR_NETWORK' || err.message.includes('ERR_INSUFFICIENT_RESOURCES')) {
        const errorMessage = language === 'ar' 
          ? 'نظامك منخفض الموارد. يرجى إغلاق علامات التبويب الأخرى وإعادة المحاولة.' 
          : 'Your system is low on resources. Please close other tabs and try again.';
        setError(errorMessage);
        showError(
          { 
            en: 'Low System Resources', 
            ar: 'موارد النظام منخفضة' 
          },
          { 
            en: 'Your system is low on resources. Please close other tabs and try again.', 
            ar: 'نظامك منخفض الموارد. يرجى إغلاق علامات التبويب الأخرى وإعادة المحاولة.' 
          }
        );
      } else if (err.response?.status === 401) {
        const errorMessage = language === 'ar' 
          ? 'غير مصرح لك بالوصول. يرجى تسجيل الدخول مرة أخرى.' 
          : 'Unauthorized access. Please log in again.';
        setError(errorMessage);
        showError(
          { 
            en: 'Unauthorized Access', 
            ar: 'وصول غير مصرح' 
          },
          { 
            en: 'Unauthorized access. Please log in again.', 
            ar: 'غير مصرح لك بالوصول. يرجى تسجيل الدخول مرة أخرى.' 
          }
        );
      } else if (err.response?.status >= 500) {
        const errorMessage = language === 'ar' 
          ? 'خطأ في الخادم. يرجى المحاولة مرة أخرى لاحقاً.' 
          : 'Server error. Please try again later.';
        setError(errorMessage);
        showError(
          { 
            en: 'Server Error', 
            ar: 'خطأ في الخادم' 
          },
          { 
            en: 'Server error. Please try again later.', 
            ar: 'خطأ في الخادم. يرجى المحاولة مرة أخرى لاحقاً.' 
          }
        );
      } else if (err.response?.status >= 400) {
        const errorMessage = language === 'ar' 
          ? 'طلب غير صالح. يرجى المحاولة مرة أخرى.' 
          : 'Invalid request. Please try again.';
        setError(errorMessage);
        showError(
          { 
            en: 'Invalid Request', 
            ar: 'طلب غير صالح' 
          },
          { 
            en: 'Invalid request. Please try again.', 
            ar: 'طلب غير صالح. يرجى المحاولة مرة أخرى.' 
          }
        );
      } else if (!navigator.onLine) {
        const errorMessage = language === 'ar' 
          ? 'أنت غير متصل بالإنترنت. يرجى التحقق من اتصالك.' 
          : 'You are offline. Please check your internet connection.';
        setError(errorMessage);
        showError(
          { 
            en: 'Offline', 
            ar: 'غير متصل بالإنترنت' 
          },
          { 
            en: 'You are offline. Please check your internet connection.', 
            ar: 'أنت غير متصل بالإنترنت. يرجى التحقق من اتصالك.' 
          }
        );
      } else {
        const errorMessage = language === 'ar' 
          ? 'فشل في تحميل البيانات. يرجى المحاولة مرة أخرى.' 
          : 'Failed to load data. Please try again.';
        setError(errorMessage);
        showError(
          { 
            en: 'Failed to Load Data', 
            ar: 'فشل في تحميل البيانات' 
          },
          { 
            en: 'Failed to load data. Please try again.', 
            ar: 'فشل في تحميل البيانات. يرجى المحاولة مرة أخرى.' 
          }
        );
      }
    } finally {
      setLoading(false);
      setInitialLoad(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [language, getCurrentUser, fetchTrees, trees.length]);

  const quickActions = [
    {
      title: language === 'ar' ? 'إضافة شخص جديد' : 'Add New Person',
      description: language === 'ar' ? 'أضف فرد جديد إلى شجرة العائلة' : 'Add a new family member to your tree',
      icon: UserPlus,
      action: () => setShowPersonForm(true),
      color: 'bg-blue-500',
    },
    {
      title: language === 'ar' ? 'إنشاء شجرة جديدة' : 'Create New Tree',
      description: language === 'ar' ? 'ابدأ شجرة عائلة جديدة' : 'Start a new family tree',
      icon: TreePine,
      action: () => setShowTreeForm(true),
      color: 'bg-green-500',
    },
  ];

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case 'high': return 'text-red-600 bg-red-50';
      case 'medium': return 'text-yellow-600 bg-yellow-50';
      case 'low': return 'text-green-600 bg-green-50';
      default: return 'text-gray-600 bg-gray-50';
    }
  };

  const getPriorityLabel = (priority: string) => {
    const labels = {
      high: language === 'ar' ? 'عالية' : 'High',
      medium: language === 'ar' ? 'متوسطة' : 'Medium',
      low: language === 'ar' ? 'منخفضة' : 'Low',
    };
    return labels[priority as keyof typeof labels] || priority;
  };

  // Skeleton loader component for stats cards
  const StatsSkeleton = () => (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
      {[...Array(4)].map((_, index) => (
        <Card key={index}>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <div className="h-4 w-24 bg-muted rounded animate-pulse"></div>
            <div className="h-4 w-4 bg-muted rounded-full animate-pulse"></div>
          </CardHeader>
          <CardContent>
            <div className="h-6 w-8 bg-muted rounded animate-pulse mb-1"></div>
            <div className="h-3 w-16 bg-muted rounded animate-pulse"></div>
          </CardContent>
        </Card>
      ))}
    </div>
  );

  // Skeleton loader for quick actions
  const QuickActionsSkeleton = () => (
    <div>
      <div className="h-6 w-32 bg-muted rounded animate-pulse mb-4"></div>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        {[...Array(4)].map((_, index) => (
          <Card key={index} className="h-24">
            <div className="p-4 space-y-3">
              <div className="h-6 w-6 bg-muted rounded animate-pulse"></div>
              <div className="h-4 w-20 bg-muted rounded animate-pulse"></div>
              <div className="h-3 w-16 bg-muted rounded animate-pulse"></div>
            </div>
          </Card>
        ))}
      </div>
    </div>
  );

  // Skeleton loader for activity and suggestions
  const ActivitySkeleton = () => (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
      <Card>
        <CardHeader>
          <div className="h-5 w-32 bg-muted rounded animate-pulse"></div>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {[...Array(3)].map((_, index) => (
              <div key={index} className="flex items-start space-x-3">
                <div className="flex-shrink-0">
                  <div className="w-8 h-8 bg-muted rounded-full animate-pulse"></div>
                </div>
                <div className="flex-1 min-w-0 space-y-2">
                  <div className="h-4 w-48 bg-muted rounded animate-pulse"></div>
                  <div className="h-3 w-20 bg-muted rounded animate-pulse"></div>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
      
      <Card>
        <CardHeader>
          <div className="h-5 w-32 bg-muted rounded animate-pulse"></div>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {[...Array(3)].map((_, index) => (
              <div key={index} className="flex items-start justify-between p-3 bg-muted/30 rounded-lg">
                <div className="flex-1 space-y-2">
                  <div className="h-4 w-32 bg-muted rounded animate-pulse"></div>
                  <div className="h-3 w-40 bg-muted rounded animate-pulse"></div>
                </div>
                <div className="h-6 w-6 bg-muted rounded animate-pulse"></div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );

  if (loading && initialLoad) {
    return (
      <div className="space-y-8">
        {/* Welcome Section Skeleton */}
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between">
          <div>
            <div className="h-8 w-48 bg-muted rounded animate-pulse mb-2"></div>
            <div className="h-4 w-64 bg-muted rounded animate-pulse"></div>
          </div>
          <div className="mt-4 sm:mt-0">
            <div className="h-10 w-32 bg-muted rounded animate-pulse"></div>
          </div>
        </div>
        
        {/* Stats Skeleton */}
        <StatsSkeleton />
        
        {/* Quick Actions Skeleton */}
        <QuickActionsSkeleton />
        
        {/* Activity and Suggestions Skeleton */}
        <ActivitySkeleton />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-64 space-y-4">
        <AlertCircle className="h-12 w-12 text-red-500" />
        <h3 className="text-xl font-medium text-foreground">
          {language === 'ar' ? 'حدث خطأ' : 'An error occurred'}
        </h3>
        <p className="text-muted-foreground text-center max-w-md">{error}</p>
        <div className="flex gap-2">
          <Button onClick={() => fetchData()}>
            <RefreshCw className="mr-2 h-4 w-4" />
            {language === 'ar' ? 'إعادة المحاولة' : 'Try Again'}
          </Button>
          <Button variant="outline" asChild>
            <Link to="/trees">
              {language === 'ar' ? 'عرض الأشجار' : 'View Trees'}
            </Link>
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {/* Memory Warning Banner */}
      {isSupported && memoryInfo.isLowMemory && (
        <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4">
          <div className="flex">
            <div className="flex-shrink-0">
              <AlertCircle className="h-5 w-5 text-yellow-400" />
            </div>
            <div className="ml-3">
              <p className="text-sm text-yellow-700">
                {language === 'ar' 
                  ? 'نظامك منخفض الموارد. يرجى إغلاق علامات التبويب الأخرى لتحسين الأداء.' 
                  : 'Your system is low on resources. Please close other tabs to improve performance.'}
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Welcome Section */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-2xl sm:text-3xl font-bold text-foreground">
            {language === 'ar' 
              ? `مرحباً، ${user?.firstName || user?.email || 'مستخدم'}!`
              : `Welcome back, ${user?.firstName || user?.email || 'User'}!`
            }
          </h1>
          <p className="mt-2 text-muted-foreground">
            {language === 'ar' 
              ? 'إليك نظرة عامة على شجرة عائلتك'
              : "Here's an overview of your family tree"
            }
          </p>
        </div>
        <div className="flex flex-col sm:flex-row gap-2 mt-4 sm:mt-0">
          {/* Admin Dashboard Link - Only visible to admins */}
          {user?.role === 'admin' && (
            <Button asChild variant="outline">
              <Link to="/admin/dashboard">
                <Settings className="mr-2 h-4 w-4" />
                {language === 'ar' ? 'لوحة التحكم' : 'Admin Dashboard'}
              </Link>
            </Button>
          )}
          <Button asChild>
            <Link to="/trees">
              {language === 'ar' ? 'عرض جميع الأشجار' : 'View All Trees'}
              <ArrowRight className="mr-2 h-4 w-4" />
            </Link>
          </Button>
        </div>
      </div>

      {/* Stats Cards */}
      {loading ? <StatsSkeleton /> : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">
                {language === 'ar' ? 'أشجار العائلة' : 'Family Trees'}
              </CardTitle>
              <Users className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-xl sm:text-2xl font-bold">{stats.trees}</div>
              <p className="text-xs text-muted-foreground">
                {language === 'ar' ? '+1 هذا الشهر' : '+1 from last month'}
              </p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">
                {language === 'ar' ? 'أفراد العائلة' : 'Family Members'}
              </CardTitle>
              <Users className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-xl sm:text-2xl font-bold">{stats.people}</div>
              <p className="text-xs text-muted-foreground">
                {language === 'ar' ? '+3 هذا الأسبوع' : '+3 this week'}
              </p>
            </CardContent>
          </Card>

          {/* <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">
                {language === 'ar' ? 'الصور' : 'Photos'}
              </CardTitle>
              <Camera className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats.photos}</div>
              <p className="text-xs text-muted-foreground">
                {language === 'ar' ? '+2 اليوم' : '+2 today'}
              </p>
            </CardContent>
          </Card> */}

          {/* <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">
                {language === 'ar' ? 'الوثائق' : 'Documents'}
              </CardTitle>
              <FileText className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats.documents}</div>
              <p className="text-xs text-muted-foreground">
                {language === 'ar' ? 'لا تغيير' : 'No change'}
              </p>
            </CardContent>
          </Card> */}
        </div>
      )}

      {/* Quick Actions */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {quickActions.map((action, index) => (
          <Card 
            key={index} 
            className="cursor-pointer hover:shadow-md transition-shadow"
            onClick={action.action}
          >
            <CardContent className="p-6 flex flex-col items-center text-center">
              <div className={`w-12 h-12 ${action.color} rounded-full flex items-center justify-center mb-4`}>
                <action.icon className="h-6 w-6 text-white" />
              </div>
              <h3 className="font-semibold text-foreground mb-2">
                {action.title}
              </h3>
              <p className="text-sm text-muted-foreground">
                {action.description}
              </p>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Tree Create Form Modal */}
      <TreeFormModal
        isOpen={showTreeForm}
        onClose={() => setShowTreeForm(false)}
        mode="create"
        onSubmit={() => {
          setShowTreeForm(false);
          fetchData();
        }}
      />

      {/* Person Form Modal */}
      <PersonFormModal
        isOpen={showPersonForm}
        onClose={() => setShowPersonForm(false)}
        trees={trees}
        onSuccess={() => {
          fetchData();
        }}
      />

      {/* Subscription Status */}
      {user?.subscription && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center justify-between">
              <span className="flex items-center">
                <TrendingUp className="h-5 w-5 mr-2" />
                {language === 'ar' ? 'حالة الاشتراك' : 'Subscription Status'}
              </span>
              <span className={`px-3 py-1 text-xs rounded-full ${
                user.subscription.status === 'active' 
                  ? 'bg-green-100 text-green-800' 
                  : 'bg-yellow-100 text-yellow-800'
              }`}>
                {user.subscription.status === 'active' 
                  ? (language === 'ar' ? 'نشط' : 'Active')
                  : (language === 'ar' ? 'منتهي' : 'Expired')
                }
              </span>
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between">
              <div>
                <p className="text-sm text-foreground">
                  {language === 'ar' ? 'الخطة الحالية:' : 'Current Plan:'} 
                  <span className="font-medium ml-1 capitalize">
                    {user.subscription.plan}
                  </span>
                </p>
                <p className="text-xs text-muted-foreground">
                  {language === 'ar' ? 'ينتهي في:' : 'Expires on:'} 
                  {new Date(user.subscription.currentPeriodEnd).toLocaleDateString()}
                </p>
              </div>
              <Button asChild variant="outline" className="mt-4 sm:mt-0">
                <Link to="/subscription">
                  {language === 'ar' ? 'إدارة الاشتراك' : 'Manage Subscription'}
                </Link>
              </Button>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
};

export default DashboardPage;