import React, { useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useUIStore } from '@/store/uiStore';
import { useTreeStore } from '@/store/treeStore';
import { treeService } from '@/services/treeService';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Textarea } from '@/components/ui/Textarea';
import { 
  TreePine, 
  Save, 
  ArrowLeft,
  Camera,
  Info,
  Loader2
} from 'lucide-react';
import toast from 'react-hot-toast';
import { useMobile } from '@/hooks/useMobile'; // Add mobile hook import
import bilingualToast from '@/utils/bilingualToast';

interface NewTreeData {
  name: string;
  nameEn: string;
  description?: string;
  descriptionEn?: string;
  coverImage?: string;
  isPublic: boolean;
  allowCollaboration: boolean;
}

interface TreeCreateFormProps {
  onCancel?: () => void;
  onSuccess?: (treeId: string) => void;
}

const TreeCreateForm: React.FC<TreeCreateFormProps> = ({ onCancel, onSuccess }) => {
  const navigate = useNavigate();
  const { language } = useUIStore();
  const { createTree, isLoading } = useTreeStore();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { isMobile } = useMobile(); // Add mobile detection

  const isRTL = language === 'ar';

  const [newTreeData, setNewTreeData] = useState<NewTreeData>({
    name: '',
    nameEn: '',
    description: '',
    descriptionEn: '',
    isPublic: true,
    allowCollaboration: false,
  });
  
  const [error, setError] = useState<string | null>(null);

  const handleCoverImageChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const result = e.target?.result as string;
        setNewTreeData(prev => ({ ...prev, coverImage: result }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCreateTree = async () => {
    try {
      // Clear previous errors
      setError(null);
      
      // Match exact API requirements from apiService.addTree
      const createdTree = await treeService.createTree(
        isRTL ? newTreeData.name : newTreeData.nameEn,
        !newTreeData.isPublic, // Convert public to private for API
        isRTL ? (newTreeData.description || '') : (newTreeData.descriptionEn || '')
      );
      
      bilingualToast.success({
        en: 'Tree created successfully',
        ar: 'تم إنشاء الشجرة بنجاح'
      });
      
      // Call onSuccess callback if provided, otherwise navigate to tree view
      if (onSuccess) {
        onSuccess(createdTree.id);
      } else {
        navigate(`/trees/${createdTree.id}`);
      }
    } catch (error: any) {
      
      // Handle specific error messages from the API
      let errorMessage = isRTL ? 'فشل في إنشاء الشجرة' : 'Failed to create tree';
      let errorTitle = isRTL ? 'خطأ في إنشاء الشجرة' : 'Tree Creation Error';
      
      // Check for specific error conditions
      if (error.response) {
        // Handle 400 status code specifically for duplicate names
        if (error.response.status === 400) {
          // Check if it's a duplicate name error based on common patterns
          if (error.response.data?.message) {
            const message = error.response.data.message.toLowerCase();
            if (message.includes('duplicate') || 
                message.includes('already exists') ||
                message.includes('in use') ||
                message.includes('unique')) {
              errorMessage = isRTL 
                ? 'اسم الشجرة مستخدم بالفعل. يرجى اختيار اسم مختلف.' 
                : 'Tree name is already in use. Please choose a different name.';
              errorTitle = isRTL ? 'اسم مكرر' : 'Duplicate Name';
            } else {
              errorMessage += `: ${error.response.data.message}`;
            }
          } else {
            // Generic 400 error message
            errorMessage = isRTL 
              ? 'طلب غير صالح. يرجى التحقق من المعلومات المدخلة.' 
              : 'Invalid request. Please check the entered information.';
            errorTitle = isRTL ? 'طلب غير صالح' : 'Invalid Request';
          }
        } else if (error.response.data?.message) {
          errorMessage += `: ${error.response.data.message}`;
        }
      } else if (error.message) {
        errorMessage += `: ${error.message}`;
      }
      
      setError(errorMessage);
      bilingualToast.error({
        en: errorMessage,
        ar: errorMessage
      });
    }
  };

  const canProceedToNext = () => {
    return newTreeData.name.trim() !== '' && newTreeData.nameEn.trim() !== '';
  };

  return (
    <div className="space-y-6">
      {/* Error Message */}
      {error && (
        <div className="bg-destructive/10 border border-destructive/20 rounded-lg p-3">
          <p className="text-destructive text-sm">{error}</p>
        </div>
      )}
      
      {/* Tree Information Form */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Info className="h-5 w-5" />
            {isMobile ? (isRTL ? 'معلومات' : 'Info') : (isRTL ? 'معلومات الشجرة' : 'Tree Information')}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-6">
          {/* Cover Image */}
          <div className="space-y-2">
            <label className="text-sm font-medium">
              {isMobile ? (isRTL ? 'صورة' : 'Image') : (isRTL ? 'صورة الغلاف' : 'Cover Image')}
            </label>
            <div className="relative">
              <div className={`w-full rounded-lg bg-gradient-to-br from-primary/20 to-primary/40 flex items-center justify-center overflow-hidden ${isMobile ? 'h-32' : 'h-48'}`}>
                {newTreeData.coverImage ? (
                  <img 
                    src={newTreeData.coverImage} 
                    alt="Tree Cover" 
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <div className="text-center">
                    <TreePine className={`mx-auto mb-2 ${isMobile ? 'h-8 w-8' : 'h-16 w-16'}`} />
                    <p className="text-sm text-muted-foreground">
                      {isMobile ? (isRTL ? 'اختر صورة' : 'Choose Image') : (isRTL ? 'اختر صورة غلاف للشجرة' : 'Choose a cover image for the tree')}
                    </p>
                  </div>
                )}
              </div>
              <Button
                size={isMobile ? "sm" : "default"}
                variant="outline"
                className={`absolute bottom-2 right-2 flex items-center gap-2 ${isMobile ? 'px-2 py-1 text-xs' : ''}`}
                onClick={() => fileInputRef.current?.click()}
              >
                <Camera className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
                {isMobile ? (isRTL ? 'صورة' : 'Image') : (isRTL ? 'اختيار صورة' : 'Choose Image')}
              </Button>
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={handleCoverImageChange}
                className="hidden"
              />
            </div>
          </div>

          <div className={`grid grid-cols-1 ${isMobile ? 'gap-4' : 'md:grid-cols-2 gap-6'}`}>
            {/* Tree Name */}
            <div className="space-y-2">
              <label className="text-sm font-medium">
                {isMobile ? (isRTL ? 'الاسم (عربي)' : 'Name (Ar)') : (isRTL ? 'اسم الشجرة (عربي) *' : 'Tree Name (Arabic) *')}
              </label>
              <Input
                value={newTreeData.name}
                onChange={(e) => setNewTreeData(prev => ({ ...prev, name: e.target.value }))}
                placeholder={isMobile ? (isRTL ? 'اسم الشجرة' : 'Tree Name') : (isRTL ? 'مثال: شجرة عائلة آل أحمد' : 'Example: Al-Ahmed Family Tree')}
                required
              />
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium">
                {isMobile ? (isRTL ? 'الاسم (إنجليزي)' : 'Name (En)') : (isRTL ? 'اسم الشجرة (إنجليزي) *' : 'Tree Name (English) *')}
              </label>
              <Input
                value={newTreeData.nameEn}
                onChange={(e) => setNewTreeData(prev => ({ ...prev, nameEn: e.target.value }))}
                placeholder={isMobile ? "Tree Name" : "Example: Al-Ahmed Family Tree"}
                required
              />
            </div>
          </div>

          {/* Description */}
          <div className="space-y-2">
            <label className="text-sm font-medium">
              {isMobile ? (isRTL ? 'وصف' : 'Description') : (isRTL ? 'وصف الشجرة' : 'Tree Description')}
            </label>
            <Textarea
              value={isRTL ? newTreeData.description || '' : newTreeData.descriptionEn || ''}
              onChange={(e) => setNewTreeData(prev => ({ 
                ...prev, 
                [isRTL ? 'description' : 'descriptionEn']: e.target.value 
              }))}
              placeholder={isMobile ? (isRTL ? 'وصف الشجرة' : 'Tree Description') : (isRTL ? 'اكتب وصفاً للشجرة...' : 'Write a description for the tree...')}
              rows={isMobile ? 3 : 4}
            />
          </div>

          {/* Privacy Settings */}
          <div className="space-y-4">
            <h3 className={`font-medium ${isMobile ? 'text-base' : 'text-lg'}`}>
              {isMobile ? (isRTL ? 'إعدادات' : 'Settings') : (isRTL ? 'إعدادات الخصوصية' : 'Privacy Settings')}
            </h3>
            
            <div className="flex items-center justify-between p-4 border rounded-lg">
              <div>
                <p className={`font-medium ${isMobile ? 'text-sm' : ''}`}>
                  {isMobile ? (isRTL ? 'عامة' : 'Public') : (isRTL ? 'شجرة عامة' : 'Public Tree')}
                </p>
                <p className={`text-sm text-muted-foreground ${isMobile ? 'text-xs' : ''}`}>
                  {isMobile ? (isRTL ? 'يمكن للجميع رؤية الشجرة' : 'Everyone can view the tree') : (isRTL ? 'يمكن للجميع رؤية الشجرة' : 'Everyone can view the tree')}
                </p>
              </div>
              <Button
                variant={newTreeData.isPublic ? "default" : "outline"}
                size={isMobile ? "sm" : "default"}
                onClick={() => setNewTreeData(prev => ({ ...prev, isPublic: !prev.isPublic }))}
              >
                {newTreeData.isPublic ? (isRTL ? 'عامة' : 'Public') : (isRTL ? 'خاصة' : 'Private')}
              </Button>
            </div>

            <div className="flex items-center justify-between p-4 border rounded-lg">
              <div>
                <p className={`font-medium ${isMobile ? 'text-sm' : ''}`}>
                  {isMobile ? (isRTL ? 'تعاون' : 'Collab') : (isRTL ? 'السماح بالتعاون' : 'Allow Collaboration')}
                </p>
                <p className={`text-sm text-muted-foreground ${isMobile ? 'text-xs' : ''}`}>
                  {isMobile ? (isRTL ? 'السماح للآخرين بالمساهمة' : 'Allow others to contribute') : (isRTL ? 'السماح للآخرين بالمساهمة' : 'Allow others to contribute')}
                </p>
              </div>
              <Button
                variant={newTreeData.allowCollaboration ? "default" : "outline"}
                size={isMobile ? "sm" : "default"}
                onClick={() => setNewTreeData(prev => ({ ...prev, allowCollaboration: !prev.allowCollaboration }))}
              >
                {newTreeData.allowCollaboration ? (isRTL ? 'مفعل' : 'On') : (isRTL ? 'معطل' : 'Off')}
              </Button>
            </div>
          </div>

          {/* Actions */}
          <div className={`flex ${isMobile ? 'flex-col gap-2' : 'gap-3 pt-4'}`}>
            <Button 
              onClick={handleCreateTree} 
              className={`flex items-center gap-2 ${isMobile ? 'w-full' : ''}`}
              disabled={isLoading || !canProceedToNext()}
            >
              {isLoading ? (
                <Loader2 className={`animate-spin ${isMobile ? 'h-3 w-3' : 'h-4 w-4'}`} />
              ) : (
                <Save className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : ''}`} />
              )}
              {isMobile ? (isRTL ? 'إنشاء' : 'Create') : (isRTL ? 'إنشاء الشجرة' : 'Create Tree')}
            </Button>
            <Button 
              variant="outline" 
              onClick={onCancel || (() => navigate('/trees'))}
              disabled={isLoading}
              className={isMobile ? 'w-full' : ''}
            >
              {isMobile ? (isRTL ? 'إلغاء' : 'Cancel') : (isRTL ? 'إلغاء' : 'Cancel')}
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

export default TreeCreateForm;