/**
 * Simple encryption/decryption utility for tree IDs
 * Uses Web Crypto API for client-side encryption
 */

// Convert string to ArrayBuffer
function stringToArrayBuffer(str: string): ArrayBuffer {
  const encoder = new TextEncoder();
  return encoder.encode(str).buffer;
}

// Convert ArrayBuffer to string
function arrayBufferToString(buffer: ArrayBuffer): string {
  const decoder = new TextDecoder();
  return decoder.decode(buffer);
}

// Convert ArrayBuffer to base64 string
function arrayBufferToBase64(buffer: ArrayBuffer): string {
  const bytes = new Uint8Array(buffer);
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

// Convert base64 string to ArrayBuffer
function base64ToArrayBuffer(base64: string): ArrayBuffer {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes.buffer;
}

// Generate a key for encryption/decryption
async function generateKey(): Promise<CryptoKey> {
  // Use a fixed key for simplicity - in production, you might want to derive this from a secret
  const keyMaterial = stringToArrayBuffer('nasabna-tree-sharing-key-2025');
  return crypto.subtle.importKey(
    'raw',
    keyMaterial,
    { name: 'AES-GCM' },
    false,
    ['encrypt', 'decrypt']
  );
}

// Encrypt a string
export async function encryptString(text: string): Promise<string> {
  try {
    console.log('Encrypting string:', text);
    const key = await generateKey();
    const encoder = new TextEncoder();
    const data = encoder.encode(text);
    
    // Generate a random IV
    const iv = crypto.getRandomValues(new Uint8Array(12));
    
    // Encrypt the data
    const encryptedData = await crypto.subtle.encrypt(
      {
        name: 'AES-GCM',
        iv: iv,
      },
      key,
      data
    );
    
    // Combine IV and encrypted data
    const combined = new Uint8Array(iv.length + encryptedData.byteLength);
    combined.set(iv, 0);
    combined.set(new Uint8Array(encryptedData), iv.length);
    
    // Return as base64 string
    const result = arrayBufferToBase64(combined.buffer);
    console.log('Encrypted result:', result);
    return result;
  } catch (error) {
    // If encryption fails, fall back to the original ID
    console.warn('Encryption failed, falling back to original ID:', error);
    return text;
  }
}

// Decrypt a string
export async function decryptString(encryptedText: string): Promise<string> {
  try {
    console.log('Decrypting string:', encryptedText);
    const key = await generateKey();
    const combined = base64ToArrayBuffer(encryptedText);
    const combinedArray = new Uint8Array(combined);
    
    // Extract IV and encrypted data
    const iv = combinedArray.slice(0, 12);
    const encryptedData = combinedArray.slice(12);
    
    // Decrypt the data
    const decryptedData = await crypto.subtle.decrypt(
      {
        name: 'AES-GCM',
        iv: iv,
      },
      key,
      encryptedData
    );
    
    // Convert to string
    const decoder = new TextDecoder();
    const result = decoder.decode(decryptedData);
    console.log('Decrypted result:', result);
    return result;
  } catch (error) {
    // If decryption fails, assume it's already a plain ID
    console.warn('Decryption failed, assuming plain ID:', error);
    return encryptedText;
  }
}