import React from 'react';
import { X, CheckCircle, AlertCircle, Info, AlertTriangle } from 'lucide-react';
import { Notification } from '@/types';
import { useUIStore } from '@/store/uiStore';
import { getLocalizedMessage, isBilingualMessage } from '@/utils/notifications';

interface ToastProps {
  notification: Notification;
  onClose: (id: string) => void;
}

const Toast: React.FC<ToastProps> = ({ notification, onClose }) => {
  const { type, title, message, id } = notification;
  const { language } = useUIStore();
  
  // Handle bilingual titles and messages
  const getTitle = () => {
    return getLocalizedMessage(title, language);
  };
  
  const getMessage = () => {
    return getLocalizedMessage(message, language);
  };
  
  const getIcon = () => {
    switch (type) {
      case 'success':
        return <CheckCircle className="h-5 w-5 text-green-500" />;
      case 'error':
        return <AlertCircle className="h-5 w-5 text-red-500" />;
      case 'warning':
        return <AlertTriangle className="h-5 w-5 text-yellow-500" />;
      case 'info':
        return <Info className="h-5 w-5 text-blue-500" />;
      default:
        return null;
    }
  };

  const getBackgroundColor = () => {
    switch (type) {
      case 'success':
        return 'bg-green-50 border-green-200';
      case 'error':
        return 'bg-red-50 border-red-200';
      case 'warning':
        return 'bg-yellow-50 border-yellow-200';
      case 'info':
        return 'bg-blue-50 border-blue-200';
      default:
        return 'bg-white border-gray-200';
    }
  };

  const getTitleColor = () => {
    switch (type) {
      case 'success':
        return 'text-green-800';
      case 'error':
        return 'text-red-800';
      case 'warning':
        return 'text-yellow-800';
      case 'info':
        return 'text-blue-800';
      default:
        return 'text-gray-800';
    }
  };

  const getMessageColor = () => {
    switch (type) {
      case 'success':
        return 'text-green-700';
      case 'error':
        return 'text-red-700';
      case 'warning':
        return 'text-yellow-700';
      case 'info':
        return 'text-blue-700';
      default:
        return 'text-gray-700';
    }
  };

  return (
    <div 
      className={`flex items-start p-4 rounded-lg border shadow-lg max-w-sm w-full ${getBackgroundColor()}`}
      role="alert"
      aria-live="assertive"
      dir={language === 'ar' ? 'rtl' : 'ltr'}
    >
      <div className="flex-shrink-0">
        {getIcon()}
      </div>
      <div className="ml-3 flex-1">
        <h3 className={`text-sm font-medium ${getTitleColor()}`}>
          {getTitle()}
        </h3>
        {getMessage() && (
          <div className={`mt-1 text-sm ${getMessageColor()}`}>
            <p>{getMessage()}</p>
          </div>
        )}
      </div>
      <div className="ml-4 flex-shrink-0">
        <button
          type="button"
          className="inline-flex rounded-md focus:outline-none focus:ring-2 focus:ring-offset-2"
          onClick={() => onClose(id)}
          aria-label={language === 'ar' ? 'إغلاق' : 'Close'}
        >
          <X className="h-5 w-5 text-gray-400 hover:text-gray-500" />
        </button>
      </div>
    </div>
  );
};

export default Toast;