import React, { useState, ReactNode } from 'react';
import { cn } from '@/utils/cn';

interface TabsProps {
  children: ReactNode;
  value: string;
  onValueChange: (value: string) => void;
}

interface TabsListProps {
  children: ReactNode;
  className?: string;
}

interface TabsTriggerProps {
  value: string;
  children: ReactNode;
  className?: string;
  onClick?: () => void;
}

interface TabsContentProps {
  value: string;
  children: ReactNode;
  className?: string;
}

const Tabs = ({ children, value, onValueChange }: TabsProps) => {
  return (
    <div className="space-y-4">
      {React.Children.map(children, child => {
        if (!React.isValidElement(child)) return child;
        
        if (child.type === TabsList) {
          return React.cloneElement(child, {
            ...child.props
          });
        }
        
        if (child.type === TabsContent) {
          return React.cloneElement(child, {
            ...child.props,
            className: cn('mt-4', child.props.className)
          });
        }
        
        return child;
      })}
    </div>
  );
};

const TabsList = ({ children, className }: TabsListProps) => {
  return (
    <div className={cn('inline-flex h-10 items-center justify-center rounded-md bg-muted p-1 text-muted-foreground', className)}>
      {React.Children.map(children, child => {
        if (!React.isValidElement(child)) return child;
        
        if (child.type === TabsTrigger) {
          return React.cloneElement(child, {
            ...child.props
          });
        }
        
        return child;
      })}
    </div>
  );
};

const TabsTrigger = ({ value, children, className }: TabsTriggerProps) => {
  return (
    <button
      type="button"
      role="tab"
      aria-selected={false}
      className={cn(
        'inline-flex items-center justify-center whitespace-nowrap rounded-sm px-3 py-1.5 text-sm font-medium ring-offset-background transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 data-[state=active]:bg-background data-[state=active]:text-foreground',
        className
      )}
    >
      {children}
    </button>
  );
};

const TabsContent = ({ value, children, className }: TabsContentProps) => {
  // This component needs to be connected to the Tabs parent component
  // For now, we'll just render the content
  return (
    <div className={className}>
      {children}
    </div>
  );
};

export { Tabs, TabsList, TabsTrigger, TabsContent };