import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuthStore } from '@/store/authStore';
import { useUIStore } from '@/store/uiStore';
import { Button } from '@/components/ui/Button';
import ToastContainer from '@/components/ui/ToastContainer';
import { 
  Menu, 
  X, 
  Home, 
  Users, 
  Search, 
  Settings, 
  User, 
  CreditCard,
  LogOut,
  Globe,
  Sun,
  Moon,
  ChevronDown
} from 'lucide-react';

interface DashboardLayoutProps {
  children: React.ReactNode;
}

const DashboardLayout: React.FC<DashboardLayoutProps> = ({ children }) => {
  const [sidebarOpen, setSidebarOpen] = React.useState(false);
  const [isProfileDropdownOpen, setIsProfileDropdownOpen] = React.useState(false);
  const location = useLocation();
  const navigate = useNavigate();
  
  const { user, logout } = useAuthStore();
  const { language, theme, setLanguage, setTheme } = useUIStore();

  // Don't render layout until we have user data to prevent layout shift
  const isUserDataReady = !!user;

  const navigation = [
    { 
      name: 'Dashboard', 
      nameAr: 'لوحة التحكم', 
      href: '/dashboard', 
      icon: Home 
    },
    { 
      name: 'Family Trees', 
      nameAr: 'أشجار العائلة', 
      href: '/trees', 
      icon: Users 
    },
    
    // { 
    //   name: 'Search', 
    //   nameAr: 'البحث', 
    //   href: '/search', 
    //   icon: Search 
    // },
    { 
      name: 'Profile', 
      nameAr: 'الملف الشخصي', 
      href: '/profile', 
      icon: User 
    },
    { 
      name: 'Subscription', 
      nameAr: 'الاشتراك', 
      href: '/subscription/manage', 
      icon: CreditCard 
    },
    { 
      name: 'Settings', 
      nameAr: 'الإعدادات', 
      href: '/settings', 
      icon: Settings 
    },
    // Add admin navigation item
    ...(user?.role === 'admin' ? [{
      name: 'Admin Dashboard',
      nameAr: 'لوحة مشرف',
      href: '/admin/dashboard',
      icon: Users // Using Users icon for admin dashboard
    }] : [])
  ];

  const toggleLanguage = () => {
    setLanguage(language === 'en' ? 'ar' : 'en');
  };

  const toggleTheme = () => {
    setTheme(theme === 'light' ? 'dark' : 'light');
  };

  const handleLogout = async () => {
    try {
      await logout();
      navigate('/');
    } catch (error) {
      // Error handling is done through UI notifications
    }
  };

  // Add RTL-aware class for the navigation
  const isCurrentPath = (path: string) => {
    // Handle both current path and paths with parameters
    return location.pathname === path || location.pathname.startsWith(path + '/');
  };

  // Apply RTL direction to document when language changes
  React.useEffect(() => {
    if (language === 'ar') {
      document.documentElement.setAttribute('dir', 'rtl');
    } else {
      document.documentElement.setAttribute('dir', 'ltr');
    }
  }, [language]);

  // Close sidebar when resizing to desktop
  React.useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 1024) { // lg breakpoint
        setSidebarOpen(false);
      }
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Close profile dropdown when clicking outside
  React.useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (isProfileDropdownOpen) {
        const profileDropdown = document.getElementById('profile-dropdown');
        const profileButton = document.getElementById('profile-button');
        
        if (profileDropdown && profileButton && 
            !profileDropdown.contains(event.target as Node) && 
            !profileButton.contains(event.target as Node)) {
          setIsProfileDropdownOpen(false);
        }
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isProfileDropdownOpen]);

  if (!isUserDataReady) {
    // Render a minimal version of the layout while loading
    return (
      <div className="min-h-screen bg-background">
        <div className={`${language === 'ar' ? 'lg:pr-72' : 'lg:pl-72'}`} >
          <div className="sticky top-0 z-40 flex h-16 shrink-0 items-center gap-x-4 border-b border-border bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60 px-4 shadow-sm sm:gap-x-6 sm:px-6 lg:px-8">
            <div className="flex flex-1"></div>
            <div className="flex items-center gap-x-4 lg:gap-x-6">
              <div className="relative">
                <div className="flex items-center space-x-3">
                  <div className="flex-shrink-0">
                    <div className="h-8 w-8 rounded-full bg-muted animate-pulse"></div>
                  </div>
                  <div className="hidden lg:block">
                    <div className="h-4 w-20 bg-muted rounded animate-pulse mb-1"></div>
                    <div className="h-3 w-16 bg-muted rounded animate-pulse"></div>
                  </div>
                </div>
              </div>
            </div>
          </div>
          <main className="py-6">
            <div className="px-4 sm:px-6 lg:px-8">
              {children}
            </div>
          </main>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      {/* Toast Container for notifications */}
      <ToastContainer />
      
      {/* Desktop sidebar */}
      <div className={`hidden lg:fixed lg:inset-y-0 lg:z-50 lg:flex lg:w-72 lg:flex-col ${language === 'ar' ? 'lg:right-0' : 'lg:left-0'}`}>
        <div className="flex grow flex-col gap-y-5 overflow-y-auto bg-card border-border px-6 pb-4 lg:border-r">
          <div className="flex h-16 shrink-0 items-center">
            <Link to="/dashboard" className={`flex items-center ${language === 'ar' ? 'space-x-reverse' : 'space-x-2'}`}>
              <svg
                className="h-8 w-8 text-primary"
                viewBox="0 0 100 100"
                fill="none"
                xmlns="http://www.w3.org/2000/svg"
              >
                <circle cx="50" cy="50" r="45" stroke="currentColor" strokeWidth="2" fill="none" opacity="0.3"/>
                <path d="M50 20 L35 35 L50 50 L65 35 Z" fill="currentColor"/>
                <path d="M35 35 L20 50 L35 65 L50 50 Z" fill="currentColor" opacity="0.8"/>
                <path d="M65 35 L80 50 L65 65 L50 50 Z" fill="currentColor" opacity="0.8"/>
                <path d="M35 65 L50 80 L65 65 L50 50 Z" fill="currentColor" opacity="0.6"/>
                <circle cx="50" cy="35" r="3" fill="currentColor"/>
                <circle cx="35" cy="50" r="3" fill="currentColor"/>
                <circle cx="65" cy="50" r="3" fill="currentColor"/>
                <circle cx="50" cy="65" r="3" fill="currentColor"/>
              </svg>
              <span className={`text-lg font-semibold text-foreground ${language === 'ar' ? 'rtl:text-right' : ''}`}>
                {language === 'ar' ? 'نسبنا' : 'Nasabna'}
              </span>
            </Link>
          </div>
          
          <nav className="flex flex-1 flex-col">
            <ul role="list" className="flex flex-1 flex-col gap-y-7">
              <li>
                <ul role="list" className="-mx-2 space-y-1">
                  {navigation.map((item) => (
                    <li key={item.name}>
                      <Link
                        to={item.href}
                        className={`group flex items-center rounded-md p-2 text-sm leading-6 font-semibold transition-colors ${
                          isCurrentPath(item.href)
                            ? 'bg-primary text-primary-foreground'
                            : 'text-muted-foreground hover:text-foreground hover:bg-muted'
                        } ${language === 'ar' ? 'flex-row-reverse' : ''}`}
                      >
                        <item.icon className="h-6 w-6 shrink-0" aria-hidden="true" />
                        <span className={`truncate ${language === 'ar' ? 'mr-3' : 'ml-3'}`}>
                          {language === 'ar' ? item.nameAr : item.name}
                        </span>
                      </Link>
                    </li>
                  ))}
                </ul>
              </li>
            </ul>
          </nav>
        </div>
      </div>

      {/* Main content */}
      <div className={`${language === 'ar' ? 'lg:pr-72' : 'lg:pl-72'}`}>
        {/* Top bar */}
        <div className="sticky top-0 z-40 flex h-16 shrink-0 items-center gap-x-4 border-b border-border bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60 px-4 shadow-sm sm:gap-x-6 sm:px-6 lg:px-8">
          <button
            type="button"
            className="-m-2.5 p-2.5 text-muted-foreground lg:hidden"
            onClick={() => setSidebarOpen(true)}
          >
            <span className="sr-only">Open sidebar</span>
            <Menu className="h-6 w-6" aria-hidden="true" />
          </button>

          {/* Separator */}
          <div className="h-6 w-px bg-border lg:hidden" aria-hidden="true" />

          <div className="flex flex-1 gap-x-4 self-stretch lg:gap-x-6">
            <div className="flex flex-1"></div>
            
            <div className="flex items-center gap-x-4 lg:gap-x-6">
              {/* Theme toggle */}
              <Button
                variant="ghost"
                size="icon"
                onClick={toggleTheme}
                className="h-9 w-9"
              >
                {theme === 'light' ? (
                  <Moon className="h-4 w-4" />
                ) : (
                  <Sun className="h-4 w-4" />
                )}
              </Button>

              {/* Language toggle */}
              <Button
                variant="ghost"
                size="icon"
                onClick={toggleLanguage}
                className="h-9 w-9"
              >
                <Globe className="h-4 w-4" />
              </Button>

              {/* Separator */}
              <div className="hidden lg:block lg:h-6 lg:w-px lg:bg-border" aria-hidden="true" />

              {/* Profile dropdown */}
              <div className="relative">
                <Button
                  id="profile-button"
                  variant="ghost"
                  className="flex items-center space-x-2 rounded-full p-1 hover:bg-muted"
                  onClick={() => setIsProfileDropdownOpen(!isProfileDropdownOpen)}
                >
                  <div className="flex-shrink-0">
                    {user?.avatar?.url ? (
                      <img
                        className="h-8 w-8 rounded-full object-cover"
                        src={user.avatar.url}
                        alt={`${user?.firstName || ''} ${user?.lastName || ''}`}
                      />
                    ) : (
                      <div className="h-8 w-8 rounded-full bg-primary/10 flex items-center justify-center">
                        <User className="h-4 w-4 text-primary" />
                      </div>
                    )}
                  </div>
                  <div className="hidden lg:block text-left">
                    <p className="text-sm font-medium text-foreground">
                      {user?.firstName ? `${user.firstName} ${user?.lastName || ''}`.trim() : user?.email || 'User'}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      {user?.email || ''}
                    </p>
                  </div>
                  <ChevronDown className="hidden lg:block h-4 w-4 text-muted-foreground" />
                </Button>

                {/* Profile dropdown menu */}
                {isProfileDropdownOpen && (
                  <div 
                    id="profile-dropdown" 
                    className={`absolute z-10 mt-2 w-56 origin-top-right rounded-md bg-card shadow-lg ring-1 ring-border focus:outline-none ${
                      language === 'ar' ? 'left-0' : 'right-0'
                    }`}
                  >
                    <div className="p-1">
                      <div className="px-4 py-2 border-b border-border">
                        <p className="text-sm font-medium text-foreground">
                          {user?.firstName ? `${user.firstName} ${user?.lastName || ''}`.trim() : user?.email || 'User'}
                        </p>
                        <p className="text-xs text-muted-foreground">
                          {user?.email || ''}
                        </p>
                      </div>
                      <Link
                        to="/profile"
                        className="block px-4 py-2 text-sm text-foreground hover:bg-muted rounded-md"
                        onClick={() => setIsProfileDropdownOpen(false)}
                      >
                        {language === 'ar' ? 'الملف الشخصي' : 'Profile'}
                      </Link>
                      <Link
                        to="/settings"
                        className="block px-4 py-2 text-sm text-foreground hover:bg-muted rounded-md"
                        onClick={() => setIsProfileDropdownOpen(false)}
                      >
                        {language === 'ar' ? 'الإعدادات' : 'Settings'}
                      </Link>
                      <button
                        onClick={() => {
                          setIsProfileDropdownOpen(false);
                          handleLogout();
                        }}
                        className="w-full text-left px-4 py-2 text-sm text-foreground hover:bg-muted rounded-md flex items-center"
                      >
                        <LogOut className="mr-2 h-4 w-4" />
                        {language === 'ar' ? 'تسجيل الخروج' : 'Logout'}
                      </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Page content */}
        <main className="py-6">
          <div className="px-4 sm:px-6 lg:px-8">
            {children}
          </div>
        </main>
      </div>

      {/* Mobile sidebar - Completely separate from header */}
      {sidebarOpen && (
        <div className="lg:hidden fixed inset-0 z-50">
          <div 
            className="fixed inset-0 bg-background/80 backdrop-blur-sm"
            onClick={() => setSidebarOpen(false)}
          />
          <div className="fixed inset-0 flex">
            <div className={`relative flex w-full max-w-xs flex-1 ${language === 'ar' ? 'ml-16' : 'mr-16'}`}>
              <div className={`absolute top-0 flex w-16 justify-center pt-5 ${language === 'ar' ? 'right-full' : 'left-full'}`}>
                <button
                  type="button"
                  className="-m-2.5 p-2.5"
                  onClick={() => setSidebarOpen(false)}
                >
                  <span className="sr-only">Close sidebar</span>
                  <X className="h-6 w-6 text-foreground" aria-hidden="true" />
                </button>
              </div>
              
              <div className="flex grow flex-col gap-y-5 overflow-y-auto bg-card px-6 pb-4 ring-1 ring-border/10">
                <div className="flex h-16 shrink-0 items-center">
                  <Link to="/dashboard" className={`flex items-center ${language === 'ar' ? 'space-x-reverse' : 'space-x-2'}`} onClick={() => setSidebarOpen(false)}>
                    <svg
                      className="h-8 w-8 text-primary"
                      viewBox="0 0 100 100"
                      fill="none"
                      xmlns="http://www.w3.org/2000/svg"
                    >
                      <circle cx="50" cy="50" r="45" stroke="currentColor" strokeWidth="2" fill="none" opacity="0.3"/>
                      <path d="M50 20 L35 35 L50 50 L65 35 Z" fill="currentColor"/>
                      <path d="M35 35 L20 50 L35 65 L50 50 Z" fill="currentColor" opacity="0.8"/>
                      <path d="M65 35 L80 50 L65 65 L50 50 Z" fill="currentColor" opacity="0.8"/>
                      <path d="M35 65 L50 80 L65 65 L50 50 Z" fill="currentColor" opacity="0.6"/>
                      <circle cx="50" cy="35" r="3" fill="currentColor"/>
                      <circle cx="35" cy="50" r="3" fill="currentColor"/>
                      <circle cx="65" cy="50" r="3" fill="currentColor"/>
                      <circle cx="50" cy="65" r="3" fill="currentColor"/>
                    </svg>
                    <span className={`text-lg font-semibold text-foreground ${language === 'ar' ? 'rtl:text-right' : ''}`}>
                      {language === 'ar' ? 'نسبنا' : 'Nasabna'}
                    </span>
                  </Link>
                </div>
                
                <nav className="flex flex-1 flex-col">
                  <ul role="list" className="flex flex-1 flex-col gap-y-7">
                    <li>
                      <ul role="list" className="-mx-2 space-y-1">
                        {navigation.map((item) => (
                          <li key={item.name}>
                            <Link
                              to={item.href}
                              className={`group flex items-center rounded-md p-2 text-sm leading-6 font-semibold transition-colors ${
                                isCurrentPath(item.href)
                                  ? 'bg-primary text-primary-foreground'
                                  : 'text-muted-foreground hover:text-foreground hover:bg-muted'
                              } ${language === 'ar' ? 'flex-row-reverse' : ''}`}
                              onClick={() => setSidebarOpen(false)}
                            >
                              <item.icon className="h-6 w-6 shrink-0" aria-hidden="true" />
                              <span className={`truncate ${language === 'ar' ? 'mr-3' : 'ml-3'}`}>
                                {language === 'ar' ? item.nameAr : item.name}
                              </span>
                            </Link>
                          </li>
                        ))}
                      </ul>
                    </li>
                  </ul>
                </nav>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default DashboardLayout;