import React, { useState } from 'react';
import { useUIStore } from '@/store/uiStore';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Textarea } from '@/components/ui/Textarea';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { 
  MapPin, 
  Phone, 
  Mail, 
  Clock, 
  Send,
  User,
  MessageSquare
} from 'lucide-react';
import contactImage from '@/assets/contacts.png';

const ContactPage: React.FC = () => {
  const { language } = useUIStore();
  const isRTL = language === 'ar';
  
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    subject: '',
    message: ''
  });
  
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);
  const [submitError, setSubmitError] = useState('');
  
  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };
  
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setSubmitError('');
    
    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1500));
      
      // Reset form
      setFormData({
        name: '',
        email: '',
        subject: '',
        message: ''
      });
      
      setSubmitSuccess(true);
      setTimeout(() => setSubmitSuccess(false), 5000);
    } catch (error) {
      setSubmitError(isRTL ? 'حدث خطأ أثناء إرسال الرسالة. يرجى المحاولة مرة أخرى.' : 'An error occurred while sending the message. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };
  
  const contactInfo = [
    {
      icon: MapPin,
      title: isRTL ? 'عنواننا' : 'Our Address',
      titleAr: 'عنواننا',
      content: isRTL ? '123 شارع العائلة، الرياض، المملكة العربية السعودية' : '123 Family Street, Riyadh, Saudi Arabia',
      contentAr: '123 شارع العائلة، الرياض، المملكة العربية السعودية'
    },
    {
      icon: Phone,
      title: isRTL ? 'اتصل بنا' : 'Call Us',
      titleAr: 'اتصل بنا',
      content: isRTL ? '+966 11 123 4567' : '+966 11 123 4567',
      contentAr: '+966 11 123 4567'
    },
    {
      icon: Mail,
      title: isRTL ? 'بريدنا الإلكتروني' : 'Email Us',
      titleAr: 'بريدنا الإلكتروني',
      content: isRTL ? 'support@nasabna.com' : 'support@nasabna.com',
      contentAr: 'support@nasabna.com'
    },
    {
      icon: Clock,
      title: isRTL ? 'ساعات العمل' : 'Working Hours',
      titleAr: 'ساعات العمل',
      content: isRTL ? 'الأحد - الخميس: 8 صباحاً - 5 مساءً' : 'Sunday - Thursday: 8AM - 5PM',
      contentAr: 'الأحد - الخميس: 8 صباحاً - 5 مساءً'
    }
  ];

  return (
    <div className="min-h-screen bg-background">
      {/* Hero Section */}
      <section className="relative py-20 md:py-32 bg-gradient-to-br from-primary/10 via-primary/5 to-background overflow-hidden">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
          <div className="text-center max-w-4xl mx-auto">
            <h1 className="text-4xl sm:text-5xl lg:text-6xl font-bold text-foreground mb-6">
              {isRTL ? 'اتصل بنا' : 'Contact Us'}
            </h1>
            <p className="text-xl text-muted-foreground mb-8 max-w-2xl mx-auto">
              {isRTL 
                ? 'هل لديك أسئلة أو تحتاج إلى مساعدة؟ فريق دعم Nasabna هنا للمساعدة.'
                : 'Have questions or need assistance? The Nasabna support team is here to help.'
              }
            </p>
          </div>
        </div>
      </section>

      {/* Contact Section */}
      <section className="py-16">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
            {/* Contact Info */}
            <div>
              <h2 className="text-3xl font-bold text-foreground mb-6">
                {isRTL ? 'ابقى على تواصل' : 'Get In Touch'}
              </h2>
              <p className="text-lg text-muted-foreground mb-8">
                {isRTL 
                  ? 'نحن نقدر ملاحظاتك واستفساراتك. لا تتردد في التواصل معنا بأي من الطرق التالية.'
                  : 'We appreciate your feedback and inquiries. Feel free to reach out to us through any of the following methods.'
                }
              </p>
              
              <div className="space-y-6">
                {contactInfo.map((info, index) => (
                  <div key={index} className="flex items-start">
                    <div className="flex-shrink-0 w-12 h-12 bg-primary/10 rounded-lg flex items-center justify-center mr-4">
                      <info.icon className="h-6 w-6 text-primary" />
                    </div>
                    <div>
                      <h3 className="text-lg font-semibold text-foreground mb-1">
                        {isRTL ? info.titleAr : info.title}
                      </h3>
                      <p className="text-muted-foreground">
                        {isRTL ? info.contentAr : info.content}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
              
              <div className="mt-12">
                <img 
                  src={contactImage} 
                  alt={isRTL ? "تواصل معنا" : "Contact Us"}
                  className="rounded-lg shadow-lg w-full max-w-md mx-auto"
                />
              </div>
            </div>
            
            {/* Contact Form */}
            <div>
              <Card>
                <CardHeader>
                  <CardTitle className="text-2xl">
                    {isRTL ? 'أرسل لنا رسالة' : 'Send Us a Message'}
                  </CardTitle>
                  <CardDescription>
                    {isRTL 
                      ? 'املأ النموذج أدناه وسنقوم بالرد عليك في أقرب وقت ممكن.'
                      : 'Fill out the form below and we\'ll get back to you as soon as possible.'
                    }
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  {submitSuccess ? (
                    <div className="bg-green-50 border border-green-200 rounded-lg p-6 text-center">
                      <div className="w-12 h-12 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
                        <Send className="h-6 w-6 text-green-600" />
                      </div>
                      <h3 className="text-lg font-semibold text-green-800 mb-2">
                        {isRTL ? 'تم إرسال الرسالة بنجاح!' : 'Message Sent Successfully!'}
                      </h3>
                      <p className="text-green-700">
                        {isRTL 
                          ? 'شكرًا لتواصلك معنا. سنقوم بالرد عليك قريبًا.'
                          : 'Thank you for contacting us. We\'ll get back to you soon.'
                        }
                      </p>
                    </div>
                  ) : (
                    <form onSubmit={handleSubmit} className="space-y-6">
                      {submitError && (
                        <div className="bg-red-50 border border-red-200 rounded-lg p-4">
                          <p className="text-red-700 text-center">{submitError}</p>
                        </div>
                      )}
                      
                      <div>
                        <label htmlFor="name" className="block text-sm font-medium text-foreground mb-2">
                          {isRTL ? 'الاسم الكامل' : 'Full Name'} *
                        </label>
                        <div className="relative">
                          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <User className="h-5 w-5 text-muted-foreground" />
                          </div>
                          <Input
                            id="name"
                            name="name"
                            value={formData.name}
                            onChange={handleInputChange}
                            placeholder={isRTL ? 'أدخل اسمك الكامل' : 'Enter your full name'}
                            className="pl-10"
                            required
                            disabled={isSubmitting}
                          />
                        </div>
                      </div>
                      
                      <div>
                        <label htmlFor="email" className="block text-sm font-medium text-foreground mb-2">
                          {isRTL ? 'البريد الإلكتروني' : 'Email Address'} *
                        </label>
                        <div className="relative">
                          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <Mail className="h-5 w-5 text-muted-foreground" />
                          </div>
                          <Input
                            id="email"
                            name="email"
                            type="email"
                            value={formData.email}
                            onChange={handleInputChange}
                            placeholder={isRTL ? 'أدخل بريدك الإلكتروني' : 'Enter your email address'}
                            className="pl-10"
                            required
                            disabled={isSubmitting}
                          />
                        </div>
                      </div>
                      
                      <div>
                        <label htmlFor="subject" className="block text-sm font-medium text-foreground mb-2">
                          {isRTL ? 'الموضوع' : 'Subject'} *
                        </label>
                        <Input
                          id="subject"
                          name="subject"
                          value={formData.subject}
                          onChange={handleInputChange}
                          placeholder={isRTL ? 'أدخل موضوع رسالتك' : 'Enter your message subject'}
                          required
                          disabled={isSubmitting}
                        />
                      </div>
                      
                      <div>
                        <label htmlFor="message" className="block text-sm font-medium text-foreground mb-2">
                          {isRTL ? 'الرسالة' : 'Message'} *
                        </label>
                        <div className="relative">
                          <div className="absolute top-3 left-3">
                            <MessageSquare className="h-5 w-5 text-muted-foreground" />
                          </div>
                          <Textarea
                            id="message"
                            name="message"
                            value={formData.message}
                            onChange={handleInputChange}
                            placeholder={isRTL ? 'اكتب رسالتك هنا...' : 'Write your message here...'}
                            rows={5}
                            className="pl-10"
                            required
                            disabled={isSubmitting}
                          />
                        </div>
                      </div>
                      
                      <Button 
                        type="submit" 
                        className="w-full flex items-center justify-center"
                        disabled={isSubmitting}
                      >
                        {isSubmitting ? (
                          <>
                            <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                            {isRTL ? 'جاري الإرسال...' : 'Sending...'}
                          </>
                        ) : (
                          <>
                            <Send className={`h-4 w-4 ${isRTL ? 'ml-2' : 'mr-2'}`} />
                            {isRTL ? 'إرسال الرسالة' : 'Send Message'}
                          </>
                        )}
                      </Button>
                    </form>
                  )}
                </CardContent>
              </Card>
            </div>
          </div>
        </div>
      </section>

      {/* FAQ Section */}
      <section className="py-16 bg-muted/30">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8">
          <div className="text-center mb-12">
            <h2 className="text-3xl font-bold text-foreground mb-4">
              {isRTL ? 'الأسئلة الشائعة' : 'Frequently Asked Questions'}
            </h2>
            <p className="text-lg text-muted-foreground max-w-2xl mx-auto">
              {isRTL 
                ? 'إليك بعض الأسئلة الشائعة التي قد تساعدك.'
                : 'Here are some frequently asked questions that might help you.'
              }
            </p>
          </div>
          
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-4xl mx-auto">
            <Card>
              <CardHeader>
                <CardTitle className="text-lg">
                  {isRTL ? 'كم من الوقت يستغرق الرد على رسالتي؟' : 'How long does it take to reply to my message?'}
                </CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-muted-foreground">
                  {isRTL 
                    ? 'عادةً نقوم بالرد على جميع الرسائل خلال 24 ساعة عمل.'
                    : 'We typically respond to all messages within 24 business hours.'
                  }
                </p>
              </CardContent>
            </Card>
            
            <Card>
              <CardHeader>
                <CardTitle className="text-lg">
                  {isRTL ? 'هل يمكنني الحصول على دعم باللغة العربية؟' : 'Can I get support in Arabic?'}
                </CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-muted-foreground">
                  {isRTL 
                    ? 'نعم، فريق الدعم لدينا يتحدث العربية والإنجليزية بطلاقة.'
                    : 'Yes, our support team is fluent in both Arabic and English.'
                  }
                </p>
              </CardContent>
            </Card>
            
            <Card>
              <CardHeader>
                <CardTitle className="text-lg">
                  {isRTL ? 'هل تقدمون دعماً فنياً؟' : 'Do you offer technical support?'}
                </CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-muted-foreground">
                  {isRTL 
                    ? 'نعم، لدينا فريق دعم تقني متخصص لمساعدتك في المشاكل التقنية.'
                    : 'Yes, we have a dedicated technical support team to help with technical issues.'
                  }
                </p>
              </CardContent>
            </Card>
            
            <Card>
              <CardHeader>
                <CardTitle className="text-lg">
                  {isRTL ? 'كيف يمكنني الإبلاغ عن مشكلة في الموقع؟' : 'How can I report a website issue?'}
                </CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-muted-foreground">
                  {isRTL 
                    ? 'يمكنك إرسال تفاصيل المشكلة عبر نموذج الاتصال هذا، وسنقوم بالتحقيق فيها فوراً.'
                    : 'You can send details of the issue through this contact form, and we\'ll investigate it immediately.'
                  }
                </p>
              </CardContent>
            </Card>
          </div>
        </div>
      </section>
    </div>
  );
};

export default ContactPage;