import { create } from 'zustand';
import { devtools, persist } from 'zustand/middleware';
import { AuthStore, User, LoginCredentials, RegisterData } from '@/types';
import { authService } from '@/services/auth';

// Memoize user data to prevent unnecessary re-renders
let currentUser: User | null = null;
let currentUserString: string = '';

const getUserWithMemoization = (user: User | null): User | null => {
  if (!user) {
    currentUser = null;
    currentUserString = '';
    return null;
  }
  
  const userString = JSON.stringify(user);
  if (userString !== currentUserString) {
    currentUser = user;
    currentUserString = userString;
  }
  
  return currentUser;
};

export const useAuthStore = create<AuthStore>()(
  devtools(
    persist(
      (set, get) => ({
        user: null,
        token: null,
        isAuthenticated: false,
        isLoading: true, // Start with loading true to prevent flash

        // Login user
        login: async (credentials: LoginCredentials) => {
          set({ isLoading: true });
          
          try {
            const response = await authService.login(credentials);
            
            // The user data is now properly mapped in authService
            set({
              user: getUserWithMemoization(response.user),
              token: response.token,
              isAuthenticated: true,
              isLoading: false,
            });
          } catch (error) {
            set({ isLoading: false });
            throw error;
          }
        },

        // Register new user
        register: async (data: RegisterData) => {
          set({ isLoading: true });
          
          try {
            const response = await authService.register(data);
            
            // The user data is now properly mapped in authService
            set({
              user: getUserWithMemoization(response.user),
              token: response.token,
              isAuthenticated: true,
              isLoading: false,
            });
          } catch (error) {
            set({ isLoading: false });
            throw error;
          }
        },

        // Logout user
        logout: async () => {
          set({ isLoading: true });
          
          try {
            await authService.logout();
          } catch (error) {
            // Logout errors are handled silently as we clear the state anyway
          } finally {
            set({
              user: null,
              token: null,
              isAuthenticated: false,
              isLoading: false,
            });
          }
        },

        // Update user data
        updateUser: (userData: Partial<User>) => {
          const currentUser = get().user;
          if (currentUser) {
            const updatedUser = { ...currentUser, ...userData };
            set({
              user: getUserWithMemoization(updatedUser),
            });
          }
        },

        // Refresh token
        refreshToken: async () => {
          try {
            const response = await authService.refreshToken();
            
            set({
              user: getUserWithMemoization(response.user),
              token: response.token,
              isAuthenticated: true,
            });
          } catch (error) {
            // If refresh fails, logout user
            set({
              user: null,
              token: null,
              isAuthenticated: false,
            });
            throw error;
          }
        },

        // Initialize auth state from storage
        initialize: () => {
          const storedUser = authService.getStoredUser();
          const storedToken = authService.getStoredToken();
          
          const isTokenExpired = authService.isTokenExpired();
          
          if (storedUser && storedToken && !isTokenExpired) {
            set({
              user: getUserWithMemoization(storedUser),
              token: storedToken,
              isAuthenticated: true,
              isLoading: false, // Set loading to false since we have stored data
            });
          } else {
            // Clear invalid data
            authService.clearStoredAuth();
            set({
              user: null,
              token: null,
              isAuthenticated: false,
              isLoading: false, // Make sure to set isLoading to false
            });
          }
          // Return a promise to indicate completion
          return Promise.resolve();
        },

        // Get current user from API
        getCurrentUser: async () => {
          // Don't set loading to true here to prevent UI flash
          // We'll rely on the initial loading state
          
          try {
            const user = await authService.getCurrentUser();
            
            set({
              user: getUserWithMemoization(user),
              isAuthenticated: true,
              isLoading: false, // Make sure to set isLoading to false
            });
            
            return user;
          } catch (error) {
            set({
              user: null,
              token: null,
              isAuthenticated: false,
              isLoading: false, // Make sure to set isLoading to false even on error
            });
            throw error;
          }
        },

        // Update profile
        updateProfile: async (data: Partial<User>) => {
          set({ isLoading: true });
          
          try {
            const updatedUser = await authService.updateProfile(data);
            
            set({
              user: updatedUser,
              isLoading: false,
            });
            
            return updatedUser;
          } catch (error) {
            set({ isLoading: false });
            throw error;
          }
        },

        // Upload avatar
        uploadAvatar: async (file: File) => {
          set({ isLoading: true });
          
          try {
            const result = await authService.uploadAvatar(file);
            const currentUser = get().user;
            
            if (currentUser) {
              set({
                user: { ...currentUser, avatar: result.avatar },
                isLoading: false,
              });
            }
            
            return result;
          } catch (error) {
            set({ isLoading: false });
            throw error;
          }
        },

        // Delete avatar
        deleteAvatar: async () => {
          set({ isLoading: true });
          
          try {
            await authService.deleteAvatar();
            const currentUser = get().user;
            
            if (currentUser) {
              set({
                user: { ...currentUser, avatar: undefined },
                isLoading: false,
              });
            }
          } catch (error) {
            set({ isLoading: false });
            throw error;
          }
        },

        // Change password
        changePassword: async (
          currentPassword: string,
          newPassword: string,
          confirmPassword: string
        ) => {
          set({ isLoading: true });
          
          try {
            await authService.changePassword(currentPassword, newPassword, confirmPassword);
            set({ isLoading: false });
          } catch (error) {
            set({ isLoading: false });
            throw error;
          }
        },

        // Update notification settings
        updateNotificationSettings: async (settings: any) => {
          set({ isLoading: true });
          
          try {
            const updatedSettings = await authService.updateNotificationSettings(settings);
            const currentUser = get().user;
            
            if (currentUser) {
              set({
                user: { ...currentUser, notifications: updatedSettings },
                isLoading: false,
              });
            }
            
            return updatedSettings;
          } catch (error) {
            set({ isLoading: false });
            throw error;
          }
        },

        // Update privacy settings
        updatePrivacySettings: async (settings: any) => {
          set({ isLoading: true });
          
          try {
            const updatedSettings = await authService.updatePrivacySettings(settings);
            const currentUser = get().user;
            
            if (currentUser) {
              set({
                user: { ...currentUser, privacy: updatedSettings },
                isLoading: false,
              });
            }
            
            return updatedSettings;
          } catch (error) {
            set({ isLoading: false });
            throw error;
          }
        },

        // Delete account
        deleteAccount: async () => {
          set({ isLoading: true });
          
          try {
            await authService.deleteAccount();
            
            set({
              user: null,
              token: null,
              isAuthenticated: false,
              isLoading: false,
            });
          } catch (error) {
            set({ isLoading: false });
            throw error;
          }
        },
      }),
      {
        name: 'auth-storage',
        partialize: (state) => ({
          user: state.user,
          token: state.token,
          isAuthenticated: state.isAuthenticated,
        }),
      }
    ),
    {
      name: 'auth-store',
    }
  )
);

// Initialize auth state on app start
if (typeof window !== 'undefined') {
  // Auto-initialize will happen through the persist middleware
}

export default useAuthStore;