import React from 'react';
import { cn } from '@/utils/cn';

interface TableProps {
  children: React.ReactNode;
  className?: string;
}

interface TableHeaderProps {
  children: React.ReactNode;
  className?: string;
}

interface TableBodyProps {
  children: React.ReactNode;
  className?: string;
}

interface TableRowProps {
  children: React.ReactNode;
  className?: string;
}

interface TableCellProps extends React.TdHTMLAttributes<HTMLTableCellElement> {
  children: React.ReactNode;
  className?: string;
}

interface TableHeadProps extends React.ThHTMLAttributes<HTMLTableCellElement> {
  children: React.ReactNode;
  className?: string;
}

const Table = ({ children, className }: TableProps) => {
  return (
    <div className="relative w-full overflow-auto">
      <table className={cn('w-full caption-bottom text-sm', className)}>
        {children}
      </table>
    </div>
  );
};

const TableHeader = ({ children, className }: TableHeaderProps) => {
  return <thead className={cn('[&_tr]:border-b', className)}>{children}</thead>;
};

const TableBody = ({ children, className }: TableBodyProps) => {
  return <tbody className={cn('[&_tr:last-child]:border-0', className)}>{children}</tbody>;
};

const TableRow = ({ children, className }: TableRowProps) => {
  return (
    <tr 
      className={cn(
        'border-b transition-colors hover:bg-muted/5 data-[state=selected]:bg-muted',
        className
      )}
    >
      {children}
    </tr>
  );
};

const TableCell = ({ children, className, ...props }: TableCellProps) => {
  return (
    <td className={cn('p-4 align-middle [&:has(td)]:py-3', className)} {...props}>
      {children}
    </td>
  );
};

const TableHead = ({ children, className, ...props }: TableHeadProps) => {
  return (
    <th 
      className={cn(
        'h-12 px-4 text-left align-middle font-medium text-muted-foreground [&:has(th)]:py-3',
        className
      )}
      {...props}
    >
      {children}
    </th>
  );
};

export {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableCell,
  TableHead
};