import { create } from 'zustand';
import { devtools, persist } from 'zustand/middleware';
import { TreeStore, Tree, Person } from '@/types';
import { treeService } from '@/services/treeService';

// Limit the number of trees stored to prevent memory issues
const MAX_STORED_TREES = 50;

// Utility function to limit array size
const limitArraySize = <T>(array: T[], maxSize: number): T[] => {
  if (array.length <= maxSize) return array;
  // Keep the most recent items
  return array.slice(-maxSize);
};

export const useTreeStore = create<TreeStore>()(
  devtools(
    persist(
      (set, get) => ({
        trees: [],
        publicTrees: [],
        currentTree: null,
        currentPerson: null,
        isLoading: false,
        error: null,

        // Fetch all trees for the current user
        fetchTrees: async () => {
          set({ isLoading: true, error: null });
          try {
            const trees = await treeService.getTrees();
            // Get current trees from state to preserve locally updated stats
            const currentTrees = get().trees;
            
            // Transform API response to match Tree interface
            const transformedTrees = trees.map(tree => {
              // Find existing tree in current state to preserve locally updated stats
              const existingTree = currentTrees.find(t => t.id === tree.id.toString());
              
              return {
                ...tree,
                id: tree.id.toString(),
                // Preserve ownership information
                ownerId: tree.ownerId || (tree.owner ? tree.owner.id : undefined),
                userRole: tree.userRole || 'owner', // User's own trees are always owned by them
                category: tree.category || 'family', // Default category
                tags: tree.tags || [],
                settings: {
                  isPublic: tree.settings?.isPublic !== undefined ? tree.settings.isPublic : !tree.isPrivate,
                  theme: tree.settings?.theme || 'default',
                  layout: tree.settings?.layout || 'vertical',
                  showPhotos: tree.settings?.showPhotos !== undefined ? tree.settings.showPhotos : true,
                  showDates: tree.settings?.showDates !== undefined ? tree.settings.showDates : true,
                  showPlaces: tree.settings?.showPlaces !== undefined ? tree.settings.showPlaces : true,
                  allowComments: tree.settings?.allowComments !== undefined ? tree.settings.allowComments : true,
                  allowSuggestions: tree.settings?.allowSuggestions !== undefined ? tree.settings.allowSuggestions : true
                },
                sharing: tree.sharing || {
                  isShared: (tree.members && tree.members.length > 0) || false,
                  allowedUsers: [],
                  shareToken: undefined,
                  publicUrl: undefined
                },
                stats: {
                  totalPeople: tree.members?.length || 0,
                  totalGenerations: (existingTree?.stats?.totalGenerations !== undefined ? existingTree.stats.totalGenerations : (tree.stats?.totalGenerations || 0)),
                  totalPhotos: tree.stats?.totalPhotos || 0,
                  completionPercentage: tree.members && tree.members.length > 0 ? 50 : 0
                },
                createdAt: tree.createdAt || new Date().toISOString(),
                updatedAt: tree.updatedAt || new Date().toISOString()
              };
            });
            
            // Limit the number of trees to prevent memory issues
            const limitedTrees = limitArraySize(transformedTrees, MAX_STORED_TREES);
            set({ trees: limitedTrees, isLoading: false });
          } catch (error: any) {
            set({ error: error.message || 'Failed to fetch trees', isLoading: false });
            throw error;
          }
        },

        // Fetch all public trees
        fetchPublicTrees: async () => {
          set({ isLoading: true, error: null });
          try {
            const publicTrees = await treeService.getPublicTrees();
            // Get current public trees from state to preserve locally updated stats
            const currentPublicTrees = get().publicTrees;
            
            // Transform API response to match Tree interface
            const transformedPublicTrees = publicTrees.map(tree => {
              // Find existing tree in current state to preserve locally updated stats
              const existingTree = currentPublicTrees.find(t => t.id === tree.id.toString());
              
              return {
                ...tree,
                id: tree.id.toString(),
                // Preserve ownership information
                ownerId: tree.ownerId || (tree.owner ? tree.owner.id : undefined),
                userRole: tree.userRole || 'viewer', // Public trees are viewed by default
                category: tree.category || 'family', // Default category
                tags: tree.tags || [],
                settings: {
                  isPublic: tree.settings?.isPublic !== undefined ? tree.settings.isPublic : !tree.isPrivate,
                  theme: tree.settings?.theme || 'default',
                  layout: tree.settings?.layout || 'vertical',
                  showPhotos: tree.settings?.showPhotos !== undefined ? tree.settings.showPhotos : true,
                  showDates: tree.settings?.showDates !== undefined ? tree.settings.showDates : true,
                  showPlaces: tree.settings?.showPlaces !== undefined ? tree.settings.showPlaces : true,
                  allowComments: tree.settings?.allowComments !== undefined ? tree.settings.allowComments : true,
                  allowSuggestions: tree.settings?.allowSuggestions !== undefined ? tree.settings.allowSuggestions : true
                },
                sharing: tree.sharing || {
                  isShared: true, // Public trees are shared by default
                  allowedUsers: [],
                  shareToken: undefined,
                  publicUrl: undefined
                },
                stats: {
                  totalPeople: tree.members?.length || 0,
                  totalGenerations: (existingTree?.stats?.totalGenerations !== undefined ? existingTree.stats.totalGenerations : (tree.stats?.totalGenerations || 0)),
                  totalPhotos: tree.stats?.totalPhotos || 0,
                  completionPercentage: tree.members && tree.members.length > 0 ? 50 : 0
                },
                createdAt: tree.createdAt || new Date().toISOString(),
                updatedAt: tree.updatedAt || new Date().toISOString()
              };
            });
            
            // Limit the number of trees to prevent memory issues
            const limitedPublicTrees = limitArraySize(transformedPublicTrees, MAX_STORED_TREES);
            set({ publicTrees: limitedPublicTrees, isLoading: false });
          } catch (error: any) {
            set({ error: error.message || 'Failed to fetch public trees', isLoading: false });
            throw error;
          }
        },

        // Create a new tree
        createTree: async (treeData) => {
          set({ isLoading: true, error: null });
          try {
            // Match exact API requirements from apiService.addTree
            const newTree = await treeService.createTree(
              treeData.name || 'Untitled Tree',
              treeData.settings?.isPublic !== undefined ? !treeData.settings.isPublic : true, // Convert public to private
              treeData.description || ''
            );
            
            // Transform the new tree to match our Tree interface
            const transformedNewTree = {
              ...newTree,
              id: newTree.id.toString(),
              // Set ownership information for newly created trees
              ownerId: newTree.ownerId || (newTree.owner ? newTree.owner.id : undefined),
              userRole: 'owner' as const, // Newly created trees are owned by the creator
              category: newTree.category || 'family',
              tags: newTree.tags || [],
              settings: {
                isPublic: newTree.settings?.isPublic !== undefined ? newTree.settings.isPublic : !newTree.isPrivate,
                theme: newTree.settings?.theme || 'default',
                layout: newTree.settings?.layout || 'vertical',
                showPhotos: newTree.settings?.showPhotos !== undefined ? newTree.settings.showPhotos : true,
                showDates: newTree.settings?.showDates !== undefined ? newTree.settings.showDates : true,
                showPlaces: newTree.settings?.showPlaces !== undefined ? newTree.settings.showPlaces : true,
                allowComments: newTree.settings?.allowComments !== undefined ? newTree.settings.allowComments : true,
                allowSuggestions: newTree.settings?.allowSuggestions !== undefined ? newTree.settings.allowSuggestions : true
              },
              sharing: newTree.sharing || {
                isShared: (newTree.members && newTree.members.length > 0) || false,
                allowedUsers: [],
                shareToken: undefined,
                publicUrl: undefined
              },
              stats: {
                totalPeople: newTree.members?.length || 0,
                totalGenerations: (newTree.stats?.totalGenerations !== undefined ? newTree.stats.totalGenerations : 0),
                totalPhotos: (newTree.stats?.totalPhotos !== undefined ? newTree.stats.totalPhotos : 0),
                completionPercentage: newTree.members && newTree.members.length > 0 ? 50 : 0
              },
              createdAt: newTree.createdAt || new Date().toISOString(),
              updatedAt: newTree.updatedAt || new Date().toISOString()
            };
            
            set((state) => {
              // Limit the number of trees to prevent memory issues
              const updatedTrees = limitArraySize([...state.trees, transformedNewTree], MAX_STORED_TREES);
              return {
                trees: updatedTrees,
                isLoading: false
              };
            });
            
            return transformedNewTree;
          } catch (error: any) {
            set({ error: error.message || 'Failed to create tree', isLoading: false });
            throw error;
          }
        },

        // Update a tree
        updateTree: async (id, treeData) => {
          set({ isLoading: true, error: null });
          try {
            // Match exact API requirements from apiService.updateTree
            const updatedTree = await treeService.updateTree(
              parseInt(id),
              treeData.name || '',
              treeData.settings?.isPublic !== undefined ? !treeData.settings.isPublic : true, // Convert public to private
              treeData.description || ''
            );
            
            set((state) => ({
              trees: state.trees.map((tree) => 
                tree.id === id ? {
                  ...tree,
                  ...updatedTree,
                  id: updatedTree.id?.toString() || id,
                  category: updatedTree.category || tree.category || 'family',
                  tags: updatedTree.tags || tree.tags || [],
                  settings: {
                    ...tree.settings,
                    ...updatedTree.settings,
                    isPublic: updatedTree.isPrivate !== undefined ? !updatedTree.isPrivate : (tree.settings?.isPublic !== undefined ? tree.settings.isPublic : true),
                    theme: updatedTree.settings?.theme || tree.settings?.theme || 'default',
                    layout: updatedTree.settings?.layout || tree.settings?.layout || 'vertical',
                    showPhotos: updatedTree.settings?.showPhotos !== undefined ? updatedTree.settings.showPhotos : (tree.settings?.showPhotos !== undefined ? tree.settings.showPhotos : true),
                    showDates: updatedTree.settings?.showDates !== undefined ? updatedTree.settings.showDates : (tree.settings?.showDates !== undefined ? tree.settings.showDates : true),
                    showPlaces: updatedTree.settings?.showPlaces !== undefined ? updatedTree.settings.showPlaces : (tree.settings?.showPlaces !== undefined ? tree.settings.showPlaces : true),
                    allowComments: updatedTree.settings?.allowComments !== undefined ? updatedTree.settings.allowComments : (tree.settings?.allowComments !== undefined ? tree.settings.allowComments : true),
                    allowSuggestions: updatedTree.settings?.allowSuggestions !== undefined ? updatedTree.settings.allowSuggestions : (tree.settings?.allowSuggestions !== undefined ? tree.settings.allowSuggestions : true)
                  },
                  sharing: {
                    ...tree.sharing,
                    ...updatedTree.sharing,
                    isShared: updatedTree.sharing?.isShared || (updatedTree.members && updatedTree.members.length > 0) || tree.sharing?.isShared || false,
                    allowedUsers: updatedTree.sharing?.allowedUsers || tree.sharing?.allowedUsers || []
                  },
                  stats: {
                    ...tree.stats,
                    ...updatedTree.stats,
                    totalPeople: updatedTree.members?.length || tree.stats?.totalPeople || 0,
                    // Preserve the generations count if it was calculated locally
                    totalGenerations: tree.stats?.totalGenerations || updatedTree.stats?.totalGenerations || 0,
                    totalPhotos: tree.stats?.totalPhotos || updatedTree.stats?.totalPhotos || 0,
                    completionPercentage: updatedTree.members && updatedTree.members.length > 0 ? 50 : (tree.stats?.completionPercentage || 0)
                  },
                  createdAt: updatedTree.createdAt || tree.createdAt || new Date().toISOString(),
                  updatedAt: updatedTree.updatedAt || new Date().toISOString()
                } : tree
              ),
              currentTree: state.currentTree?.id === id ? {
                ...state.currentTree,
                ...updatedTree,
                id: updatedTree.id?.toString() || id,
                category: updatedTree.category || state.currentTree.category || 'family',
                tags: updatedTree.tags || state.currentTree.tags || [],
                settings: {
                  ...state.currentTree.settings,
                  ...updatedTree.settings,
                  isPublic: updatedTree.isPrivate !== undefined ? !updatedTree.isPrivate : (state.currentTree.settings?.isPublic !== undefined ? state.currentTree.settings.isPublic : true),
                  theme: updatedTree.settings?.theme || state.currentTree.settings?.theme || 'default',
                  layout: updatedTree.settings?.layout || state.currentTree.settings?.layout || 'vertical',
                  showPhotos: updatedTree.settings?.showPhotos !== undefined ? updatedTree.settings.showPhotos : (state.currentTree.settings?.showPhotos !== undefined ? state.currentTree.settings.showPhotos : true),
                  showDates: updatedTree.settings?.showDates !== undefined ? updatedTree.settings.showDates : (state.currentTree.settings?.showDates !== undefined ? state.currentTree.settings.showDates : true),
                  showPlaces: updatedTree.settings?.showPlaces !== undefined ? updatedTree.settings.showPlaces : (state.currentTree.settings?.showPlaces !== undefined ? state.currentTree.settings.showPlaces : true),
                  allowComments: updatedTree.settings?.allowComments !== undefined ? updatedTree.settings.allowComments : (state.currentTree.settings?.allowComments !== undefined ? state.currentTree.settings.allowComments : true),
                  allowSuggestions: updatedTree.settings?.allowSuggestions !== undefined ? updatedTree.settings.allowSuggestions : (state.currentTree.settings?.allowSuggestions !== undefined ? state.currentTree.settings.allowSuggestions : true)
                },
                sharing: {
                  ...state.currentTree.sharing,
                  ...updatedTree.sharing,
                  isShared: updatedTree.sharing?.isShared || (updatedTree.members && updatedTree.members.length > 0) || state.currentTree.sharing?.isShared || false,
                  allowedUsers: updatedTree.sharing?.allowedUsers || state.currentTree.sharing?.allowedUsers || []
                },
                stats: {
                  ...state.currentTree.stats,
                  ...updatedTree.stats,
                  totalPeople: updatedTree.members?.length || state.currentTree.stats?.totalPeople || 0,
                  // Preserve the generations count if it was calculated locally
                  totalGenerations: state.currentTree.stats?.totalGenerations || updatedTree.stats?.totalGenerations || 0,
                  totalPhotos: state.currentTree.stats?.totalPhotos || updatedTree.stats?.totalPhotos || 0,
                  completionPercentage: updatedTree.members && updatedTree.members.length > 0 ? 50 : (state.currentTree.stats?.completionPercentage || 0)
                },
                createdAt: updatedTree.createdAt || state.currentTree.createdAt || new Date().toISOString(),
                updatedAt: updatedTree.updatedAt || new Date().toISOString()
              } : state.currentTree,
              isLoading: false
            }));

            return updatedTree;
          } catch (error: any) {
            set({ error: error.message || 'Failed to update tree', isLoading: false });
            throw error;
          }
        },

        // Delete a tree
        deleteTree: async (id) => {
          set({ isLoading: true, error: null });
          try {
            await treeService.deleteTree(parseInt(id));
            
            set((state) => ({
              trees: state.trees.filter((tree) => tree.id !== id),
              currentTree: state.currentTree?.id === id ? null : state.currentTree,
              isLoading: false
            }));
          } catch (error: any) {
            set({ error: error.message || 'Failed to delete tree', isLoading: false });
            throw error;
          }
        },

        // Set current tree
        setCurrentTree: (tree) => {
          set({ currentTree: tree });
        },

        // Fetch persons in a tree
        fetchPersonsInTree: async (treeId) => {
          set({ isLoading: true, error: null });
          try {
            const persons = await treeService.getPersonsInTree(parseInt(treeId));
            
            // For trees owned by the current user, also fetch relationships to ensure all data is available
            try {
              const relationships = await treeService.getRelationships();
              // Removed console.log for fetched relationships for tree
              // We're not storing relationships in the store directly, but we're ensuring they're fetched
            } catch (relError) {
              // Removed console.warn for could not fetch relationships for tree
            }
            
            // In a real implementation, you might want to store persons in the store
            set({ isLoading: false });
            return persons;
          } catch (error: any) {
            set({ error: error.message || 'Failed to fetch persons', isLoading: false });
            throw error;
          }
        },

        // Add a person to a tree
        addPersonToTree: async (personData) => {
          set({ isLoading: true, error: null });
          try {
            // Match exact API requirements from apiService.addPerson
            // Extract the name parts for the full name
            const fullName = `${personData.firstName || ''} ${personData.lastName || ''}`.trim();
            
            const newPerson = await treeService.addPersonToTree(
              fullName || 'Unknown', // name is required
              personData.birth?.date || '', // birthDate is optional
              personData.birth?.place?.city || '', // birthPlace is optional
              personData.occupation?.[0]?.title || '', // occupation is optional
              personData.gender || 'unknown', // gender is optional
              personData.death?.date || '', // deathDate is optional
              personData.isDeceased || false, // isDeceased is required
              parseInt(personData.tree || '0') // familyTreeId is required
            );
            
            set({ isLoading: false });
            return newPerson;
          } catch (error: any) {
            set({ error: error.message || 'Failed to add person', isLoading: false });
            throw error;
          }
        },

        // Update a person
        updatePerson: async (id, personData) => {
          set({ isLoading: true, error: null });
          try {
            // Match exact API requirements from apiService.updatePerson
            // Extract the name parts for the full name
            const fullName = `${personData.firstName || ''} ${personData.lastName || ''}`.trim();
            
            const updatedPerson = await treeService.updatePerson(
              parseInt(id),
              fullName || 'Unknown', // name is required
              personData.birth?.date || '', // birthDate is optional
              personData.birth?.place?.city || '', // birthPlace is optional
              personData.occupation?.[0]?.title || '', // occupation is optional
              personData.gender || 'unknown', // gender is optional
              parseInt(personData.tree || '0') // familyTreeId is required
            );

            set({ isLoading: false });
            return updatedPerson;
          } catch (error: any) {
            set({ error: error.message || 'Failed to update person', isLoading: false });
            throw error;
          }
        },

        // Delete a person
        deletePerson: async (id) => {
          set({ isLoading: true, error: null });
          try {
            await treeService.deletePerson(parseInt(id));
            set({ isLoading: false });
          } catch (error: any) {
            set({ error: error.message || 'Failed to delete person', isLoading: false });
            throw error;
          }
        },

        // Get relationships
        getRelationships: async () => {
          set({ isLoading: true, error: null });
          try {
            const relationships = await treeService.getRelationships();
            set({ isLoading: false });
            return relationships;
          } catch (error: any) {
            set({ error: error.message || 'Failed to fetch relationships', isLoading: false });
            throw error;
          }
        },

        // Delete relationship
        deleteRelationship: async (id) => {
          set({ isLoading: true, error: null });
          try {
            await treeService.deleteRelationship(parseInt(id));
            set({ isLoading: false });
          } catch (error: any) {
            set({ error: error.message || 'Failed to delete relationship', isLoading: false });
            throw error;
          }
        },

        // Set current person
        setCurrentPerson: (person) => {
          set({ currentPerson: person });
        },

        // Add a method to update tree generations count
        updateTreeGenerations: (treeId: string, generationsCount: number) => {
          set((state) => ({
            trees: state.trees.map((tree) => 
              tree.id === treeId ? {
                ...tree,
                stats: {
                  ...tree.stats,
                  totalGenerations: generationsCount
                }
              } : tree
            ),
            currentTree: state.currentTree?.id === treeId ? {
              ...state.currentTree,
              stats: {
                ...state.currentTree.stats,
                totalGenerations: generationsCount
              }
            } : state.currentTree
          }));
        },

        // Upload tree photo
        uploadTreePhoto: async (treeId, file) => {
          set({ isLoading: true, error: null });
          try {
            const result = await treeService.uploadTreePhoto(parseInt(treeId), file);
            set({ isLoading: false });
            return result;
          } catch (error: any) {
            set({ error: error.message || 'Failed to upload tree photo', isLoading: false });
            throw error;
          }
        },

        // Upload person photo
        uploadPersonPhoto: async (personId, file) => {
          set({ isLoading: true, error: null });
          try {
            const result = await treeService.uploadPersonPhoto(parseInt(personId), file);
            set({ isLoading: false });
            return result;
          } catch (error: any) {
            set({ error: error.message || 'Failed to upload person photo', isLoading: false });
            throw error;
          }
        },
      }),
      {
        name: 'tree-storage',
        partialize: (state) => ({
          trees: limitArraySize(state.trees, MAX_STORED_TREES),
          publicTrees: limitArraySize(state.publicTrees, MAX_STORED_TREES), // Persist public trees
          currentTree: state.currentTree,
        }),
      }
    ),
    {
      name: 'tree-store',
    }
  )
);

export default useTreeStore;