import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { useUIStore } from '@/store/uiStore';
import { useAuthStore } from '@/store/authStore';
import { useTreeStore } from '@/store/treeStore';
import { treeService } from '@/services/treeService';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';
import PersonFormModal from '@/components/trees/PersonFormModal';
import { 
  User, 
  Edit, 
  Share2, 
  Calendar, 
  MapPin, 
  Phone, 
  Mail, 
  Heart,
  Users,
  ArrowLeft,
  Camera,
  FileText,
  Crown,
  Baby,
  Briefcase,
  GraduationCap,
  Home,
  Globe,
  Clock,
  TreePine,
  Loader2,
  AlertCircle
} from 'lucide-react';
import { useMobile } from '@/hooks/useMobile'; // Add mobile hook import
import { toast } from 'react-hot-toast';
import bilingualToast from '@/utils/bilingualToast';

interface Person {
  id: string;
  firstName: string;
  firstNameEn: string;
  lastName: string;
  lastNameEn: string;
  gender: 'male' | 'female' | 'unknown';
  birthDate?: string;
  deathDate?: string;
  birthPlace?: string;
  birthPlaceEn?: string;
  deathPlace?: string;
  deathPlaceEn?: string;
  isAlive: boolean;
  parentIds?: string[];
  spouseIds?: string[];
  childrenIds?: string[];
  generation: number;
  photo?: string;
  email?: string;
  phone?: string;
  occupation?: string;
  occupationEn?: string;
  education?: string;
  educationEn?: string;
  biography?: string;
  biographyEn?: string;
  treeId: string;
  createdAt: string;
  updatedAt: string;
  familyTreeId?: string;
  relationships?: {
    father?: string | any;
    mother?: string | any;
    spouses?: (string | any)[];
    children?: (string | any)[];
    siblings?: (string | any)[];
  };
  // Add all the additional fields from the API
  middleName?: string;
  nickname?: string;
  fullName?: string;
  displayName?: string;
  arabicName?: {
    firstName?: string;
    middleName?: string;
    lastName?: string;
  };
  fullArabicName?: string;
  age?: number;
  physical?: {
    height?: string;
    weight?: string;
    eyeColor?: string;
    hairColor?: string;
    complexion?: string;
    distinguishingMarks?: string;
  };
  contact?: {
    email?: string;
    phone?: string;
    address?: {
      street?: string;
      city?: string;
      state?: string;
      country?: string;
      postalCode?: string;
    };
    socialMedia?: {
      facebook?: string;
      twitter?: string;
      linkedin?: string;
      instagram?: string;
    };
  };
  photos?: any[];
  documents?: any[];
  primaryPhoto?: any;
  notes?: string;
  military?: {
    branch: string;
    rank?: string;
    serviceNumber?: string;
    startDate?: string;
    endDate?: string;
    conflicts?: string[];
    decorations?: string[];
    dischargeType?: string;
  };
  religion?: string;
  tags?: string[];
  position?: {
    generation: number;
    x: number;
    y: number;
    level?: number;
  };
  createdBy?: string;
  status?: 'active' | 'archived' | 'deleted';
}

interface RelatedPerson {
  id: string;
  firstName: string;
  firstNameEn: string;
  lastName: string;
  lastNameEn: string;
  relationship: string;
  relationshipEn: string;
  photo?: string;
}

const PersonPage: React.FC = () => {
  const { id } = useParams<{ id: string }>(); // Explicitly type the parameter
  const { language } = useUIStore();
  const { user } = useAuthStore();
  const { trees, currentTree } = useTreeStore();
  const { isMobile } = useMobile(); // Add mobile detection
  const navigate = useNavigate();
  const [person, setPerson] = useState<Person | null>(null);
  const [relatives, setRelatives] = useState<RelatedPerson[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isEditPersonModalOpen, setIsEditPersonModalOpen] = useState(false);

  const isRTL = language === 'ar';

  // Check if current user is the owner of the tree that contains this person
  const isTreeOwner = (() => {
    if (!user || !person) return false;
    
    // Find the tree that contains this person
    const treeId = person.treeId || person.familyTreeId;
    if (!treeId) return false;
    
    const tree = trees.find(t => t.id === treeId) || currentTree;
    if (!tree) return false;
    
    // Check if user is the owner
    return tree.ownerId === user.id || tree.userRole === 'owner';
  })();

  // Fetch person data from API
  useEffect(() => {
    const fetchPersonData = async () => {
      // Check if id exists and is valid
      if (!id) {
        setError(language === 'ar' ? 'معرف الشخص غير موجود' : 'Person ID not found');
        setLoading(false);
        return;
      }
      
      // Check if ID is a valid positive number
      const personId = parseInt(id);
      if (isNaN(personId) || personId <= 0) {
        setError(language === 'ar' ? 'معرف الشخص غير صالح: ' + id : 'Invalid person ID: ' + id);
        setLoading(false);
        return;
      }
      
      try {
        setLoading(true);
        setError(null);
        
        // Fetch person data from API
        // Removed logging: Fetching person data for ID
        let personData;
        
        try {
          // Try the standard approach first
          const response: any = await treeService.getPersonById(personId);
          // Removed logging: API Response
          // Removed logging: API Response type
          // Removed logging: API Response keys
          
          // Handle different response formats
          // The response might be wrapped in a data object or might be the person object directly
          if (response) {
            if (response.hasOwnProperty('data')) {
              // Response is wrapped in a data object
              personData = response.data;
              // Removed logging: Using response.data
            } else {
              // Response is the person object directly
              personData = response;
              // Removed logging: Using response directly
            }
          } else {
            throw new Error('Empty response from API');
          }
        } catch (apiError: any) {
          // Removed console.error for API Error
          // Removed console.error for API Error response
          // Try alternative endpoint or approach if needed
          throw apiError;
        }
        
        // Removed logging: Person data to process
        // Removed logging: Person data type
        // Removed logging: Person data keys
        
        // Check if personData exists
        if (!personData) {
          throw new Error('No person data received');
        }
        
        // Transform API data to match our interface
        const transformedPerson: Person = {
          id: (personData.id || personId).toString(),
          firstName: personData.arabicName?.firstName || personData.firstName || personData.name || '',
          firstNameEn: personData.firstName || personData.name || '',
          lastName: personData.arabicName?.lastName || personData.lastName || '',
          lastNameEn: personData.lastName || '',
          gender: personData.gender === 'male' || personData.gender === 'Male' ? 'male' : 
                  personData.gender === 'female' || personData.gender === 'Female' ? 'female' : 'unknown',
          birthDate: personData.birthDate || personData.birth?.date || undefined,
          deathDate: personData.deathDate || personData.death?.date || undefined,
          birthPlace: personData.birthPlace || personData.birth?.place?.city || undefined,
          birthPlaceEn: personData.birthPlace || personData.birth?.place?.city || undefined,
          deathPlace: personData.deathPlace || personData.death?.place?.city || undefined,
          deathPlaceEn: personData.deathPlace || personData.death?.place?.city || undefined,
          isAlive: !personData.isDeceased,
          generation: personData.generation || personData.position?.generation || 1,
          photo: personData.photoUrl || personData.primaryPhoto?.url || personData.photos?.[0]?.url || undefined,
          email: personData.email || personData.contact?.email || '',
          phone: personData.phone || personData.contact?.phone || '',
          occupation: Array.isArray(personData.occupation) && personData.occupation.length > 0 
            ? personData.occupation[0].title 
            : (personData.occupation || ''),
          occupationEn: Array.isArray(personData.occupation) && personData.occupation.length > 0 
            ? personData.occupation[0].title 
            : (personData.occupation || ''),
          education: personData.education || '',
          educationEn: personData.education || '',
          biography: personData.biography || personData.notes || '',
          biographyEn: personData.biography || personData.notes || '',
          treeId: personData.familyTreeId?.toString() || personData.treeId?.toString() || personData.tree || '',
          familyTreeId: personData.familyTreeId?.toString() || personData.treeId?.toString() || personData.tree || '',
          createdAt: personData.createdAt || new Date().toISOString(),
          updatedAt: personData.updatedAt || new Date().toISOString(),
          relationships: personData.relationships || {},
          // Add all the additional fields from the API
          middleName: personData.middleName || '',
          nickname: personData.nickname || '',
          fullName: personData.fullName || '',
          displayName: personData.displayName || '',
          arabicName: personData.arabicName || {},
          fullArabicName: personData.fullArabicName || '',
          age: personData.age || undefined,
          physical: personData.physical || {},
          contact: personData.contact || {},
          photos: personData.photos || [],
          documents: personData.documents || [],
          primaryPhoto: personData.primaryPhoto || {},
          notes: personData.notes || '',
          military: personData.military || {},
          religion: personData.religion || '',
          tags: personData.tags || [],
          position: personData.position || {},
          createdBy: personData.createdBy || '',
          status: personData.status || 'active'
        };
        
        // Removed logging: Transformed person data
        setPerson(transformedPerson);
        
        // Log the raw person data to see what relationships are available
        // Removed logging: Raw person data with relationships
        // Removed logging: Person relationships field
        // Removed logging: Person relationships type
        
        // Fetch relatives data
        try {
          // Get the family tree ID from the person data
          const familyTreeId = personData.familyTreeId || personData.treeId || personData.tree;
          
          if (familyTreeId) {
            // Fetch all persons in the tree to find relatives
            const allPersonsInTree = await treeService.getPersonsInTree(familyTreeId);
            
            // Log the persons in tree for debugging
            // Removed logging: All persons in tree
            // Removed logging: Number of persons in tree
            
            // Use the relationships data that's already part of the person object
            const personRelationships = personData.relationships || {};
            
            // Log relationships for debugging
            // Removed logging: Person relationships
            // Removed logging: Person relationships keys
            
            // Process relationships to create relatives data
            const relativesData: RelatedPerson[] = [];
            
            // Process parents
            if (personRelationships.father) {
              // Removed logging: Processing father relationship
              const fatherId = typeof personRelationships.father === 'string' 
                ? personRelationships.father 
                : personRelationships.father.id;
                
              // Removed logging: Father ID
              const father = allPersonsInTree.find(p => p.id === fatherId);
              // Removed logging: Found father
              if (father) {
                relativesData.push({
                  id: father.id?.toString() || '',
                  firstName: father.firstName || '',
                  firstNameEn: father.firstName || '',
                  lastName: father.lastName || '',
                  lastNameEn: father.lastName || '',
                  relationship: language === 'ar' ? 'أب' : 'Father',
                  relationshipEn: 'Father'
                });
              }
            }
            
            if (personRelationships.mother) {
              // Removed logging: Processing mother relationship
              const motherId = typeof personRelationships.mother === 'string' 
                ? personRelationships.mother 
                : personRelationships.mother.id;
                
              // Removed logging: Mother ID
              const mother = allPersonsInTree.find(p => p.id === motherId);
              // Removed logging: Found mother
              if (mother) {
                relativesData.push({
                  id: mother.id?.toString() || '',
                  firstName: mother.firstName || '',
                  firstNameEn: mother.firstName || '',
                  lastName: mother.lastName || '',
                  lastNameEn: mother.lastName || '',
                  relationship: language === 'ar' ? 'أم' : 'Mother',
                  relationshipEn: 'Mother'
                });
              }
            }
            
            // Process spouses
            if (personRelationships.spouses && Array.isArray(personRelationships.spouses)) {
              // Removed logging: Processing spouses relationships
              personRelationships.spouses.forEach((spouseObj: any) => {
                const spouseId = typeof spouseObj === 'string' 
                  ? spouseObj 
                  : (typeof spouseObj.person === 'string' ? spouseObj.person : spouseObj.person?.id);
                  
                // Removed logging: Spouse ID
                const spouse = allPersonsInTree.find(p => p.id === spouseId);
                // Removed logging: Found spouse
                if (spouse) {
                  relativesData.push({
                    id: spouse.id?.toString() || '',
                    firstName: spouse.firstName || '',
                    firstNameEn: spouse.firstName || '',
                    lastName: spouse.lastName || '',
                    lastNameEn: spouse.lastName || '',
                    relationship: language === 'ar' ? 'زوج' : 'Spouse',
                    relationshipEn: 'Spouse'
                  });
                }
              });
            }
            
            // Process children
            if (personRelationships.children && Array.isArray(personRelationships.children)) {
              // Processing children relationships
              personRelationships.children.forEach((childObj: any) => {
                const childId = typeof childObj === 'string' ? childObj : childObj.id;
                // Child ID: childId
                const child = allPersonsInTree.find(p => p.id === childId);
                // Found child: child
                if (child) {
                  relativesData.push({
                    id: child.id?.toString() || '',
                    firstName: child.firstName || '',
                    firstNameEn: child.firstName || '',
                    lastName: child.lastName || '',
                    lastNameEn: child.lastName || '',
                    relationship: language === 'ar' ? 'طفل' : 'Child',
                    relationshipEn: 'Child'
                  });
                }
              });
            }
            
            // Process siblings
            if (personRelationships.siblings && Array.isArray(personRelationships.siblings)) {
              // Processing siblings relationships
              personRelationships.siblings.forEach((siblingObj: any) => {
                const siblingId = typeof siblingObj === 'string' ? siblingObj : siblingObj.id;
                // Sibling ID: siblingId
                const sibling = allPersonsInTree.find(p => p.id === siblingId);
                // Found sibling: sibling
                if (sibling) {
                  relativesData.push({
                    id: sibling.id?.toString() || '',
                    firstName: sibling.firstName || '',
                    firstNameEn: sibling.firstName || '',
                    lastName: sibling.lastName || '',
                    lastNameEn: sibling.lastName || '',
                    relationship: language === 'ar' ? 'أخ' : 'Sibling',
                    relationshipEn: 'Sibling'
                  });
                }
              });
            }
            
            // Log the relatives data for debugging
            // Relatives data: relativesData
            // Number of relatives found: relativesData.length
            
            // If no specific relationships found, show some persons from the same tree as potential relatives
            if (relativesData.length === 0) {
              // No specific relationships found, using fallback approach
              const potentialRelatives = allPersonsInTree
                .filter(p => p.id && parseInt(p.id.toString()) !== personId)
                .slice(0, 5);
              
              // Potential relatives: potentialRelatives
              
              potentialRelatives.forEach(person => {
                relativesData.push({
                  id: person.id?.toString() || '',
                  firstName: person.firstName || '',
                  firstNameEn: person.firstName || '',
                  lastName: person.lastName || '',
                  lastNameEn: person.lastName || '',
                  relationship: language === 'ar' ? 'مرتبط' : 'Related',
                  relationshipEn: 'Related'
                });
              });
            }
            
            setRelatives(relativesData);
          } else {
            // No family tree ID found, using mock data
            // Fallback to mock data if no family tree ID
            const mockRelatives: RelatedPerson[] = [
              {
                id: '2',
                firstName: 'فاطمة',
                firstNameEn: 'Fatima',
                lastName: 'أحمد',
                lastNameEn: 'Ahmed',
                relationship: 'ابنة',
                relationshipEn: 'Daughter'
              },
              {
                id: '3',
                firstName: 'محمد',
                firstNameEn: 'Mohammed',
                lastName: 'أحمد',
                lastNameEn: 'Ahmed',
                relationship: 'ابن',
                relationshipEn: 'Son'
              }
            ];
            setRelatives(mockRelatives);
          }
        } catch (relativesError) {
          // Error fetching relatives: relativesError
          // Fallback to mock data on error
          const mockRelatives: RelatedPerson[] = [
            {
              id: '2',
              firstName: 'فاطمة',
              firstNameEn: 'Fatima',
              lastName: 'أحمد',
              lastNameEn: 'Ahmed',
              relationship: 'ابنة',
              relationshipEn: 'Daughter'
            },
            {
              id: '3',
              firstName: 'محمد',
              firstNameEn: 'Mohammed',
              lastName: 'أحمد',
              lastNameEn: 'Ahmed',
              relationship: 'ابن',
              relationshipEn: 'Son'
            }
          ];
          setRelatives(mockRelatives);
        }
      } catch (err: any) {
        // Error fetching person data: err
        setError(language === 'ar' ? 'فشل في تحميل بيانات الشخص' : 'Failed to load person data');
      } finally {
        setLoading(false);
      }
    };

    fetchPersonData();
  }, [id, language]);

  const getPersonAge = (birthDate?: string, deathDate?: string) => {
    // Check if birthDate is provided and valid
    if (!birthDate) {
      return 0;
    }
    
    // Parse the birth date
    let birth: Date;
    try {
      if (birthDate.includes('T')) {
        // ISO date string
        birth = new Date(birthDate);
      } else if (birthDate.includes('-')) {
        // YYYY-MM-DD format
        const parts = birthDate.split('-');
        if (parts.length === 3) {
          birth = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
        } else {
          birth = new Date(birthDate);
        }
      } else if (birthDate.includes('/')) {
        // MM/DD/YYYY or DD/MM/YYYY format
        const parts = birthDate.split('/');
        if (parts.length === 3) {
          // Assuming MM/DD/YYYY format first
          birth = new Date(parseInt(parts[2]), parseInt(parts[0]) - 1, parseInt(parts[1]));
        } else {
          birth = new Date(birthDate);
        }
      } else {
        // Try to parse directly
        birth = new Date(birthDate);
      }
    } catch (e) {
      // Error parsing birth date: birthDate, e
      return 0;
    }
    
    // Check if the date is valid
    if (isNaN(birth.getTime())) {
      // Invalid birth date: birthDate
      return 0;
    }
    
    // Use death date if provided and valid, otherwise use current date
    let end: Date;
    if (deathDate && deathDate.trim() !== '') {
      try {
        if (deathDate.includes('T')) {
          end = new Date(deathDate);
        } else if (deathDate.includes('-')) {
          const parts = deathDate.split('-');
          if (parts.length === 3) {
            end = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
          } else {
            end = new Date(deathDate);
          }
        } else if (deathDate.includes('/')) {
          const parts = deathDate.split('/');
          if (parts.length === 3) {
            end = new Date(parseInt(parts[2]), parseInt(parts[0]) - 1, parseInt(parts[1]));
          } else {
            end = new Date(deathDate);
          }
        } else {
          end = new Date(deathDate);
        }
        
        // Check if death date is valid
        if (isNaN(end.getTime())) {
          // Invalid death date: deathDate
          end = new Date(); // Fall back to current date
        }
      } catch (e) {
        // Error parsing death date: deathDate, e
        end = new Date(); // Fall back to current date
      }
    } else {
      end = new Date();
    }
    
    // Calculate age
    let age = end.getFullYear() - birth.getFullYear();
    const monthDiff = end.getMonth() - birth.getMonth();
    
    // If birth month hasn't occurred yet this year, or if it's the same month but the day hasn't occurred yet
    if (monthDiff < 0 || (monthDiff === 0 && end.getDate() < birth.getDate())) {
      age--;
    }
    
    // Ensure age is not negative
    return age >= 0 ? age : 0;
  };

  const getPersonIcon = (generation: number) => {
    if (generation === 1) return Crown;
    if (generation === 2) return User;
    return Baby;
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <div className="text-center">
          <Loader2 className="h-12 w-12 animate-spin text-primary mx-auto mb-4" />
          <p className="text-muted-foreground">
            {isRTL ? 'جاري تحميل ملف الشخص...' : 'Loading person profile...'}
          </p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-center py-12">
        <div className="mx-auto w-16 h-16 bg-destructive/10 rounded-full flex items-center justify-center mb-4">
          <AlertCircle className="h-8 w-8 text-destructive" />
        </div>
        <h2 className="text-2xl font-bold text-destructive mb-4">
          {error}
        </h2>
        <p className="text-muted-foreground mb-4">
          {language === 'ar' ? 'معرف الشخص المطلوب: ' : 'Requested Person ID: '}
          <code className="bg-muted px-2 py-1 rounded">{id}</code>
        </p>
        <div className="flex flex-col sm:flex-row gap-2 justify-center">
          <Button onClick={() => navigate(-1)}>
            {language === 'ar' ? 'العودة' : 'Go Back'}
          </Button>
          <Button variant="outline" onClick={() => window.location.reload()}>
            {language === 'ar' ? 'إعادة المحاولة' : 'Try Again'}
          </Button>
        </div>
      </div>
    );
  }

  if (!person) {
    return (
      <div className="text-center py-12">
        <h2 className="text-2xl font-bold text-muted-foreground mb-4">
          {isRTL ? 'الشخص غير موجود' : 'Person not found'}
        </h2>
        <Button asChild>
          <Link to="/trees" className="flex items-center">
            {isRTL ? 'العودة للأشجار' : 'Back to Trees'}
          </Link>
        </Button>
      </div>
    );
  }

  const PersonIcon = getPersonIcon(person.generation);

  return (
    <div className="space-y-6">
      {/* Back Button */}
      <div>
        <Button asChild variant="ghost" size={isMobile ? "sm" : "default"}>
          <Link to={`/trees/${person?.treeId}`} className="flex items-center">
            <ArrowLeft className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : 'mr-2'}`} />
            <span className={isMobile ? 'hidden' : ''}>{isRTL ? 'العودة للشجرة' : 'Back to Tree'}</span>
          </Link>
        </Button>
      </div>

      {/* Person Header */}
      <Card>
        <CardHeader className={isMobile ? 'p-4' : ''}>
          <div className={`flex ${isMobile ? 'flex-col gap-4' : 'flex-col sm:flex-row sm:items-start gap-6'}`}>
            {/* Photo */}
            <div className="flex-shrink-0">
              <div className={`rounded-full flex items-center justify-center ${
                person?.gender === 'male' 
                  ? 'bg-blue-100 text-blue-600' 
                  : 'bg-pink-100 text-pink-600'
              } ${isMobile ? 'w-24 h-24' : 'w-32 h-32'}`}>
                {person?.photo ? (
                  <img 
                    src={person.photo} 
                    alt={isRTL ? person.firstName : person.firstNameEn}
                    className="w-full h-full rounded-full object-cover"
                  />
                ) : (
                  <User className={`text-muted-foreground ${isMobile ? 'h-12 w-12' : 'h-16 w-16'}`} />
                )}
              </div>
            </div>

            {/* Basic Info */}
            <div className="flex-1">
              <div className={`flex ${isMobile ? 'flex-col gap-3' : 'flex-col sm:flex-row sm:items-start sm:justify-between gap-4'}`}>
                <div>
                  <h1 className={`font-bold text-foreground ${isMobile ? 'text-xl mb-1' : 'text-3xl mb-2'}`}>
                    {isRTL ? `${person?.firstName} ${person?.lastName}` : `${person?.firstNameEn} ${person?.lastNameEn}`}
                  </h1>
                  
                  <div className={`flex flex-wrap items-center gap-2 ${isMobile ? 'text-xs' : 'text-sm'} text-muted-foreground mb-3`}>
                    {person?.birthDate && (
                      <div className="flex items-center gap-1">
                        <Calendar className={`h-3 w-3 ${isMobile ? 'h-2.5 w-2.5' : 'h-4 w-4'}`} />
                        <span>
                          {getPersonAge(person.birthDate, person.deathDate)} {isRTL ? 'سنة' : 'years old'}
                          {!person.isAlive && ` (${isRTL ? 'متوفى' : 'Deceased'})`}
                        </span>
                      </div>
                    )}
                    
                    <div className="flex items-center gap-1">
                      <TreePine className={`h-3 w-3 ${isMobile ? 'h-2.5 w-2.5' : 'h-4 w-4'}`} />
                      <span>{isRTL ? `الجيل ${person?.generation}` : `Generation ${person?.generation}`}</span>
                    </div>

                    <Badge variant={person?.gender === 'male' ? 'info' : 'secondary'} className={isMobile ? 'text-xs px-1.5 py-0.5' : ''}>
                      {person?.gender === 'male' 
                        ? (isRTL ? 'ذكر' : 'Male') 
                        : (isRTL ? 'أنثى' : 'Female')
                      }
                    </Badge>

                    {!person?.isAlive && (
                      <Badge variant="outline" className={isMobile ? 'text-xs px-1.5 py-0.5' : ''}>
                        {isRTL ? 'متوفى' : 'Deceased'}
                      </Badge>
                    )}
                  </div>

                  {/* Birth/Death Info */}
                  <div className={`space-y-1 ${isMobile ? 'text-xs' : 'text-sm'}`}>
                    {person?.birthDate && (
                      <div className="flex items-center gap-2">
                        <Calendar className={`h-3 w-3 ${isMobile ? 'h-2.5 w-2.5' : 'h-4 w-4'} text-green-600`} />
                        <span className="font-medium">{isRTL ? 'تاريخ الميلاد:' : 'Born:'}</span>
                        <span>{new Date(person.birthDate).toLocaleDateString(isRTL ? 'ar-SA' : 'en-US')}</span>
                        {person.birthPlace && (
                          <>
                            <span className="text-muted-foreground">{isRTL ? 'في' : 'in'}</span>
                            <span>{isRTL ? person.birthPlace : person.birthPlaceEn}</span>
                          </>
                        )}
                      </div>
                    )}

                    {person?.deathDate && (
                      <div className="flex items-center gap-2">
                        <Calendar className={`h-3 w-3 ${isMobile ? 'h-2.5 w-2.5' : 'h-4 w-4'} text-red-600`} />
                        <span className="font-medium">{isRTL ? 'تاريخ الوفاة:' : 'Died:'}</span>
                        <span>{new Date(person.deathDate).toLocaleDateString(isRTL ? 'ar-SA' : 'en-US')}</span>
                        {person.deathPlace && (
                          <>
                            <span className="text-muted-foreground">{isRTL ? 'في' : 'in'}</span>
                            <span>{isRTL ? person.deathPlace : person.deathPlaceEn}</span>
                          </>
                        )}
                      </div>
                    )}
                  </div>
                </div>

                {/* Action Buttons */}
                <div className={`flex ${isMobile ? 'gap-1' : 'gap-2'}`}>
                  {isTreeOwner && (
                    <Button 
                      size={isMobile ? "sm" : "sm"} 
                      variant="outline"
                      onClick={() => setIsEditPersonModalOpen(true)}
                    >
                      <Edit className={`h-4 w-4 ${isMobile ? 'h-33 w-3' : 'mr-2'}`} />
                      <span className={isMobile ? 'hidden' : ''}>{isRTL ? 'تعديل' : 'Edit'}</span>
                    </Button>
                  )}
                  <Button size={isMobile ? "sm" : "sm"} variant="outline">
                    <Share2 className={`h-4 w-4 ${isMobile ? 'h-3 w-3' : 'mr-2'}`} />
                    <span className={isMobile ? 'hidden' : ''}>{isRTL ? 'مشاركة' : 'Share'}</span>
                  </Button>
                </div>
              </div>
            </div>
          </div>
        </CardHeader>
      </Card>

      <div className={`grid ${isMobile ? 'grid-cols-1 gap-4' : 'grid-cols-1 lg:grid-cols-3 gap-6'}`}>
        {/* Main Content */}
        <div className={`space-y-4 ${isMobile ? 'lg:col-span-1' : 'lg:col-span-2'} space-y-4`}>
          {/* Person Summary Section - Enhanced to include all requested data */}
          <Card>
            <CardHeader className={isMobile ? 'p-4' : ''}>
              <CardTitle className="flex items-center gap-2">
                <User className={`h-4 w-4 ${isMobile ? 'h-3.5 w-3.5' : 'h-5 w-5'}`} />
                {isRTL ? 'ملخص البيانات' : 'Person Summary'}
              </CardTitle>
            </CardHeader>
            <CardContent className={`space-y-3 ${isMobile ? 'p-4' : ''}`}>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {/* Name */}
                <div className={`flex justify-between items-center p-2 rounded-lg ${isMobile ? 'p-2' : 'p-3'} bg-muted/50`}>
                  <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الاسم:' : 'Name:'}</span>
                  <span className={`text-foreground truncate max-w-[60%] text-right ${isMobile ? 'text-xs' : 'text-sm'}`}>
                    {isRTL ? `${person?.firstName} ${person?.lastName}` : `${person?.firstNameEn} ${person?.lastNameEn}`}
                  </span>
                </div>
                
                {/* Date of Birth */}
                {person?.birthDate && (
                  <div className={`flex justify-between items-center p-2 rounded-lg ${isMobile ? 'p-2' : 'p-3'} bg-muted/50`}>
                    <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'تاريخ الميلاد:' : 'Date of Birth:'}</span>
                    <span className={`text-foreground ${isMobile ? 'text-xs' : 'text-sm'}`}>
                      {new Date(person.birthDate).toLocaleDateString(isRTL ? 'ar-SA' : 'en-US')}
                    </span>
                  </div>
                )}
                
                {/* Status */}
                <div className={`flex justify-between items-center p-2 rounded-lg ${isMobile ? 'p-2' : 'p-3'} bg-muted/50`}>
                  <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الحالة:' : 'Status:'}</span>
                  <Badge 
                    variant={person?.isAlive ? 'default' : 'destructive'} 
                    className={`font-normal ${isMobile ? 'text-xs px-1.5 py-0.5' : 'text-xs'}`}
                  >
                    {person?.isAlive ? (isRTL ? 'على قيد الحياة' : 'Alive') : (isRTL ? 'متوفى' : 'Deceased')}
                  </Badge>
                </div>
                
                {/* Occupation */}
                {person?.occupation && (
                  <div className={`flex justify-between items-center p-2 rounded-lg ${isMobile ? 'p-2' : 'p-3'} bg-muted/50`}>
                    <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'المهنة:' : 'Occupation:'}</span>
                    <span className={`text-foreground truncate max-w-[60%] text-right ${isMobile ? 'text-xs' : 'text-sm'}`}>
                      {isRTL ? person.occupation : person.occupationEn}
                    </span>
                  </div>
                )}
                
                {/* Place of Birth */}
                {person?.birthPlace && (
                  <div className={`flex justify-between items-center p-2 rounded-lg ${isMobile ? 'p-2' : 'p-3'} bg-muted/50`}>
                    <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'مكان الميلاد:' : 'Place of Birth:'}</span>
                    <span className={`text-foreground truncate max-w-[60%] text-right ${isMobile ? 'text-xs' : 'text-sm'}`}>
                      {isRTL ? person.birthPlace : person.birthPlaceEn}
                    </span>
                  </div>
                )}
                
                {/* Generation */}
                <div className={`flex justify-between items-center p-2 rounded-lg ${isMobile ? 'p-2' : 'p-3'} bg-muted/50`}>
                  <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الجيل:' : 'Generation:'}</span>
                  <span className={`text-foreground ${isMobile ? 'text-xs' : 'text-sm'}`}>
                    {isRTL ? `الجيل ${person?.generation}` : `Gen ${person?.generation}`}
                  </span>
                </div>
                
                {/* Gender */}
                <div className={`flex justify-between items-center p-2 rounded-lg ${isMobile ? 'p-2' : 'p-3'} bg-muted/50`}>
                  <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الجنس:' : 'Gender:'}</span>
                  <Badge 
                    variant={person?.gender === 'male' ? 'info' : 'secondary'} 
                    className={`font-normal ${isMobile ? 'text-xs px-1.5 py-0.5' : 'text-xs'}`}
                  >
                    {person?.gender === 'male' ? (isRTL ? 'ذكر' : 'Male') : (isRTL ? 'أنثى' : 'Female')}
                  </Badge>
                </div>
                
                {/* Age */}
                {person?.birthDate && (
                  <div className={`flex justify-between items-center p-2 rounded-lg ${isMobile ? 'p-2' : 'p-3'} bg-muted/50`}>
                    <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'العمر:' : 'Age:'}</span>
                    <span className={`text-foreground ${isMobile ? 'text-xs' : 'text-sm'}`}>
                      {getPersonAge(person.birthDate, person.deathDate)} {isRTL ? 'سنة' : 'years'}
                    </span>
                  </div>
                )}
                
                {/* Additional fields if available */}
                {person?.status && (
                  <div className={`flex justify-between items-center p-2 rounded-lg ${isMobile ? 'p-2' : 'p-3'} bg-muted/50`}>
                    <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الوضع:' : 'Status:'}</span>
                    <span className={`text-foreground ${isMobile ? 'text-xs' : 'text-sm'}`}>
                      {person.status}
                    </span>
                  </div>
                )}
              </div>
            </CardContent>
          </Card>

          {/* Contact Information */}
          {(person?.email || person?.phone || person?.contact?.email || person?.contact?.phone || person?.contact?.address) && (
            <Card>
              <CardHeader className={isMobile ? 'p-4' : ''}>
                <CardTitle className="flex items-center gap-2">
                  <Phone className={`h-4 w-4 ${isMobile ? 'h-3.5 w-3.5' : 'h-5 w-5'}`} />
                  {isRTL ? 'معلومات الاتصال' : 'Contact Information'}
                </CardTitle>
              </CardHeader>
              <CardContent className={`space-y-2 ${isMobile ? 'p-4' : 'space-y-3'}`}>
                {(person?.email || person?.contact?.email) && (
                  <div className="flex items-center gap-2">
                    <Mail className={`h-3.5 w-3.5 ${isMobile ? 'h-3 w-3' : 'h-4 w-4'} text-muted-foreground`} />
                    <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'البريد الإلكتروني:' : 'Email:'}</span>
                    <a href={`mailto:${person.email || person.contact?.email}`} className={`text-primary hover:underline ${isMobile ? 'text-xs' : 'text-sm'}`}>
                      {person.email || person.contact?.email}
                    </a>
                  </div>
                )}
                {(person?.phone || person?.contact?.phone) && (
                  <div className="flex items-center gap-2">
                    <Phone className={`h-3.5 w-3.5 ${isMobile ? 'h-3 w-3' : 'h-4 w-4'} text-muted-foreground`} />
                    <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الهاتف:' : 'Phone:'}</span>
                    <a href={`tel:${person.phone || person.contact?.phone}`} className={`text-primary hover:underline ${isMobile ? 'text-xs' : 'text-sm'}`}>
                      {person.phone || person.contact?.phone}
                    </a>
                  </div>
                )}
                {person?.contact?.address && (
                  <div className="flex items-start gap-2">
                    <Home className={`h-3.5 w-3.5 ${isMobile ? 'h-3 w-3' : 'h-4 w-4'} text-muted-foreground mt-0.5`} />
                    <div>
                      <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'العنوان:' : 'Address:'}</span>
                      <div className={`text-muted-foreground ${isMobile ? 'text-xs' : 'text-sm'}`}>
                        {person.contact.address.street && <div>{person.contact.address.street}</div>}
                        {(person.contact.address.city || person.contact.address.state || person.contact.address.country) && (
                          <div>
                            {[person.contact.address.city, person.contact.address.state, person.contact.address.country]
                              .filter(Boolean)
                              .join(', ')}
                          </div>
                        )}
                        {person.contact.address.postalCode && <div>{person.contact.address.postalCode}</div>}
                      </div>
                    </div>
                  </div>
                )}
                {person?.contact?.socialMedia && (
                  <div className="flex items-center gap-2">
                    <Globe className={`h-3.5 w-3.5 ${isMobile ? 'h-3 w-3' : 'h-4 w-4'} text-muted-foreground`} />
                    <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'وسائل التواصل الاجتماعي:' : 'Social Media:'}</span>
                    <div className="flex gap-2">
                      {person.contact.socialMedia.facebook && (
                        <a href={person.contact.socialMedia.facebook} target="_blank" rel="noopener noreferrer" className="text-primary hover:underline text-xs">
                          Facebook
                        </a>
                      )}
                      {person.contact.socialMedia.twitter && (
                        <a href={person.contact.socialMedia.twitter} target="_blank" rel="noopener noreferrer" className="text-primary hover:underline text-xs">
                          Twitter
                        </a>
                      )}
                      {person.contact.socialMedia.linkedin && (
                        <a href={person.contact.socialMedia.linkedin} target="_blank" rel="noopener noreferrer" className="text-primary hover:underline text-xs">
                          LinkedIn
                        </a>
                      )}
                      {person.contact.socialMedia.instagram && (
                        <a href={person.contact.socialMedia.instagram} target="_blank" rel="noopener noreferrer" className="text-primary hover:underline text-xs">
                          Instagram
                        </a>
                      )}
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>
          )}

          {/* Physical Information */}
          {person?.physical && (person.physical.height || person.physical.weight || person.physical.eyeColor || person.physical.hairColor) && (
            <Card>
              <CardHeader className={isMobile ? 'p-4' : ''}>
                <CardTitle className="flex items-center gap-2">
                  <User className={`h-4 w-4 ${isMobile ? 'h-3.5 w-3.5' : 'h-5 w-5'}`} />
                  {isRTL ? 'المعلومات الجسدية' : 'Physical Information'}
                </CardTitle>
              </CardHeader>
              <CardContent className={`space-y-2 ${isMobile ? 'p-4' : 'space-y-3'}`}>
                {person.physical.height && (
                  <div className="flex items-center gap-2">
                    <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الطول:' : 'Height:'}</span>
                    <span className={isMobile ? 'text-xs' : 'text-sm'}>{person.physical.height}</span>
                  </div>
                )}
                {person.physical.weight && (
                  <div className="flex items-center gap-2">
                    <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'الوزن:' : 'Weight:'}</span>
                    <span className={isMobile ? 'text-xs' : 'text-sm'}>{person.physical.weight}</span>
                  </div>
                )}
                {person.physical.eyeColor && (
                  <div className="flex items-center gap-2">
                    <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'لون العينين:' : 'Eye Color:'}</span>
                    <span className={isMobile ? 'text-xs' : 'text-sm'}>{isRTL ? person.physical.eyeColor : person.physical.eyeColor}</span>
                  </div>
                )}
                {person.physical.hairColor && (
                  <div className="flex items-center gap-2">
                    <span className={`font-medium ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'لون الشعر:' : 'Hair Color:'}</span>
                    <span className={isMobile ? 'text-xs' : 'text-sm'}>{isRTL ? person.physical.hairColor : person.physical.hairColor}</span>
                  </div>
                )}
              </CardContent>
            </Card>
          )}

          {/* Biography */}
          {(person?.biography || person?.notes) && (
            <Card>
              <CardHeader className={isMobile ? 'p-4' : ''}>
                <CardTitle className="flex items-center gap-2">
                  <FileText className={`h-4 w-4 ${isMobile ? 'h-3.5 w-3.5' : 'h-5 w-5'}`} />
                  {isRTL ? 'السيرة الذاتية' : 'Biography'}
                </CardTitle>
              </CardHeader>
              <CardContent className={isMobile ? 'p-4' : ''}>
                <p className={`text-foreground leading-relaxed whitespace-pre-wrap ${isMobile ? 'text-sm' : ''}`}>
                  {isRTL ? (person.biography || person.notes) : (person.biographyEn || person.notes)}
                </p>
              </CardContent>
            </Card>
          )}

          {/* Religion */}
          {person?.religion && (
            <Card>
              <CardHeader className={isMobile ? 'p-4' : ''}>
                <CardTitle className="flex items-center gap-2">
                  <Heart className={`h-4 w-4 ${isMobile ? 'h-3.5 w-3.5' : 'h-5 w-5'}`} />
                  {isRTL ? 'الديانة' : 'Religion'}
                </CardTitle>
              </CardHeader>
              <CardContent className={isMobile ? 'p-4' : ''}>
                <p className={`text-foreground ${isMobile ? 'text-sm' : ''}`}>
                  {isRTL ? person.religion : person.religion}
                </p>
              </CardContent>
            </Card>
          )}

          {/* Photos */}
          {person?.photos && person.photos.length > 0 && (
            <Card>
              <CardHeader className={isMobile ? 'p-4' : ''}>
                <CardTitle className="flex items-center gap-2">
                  <Camera className={`h-4 w-4 ${isMobile ? 'h-3.5 w-3.5' : 'h-5 w-5'}`} />
                  {isRTL ? 'الصور' : 'Photos'}
                  <Badge variant="secondary" className={isMobile ? 'text-xs px-1.5 py-0.5' : ''}>{person.photos.length}</Badge>
                </CardTitle>
              </CardHeader>
              <CardContent className={isMobile ? 'p-4' : ''}>
                <div className="grid grid-cols-3 gap-2">
                  {person.photos.slice(0, 6).map((photo: any) => (
                    <div key={photo.id} className="aspect-square rounded-lg overflow-hidden">
                      <img 
                        src={photo.url || photo.thumbnailUrl} 
                        alt={photo.caption || isRTL ? 'صورة' : 'Photo'} 
                        className="w-full h-full object-cover"
                      />
                    </div>
                  ))}
                  {person.photos.length > 6 && (
                    <div className="aspect-square rounded-lg bg-muted flex items-center justify-center">
                      <span className="text-xs text-muted-foreground">+{person.photos.length - 6}</span>
                    </div>
                  )}
                </div>
              </CardContent>
            </Card>
          )}

          {/* Documents */}
          {person?.documents && person.documents.length > 0 && (
            <Card>
              <CardHeader className={isMobile ? 'p-4' : ''}>
                <CardTitle className="flex items-center gap-2">
                  <FileText className={`h-4 w-4 ${isMobile ? 'h-3.5 w-3.5' : 'h-5 w-5'}`} />
                  {isRTL ? 'الوثائق' : 'Documents'}
                  <Badge variant="secondary" className={isMobile ? 'text-xs px-1.5 py-0.5' : ''}>{person.documents.length}</Badge>
                </CardTitle>
              </CardHeader>
              <CardContent className={isMobile ? 'p-4' : ''}>
                <div className={`space-y-2 ${isMobile ? 'space-y-2' : 'space-y-3'}`}>
                  {person.documents.slice(0, 5).map((doc: any) => (
                    <div key={doc.id} className={`flex items-center gap-2 p-2 rounded-lg hover:bg-muted/50 transition-colors ${isMobile ? 'p-2' : 'p-3'}`}>
                      <FileText className={`h-4 w-4 ${isMobile ? 'h-3.5 w-3.5' : 'h-5 w-5'} text-muted-foreground`} />
                      <div className="flex-1 min-w-0">
                        <p className={`font-medium text-foreground truncate ${isMobile ? 'text-sm' : ''}`}>{doc.name || doc.caption}</p>
                        <p className={`text-muted-foreground ${isMobile ? 'text-xs' : 'text-xs'}`}>
                          {doc.type || doc.mimeType}
                        </p>
                      </div>
                      <Button size="sm" variant="ghost" className={isMobile ? 'h-6 w-6 p-0' : 'h-8 w-8 p-0'}>
                        <span className={`text-xs ${isMobile ? 'text-xs' : 'text-sm'}`}>{isRTL ? 'تحميل' : 'Download'}</span>
                      </Button>
                    </div>
                  ))}
                  {person.documents.length > 5 && (
                    <div className={`text-center text-muted-foreground ${isMobile ? 'text-xs' : 'text-sm'}`}>
                      {isRTL ? `و${person.documents.length - 5} وثائق إضافية` : `And ${person.documents.length - 5} more documents`}
                    </div>
                  )}
                </div>
              </CardContent>
            </Card>
          )}
        </div>

        {/* Sidebar - Removed Family Members and Quick Info sections as requested */}
        <div className={`space-y-4 ${isMobile ? 'lg:col-span-1' : ''} space-y-4`}>
          {/* Empty sidebar container */}
        </div>
      </div>

      {/* Edit Person Modal */}
      {isEditPersonModalOpen && person && (
        <PersonFormModal
          isOpen={isEditPersonModalOpen}
          onClose={() => setIsEditPersonModalOpen(false)}
          onSubmit={(updatedPerson: any) => {
            // Update the person state with the updated person data
            if (person) {
              setPerson({
                ...person,
                firstName: updatedPerson.name.split(' ')[0] || updatedPerson.name || person.firstName,
                lastName: updatedPerson.name.split(' ').slice(1).join(' ') || person.lastName,
                firstNameEn: updatedPerson.name.split(' ')[0] || updatedPerson.name || person.firstNameEn,
                lastNameEn: updatedPerson.name.split(' ').slice(1).join(' ') || person.lastNameEn,
                gender: updatedPerson.gender || person.gender,
                birthDate: updatedPerson.birthDate || person.birthDate,
                deathDate: updatedPerson.deathDate || person.deathDate,
                birthPlace: updatedPerson.birthPlace || person.birthPlace,
                birthPlaceEn: updatedPerson.birthPlaceEn || person.birthPlaceEn,
                deathPlace: updatedPerson.deathPlace || person.deathPlace,
                deathPlaceEn: updatedPerson.deathPlaceEn || person.deathPlaceEn,
                isAlive: updatedPerson.isAlive !== undefined ? updatedPerson.isAlive : person.isAlive,
                occupation: updatedPerson.occupation || person.occupation,
                occupationEn: updatedPerson.occupationEn || person.occupationEn
              });
            }
            setIsEditPersonModalOpen(false);
            bilingualToast.success({
              en: 'Person updated successfully',
              ar: 'تم تحديث بيانات الشخص بنجاح'
            });
          }}
          familyTreeId={person.treeId || person.familyTreeId || ''}
          familyMembers={[]} // Empty array as we're not using family members in this context
          initialData={{
            id: person.id,
            name: `${person.firstName} ${person.lastName}`,
            gender: person.gender,
            birthDate: person.birthDate,
            deathDate: person.deathDate,
            birthPlace: person.birthPlace,
            birthPlaceEn: person.birthPlaceEn,
            occupation: person.occupation,
            occupationEn: person.occupationEn,
            isAlive: person.isAlive
          }}
          mode={'edit'}
        />
      )}
    </div>
  );
};

export default PersonPage;