import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useAuthStore } from '@/store/authStore';
import { useUIStore } from '@/store/uiStore';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { Eye, EyeOff, Mail, Lock } from 'lucide-react';
import toast from 'react-hot-toast';
import bilingualToast from '@/utils/bilingualToast';
import { useMobile } from '@/hooks/useMobile';

const loginSchema = z.object({
  email: z.string().email('Please enter a valid email address'),
  password: z.string().min(6, 'Password must be at least 6 characters'),
});

type LoginFormData = z.infer<typeof loginSchema>;

const LoginPage: React.FC = () => {
  const navigate = useNavigate();
  const { login, isLoading } = useAuthStore();
  const { language } = useUIStore();
  const [showPassword, setShowPassword] = React.useState(false);
  const { isMobile } = useMobile();

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<LoginFormData>({
    resolver: zodResolver(loginSchema),
  });

  const onSubmit = async (data: LoginFormData) => {
    try {
      await login(data);
      bilingualToast.success({
        en: 'Login successful',
        ar: 'تم تسجيل الدخول بنجاح'
      });
      
      // Give a small delay for the auth state to update before navigating
      setTimeout(() => {
        navigate('/dashboard');
      }, 500);
    } catch (error: any) {
      // Removed console.error for login error
      let message = error?.message || (language === 'ar' ? 'حدث خطأ أثناء تسجيل الدخول' : 'Login failed');
      
      // Provide more specific error messages based on the error type
      if (error?.message?.includes('405')) {
        message = language === 'ar' 
          ? 'خطأ في الخادم. يرجى المحاولة مرة أخرى لاحقًا' 
          : 'Server error. Please try again later.';
      } else if (error?.message?.includes('Network Error') || error?.message?.includes('Unable to reach')) {
        message = language === 'ar' 
          ? 'خطأ في الشبكة. يرجى التحقق من اتصالك بالإنترنت' 
          : 'Network error. Please check your internet connection.';
      } else if (error?.message?.includes('401') || error?.message?.includes('Unauthorized')) {
        message = language === 'ar' 
          ? 'البريد الإلكتروني أو كلمة المرور غير صحيحة' 
          : 'Invalid email or password.';
      }
      
      bilingualToast.error({
        en: message,
        ar: message
      });
    }
  };

  return (
    <Card className={`w-full ${isMobile ? 'max-w-md mx-4' : 'max-w-md'}`}>
      <CardHeader className="space-y-1">
        <CardTitle className={`text-2xl font-bold text-center ${isMobile ? 'text-xl' : ''}`}>
          {language === 'ar' ? 'تسجيل الدخول' : 'Sign In'}
        </CardTitle>
        <CardDescription className="text-center">
          {language === 'ar' 
            ? 'أدخل بياناتك للوصول إلى حسابك'
            : 'Enter your credentials to access your account'
          }
        </CardDescription>
      </CardHeader>
      
      <CardContent>
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          {/* Email field */}
          <div className="space-y-2">
            <Input
              {...register('email')}
              type="email"
              placeholder={language === 'ar' ? 'البريد الإلكتروني' : 'Email address'}
              leftIcon={<Mail className="h-4 w-4" />}
              error={errors.email?.message}
              disabled={isLoading}
              className={isMobile ? 'text-sm' : ''}
            />
          </div>

          {/* Password field */}
          <div className="space-y-2">
            <Input
              {...register('password')}
              type="password"
              placeholder={language === 'ar' ? 'كلمة المرور' : 'Password'}
              leftIcon={<Lock className="h-4 w-4" />}
              showPasswordToggle
              error={errors.password?.message}
              disabled={isLoading}
              className={isMobile ? 'text-sm' : ''}
            />
          </div>

          {/* Forgot password link */}
          <div className={`flex justify-end ${isMobile ? 'text-sm' : ''}`}>
            <Link
              to="/forgot-password"
              className="text-sm text-primary hover:text-primary/80 underline"
            >
              {language === 'ar' ? 'نسيت كلمة المرور؟' : 'Forgot password?'}
            </Link>
          </div>

          {/* Submit button */}
          <Button
            type="submit"
            className={`w-full ${isMobile ? 'h-10 text-sm' : ''}`}
            loading={isLoading}
            loadingText={language === 'ar' ? 'جاري تسجيل الدخول...' : 'Signing in...'}
          >
            {language === 'ar' ? 'تسجيل الدخول' : 'Sign In'}
          </Button>
        </form>

        {/* Divider */}
        <div className="relative my-6">
          <div className="absolute inset-0 flex items-center">
            <span className="w-full border-t border-border" />
          </div>
          <div className="relative flex justify-center text-xs uppercase">
            <span className="bg-background px-2 text-muted-foreground">
              {language === 'ar' ? 'أو' : 'or'}
            </span>
          </div>
        </div>

        {/* Sign up link */}
        <div className={`text-center ${isMobile ? 'text-sm' : ''}`}>
          <p className="text-sm text-muted-foreground">
            {language === 'ar' ? 'ليس لديك حساب؟ ' : "Don't have an account? "}
            <Link
              to="/register"
              className="text-primary hover:text-primary/80 underline font-medium"
            >
              {language === 'ar' ? 'إنشاء حساب جديد' : 'Sign up'}
            </Link>
          </p>
        </div>

        {/* Demo credentials (development only)
        {import.meta.env.DEV && (
          <div className={`mt-6 p-4 bg-muted/50 rounded-lg ${isMobile ? 'text-xs' : 'text-sm'}`}>
            <p className="text-xs text-muted-foreground mb-2 font-medium">
              Demo Credentials:
            </p>
            <div className="text-xs text-muted-foreground space-y-1">
              <p>Email: demo@myheritagetree.com</p>
              <p>Password: demo123</p>
            </div>
          </div>
        )} */}
      </CardContent>
    </Card>
  );
};

export default LoginPage;