import React from 'react';
import { Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { useAuthStore } from '@/store/authStore';
import { useUIStore } from '@/store/uiStore';

// Layout components
import AuthLayout from '@/components/layouts/AuthLayout';
import DashboardLayout from '@/components/layouts/DashboardLayout';
import PublicLayout from '@/components/layouts/PublicLayout';
import AdminRoute from '@/components/layouts/AdminRoute';

// Page components
import HomePage from '@/pages/HomePage';
import LoginPage from '@/pages/auth/LoginPage';
import RegisterPage from '@/pages/auth/RegisterPage';
import ForgotPasswordPage from '@/pages/auth/ForgotPasswordPage';
import ResetPasswordPage from '@/pages/auth/ResetPasswordPage';
import VerifyEmailPage from '@/pages/auth/VerifyEmailPage';

import DashboardPage from '@/pages/dashboard/DashboardPage';
import TreesPage from '@/pages/trees/TreesPage';
import TreeViewPage from '@/pages/trees/TreeViewPage';
import TreeEditPage from '@/pages/trees/TreeEditPage';
import SharedTreePage from '@/pages/trees/SharedTreePage';
import PersonPage from '@/pages/persons/PersonPage';
import PersonEditPage from '@/pages/persons/PersonEditPage';
import SearchPage from '@/pages/SearchPage';
import SettingsPage from '@/pages/settings/SettingsPage';
import SubscriptionPage from '@/pages/subscription/SubscriptionPage';
import SubscriptionPlansPage from '@/pages/subscription/SubscriptionPlansPage';
import CheckoutPage from '@/pages/subscription/CheckoutPage';
import SubscriptionManagePage from '@/pages/subscription/SubscriptionManagePage';
import ProfilePage from '@/pages/profile/ProfilePage';
import FeaturesPage from '@/pages/FeaturesPage';
import AboutPage from '@/pages/AboutPage';
import ContactPage from '@/pages/ContactPage';
import PrivacyPage from '@/pages/PrivacyPage';
import TermsPage from '@/pages/TermsPage';
import AdminDashboardPage from '@/pages/admin/AdminDashboardPage';
import ManageJoinRequestsPage from '@/pages/admin/ManageJoinRequestsPage';
import SubscriptionPaymentPage from '@/pages/subscription/SubscriptionPaymentPage';


import NotFoundPage from '@/pages/NotFoundPage';
import LoadingPage from '@/pages/LoadingPage';

// Form components
import TreeCreateForm from '@/components/forms/TreeCreateForm';
import PersonCreateForm from '@/components/forms/PersonCreateForm';

// Protected Route component - TS import fix
const ProtectedRoute: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { isAuthenticated, isLoading, user } = useAuthStore();
  const location = useLocation();
  
  // Protected route authentication check

  // If still loading, show loading page
  if (isLoading) {
    // Still loading, showing loading page
    return <LoadingPage />;
  }

  if (!isAuthenticated) {
    // User not authenticated, redirecting to login
    // Save the attempted URL for redirect after login
    const attemptedUrl = location.pathname + location.search;
    localStorage.setItem('attemptedUrl', attemptedUrl);
    return <Navigate to="/login" replace />;
  }

  // User authenticated, rendering children
  return <>{children}</>;
};

// Public Route component (redirect to dashboard if authenticated)
const PublicRoute: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { isAuthenticated, isLoading } = useAuthStore();
  
  // Public route authentication check

  // If we're loading and we're already authenticated, don't show loading page
  const showLoading = isLoading && !isAuthenticated;
  
  // Public route loading check

  if (showLoading) {
    return <LoadingPage />;
  }

  if (isAuthenticated) {
    // Check if there's a saved attempted URL to redirect to
    const attemptedUrl = localStorage.getItem('attemptedUrl');
    if (attemptedUrl) {
      localStorage.removeItem('attemptedUrl');
      return <Navigate to={attemptedUrl} replace />;
    }
    return <Navigate to="/dashboard" replace />;
  }

  return <>{children}</>;
};

// Main App component
const App: React.FC = () => {
  const { isLoading, isAuthenticated, user } = useAuthStore();
  const { language, theme } = useUIStore();
  
  // App component render with auth state

  // Apply theme and language classes to document
  React.useEffect(() => {
    // Apply theme and language
    const root = document.documentElement;
    
    // Apply language and direction
    root.setAttribute('lang', language);
    root.setAttribute('dir', language === 'ar' ? 'rtl' : 'ltr');
    
    // Apply theme
    if (theme === 'auto') {
      const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
      root.classList.toggle('dark', prefersDark);
    } else {
      root.classList.toggle('dark', theme === 'dark');
    }
  }, [language, theme]);

  // Show loading screen on initial load
  if (isLoading) {
    // Show loading page while initializing
    return <LoadingPage />;
  }

  // Render main app content
  return (
    <div className="min-h-screen bg-background text-foreground">
      <Routes>
        {/* Public routes */}
        <Route
          path="/"
          element={
            <PublicLayout>
              <HomePage />
            </PublicLayout>
          }
        />

        {/* Auth routes */}
        <Route
          path="/login"
          element={
            <PublicRoute>
              <AuthLayout>
                <LoginPage />
              </AuthLayout>
            </PublicRoute>
          }
        />
        <Route
          path="/register"
          element={
            <PublicRoute>
              <AuthLayout>
                <RegisterPage />
              </AuthLayout>
            </PublicRoute>
          }
        />
        <Route
          path="/forgot-password"
          element={
            <PublicRoute>
              <AuthLayout>
                <ForgotPasswordPage />
              </AuthLayout>
            </PublicRoute>
          }
        />
        <Route
          path="/reset-password"
          element={
            <PublicRoute>
              <AuthLayout>
                <ResetPasswordPage />
              </AuthLayout>
            </PublicRoute>
          }
        />
        <Route
          path="/verify-email"
          element={
            <AuthLayout>
              <VerifyEmailPage />
            </AuthLayout>
          }
        />

        {/* Shared tree route - public access */}
        <Route
          path="/shared/:id"
          element={
            <SharedTreePage />
          }
        />

        {/* Protected routes */}
        <Route
          path="/dashboard"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <DashboardPage />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />

        {/* Trees routes */}
        <Route
          path="/trees"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <TreesPage />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/trees/create"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <TreeCreateForm />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/trees/:id"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <TreeViewPage />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />
      
        
        <Route
          path="/trees/:id/edit"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <TreeEditPage />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />

        {/* Person routes */}
        <Route
          path="/persons/create"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <PersonCreateForm />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/persons/:id"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <PersonPage />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/persons/:id/edit"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <PersonEditPage />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />

       

        {/* Other protected routes */}
        <Route
          path="/search"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <SearchPage />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/contact"
          element={
            <PublicLayout>
              <ContactPage />
            </PublicLayout>
          }
        />
        <Route
          path="/profile"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <ProfilePage />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/settings"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <SettingsPage />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/subscription"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <SubscriptionPage />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/subscription/plans"
          element={
            <PublicLayout>
              <SubscriptionPlansPage />
            </PublicLayout>
          }
        />
        <Route
          path="/subscription/payment/:planId"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <SubscriptionPaymentPage />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />
        <Route
          path="/features"
          element={
            <PublicLayout>
              <FeaturesPage />
            </PublicLayout>
          }
        />
        <Route
          path="/about"
          element={
            <PublicLayout>
              <AboutPage />
            </PublicLayout>
          }
        />
        <Route
          path="/privacy"
          element={
            <PublicLayout>
              <PrivacyPage />
            </PublicLayout>
          }
        />
        <Route
          path="/terms"
          element={
            <PublicLayout>
              <TermsPage />
            </PublicLayout>
          }
        />
        <Route
          path="/subscription/checkout"
          element={
            <PublicLayout>
              <CheckoutPage />
            </PublicLayout>
          }
        />
        <Route
          path="/subscription/manage"
          element={
            <ProtectedRoute>
              <DashboardLayout>
                <SubscriptionManagePage />
              </DashboardLayout>
            </ProtectedRoute>
          }
        />

        {/* Admin routes */}
        <Route
          path="/admin/dashboard"
          element={
            <AdminRoute>
              <DashboardLayout>
                <AdminDashboardPage />
              </DashboardLayout>
            </AdminRoute>
          }
        />
        <Route
          path="/admin/join-requests"
          element={
            <AdminRoute>
              <DashboardLayout>
                <ManageJoinRequestsPage />
              </DashboardLayout>
            </AdminRoute>
          }
        />

      

        {/* 404 route */}
        <Route
          path="*"
          element={
            <PublicLayout>
              <NotFoundPage />
            </PublicLayout>
          }
        />
      </Routes>
    </div>
  );
};

export default App;